        long actions = 0;
        long prevLevel = levels[start];

        for (int i = start + 1; i <= end; i++) {
            if (levels[i] < prevLevel) {
                actions += prevLevel - levels[i];
                prevLevel = prevLevel;
            } else {
                prevLevel = levels[i];
            }
        }

        return actions;
    }

    public static int countStableSegments(int[] levels, long m) {
        int n = levels.length;
        int count = 0;

        for (int i = 0; i < n; i++) {
            for (int j = i; j < n; j++) {
                long needed = minWateringActions(levels, i, j);
                if (needed <= m) {
                    count++;
                }
            }
        }

        return count;
    }

