using namespace std;

class Garden {
public:
    long long countStableSegments(const vector<int>& levels, int m) {
        int n = levels.size();
        long long count = 0;
        int left = 0;
        long long current_cost = 0;
        deque<int> dq;

        for (int right = 0; right < n; ++right) {
            while (!dq.empty() && levels[dq.back()] <= levels[right]) {
                int idx = dq.back();
                dq.pop_back();
                int prev_idx = dq.empty() ? left - 1 : dq.back();
                current_cost += (long long)(levels[right] - levels[idx]) * (idx - prev_idx);
            }
            dq.push_back(right);

            while (current_cost > m) {
                current_cost -= (levels[dq.front()] - levels[left]);
                if (dq.front() == left) {
                    dq.pop_front();
                }
                left++;
            }
            count += (right - left + 1);
        }
        return count;
    }
};

