func solve(levels []int, m int) int64 {
	n := len(levels)
	var count int64 = 0
	left := 0
	cost := int64(0)
	stack := []int{}

	for right := 0; right < n; right++ {
		for len(stack) > 0 && levels[stack[len(stack)-1]] <= levels[right] {
			idx := stack[len(stack)-1]
			stack = stack[:len(stack)-1]
			prevIdx := -1
			if len(stack) > 0 {
				prevIdx = stack[len(stack)-1]
			}

			start := prevIdx + 1
			if start < left {
				start = left
			}

			if idx >= start {
				cost += int64(levels[right]-levels[idx]) * int64(idx-start+1)
			}
		}
		stack = append(stack, right)

		for cost > int64(m) && left <= right {
			for len(stack) > 0 && stack[0] < left {
				stack = stack[1:]
			}

			topIdx := stack[0]
			cost -= int64(levels[topIdx] - levels[left])
			left++
		}
		count += int64(right - left + 1)
	}

	return count
}

