    public static long countStableSegments(int[] levels, long m) {
        int n = levels.length;
        long totalStable = 0;
        int right = 0;
        long currentCost = 0;
        Deque<Integer> deque = new ArrayDeque<>();

        for (int left = 0; left < n; left++) {
            while (right < n) {
                long addedCost = 0;
                if (!deque.isEmpty()) {
                    int lastIdx = deque.peekLast();
                    if (levels[right] < levels[lastIdx]) {
                        addedCost = (long) levels[lastIdx] - levels[right];
                    }
                }

                if (currentCost + addedCost <= m) {
                    if (!deque.isEmpty() && levels[right] < levels[deque.peekLast()]) {
                        currentCost += addedCost;
                        deque.addLast(right);
                    } else {
                        deque.addLast(right);
                    }
                    right++;
                } else {
                    break;
                }
            }

            totalStable += (right - left);

            if (!deque.isEmpty() && deque.peekFirst() == left) {
                int removedIdx = deque.pollFirst();
                if (!deque.isEmpty()) {
                    int nextMaxIdx = -1;
                    int maxVal = -1;

                    int tempLeft = left + 1;
                    if(tempLeft < right) {
                        long newCost = 0;
                        int currentMax = levels[tempLeft];
                        for(int i = tempLeft + 1; i < right; i++) {
                            if(levels[i] < currentMax) {
                                newCost += (currentMax - levels[i]);
                            } else {
                                currentMax = levels[i];
                            }
                        }
                        currentCost = newCost;

                        deque.clear();
                        if(tempLeft < right) {
                            int curM = levels[tempLeft];
                            deque.addLast(tempLeft);
                            for(int i = tempLeft + 1; i < right; i++) {
                                if(levels[i] > curM) {
                                    curM = levels[i];
                                    deque.addLast(i);
                                } else if (levels[i] < levels[deque.peekLast()]) {
                                    deque.addLast(i);
                                }
                            }
                        }
                    } else {
                        currentCost = 0;
                        deque.clear();
                    }
                } else {
                    currentCost = 0;
                }
            }
        }
        return totalStable;
    }
}

