func optimalTreasure(grid [][]int) int {
    m := len(grid)
    n := len(grid[0])

    dp := make([][][]int, m)
    for i := 0; i < m; i++ {
        dp[i] = make([][]int, n)
        for j := 0; j < n; j++ {
            dp[i][j] = make([]int, 3)
            for k := 0; k < 3; k++ {
                dp[i][j][k] = -1000000000
            }
        }
    }

    if grid[0][0] < 0 {
        dp[0][0][1] = 0
        dp[0][0][0] = grid[0][0]
    } else {
        dp[0][0][0] = grid[0][0]
    }

    for i := 0; i < m; i++ {
        for j := 0; j < n; j++ {
            if i == 0 && j == 0 {
                continue
            }

            cellValue := grid[i][j]

            for skips := 0; skips <= 2; skips++ {
                fromTop := -1000000000
                fromLeft := -1000000000

                if i > 0 {
                    fromTop = dp[i-1][j][skips]
                }
                if j > 0 {
                    fromLeft = dp[i][j-1][skips]
                }

                best := max(fromTop, fromLeft)
                if best > -1000000000 {
                    dp[i][j][skips] = max(dp[i][j][skips], best+cellValue)
                }

                if cellValue < 0 && skips > 0 {
                    fromTop = -1000000000
                    fromLeft = -1000000000

                    if i > 0 {
                        fromTop = dp[i-1][j][skips-1]
                    }
                    if j > 0 {
                        fromLeft = dp[i][j-1][skips-1]
                    }

                    best = max(fromTop, fromLeft)
                    if best > -1000000000 {
                        dp[i][j][skips] = max(dp[i][j][skips], best)
                    }
                }
            }
        }
    }

    result := dp[m-1][n-1][0]
    result = max(result, dp[m-1][n-1][1])
    result = max(result, dp[m-1][n-1][2])

    return result
}

