import java.util.*;

public class Solution {

    public int optimalTreasure(int[][] grid) {
        int m = grid.length;
        int n = grid[0].length;

        int[][][][] dp = new int[m][n][3][3];
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                for (int k = 0; k < 3; k++) {
                    Arrays.fill(dp[i][j][k], Integer.MIN_VALUE);
                }
            }
        }

        dp[0][0][0][0] = grid[0][0];
        if (grid[0][0] < 0) {
            dp[0][0][1][0] = 0;
        }

        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                if (i == 0 && j == 0) continue;

                for (int used = 0; used <= 2; used++) {
                    for (int last = 0; last <= 2; last++) {
                        int currentValue = grid[i][j];

                        if (i > 0 && dp[i-1][j][used][last] != Integer.MIN_VALUE) {
                            dp[i][j][used][0] = Math.max(dp[i][j][used][0], dp[i-1][j][used][last] + currentValue);
                        }
                        if (j > 0 && dp[i][j-1][used][last] != Integer.MIN_VALUE) {
                            dp[i][j][used][0] = Math.max(dp[i][j][used][0], dp[i][j-1][used][last] + currentValue);
                        }

                        if (currentValue < 0 && used < 2) {
                            if (i > 0 && dp[i-1][j][used][last] != Integer.MIN_VALUE) {
                                dp[i][j][used+1][1] = Math.max(dp[i][j][used+1][1], dp[i-1][j][used][last]);
                            }
                            if (j > 0 && dp[i][j-1][used][last] != Integer.MIN_VALUE) {
                                dp[i][j][used+1][1] = Math.max(dp[i][j][used+1][1], dp[i][j-1][used][last]);
                            }
                        }
                    }
                }
            }
        }

        int result = Integer.MIN_VALUE;
        for (int used = 0; used <= 2; used++) {
            for (int last = 0; last <= 2; last++) {
                result = Math.max(result, dp[m-1][n-1][used][last]);
            }
        }

        return result;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int m = sc.nextInt();
        int n = sc.nextInt();
        int[][] grid = new int[m][n];

        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                grid[i][j] = sc.nextInt();
            }
        }

        Solution sol = new Solution();
        int answer = sol.optimalTreasure(grid);
        System.out.println(answer);

        sc.close();
    }
}

