	if !scanner.Scan() {
		return
	}
	n, _ := strconv.Atoi(scanner.Text())

	grid := make([][]int, m)
	for i := 0; i < m; i++ {
		grid[i] = make([]int, n)
		for j := 0; j < n; j++ {
			if scanner.Scan() {
				val, _ := strconv.Atoi(scanner.Text())
				grid[i][j] = val
			}
		}
	}

	dp := make([][][3]int64, m)
	for i := 0; i < m; i++ {
		dp[i] = make([][3]int64, n)
		for j := 0; j < n; j++ {
			for k := 0; k < 3; k++ {
				dp[i][j][k] = -2e18
			}
		}
	}

	val0 := int64(grid[0][0])
	dp[0][0][0] = val0
	if grid[0][0] < 0 {
		dp[0][0][1] = 0
	}

	for i := 0; i < m; i++ {
		for j := 0; j < n; j++ {
			for k := 0; k < 3; k++ {
				if dp[i][j][k] <= -1e18 {
					continue
				}

				if i+1 < m {
					v := int64(grid[i+1][j])
					if dp[i][j][k]+v > dp[i+1][j][k] {
						dp[i+1][j][k] = dp[i][j][k] + v
					}
					if k < 2 && grid[i+1][j] < 0 {
						if dp[i][j][k] > dp[i+1][j][k+1] {
							dp[i+1][j][k+1] = dp[i][j][k]
						}
					}
				}

				if j+1 < n {
					v := int64(grid[i][j+1])
					if dp[i][j][k]+v > dp[i][j+1][k] {
						dp[i][j+1][k] = dp[i][j][k] + v
					}
					if k < 2 && grid[i][j+1] < 0 {
						if dp[i][j][k] > dp[i][j+1][k+1] {
							dp[i][j+1][k+1] = dp[i][j][k]
						}
					}
				}
			}
		}
	}

	ans := dp[m-1][n-1][0]
	if dp[m-1][n-1][1] > ans {
		ans = dp[m-1][n-1][1]
	}
	if dp[m-1][n-1][2] > ans {
		ans = dp[m-1][n-1][2]
	}
	fmt.Println(ans)
