            }
        }
        System.out.println(solve(grid, m, n));
    }

    private static long solve(int[][] grid, int m, int n) {
        long[][][] dp = new long[m][n][3];
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                for (int k = 0; k < 3; k++) {
                    dp[i][j][k] = Long.MIN_VALUE;
                }
            }
        }

        dp[0][0][0] = (long) grid[0][0];
        if (grid[0][0] < 0) {
            dp[0][0][1] = 0;
        }

        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                for (int k = 0; k < 3; k++) {
                    if (dp[i][j][k] == Long.MIN_VALUE) continue;

                    int[][] dirs = {{0, 1}, {1, 0}};
                    for (int[] dir : dirs) {
                        int ni = i + dir[0];
                        int nj = j + dir[1];

                        if (ni < m && nj < n) {
                            long val = (long) grid[ni][nj];

                            dp[ni][nj][k] = Math.max(dp[ni][nj][k], dp[i][j][k] + val);

                            if (k + 1 < 3 && val < 0) {
                                dp[ni][nj][k + 1] = Math.max(dp[ni][nj][k + 1], dp[i][j][k]);
                            }
                        }
                    }
                }
            }
        }

        long res = dp[m - 1][n - 1][0];
        res = Math.max(res, dp[m - 1][n - 1][1]);
        res = Math.max(res, dp[m - 1][n - 1][2]);
        return res;
    }
}

