struct Result {
    long long maxDist;
    int minStations;
};

class Solution {
public:
    vector<vector<pair<int, long long>>> adj;
    vector<int> attractions;
    long long globalMaxDist;
    int globalMinStations;

    Result dfs(int node, int parent, unordered_set<int>& visitedAttractions) {
        int attraction = attractions[node];
        bool wasPresent = visitedAttractions.count(attraction) > 0;

        if (wasPresent) {
            return {0, 0};
        }

        visitedAttractions.insert(attraction);

        long long maxDist = 0;
        int minStations = 1;

        vector<Result> childResults;

        for (auto& edge : adj[node]) {
            int child = edge.first;
            long long dist = edge.second;

            if (child == parent) continue;

            Result childRes = dfs(child, node, visitedAttractions);

            if (childRes.minStations > 0) {
                childResults.push_back({childRes.maxDist + dist, childRes.minStations});
            }
        }

        if (childResults.empty()) {
            if (maxDist > globalMaxDist || (maxDist == globalMaxDist && minStations < globalMinStations)) {
                globalMaxDist = maxDist;
                globalMinStations = minStations;
            }
        } else {
            sort(childResults.begin(), childResults.end(), [](const Result& a, const Result& b) {
                return a.maxDist > b.maxDist;
            });

            maxDist = childResults[0].maxDist;
            minStations = childResults[0].minStations + 1;

            if (maxDist > globalMaxDist || (maxDist == globalMaxDist && minStations < globalMinStations)) {
                globalMaxDist = maxDist;
                globalMinStations = minStations;
            }

            if (childResults.size() >= 2) {
                long long combinedDist = childResults[0].maxDist + childResults[1].maxDist;
                int combinedStations = childResults[0].minStations + childResults[1].minStations + 1;

                if (combinedDist > globalMaxDist || (combinedDist == globalMaxDist && combinedStations < globalMinStations)) {
                    globalMaxDist = combinedDist;
                    globalMinStations = combinedStations;
                }
            }
        }

        visitedAttractions.erase(attraction);

        return {maxDist, minStations};
    }

    vector<long long> solve(vector<vector<long long>>& routes, vector<int>& attr) {
        int n = attr.size();
        attractions = attr;
        adj.resize(n);
        globalMaxDist = 0;
        globalMinStations = 1;

        for (auto& route : routes) {
            int u = route[0];
            int v = route[1];
            long long dist = route[2];
            adj[u].push_back({v, dist});
            adj[v].push_back({u, dist});
        }

        unordered_set<int> visitedAttractions;
        dfs(0, -1, visitedAttractions);

        return {globalMaxDist, globalMinStations};
    }
};

