func longestAdventureRoute(routes [][]int, attractions []int) []int {
    n := len(attractions)
    if n == 0 {
        return []int{0, 0}
    }

    graph := make([][][2]int, n)
    for _, route := range routes {
        x, y, d := route[0], route[1], route[2]
        graph[x] = append(graph[x], [2]int{y, d})
        graph[y] = append(graph[y], [2]int{x, d})
    }

    maxDist := 0
    minStations := 1

    var dfs func(node, parent int, visited map[int]bool, dist, stations int)
    dfs = func(node, parent int, visited map[int]bool, dist, stations int) {
        if dist > maxDist {
            maxDist = dist
            minStations = stations
        } else if dist == maxDist && stations < minStations {
            minStations = stations
        }

        for _, edge := range graph[node] {
            child, d := edge[0], edge[1]
            if child == parent {
                continue
            }

            attractionType := attractions[child]
            if !visited[attractionType] {
                visited[attractionType] = true
                dfs(child, node, visited, dist+d, stations+1)
                delete(visited, attractionType)
            }
        }
    }

    var buildTree func(node, parent int)
    buildTree = func(node, parent int) {
        visited := make(map[int]bool)
        visited[attractions[node]] = true
        dfs(node, parent, visited, 0, 1)

        for _, edge := range graph[node] {
            child := edge[0]
            if child != parent {
                buildTree(child, node)
            }
        }
    }

    buildTree(0, -1)

    return []int{maxDist, minStations}
}

