        for stationX, stationY, distance in routes:
            graph[stationX].append((stationY, distance))
            graph[stationY].append((stationX, distance))

        parent = [-1] * n
        children = defaultdict(list)

        def build_tree(node, par):
            parent[node] = par
            for neighbor, dist in graph[node]:
                if neighbor != par:
                    children[node].append((neighbor, dist))
                    build_tree(neighbor, node)

        build_tree(0, -1)

        max_distance = 0
        min_stations = float('inf')

        def dfs(node, visited_artifacts, current_distance, station_count):
            nonlocal max_distance, min_stations

            artifact = attractions[node]
            if artifact in visited_artifacts:
                return

            visited_artifacts.add(artifact)

            if current_distance > max_distance:
                max_distance = current_distance
                min_stations = station_count
            elif current_distance == max_distance:
                min_stations = min(min_stations, station_count)

            for child, dist in children[node]:
                dfs(child, visited_artifacts, current_distance + dist, station_count + 1)

            visited_artifacts.remove(artifact)

        for start_node in range(n):
