            for(auto& e : adj[u]){
                if(e.to != parent[u]){
                    parent[e.to] = u;
                    children[u].push_back(e.to);
                    q.push_back(e.to);
                }
            }
        }

        vector<vector<Edge>> tree_adj(n);
        for(int i=0; i<n; ++i){
            for(auto& e : adj[i]){
                if(e.to != parent[i]){
                    tree_adj[i].push_back(e);
                }
            }
        }

        for (int i = 0; i < n; ++i) {
            visited.clear();
            dfs(i, parent[i], 0, 1, tree_adj, attractions);
        }

        return {maxDist, (long long)minNodes};
