using namespace std;

int shortestValidRouteSegment(string map_str, string pattern) {
    int n = map_str.length();
    int m = pattern.length();

    int first_hash = -1, second_hash = -1;
    for (int i = 0; i < m; i++) {
        if (pattern[i] == '#') {
            if (first_hash == -1) first_hash = i;
            else second_hash = i;
        }
    }

    string prefix = pattern.substr(0, first_hash);
    string middle = pattern.substr(first_hash + 1, second_hash - first_hash - 1);
    string suffix = pattern.substr(second_hash + 1);

    int min_len = -1;

    for (int start = 0; start < n; start++) {
        if (start + (int)prefix.length() > n) break;

        bool prefix_match = true;
        for (int i = 0; i < (int)prefix.length(); i++) {
            if (map_str[start + i] != prefix[i]) {
                prefix_match = false;
                break;
            }
        }
        if (!prefix_match) continue;

        int prefix_end = start + prefix.length();

        for (int end = prefix_end; end <= n; end++) {
            if (end < (int)suffix.length()) continue;

            bool suffix_match = true;
            for (int i = 0; i < (int)suffix.length(); i++) {
                if (map_str[end - suffix.length() + i] != suffix[i]) {
                    suffix_match = false;
                    break;
                }
            }
            if (!suffix_match) continue;

            int suffix_start = end - suffix.length();

            if (suffix_start < prefix_end) continue;

            string between = map_str.substr(prefix_end, suffix_start - prefix_end);

            if (middle.empty()) {
                int seg_len = end - start;
                if (min_len == -1 || seg_len < min_len) {
                    min_len = seg_len;
                }
            } else {
                size_t pos = between.find(middle);
                if (pos != string::npos) {
                    int seg_len = end - start;
                    if (min_len == -1 || seg_len < min_len) {
                        min_len = seg_len;
                    }
                }
            }
        }
    }

    return min_len;
}

