func matches(segment string, prefix string, middle string, suffix string) bool {
    if !strings.HasPrefix(segment, prefix) {
        return false
    }

    if !strings.HasSuffix(segment, suffix) {
        return false
    }

    if len(segment) < len(prefix) + len(suffix) {
        return false
    }

    remaining := segment[len(prefix):len(segment)-len(suffix)]

    if len(middle) == 0 {
        return true
    }

    idx := strings.Index(remaining, middle)
    return idx != -1
}

