func solve(code string) int64 {
	n := len(code)
	var total int64 = 0

	modCounts := make([][9][]int, 10)
	for i := 0; i < 10; i++ {
		for m := 1; m <= 9; m++ {
			modCounts[i][m-1] = make([]int, m)
		}
	}

	powerMods := make([][10]int, n+1)
	for m := 1; m <= 9; m++ {
		powerMods[0][m] = 1 % m
		for i := 1; i <= n; i++ {
			powerMods[i][m] = (powerMods[i-1][m] * 10) % m
		}
	}

	prefixMods := make([][10]int, n+1)
	for i := 0; i < n; i++ {
		digit := int(code[i] - '0')
		for m := 1; m <= 9; m++ {
			prefixMods[i+1][m] = (prefixMods[i][m]*10 + digit) % m
		}

		lastDigit := digit
		if lastDigit != 0 {
			m := lastDigit
			target := prefixMods[i+1][m]

			count := 0
			for prevLastDigit := 0; prevLastDigit <= 9; prevLastDigit++ {
				count += modCounts[prevLastDigit][m-1][target]
			}
			total += int64(count)
			total++
		}

		for m := 1; m <= 9; m++ {
			modCounts[lastDigit][m-1][prefixMods[i+1][m]]++
		}
	}

	return total
}

