int minimumUpgrades(vector<int>& scores, vector<int>& milestones) {
    int n = scores.size();
    int m = milestones.size();

    int minMoves = INT_MAX;

    vector<int> perm(m);
    for (int i = 0; i < m; i++) {
        perm[i] = i;
    }

    do {
        vector<int> assignment(m);
        for (int i = 0; i < m; i++) {
            assignment[i] = i;
        }

        do {
            vector<bool> used(n, false);
            int moves = 0;
            bool valid = true;

            for (int i = 0; i < m; i++) {
                int milestone = milestones[perm[i]];
                int bestScore = -1;
                int bestCost = INT_MAX;

                for (int j = 0; j < n; j++) {
                    if (!used[j]) {
                        int nextMultiple = ((scores[j] + milestone - 1) / milestone) * milestone;
                        int cost = nextMultiple - scores[j];
                        if (cost < bestCost) {
                            bestCost = cost;
                            bestScore = j;
                        }
                    }
                }

                if (bestScore == -1) {
                    valid = false;
                    break;
                }

                used[bestScore] = true;
                moves += bestCost;
            }

            if (valid) {
                minMoves = min(minMoves, moves);
            }

        } while (next_permutation(assignment.begin(), assignment.end()) && m <= n);

    } while (next_permutation(perm.begin(), perm.end()));

    vector<int> sortedScores = scores;
    sort(sortedScores.begin(), sortedScores.end());

    function<int(int, int)> solve = [&](int mask, int idx) -> int {
        if (mask == (1 << m) - 1) return 0;
        if (idx >= n) return INT_MAX / 2;

        int res = solve(mask, idx + 1);

        for (int i = 0; i < m; i++) {
            if (mask & (1 << i)) continue;
            int milestone = milestones[i];
            int nextMultiple = ((sortedScores[idx] + milestone - 1) / milestone) * milestone;
            int cost = nextMultiple - sortedScores[idx];
            int subRes = solve(mask | (1 << i), idx + 1);
            if (subRes != INT_MAX / 2) {
                res = min(res, cost + subRes);
            }
        }

        return res;
    };

    return solve(0, 0);
}

