func minimumUpgrades(scores []int, milestones []int) int {
    n := len(scores)
    m := len(milestones)

    minMoves := math.MaxInt32

    var backtrack func(int, []bool, int)
    backtrack = func(scoreIdx int, covered []bool, moves int) {
        if moves >= minMoves {
            return
        }

        allCovered := true
        for i := 0; i < m; i++ {
            if !covered[i] {
                allCovered = false
                break
            }
        }

        if allCovered {
            if moves < minMoves {
                minMoves = moves
            }
            return
        }

        if scoreIdx >= n {
            return
        }

        score := scores[scoreIdx]

        maxMilestone := 0
        for _, ms := range milestones {
            if ms > maxMilestone {
                maxMilestone = ms
            }
        }

        maxIncrease := maxMilestone - score + maxMilestone
        if maxIncrease < 0 {
            maxIncrease = maxMilestone
        }

        for increase := 0; increase <= maxIncrease; increase++ {
            newScore := score + increase
            newCovered := make([]bool, m)
            copy(newCovered, covered)

            for i := 0; i < m; i++ {
                if newCovered[i] {
                    continue
                }
                if newScore % milestones[i] == 0 {
                    newCovered[i] = true
                }
            }

            backtrack(scoreIdx+1, newCovered, moves+increase)
        }
    }

    covered := make([]bool, m)
    for i := 0; i < m; i++ {
        for j := 0; j < n; j++ {
            if scores[j] % milestones[i] == 0 {
                covered[i] = true
                break
            }
        }
    }

    backtrack(0, covered, 0)

    return minMoves
}

