            return minMoves;
        }

        private int tryAssignment(int[] scores, int[] milestones, int idx, int[] assignment, int[] order) {
            if (idx == milestones.length) {
                return calculateMoves(scores, milestones, assignment);
            }

            int milestoneIdx = order[idx];
            int minMoves = Integer.MAX_VALUE;

            for (int scoreIdx = 0; scoreIdx < scores.length; scoreIdx++) {
                assignment[milestoneIdx] = scoreIdx;
                int moves = tryAssignment(scores, milestones, idx + 1, assignment, order);
                minMoves = Math.min(minMoves, moves);
            }

            return minMoves;
        }

        private int calculateMoves(int[] scores, int[] milestones, int[] assignment) {
            int[] maxNeeded = new int[scores.length];

            for (int i = 0; i < milestones.length; i++) {
                int milestone = milestones[i];
                int scoreIdx = assignment[i];
                int score = scores[scoreIdx];

                int nextMultiple = ((score + milestone - 1) / milestone) * milestone;
                int needed = nextMultiple - score;

                maxNeeded[scoreIdx] = Math.max(maxNeeded[scoreIdx], needed);
            }

            int total = 0;
            for (int moves : maxNeeded) {
                total += moves;
            }
            return total;
        }

        private boolean nextPermutation(int[] array) {
            int i = array.length - 2;
            while (i >= 0 && array[i] >= array[i + 1]) {
                i--;
            }

            if (i < 0) {
                return false;
            }

            int j = array.length - 1;
            while (array[j] <= array[i]) {
                j--;
            }

            swap(array, i, j);
            reverse(array, i + 1, array.length - 1);
            return true;
        }

        private void swap(int[] array, int i, int j) {
            int temp = array[i];
            array[i] = array[j];
            array[j] = temp;
        }

        private void reverse(int[] array, int start, int end) {
            while (start < end) {
                swap(array, start, end);
                start++;
                end--;
            }
        }
    }

