        vector<vector<int>> cost(n, vector<int>(m));

        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < m; ++j) {
                int rem = scores[i] % milestones[j];
                if (rem == 0) cost[i][j] = 0;
                else cost[i][j] = milestones[j] - rem;
            }
        }

        vector<vector<int>> mask_costs(n, vector<int>(1 << m));
        for (int i = 0; i < n; ++i) {
            for (int mask = 0; mask < (1 << m); ++mask) {
                int max_c = 0;
                for (int j = 0; j < m; ++j) {
                    if ((mask >> j) & 1) {
                        max_c = max(max_c, cost[i][j]);
                    }
                }
                mask_costs[i][mask] = max_c;
            }
        }

        vector<int> dp(1 << m, 1e9);
        dp[0] = 0;

        for (int i = 0; i < n; ++i) {
            vector<int> next_dp = dp;
            for (int prev_mask = 0; prev_mask < (1 << m); ++prev_mask) {
                if (dp[prev_mask] == 1e9) continue;
                int remaining = ((1 << m) - 1) ^ prev_mask;
                for (int submask = remaining; submask > 0; submask = (submask - 1) & remaining) {
                    next_dp[prev_mask | submask] = min(next_dp[prev_mask | submask], dp[prev_mask] + mask_costs[i][submask]);
                }
            }
            dp = next_dp;
        }

        return dp[(1 << m) - 1];
    }
};

