    private static int[] parse(String line) {
        line = line.trim();
        if (line.startsWith("scores = ")) line = line.substring(9);
        else if (line.startsWith("milestones = ")) line = line.substring(13);
        line = line.replace("[", "").replace("]", "").replace(" ", "");
        if (line.isEmpty()) return new int[0];
        String[] parts = line.split(",");
        int[] res = new int[parts.length];
        for (int i = 0; i < parts.length; i++) res[i] = Integer.parseInt(parts[i]);
        return res;
    }

    private static int solve(int[] scores, int[] milestones) {
        int m = milestones.length;
        int n = scores.length;
        int[][] cost = new int[n][1 << m];

        for (int i = 0; i < n; i++) {
            for (int mask = 0; mask < (1 << m); mask++) {
                int minMoves = Integer.MAX_VALUE;
                for (int target = scores[i]; target <= scores[i] + 10000; target++) {
                    boolean ok = true;
                    for (int j = 0; j < m; j++) {
                        if (((mask >> j) & 1) == 1) {
                            if (target % milestones[j] != 0) {
                                ok = false;
                                break;
                            }
                        }
                    }
                    if (ok) {
                        minMoves = target - scores[i];
                        break;
                    }
                }
                cost[i][mask] = minMoves;
            }
        }

        long[] dp = new long[1 << m];
        Arrays.fill(dp, Integer.MAX_VALUE);
        dp[0] = 0;

        for (int i = 0; i < n; i++) {
            long[] nextDp = dp.clone();
            for (int mask = 0; mask < (1 << m); mask++) {
                if (dp[mask] == Integer.MAX_VALUE) continue;
                for (int submask = 1; submask < (1 << m); submask++) {
                    int newMask = mask | submask;
                    if (cost[i][submask] != Integer.MAX_VALUE) {
                        nextDp[newMask] = Math.min(nextDp[newMask], dp[mask] + cost[i][submask]);
                    }
                }
            }
            dp = nextDp;
        }

        return (int) dp[(1 << m) - 1];
    }
}

