using namespace std;

string solve(string inscription) {
    int n = inscription.length();
    if (n < 3) return "";

    int minOps = INT_MAX;
    string result = "";

    for (char target = 'a'; target <= 'z'; target++) {
        int ops = 0;
        for (int i = 0; i < n; i++) {
            ops += abs(inscription[i] - target);
        }
        if (ops < minOps) {
            minOps = ops;
            result = string(n, target);
        }
    }

    vector<int> groups;
    int i = 0;
    while (i < n) {
        int j = i;
        while (j < n && inscription[j] == inscription[i]) {
            j++;
        }
        groups.push_back(j - i);
        i = j;
    }

    if (groups.size() == 1 && groups[0] >= 3) {
        return inscription;
    }

    for (char target = 'a'; target <= 'z'; target++) {
        for (int mask = 0; mask < (1 << n); mask++) {
            string candidate = inscription;
            int ops = 0;
            bool valid = true;

            for (int pos = 0; pos < n; pos++) {
                if (mask & (1 << pos)) {
                    candidate[pos] = target;
                    ops += abs(inscription[pos] - target);
                }
            }

            vector<pair<char, int>> runs;
            int idx = 0;
            while (idx < n) {
                int start = idx;
                while (idx < n && candidate[idx] == candidate[start]) {
                    idx++;
                }
                runs.push_back({candidate[start], idx - start});
            }

            bool isIdeal = true;
            for (auto& run : runs) {
                if (run.second < 3) {
                    isIdeal = false;
                    break;
                }
            }

            if (isIdeal) {
                if (ops < minOps || (ops == minOps && candidate < result)) {
                    minOps = ops;
                    result = candidate;
                }
            }
        }
    }

    if (minOps == INT_MAX) return "";
    return result;
}

