func tryAssignment(inscription string, numGroups int, targets []byte) (string, int) {
    n := len(inscription)

    dp := make([][][]int, n+1)
    parent := make([][][]struct{ pos, group, count int }, n+1)

    for i := range dp {
        dp[i] = make([][]int, numGroups+1)
        parent[i] = make([][]struct{ pos, group, count int }, numGroups+1)
        for j := range dp[i] {
            dp[i][j] = make([]int, n+1)
            parent[i][j] = make([]struct{ pos, group, count int }, n+1)
            for k := range dp[i][j] {
                dp[i][j][k] = int(1e9)
            }
        }
    }

    dp[0][0][0] = 0

    for i := 0; i < n; i++ {
        for g := 0; g <= numGroups; g++ {
            for cnt := 0; cnt <= n; cnt++ {
