                        dp[i+1][g][newCnt] = dp[i][g][cnt] + cost
                        parent[i+1][g][newCnt] = struct{ pos, group, count int }{i, g, cnt}
                    }
                }

                if cnt >= 3 && g+1 <= numGroups {
                    if dp[i][g][cnt] < dp[i][g+1][0] {
                        dp[i][g+1][0] = dp[i][g][cnt]
                        parent[i][g+1][0] = struct{ pos, group, count int }{i, g, cnt}
                    }
                }
