    }

    minCost := int(1e9)
    endGroup := -1
    for g := 1; g <= numGroups; g++ {
        for cnt := 3; cnt <= n; cnt++ {
            if dp[n][g][cnt] < minCost {
                minCost = dp[n][g][cnt]
                endGroup = g
            }
        }
    }

    if endGroup == -1 {
