public class Solution {

    public String minimalChangeIdealInscription(String inscription) {
        int n = inscription.length();

        if (n < 3) {
            return "";
        }

        int minCost = Integer.MAX_VALUE;
        String result = "";

        for (int mask = 0; mask < (1 << (n - 1)); mask++) {
            List<Integer> groups = new ArrayList<>();
            int start = 0;

            for (int i = 0; i < n - 1; i++) {
                if ((mask & (1 << i)) != 0) {
                    groups.add(i + 1 - start);
                    start = i + 1;
                }
            }
            groups.add(n - start);

            boolean valid = true;
            for (int len : groups) {
                if (len < 3) {
                    valid = false;
                    break;
                }
            }

            if (!valid) continue;

            int pos = 0;
            int totalCost = 0;
            StringBuilder candidate = new StringBuilder();

            for (int groupLen : groups) {
                int bestCost = Integer.MAX_VALUE;
                char bestChar = 'a';

                for (char target = 'a'; target <= 'z'; target++) {
                    int cost = 0;
                    for (int i = pos; i < pos + groupLen; i++) {
                        cost += Math.abs(inscription.charAt(i) - target);
                    }

                    if (cost < bestCost) {
                        bestCost = cost;
                        bestChar = target;
                    }
                }

                totalCost += bestCost;
                for (int i = 0; i < groupLen; i++) {
                    candidate.append(bestChar);
                }
                pos += groupLen;
            }

            if (totalCost < minCost || (totalCost == minCost && candidate.toString().compareTo(result) < 0)) {
                minCost = totalCost;
                result = candidate.toString();
            }
        }

        return result;
    }

