class Solution:
    def minimalChangeIdealInscription(self, inscription: str) -> str:
        n = len(inscription)

        if n < 3:
            return ""

        best_cost = float('inf')
        best_result = ""

        def cost_to_change(s, target_char):
            total = 0
            for ch in s:
                total += abs(ord(ch) - ord(target_char))
            return total

        def try_partition(partition):
            nonlocal best_cost, best_result

            valid = True
            for start, end in partition:
                if end - start < 3:
                    valid = False
                    break

            if not valid:
                return

            total_cost = 0
            result_parts = []

            for start, end in partition:
                segment = inscription[start:end]
                min_seg_cost = float('inf')
                best_char = None

                for target in range(ord('a'), ord('z') + 1):
                    target_char = chr(target)
                    seg_cost = cost_to_change(segment, target_char)
                    if seg_cost < min_seg_cost or (seg_cost == min_seg_cost and (best_char is None or target_char < best_char)):
                        min_seg_cost = seg_cost
                        best_char = target_char

                total_cost += min_seg_cost
                result_parts.append(best_char * (end - start))

            if total_cost < best_cost or (total_cost == best_cost and ''.join(result_parts) < best_result):
                best_cost = total_cost
                best_result = ''.join(result_parts)

        def generate_partitions(pos, current_partition):
            if pos == n:
                if current_partition:
                    try_partition(current_partition[:])
                return

            for end in range(pos + 3, n + 1):
                current_partition.append((pos, end))
                generate_partitions(end, current_partition)
                current_partition.pop()

        generate_partitions(0, [])

        return best_result if best_cost != float('inf') else ""

