class Solution {
public:
    int findUniqueSignal(vector<int>& signals, int w) {
        int n = signals.size();
        map<int, set<int>> valueToWindows;

        for (int i = 0; i <= n - w; i++) {
            for (int j = i; j < i + w; j++) {
                valueToWindows[signals[j]].insert(i);
            }
        }

        int maxValue = -1;
        for (auto& p : valueToWindows) {
            if (p.second.size() == 1) {
                maxValue = max(maxValue, p.first);
            }
        }

        return maxValue;
    }
};

