    bool findUniformSegment(string sequence, int n) {
        int len = sequence.length();

        for (int i = 0; i <= len - n; i++) {
            bool allSame = true;
            char c = sequence[i];

            for (int j = i; j < i + n; j++) {
                if (sequence[j] != c) {
                    allSame = false;
                    break;
                }
            }

            if (allSame) {
