import java.util.*;

public class Solution {
    public boolean findUniformSegment(String sequence, int n) {
        int len = sequence.length();

        for (int i = 0; i <= len - n; i++) {
            boolean isUniform = true;
            char c = sequence.charAt(i);

            for (int j = i; j < i + n; j++) {
                if (sequence.charAt(j) != c) {
                    isUniform = false;
                    break;
                }
            }

            if (!isUniform) {
                continue;
            }

            boolean validBefore = true;
            if (i > 0) {
                if (sequence.charAt(i - 1) == c) {
                    validBefore = false;
                }
            }

            boolean validAfter = true;
            if (i + n < len) {
                if (sequence.charAt(i + n) == c) {
                    validAfter = false;
                }
            }

            if (validBefore && validAfter) {
                return true;
            }
        }

