using namespace std;

const long long MOD = 1e9 + 7;

long long mod_pow(long long base, long long exp, long long mod) {
    long long result = 1;
    base %= mod;
    while (exp > 0) {
        if (exp % 2 == 1) {
            result = (result * base) % mod;
        }
        base = (base * base) % mod;
        exp /= 2;
    }
    return result;
}

long long mod_inverse(long long a, long long mod) {
    return mod_pow(a, mod - 2, mod);
}

int main() {
    int n, maxCount;
    cin >> n;
    vector<long long> scores(n);
    for (int i = 0; i < n; i++) {
        cin >> scores[i];
    }
    cin >> maxCount;

    vector<long long> fact(n + 1);
    fact[0] = 1;
    for (int i = 1; i <= n; i++) {
        fact[i] = (fact[i - 1] * i) % MOD;
    }

    vector<long long> inv_fact(n + 1);
    inv_fact[n] = mod_inverse(fact[n], MOD);
    for (int i = n - 1; i >= 0; i--) {
        inv_fact[i] = (inv_fact[i + 1] * (i + 1)) % MOD;
    }

    auto C = [&](int n, int k) -> long long {
        if (k < 0 || k > n) return 0;
        return (fact[n] * inv_fact[k] % MOD) * inv_fact[n - k] % MOD;
    };

    long long total = 0;

    for (int i = 0; i < n; i++) {
        for (int k = 1; k <= maxCount; k++) {
            long long as_min = 0;
            long long as_max = 0;

            int greater = 0;
            for (int j = 0; j < n; j++) {
                if (j != i && scores[j] > scores[i]) {
                    greater++;
                }
            }
            as_min = C(greater, k - 1);

            int smaller = 0;
            for (int j = 0; j < n; j++) {
                if (j != i && scores[j] < scores[i]) {
                    smaller++;
                }
            }
            as_max = C(smaller, k - 1);

            long long contribution = ((as_min + as_max) % MOD * (scores[i] % MOD)) % MOD;
            total = (total + contribution) % MOD;
        }
    }

    cout << total << endl;

    return 0;
}

