func computeExtremeSum(scores []int, maxCount int) int {
    n := len(scores)
    result := int64(0)

    for size := 1; size <= maxCount && size <= n; size++ {
        contribution := computeContributionForSize(scores, size)
        result = (result + contribution) % MOD
    }

    return int(result)
}

func computeContributionForSize(scores []int, size int) int64 {
    n := len(scores)
    total := int64(0)

    indices := make([]int, size)
    for i := 0; i < size; i++ {
        indices[i] = i
    }

    for {
        minVal := scores[indices[0]]
        maxVal := scores[indices[0]]
        for i := 1; i < size; i++ {
            if scores[indices[i]] < minVal {
                minVal = scores[indices[i]]
            }
            if scores[indices[i]] > maxVal {
                maxVal = scores[indices[i]]
            }
        }
        total = (total + int64(minVal) + int64(maxVal)) % MOD

        nextPos := size - 1
        for nextPos >= 0 {
            if indices[nextPos] < n - size + nextPos {
                break
            }
            nextPos--
        }

        if nextPos < 0 {
            break
        }

        indices[nextPos]++
        for i := nextPos + 1; i < size; i++ {
            indices[i] = indices[i-1] + 1
        }
    }

    return total
}

