    static long computeExtremeSum(int[] scores, int maxCount) {
        int n = scores.length;
        long result = 0;

        long[][] C = new long[n + 1][n + 1];
        for (int i = 0; i <= n; i++) {
            C[i][0] = 1;
            for (int j = 1; j <= i; j++) {
                C[i][j] = (C[i-1][j-1] + C[i-1][j]) % MOD;
            }
        }

        for (int len = 1; len <= Math.min(maxCount, n); len++) {
            for (int i = 0; i < n; i++) {
                long contribution = 0;

                long asMin = 0;
                for (int j = i + 1; j < n; j++) {
                    if (scores[j] >= scores[i]) {
                        int remaining = j - i - 1;
                        int need = len - 2;
                        if (need >= 0 && need <= remaining) {
                            asMin = (asMin + C[remaining][need]) % MOD;
                        }
                    }
                }

                long asMax = 0;
                for (int j = i + 1; j < n; j++) {
                    if (scores[j] <= scores[i]) {
                        int remaining = j - i - 1;
                        int need = len - 2;
                        if (need >= 0 && need <= remaining) {
                            asMax = (asMax + C[remaining][need]) % MOD;
                        }
                    }
                }

                if (len == 1) {
                    contribution = (2L * scores[i]) % MOD;
                } else {
                    contribution = ((long)scores[i] * asMin % MOD + (long)scores[i] * asMax % MOD) % MOD;
                }

                result = (result + contribution) % MOD;
            }
        }

        return result;
    }
