class DeviceAnalyzer:
    def computeExtremeSum(self, scores: List[int], maxCount: int) -> int:
        MOD = 10**9 + 7
        n = len(scores)
        result = 0

        for k in range(1, min(maxCount, n) + 1):
            for i in range(n):
                min_val = scores[i]
                max_val = scores[i]

                def count_subsequences(pos, remaining, current_min, current_max):
                    if remaining == 0:
                        return (current_min + current_max) % MOD
                    if pos >= n:
                        return 0

                    take = count_subsequences(pos + 1, remaining - 1, 
                                             min(current_min, scores[pos]), 
                                             max(current_max, scores[pos]))
                    skip = count_subsequences(pos + 1, remaining, current_min, current_max)

                    return (take + skip) % MOD

                if k == 1:
                    result = (result + 2 * scores[i]) % MOD
                else:
                    for mask in range(1 << n):
                        if bin(mask).count('1') != k:
                            continue
                        subsequence = [scores[j] for j in range(n) if mask & (1 << j)]
                        if len(subsequence) == k:
                            result = (result + min(subsequence) + max(subsequence)) % MOD

        return result

