int computeCost(const vector<int>& levels, int start, int groupSize) {
    vector<int> segment;
    for (int i = start; i < start + groupSize; i++) {
        segment.push_back(levels[i]);
    }
    sort(segment.begin(), segment.end());
    int median = segment[groupSize / 2];
    int cost = 0;
    for (int val : segment) {
        cost += abs(val - median);
    }
    return cost;
}

int solve(const vector<int>& levels, int groupSize, int groupCount) {
    int n = levels.size();
    vector<int> segmentCosts;

    for (int i = 0; i + groupSize <= n; i++) {
        segmentCosts.push_back(computeCost(levels, i, groupSize));
    }

    int numSegments = segmentCosts.size();

    const int INF = 1e9;
    vector<vector<int>> dp(numSegments + 1, vector<int>(groupCount + 1, INF));
    dp[0][0] = 0;

    for (int i = 0; i < numSegments; i++) {
        for (int j = 0; j <= groupCount; j++) {
            if (dp[i][j] == INF) continue;

            dp[i + 1][j] = min(dp[i + 1][j], dp[i][j]);

            if (j < groupCount && i + groupSize <= numSegments) {
                dp[i + groupSize][j + 1] = min(dp[i + groupSize][j + 1], dp[i][j] + segmentCosts[i]);
            }
        }
    }

    int result = INF;
    for (int i = 0; i <= numSegments; i++) {
        result = min(result, dp[i][groupCount]);
    }

    return result;
}

