func minAdjustments(levels []int, groupSize int, groupCount int) int {
    n := len(levels)

    costs := make([]int, n-groupSize+1)
    for i := 0; i <= n-groupSize; i++ {
        segment := make([]int, groupSize)
        copy(segment, levels[i:i+groupSize])
        sort.Ints(segment)
        median := segment[groupSize/2]

        cost := 0
        for j := i; j < i+groupSize; j++ {
            cost += abs(levels[j] - median)
        }
        costs[i] = cost
    }

    dp := make([][]int, n-groupSize+1)
    for i := range dp {
        dp[i] = make([]int, groupCount+1)
        for j := range dp[i] {
            dp[i][j] = 1e9
        }
    }

    dp[0][0] = 0

    for i := 0; i <= n-groupSize; i++ {
        for g := 0; g <= groupCount; g++ {
            if dp[i][g] == 1e9 {
                continue
            }

            if i+1 <= n-groupSize {
                dp[i+1][g] = min(dp[i+1][g], dp[i][g])
            }

            if g < groupCount && i+groupSize <= n-groupSize {
                dp[i+groupSize][g+1] = min(dp[i+groupSize][g+1], dp[i][g]+costs[i])
            } else if g < groupCount && i+groupSize == n-groupSize+1 {
                nextIdx := i + groupSize
                if nextIdx <= n-groupSize {
                    dp[nextIdx][g+1] = min(dp[nextIdx][g+1], dp[i][g]+costs[i])
                } else {
                    result := dp[i][g] + costs[i]
                    if g+1 == groupCount {
                        return result
                    }
                }
            }
        }
    }

    result := 1e9
    for i := groupCount*groupSize; i <= n; i++ {
        if i <= n-groupSize {
            result = min(result, dp[i][groupCount])
        }
    }

    for i := 0; i <= n-groupSize; i++ {
        result = min(result, dp[i][groupCount])
    }

    return result
}

