        int[][] cost = new int[maxSegments][maxSegments];

        for (int i = 0; i < maxSegments; i++) {
            for (int j = i; j < maxSegments; j++) {
                cost[i][j] = Integer.MAX_VALUE;
            }
        }

        for (int i = 0; i < maxSegments; i++) {
            int start = i * groupSize;
            int end = start + groupSize;
            int[] segment = new int[groupSize];
            for (int k = 0; k < groupSize; k++) {
                segment[k] = levels[start + k];
            }
            cost[i][i] = getCost(segment);
        }

        for (int len = 2; len <= maxSegments; len++) {
            for (int i = 0; i + len <= maxSegments; i++) {
                int j = i + len - 1;
                cost[i][j] = cost[i][j-1] + cost[j][j];
            }
        }

        int[][] dp = new int[maxSegments + 1][groupCount + 1];
        for (int i = 0; i <= maxSegments; i++) {
            for (int j = 0; j <= groupCount; j++) {
                dp[i][j] = Integer.MAX_VALUE;
            }
        }
        dp[0][0] = 0;

        for (int i = 1; i <= maxSegments; i++) {
            for (int j = 0; j <= groupCount && j <= i; j++) {
                if (j > 0) {
                    for (int k = j - 1; k < i; k++) {
                        if (dp[k][j-1] != Integer.MAX_VALUE) {
                            dp[i][j] = Math.min(dp[i][j], dp[k][j-1] + cost[k][i-1]);
                        }
                    }
                }
                if (j < groupCount && dp[i-1][j] != Integer.MAX_VALUE) {
                    dp[i][j] = Math.min(dp[i][j], dp[i-1][j]);
                }
            }
        }

        return dp[maxSegments][groupCount];
    }

    private int getCost(int[] arr) {
        int[] sorted = arr.clone();
        Arrays.sort(sorted);
        int median = sorted[sorted.length / 2];
        int cost = 0;
        for (int val : arr) {
            cost += Math.abs(val - median);
        }
        return cost;
    }

