class Solution:
    def minAdjustments(self, levels: List[int], groupSize: int, groupCount: int) -> int:
        n = len(levels)

        def cost_to_unify(start, size):
            segment = sorted(levels[start:start + size])
            median = segment[size
            return sum(abs(x - median) for x in segment)

        INF = float('inf')
        dp = [[INF] * (groupCount + 1) for _ in range(n + 1)]
        dp[0][0] = 0

        for i in range(n + 1):
            for j in range(groupCount + 1):
                if dp[i][j] == INF:
                    continue

                if i < n:
                    dp[i + 1][j] = min(dp[i + 1][j], dp[i][j])

                if j < groupCount and i + groupSize <= n:
                    cost = cost_to_unify(i, groupSize)
                    dp[i + groupSize][j + 1] = min(dp[i + groupSize][j + 1], dp[i][j] + cost)

        result = INF
        for i in range(n + 1):
            result = min(result, dp[i][groupCount])

        return result

