class Solution {
public:
    long long minAdjustments(vector<int>& levels, int groupSize, int groupCount) {
        int n = levels.size();
        vector<long long> costs(n - groupSize + 1);

        for (int i = 0; i <= n - groupSize; ++i) {
            vector<int> window(groupSize);
            for (int j = 0; j < groupSize; ++j) {
                window[j] = levels[i + j];
            }
            sort(window.begin(), window.end());
            int median = window[groupSize / 2];
            long long cost = 0;
            for (int val : window) {
                cost += abs(val - median);
            }
            costs[i] = cost;
        }

        vector<vector<long long>> dp(groupCount + 1, vector<long long>(n + 1, -1));
        fill(dp[0].begin(), dp[0].end(), 0);

        for (int k = 1; k <= groupCount; ++k) {
            for (int j = k * groupSize; j <= n; ++j) {
                long long res = dp[k][j - 1];
                long long current_cost = costs[j - groupSize] + dp[k - 1][j - groupSize];

                if (res == -1 || current_cost < res) {
                    res = current_cost;
                }
                dp[k][j] = res;
            }
        }

        return dp[groupCount][n];
    }
