func splitInput(s string) []string {
	var res []string
	bracketCount := 0
	start := 0
	for i := 0; i < len(s); i++ {
		if s[i] == '[' {
			bracketCount++
		} else if s[i] == ']' {
			bracketCount--
		} else if s[i] == ',' && bracketCount == 0 {
			res = append(res, s[start:i])
			start = i + 1
		}
	}
	res = append(res, s[start:])
	return res
}

func solve(levels []int, groupSize int, groupCount int) int64 {
	n := len(levels)
	costs := make([]int64, n-groupSize+1)

	for i := 0; i <= n-groupSize; i++ {
		sub := make([]int, groupSize)
		copy(sub, levels[i:i+groupSize])
		sort.Ints(sub)
		median := sub[groupSize/2]
		var cost int64
		for _, v := range sub {
			diff := int64(v - median)
			if diff < 0 {
				cost -= diff
			} else {
				cost += diff
			}
		}
		costs[i] = cost
	}

	dp := make([][]int64, groupCount+1)
	for i := range dp {
		dp[i] = make([]int64, n+1)
		for j := range dp[i] {
			dp[i][j] = math.MaxInt64 / 2
		}
	}

	for j := 0; j <= n; j++ {
		dp[0][j] = 0
	}

	for i := 1; i <= groupCount; i++ {
		minPrev := dp[i-1][0]
		for j := 1; j <= n; j++ {
			if j >= groupSize {
				if dp[i-1][j-groupSize] < minPrev {
					minPrev = dp[i-1][j-groupSize]
				}
				currentCost := minPrev + costs[j-groupSize]
				if currentCost < dp[i][j-1] {
					dp[i][j] = currentCost
				} else {
					dp[i][j] = dp[i][j-1]
				}
			} else {
				dp[i][j] = dp[i][j-1]
			}
		}
	}

	return dp[groupCount][n]
}

