using namespace std;

class Solution {
public:
    int minimizeMaxCost(int hubs_count, vector<vector<int>>& connections, int allowance) {
        if (connections.empty()) return -1;

        set<int> uniqueCosts;
        for (auto& conn : connections) {
            uniqueCosts.insert(conn[2]);
        }
        vector<int> costs(uniqueCosts.begin(), uniqueCosts.end());
        sort(costs.begin(), costs.end());

        int left = 0, right = costs.size() - 1;
        int result = -1;

        while (left <= right) {
            int mid = (left + right) / 2;
            int maxCost = costs[mid];

            if (canReachZero(hubs_count, connections, allowance, maxCost)) {
                result = maxCost;
                right = mid - 1;
            } else {
                left = mid + 1;
            }
        }

        return result;
    }

private:
    bool canReachZero(int hubs_count, vector<vector<int>>& connections, int allowance, int maxCost) {
        vector<vector<pair<int, int>>> graph(hubs_count);

        for (auto& conn : connections) {
            int src = conn[0], dst = conn[1], cost = conn[2];
            if (cost <= maxCost) {
                graph[src].push_back({dst, cost});
            }
        }

        vector<int> dist(hubs_count, INT_MAX);
        dist[0] = 0;
        queue<int> q;
        q.push(0);

        while (!q.empty()) {
            int u = q.front();
            q.pop();

            for (auto& [v, cost] : graph[u]) {
                if (dist[u] + 1 < dist[v]) {
                    dist[v] = dist[u] + 1;
                    q.push(v);
                }
            }
        }

        for (int i = 1; i < hubs_count; i++) {
            if (dist[i] == INT_MAX) {
                return false;
            }
        }

        vector<bool> canReach(hubs_count, false);
        canReach[0] = true;

        bool changed = true;
        while (changed) {
            changed = false;
            for (int u = 0; u < hubs_count; u++) {
                if (canReach[u]) continue;

                vector<pair<int, int>> validEdges;
                for (auto& [v, cost] : graph[u]) {
                    if (canReach[v]) {
                        validEdges.push_back({cost, v});
                    }
                }

                if (!validEdges.empty() && validEdges.size() <= allowance) {
                    canReach[u] = true;
                    changed = true;
                }
            }
        }

        for (int i = 1; i < hubs_count; i++) {
            if (!canReach[i]) {
                return false;
            }
        }

        return true;
    }
};

