func minimizeMaxCost(hubs_count int, connections [][3]int, allowance int) int {
    if hubs_count == 1 {
        return 0
    }

    costs := make(map[int]bool)
    for _, conn := range connections {
        costs[conn[2]] = true
    }

    uniqueCosts := make([]int, 0, len(costs))
    for cost := range costs {
        uniqueCosts = append(uniqueCosts, cost)
    }
    sort.Ints(uniqueCosts)

    left, right := 0, len(uniqueCosts)-1
    result := -1

    for left <= right {
        mid := (left + right) / 2
        maxCost := uniqueCosts[mid]

        if canReachHub0(hubs_count, connections, allowance, maxCost) {
            result = maxCost
            right = mid - 1
        } else {
            left = mid + 1
        }
    }

    return result
}

func canReachHub0(hubs_count int, connections [][3]int, allowance int, maxCost int) bool {
    adjList := make([][][2]int, hubs_count)
    for i := range adjList {
        adjList[i] = make([][2]int, 0)
    }

    for _, conn := range connections {
        if conn[2] <= maxCost {
            adjList[conn[0]] = append(adjList[conn[0]], [2]int{conn[1], conn[2]})
        }
    }

    for i := 0; i < hubs_count; i++ {
        sort.Slice(adjList[i], func(a, b int) bool {
            return adjList[i][a][1] < adjList[i][b][1]
        })
        if len(adjList[i]) > allowance {
            adjList[i] = adjList[i][:allowance]
        }
    }

    visited := make([]bool, hubs_count)
    queue := make([]int, 0)
    queue = append(queue, 0)
    visited[0] = true

    for len(queue) > 0 {
        node := queue[0]
        queue = queue[1:]

        for _, edge := range adjList[node] {
            neighbor := edge[0]
            if !visited[neighbor] {
                visited[neighbor] = true
                queue = append(queue, neighbor)
            }
        }
    }

    reachesHub0 := make([]bool, hubs_count)
    reachesHub0[0] = true

    changed := true
    for changed {
        changed = false
        for node := 0; node < hubs_count; node++ {
            if !reachesHub0[node] {
                for _, edge := range adjList[node] {
                    neighbor := edge[0]
                    if reachesHub0[neighbor] {
                        reachesHub0[node] = true
                        changed = true
                        break
                    }
                }
            }
        }
    }

    for i := 0; i < hubs_count; i++ {
        if !reachesHub0[i] {
            return false
        }
    }

    return true
}

