public class Solution {

    public int minimizeMaxCost(int hubs_count, int[][] connections, int allowance) {
        Set<Integer> uniqueCosts = new TreeSet<>();
        for (int[] conn : connections) {
            uniqueCosts.add(conn[2]);
        }

        List<Integer> costs = new ArrayList<>(uniqueCosts);
        Collections.sort(costs);

        int left = 0, right = costs.size() - 1;
        int result = -1;

        while (left <= right) {
            int mid = (left + right) / 2;
            int maxCost = costs.get(mid);

            if (canReachHub0(hubs_count, connections, allowance, maxCost)) {
                result = maxCost;
                right = mid - 1;
            } else {
                left = mid + 1;
            }
        }

        return result;
    }

    private boolean canReachHub0(int hubs_count, int[][] connections, int allowance, int maxCost) {
        List<List<int[]>> graph = new ArrayList<>();
        for (int i = 0; i < hubs_count; i++) {
            graph.add(new ArrayList<>());
        }

        for (int[] conn : connections) {
            if (conn[2] <= maxCost) {
                graph.get(conn[0]).add(new int[]{conn[1], conn[2]});
            }
        }

        for (int i = 0; i < hubs_count; i++) {
            List<int[]> edges = graph.get(i);
            edges.sort(Comparator.comparingInt(a -> a[1]));
            if (edges.size() > allowance) {
                graph.set(i, edges.subList(0, allowance));
            }
        }

        boolean[] visited = new boolean[hubs_count];
        Queue<Integer> queue = new LinkedList<>();
        queue.offer(0);
        visited[0] = true;

        while (!queue.isEmpty()) {
            int curr = queue.poll();
            for (int i = 0; i < hubs_count; i++) {
                if (!visited[i]) {
                    for (int[] edge : graph.get(i)) {
                        if (edge[0] == curr) {
                            visited[i] = true;
                            queue.offer(i);
                            break;
                        }
                    }
                }
            }
        }

        for (int i = 0; i < hubs_count; i++) {
            if (!visited[i]) {
                return false;
            }
        }

        return true;
    }

