from typing import List
from collections import deque

class Solution:
    def minimizeMaxCost(self, hubs_count: int, connections: List[List[int]], allowance: int) -> int:
        def can_reach_all(max_cost):
            graph = [[] for _ in range(hubs_count)]
            for src, dst, cost in connections:
                if cost <= max_cost:
                    graph[src].append(dst)

            for node in range(hubs_count):
                if len(graph[node]) > allowance:
                    return False

            for node in range(hubs_count):
                if node == 0:
                    continue
                visited = [False] * hubs_count
                queue = deque([node])
                visited[node] = True
                found = False
                while queue:
                    curr = queue.popleft()
                    if curr == 0:
                        found = True
                        break
                    for neighbor in graph[curr]:
                        if not visited[neighbor]:
                            visited[neighbor] = True
                            queue.append(neighbor)
                if not found:
                    return False
            return True

        costs = sorted(set(cost for _, _, cost in connections))

        left, right = 0, len(costs) - 1
        result = -1

        while left <= right:
            mid = (left + right)
            if can_reach_all(costs[mid]):
                result = costs[mid]
                right = mid - 1
            else:
                left = mid + 1

        return result

