        if (u != 0 && count == 0) return false;
    }

    vector<bool> visited(n, false);
    queue<int> q;
    q.push(0);
    visited[0] = true;
    int reached = 1;

    while (!q.empty()) {
        int v = q.front();
        q.pop();
        for (int u : rev_adj[v]) {
            if (!visited[u]) {
                visited[u] = true;
                reached++;
                q.push(u);
            }
        }
    }
    return reached == n;
}

