public class Solution {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        if (!sc.hasNextInt()) return;
        int hubs_count = sc.nextInt();
        int allowance = sc.nextInt();
        int m = sc.nextInt();
        int[][] connections = new int[m][3];
        int maxCost = 0;
        for (int i = 0; i < m; i++) {
            connections[i][0] = sc.nextInt();
            connections[i][1] = sc.nextInt();
            connections[i][2] = sc.nextInt();
            if (connections[i][2] > maxCost) maxCost = connections[i][2];
        }

        int low = 1, high = maxCost, ans = -1;
        while (low <= high) {
            int mid = low + (high - low) / 2;
            if (canReach(hubs_count, connections, mid)) {
                ans = mid;
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }
        System.out.println(ans);
    }

    private static boolean canReach(int n, int[][] edges, int limit) {
        List<Integer>[] adj = new ArrayList[n];
        for (int i = 0; i < n; i++) adj[i] = new ArrayList<>();
        for (int[] e : edges) {
            if (e[2] <= limit) {
                adj[e[1]].add(e[0]);
            }
        }

        boolean[] visited = new boolean[n];
        Queue<Integer> q = new LinkedList<>();
        q.add(0);
        visited[0] = true;
        int count = 1;

        while (!q.isEmpty()) {
            int u = q.poll();
            for (int v : adj[u]) {
                if (!visited[v]) {
                    visited[v] = true;
                    count++;
                    q.add(v);
                }
            }
        }
        return count == n;
    }
}

