class Solution:
    def minimizeMaxCost(self, hubs_count: int, connections: list, allowance: int) -> int:
        if allowance < 1:
            return -1

        adj = [[] for _ in range(hubs_count)]
        max_c = 0
        for u, v, w in connections:
            adj[v].append((u, w))
            if w > max_c:
                max_c = w

        def check(limit):
            visited = [False] * hubs_count
            visited[0] = True
            queue = deque([0])
            count = 1
            while queue:
                v = queue.popleft()
                for u, w in adj[v]:
                    if w <= limit and not visited[u]:
                        visited[u] = True
                        count += 1
                        queue.append(u)
            return count == hubs_count

        low = 1
        high = max_c
        ans = -1

        while low <= high:
            mid = (low + high)
            if check(mid):
                ans = mid
                high = mid - 1
            else:
                low = mid + 1

        return ans

