public class Solution {

    public int[] tallyAnnouncements(int totalAttendees, String[][] events) {
        int[] counts = new int[totalAttendees];
        Map<Integer, Integer> absentUntil = new HashMap<>();

        for (String[] event : events) {
            String eventType = event[0];
            int timestamp = Integer.parseInt(event[1]);

            Set<Integer> currentlyAbsent = new HashSet<>();
            for (Map.Entry<Integer, Integer> entry : absentUntil.entrySet()) {
                if (entry.getValue() > timestamp) {
                    currentlyAbsent.add(entry.getKey());
                }
            }

            if (eventType.equals("ABSENT")) {
                int attendeeId = Integer.parseInt(event[2]);
                absentUntil.put(attendeeId, timestamp + 60);
            } else if (eventType.equals("ANNOUNCEMENT")) {
                String mentionsInfo = event[2];

                if (mentionsInfo.equals("EVERYONE")) {
                    for (int i = 0; i < totalAttendees; i++) {
                        counts[i]++;
                    }
                } else if (mentionsInfo.equals("PRESENT")) {
                    for (int i = 0; i < totalAttendees; i++) {
                        if (!currentlyAbsent.contains(i)) {
                            counts[i]++;
                        }
                    }
                } else {
                    String[] tokens = mentionsInfo.split(" ");
                    for (String token : tokens) {
                        if (token.startsWith("attendee")) {
                            int attendeeId = Integer.parseInt(token.substring(8));
                            counts[attendeeId]++;
                        }
                    }
                }
            }
        }

        return counts;
    }

