bool compareEvents(const Event& a, const Event& b) {
    if (a.timestamp != b.timestamp) {
        return a.timestamp < b.timestamp;
    }
    if (a.type != b.type) {
        return a.type == "ABSENT";
    }
    return a.originalOrder < b.originalOrder;
}

class Solution {
public:
    vector<int> tallyAnnouncements(int totalAttendees, vector<vector<string>>& eventStrings) {
        int n = eventStrings.size();
        vector<Event> events(n);
        for (int i = 0; i < n; ++i) {
            events[i].type = eventStrings[i][0];
            events[i].timestamp = stoi(eventStrings[i][1]);
            events[i].info = eventStrings[i][2];
            events[i].originalOrder = i;
        }

        sort(events.begin(), events.end(), compareEvents);

        vector<int> counts(totalAttendees, 0);
        vector<int> absentUntil(totalAttendees, -1);

        for (const auto& e : events) {
