                        for (int i = 0; i < totalAttendees; ++i) {
                            if (absentUntil[i] <= e.timestamp) {
                                counts[i]++;
                            }
                        }
                    } else {
                        int id = stoi(token.substr(8));
                        counts[id]++;
                    }
                }
            }
