class Solution {
public:
    long long maxGameSegmentsSum(vector<int>& scores, int p, int n) {
        int len = scores.size();
        vector<long long> prefix(len + 1, 0);
        for (int i = 0; i < len; i++) {
            prefix[i + 1] = prefix[i] + scores[i];
        }

        vector<vector<long long>> dp(p + 1, vector<long long>(len + 1, LLONG_MIN));
        dp[0][0] = 0;

        for (int k = 1; k <= p; k++) {
            for (int i = k * n; i <= len; i++) {
                dp[k][i] = dp[k][i - 1];
                for (int j = i - n; j >= (k - 1) * n; j--) {
                    if (dp[k - 1][j] != LLONG_MIN) {
                        long long segmentSum = prefix[i] - prefix[j];
                        dp[k][i] = max(dp[k][i], dp[k - 1][j] + segmentSum);
                    }
                }
            }
        }

        return dp[p][len];
    }
};

