func maxGameSegmentsSum(scores []int, p int, n int) int {
    length := len(scores)

    prefixSum := make([]int, length+1)
    for i := 0; i < length; i++ {
        prefixSum[i+1] = prefixSum[i] + scores[i]
    }

    dp := make([][]int, length+1)
    for i := range dp {
        dp[i] = make([]int, p+1)
        for j := range dp[i] {
            dp[i][j] = math.MinInt32
        }
    }
    dp[0][0] = 0

    for i := 0; i <= length; i++ {
        for j := 0; j <= p; j++ {
            if dp[i][j] == math.MinInt32 {
                continue
            }

            if j < p {
                for end := i + n; end <= length; end++ {
                    segmentSum := prefixSum[end] - prefixSum[i]
                    if dp[end][j+1] < dp[i][j] + segmentSum {
                        dp[end][j+1] = dp[i][j] + segmentSum
                    }
                }
            }
        }
    }

    result := math.MinInt32
    for i := 0; i <= length; i++ {
        if dp[i][p] > result {
            result = dp[i][p]
        }
    }

    return result
}

