public class Solution {
    public long maxGameSegmentsSum(int[] scores, int p, int n) {
        int len = scores.length;
        long[][] dp = new long[len + 1][p + 1];

        for (int i = 0; i <= len; i++) {
            for (int j = 0; j <= p; j++) {
                dp[i][j] = Long.MIN_VALUE / 2;
            }
        }
        dp[0][0] = 0;

        for (int i = 1; i <= len; i++) {
            for (int j = 0; j <= p; j++) {
                dp[i][j] = dp[i - 1][j];

                if (j > 0) {
                    long sum = 0;
                    for (int k = i - 1; k >= 0 && i - k >= n; k--) {
                        sum += scores[k];
                        dp[i][j] = Math.max(dp[i][j], dp[k][j - 1] + sum);
                    }
                }
            }
        }

        return dp[len][p];
    }

