long long calculateExtremeGemSum(vector<int>& chestValues, int limit) {
    int n = chestValues.size();
    long long totalScore = 0;

    for (int i = 0; i < n; i++) {
        int minVal = chestValues[i];
        int maxVal = chestValues[i];

        for (int j = i; j < n && j < i + limit; j++) {
            minVal = min(minVal, chestValues[j]);
            maxVal = max(maxVal, chestValues[j]);
            totalScore += (long long)minVal + maxVal;
        }
    }

    return totalScore;
}

