func calculateExtremes(arr []int, limit int, findMax bool) int64 {
	n := len(arr)
	left := make([]int, n)
	right := make([]int, n)
	stack := make([]int, 0, n)

	for i := 0; i < n; i++ {
		for len(stack) > 0 {
			top := stack[len(stack)-1]
			isBetter := false
			if findMax {
				isBetter = arr[i] > arr[top]
			} else {
				isBetter = arr[i] < arr[top]
			}
			if isBetter {
				stack = stack[:len(stack)-1]
			} else {
				break
			}
		}
		if len(stack) == 0 {
			left[i] = -1
		} else {
			left[i] = stack[len(stack)-1]
		}
		stack = append(stack, i)
	}

	stack = stack[:0]
	for i := n - 1; i >= 0; i-- {
		for len(stack) > 0 {
			top := stack[len(stack)-1]
			isBetter := false
			if findMax {
				isBetter = arr[i] >= arr[top]
			} else {
				isBetter = arr[i] <= arr[top]
			}
			if isBetter {
				stack = stack[:len(stack)-1]
			} else {
				break
			}
		}
		if len(stack) == 0 {
			right[i] = n
		} else {
			right[i] = stack[len(stack)-1]
		}
		stack = append(stack, i)
	}

	var total int64 = 0
	for i := 0; i < n; i++ {
		L := i - left[i]
		R := right[i] - i
		total += countValidSubarrays(L, R, limit) * int64(arr[i])
	}
	return total
}

func countValidSubarrays(L, R, K int) int64 {
	if L > R {
		L, R = R, L
	}
	var count int64 = 0
	if K <= L {
		count = int64(K) * int64(K+1) / 2
	} else if K <= R {
		count = int64(L) * int64(L+1) / 2
		count += int64(L) * int64(K-L)
	} else if K < L+R {
		count = int64(L) * int64(L+1) / 2
		count += int64(L) * int64(R-L)
		rem := K - R
		base := int64(L - 1)
		count += (base + base - int64(rem) + 1) * int64(rem) / 2
	} else {
		count = int64(L) * int64(R)
	}
	return count
}

