    private static long solve(int[] a, int k) {
        return calculateSum(a, k, true) + calculateSum(a, k, false);
    }

    private static long calculateSum(int[] a, int k, boolean findMax) {
        int n = a.length;
        int[] left = new int[n];
        int[] right = new int[n];
        Deque<Integer> stack = new ArrayDeque<>();

        for (int i = 0; i < n; i++) {
            while (!stack.isEmpty()) {
                int top = stack.peek();
                if (findMax) {
                    if (a[top] < a[i]) stack.pop();
                    else break;
                } else {
                    if (a[top] > a[i]) stack.pop();
                    else break;
                }
            }
            left[i] = stack.isEmpty() ? -1 : stack.peek();
            stack.push(i);
        }

        stack.clear();
        for (int i = n - 1; i >= 0; i--) {
            while (!stack.isEmpty()) {
                int top = stack.peek();
                if (findMax) {
                    if (a[top] <= a[i]) stack.pop();
                    else break;
                } else {
                    if (a[top] >= a[i]) stack.pop();
                    else break;
                }
            }
            right[i] = stack.isEmpty() ? n : stack.peek();
            stack.push(i);
        }

        long total = 0;
        for (int i = 0; i < n; i++) {
            int L = i - left[i];
            int R = right[i] - i;
            total += (long) a[i] * countSubarrays(L, R, k);
        }
        return total;
    }

    private static long countSubarrays(int L, int R, int k) {
        if (L > R) {
            int temp = L;
            L = R;
            R = temp;
        }

        long count = 0;
        if (k <= L) {
            count = (long) k * (k + 1) / 2;
        } else if (k <= R) {
            count = (long) L * (L + 1) / 2 + (long) L * (k - L);
        } else if (k < L + R - 1) {
            long full = (long) L * R;
            int d = (L + R - 1) - k;
            count = full - (long) d * (d + 1) / 2;
        } else {
            count = (long) L * R;
        }
        return count;
    }
}

