class Solution {
public:
    int computeLongestZRoute(vector<vector<int>>& layout) {
        if (layout.empty() || layout[0].empty()) return 0;

        int m = layout.size();
        int n = layout[0].size();
        int maxLen = 0;

        vector<pair<int, int>> directions = {{1, 1}, {1, -1}, {-1, 1}, {-1, -1}};

        auto getClockwise = [](int dir) -> int {
            return (dir + 1) % 4;
        };

        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                if (layout[i][j] == 1) {
                    for (int dir = 0; dir < 4; dir++) {
                        int len1 = explore(layout, i, j, dir, false, m, n, directions, getClockwise);
                        maxLen = max(maxLen, len1);
                    }
                }
            }
        }

        return maxLen;
    }

private:
    int explore(vector<vector<int>>& layout, int startR, int startC, int dir, bool turned, 
                int m, int n, vector<pair<int, int>>& directions, auto& getClockwise) {
        int r = startR;
        int c = startC;
        int len = 1;
        int expectedValue = 2;

        while (true) {
            r += directions[dir].first;
            c += directions[dir].second;

            if (r < 0 || r >= m || c < 0 || c >= n) break;
            if (layout[r][c] != expectedValue) break;

            len++;

            if (!turned) {
                int newDir = getClockwise(dir);
                int lenWithTurn = len + explore(layout, r, c, newDir, true, m, n, directions, getClockwise) - 1;
                len = max(len, lenWithTurn);
            }

            expectedValue = (expectedValue == 2) ? 0 : 2;
        }

        return len;
    }
};

