func max(a, b int) int {
    if a > b {
        return a
    }
    return b
}

func getClockwiseTurn(dr, dc int) (int, int) {
    if dr == 1 && dc == 1 {
        return 1, -1
    } else if dr == 1 && dc == -1 {
        return -1, -1
    } else if dr == -1 && dc == -1 {
        return -1, 1
    } else {
        return 1, 1
    }
}

func exploreTrail(layout [][]int, startR, startC, dr, dc int, hasTurned bool) int {
    rows := len(layout)
    cols := len(layout[0])

    r, c := startR, startC
    length := 1
    expectValue := 2

    for {
        r += dr
        c += dc

        if r < 0 || r >= rows || c < 0 || c >= cols {
            break
        }

        if layout[r][c] != expectValue {
            break
        }

        length++

        if expectValue == 2 {
            expectValue = 0
        } else {
            expectValue = 2
        }
    }

    maxLen := length

    if !hasTurned && length > 1 {
        turnR, turnC := startR+dr, startC+dc
        newDr, newDc := getClockwiseTurn(dr, dc)

        turnedLen := exploreFromTurn(layout, turnR, turnC, newDr, newDc, expectValue)
        if turnedLen > 0 {
            maxLen = max(maxLen, length + turnedLen)
        }

        for step := 2; step < length; step++ {
            curR := startR + step*dr
            curC := startC + step*dc

            if curR < 0 || curR >= len(layout) || curC < 0 || curC >= len(layout[0]) {
                break
            }

            nextExpect := expectValue
            if step % 2 == 0 {
                nextExpect = 2
            } else {
                nextExpect = 0
            }

            turnedLen := exploreFromTurn(layout, curR, curC, newDr, newDc, nextExpect)
            if turnedLen > 0 {
                maxLen = max(maxLen, step + turnedLen)
            }
        }
    }

    return maxLen
}

func exploreFromTurn(layout [][]int, startR, startC, dr, dc int, expectValue int) int {
