public class Solution {

    public int computeLongestZRoute(int[][] layout) {
        if (layout == null || layout.length == 0) return 0;

        int maxLength = 0;
        int rows = layout.length;
        int cols = layout[0].length;

        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                if (layout[i][j] == 1) {
                    int[][] directions = {{1, 1}, {1, -1}, {-1, 1}, {-1, -1}};
                    for (int d = 0; d < 4; d++) {
                        int len = explore(layout, i, j, directions[d][0], directions[d][1], false);
                        maxLength = Math.max(maxLength, len);
                    }
                }
            }
        }

        return maxLength;
    }

    private int explore(int[][] layout, int r, int c, int dr, int dc, boolean turned) {
        int rows = layout.length;
        int cols = layout[0].length;

        int length = 1;
        int nextExpected = 2;

        r += dr;
        c += dc;

        while (r >= 0 && r < rows && c >= 0 && c < cols) {
            if (layout[r][c] != nextExpected) {
                break;
            }

            length++;

            int maxWithTurn = length;
            if (!turned) {
                int[] newDir = getClockwiseTurn(dr, dc);
                int turnLen = exploreContinue(layout, r, c, newDir[0], newDir[1], nextExpected);
                maxWithTurn = Math.max(maxWithTurn, length + turnLen);
            }

            nextExpected = (nextExpected == 2) ? 0 : 2;
            r += dr;
            c += dc;

            if (!turned && maxWithTurn > length) {
                return maxWithTurn;
            }
        }

        return length;
    }

    private int exploreContinue(int[][] layout, int r, int c, int dr, int dc, int currentExpected) {
        int rows = layout.length;
        int cols = layout[0].length;

        int nextExpected = (currentExpected == 2) ? 0 : 2;
        int length = 0;

        r += dr;
        c += dc;

        while (r >= 0 && r < rows && c >= 0 && c < cols) {
            if (layout[r][c] != nextExpected) {
                break;
            }

            length++;
            nextExpected = (nextExpected == 2) ? 0 : 2;
            r += dr;
            c += dc;
        }

        return length;
    }

    private int[] getClockwiseTurn(int dr, int dc) {
        if (dr == 1 && dc == 1) return new int[]{1, -1};
        if (dr == 1 && dc == -1) return new int[]{-1, -1};
        if (dr == -1 && dc == -1) return new int[]{-1, 1};
        if (dr == -1 && dc == 1) return new int[]{1, 1};
        return new int[]{0, 0};
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        String input = sc.nextLine();

        input = input.trim();
        if (input.startsWith("layout = ")) {
            input = input.substring(9);
        }

        int[][] layout = parseMatrix(input);

        Solution sol = new Solution();
        int result = sol.computeLongestZRoute(layout);
        System.out.println(result);

        sc.close();
    }

    private static int[][] parseMatrix(String s) {
        s = s.trim();
        if (s.equals("[[]]")) return new int[0][0];

        s = s.substring(1, s.length() - 1);

        String[] rows = s.split("\\],\\[");
        int[][] matrix = new int[rows.length][];

        for (int i = 0; i < rows.length; i++) {
            String row = rows[i].replace("[", "").replace("]", "");
            String[] nums = row.split(",");
            matrix[i] = new int[nums.length];
            for (int j = 0; j < nums.length; j++) {
                matrix[i][j] = Integer.parseInt(nums[j].trim());
            }
        }

        return matrix;
    }
}

