    def computeLongestZRoute(self, layout: List[List[int]]) -> int:
        if not layout or not layout[0]:
            return 0

        rows = len(layout)
        cols = len(layout[0])

        directions = [(1, 1), (1, -1), (-1, -1), (-1, 1)]

        def get_clockwise(dir_idx):
            return (dir_idx + 1) % 4

        def dfs(r, c, dir_idx, step, turned, max_len):
            dr, dc = directions[dir_idx]
            nr, nc = r + dr, c + dc

            if nr < 0 or nr >= rows or nc < 0 or nc >= cols:
                return max_len

            if step % 2 == 1:
                expected = 2
            else:
                expected = 0

            if layout[nr][nc] != expected:
                return max_len

            current_len = step + 1
            max_len = max(max_len, current_len)

            max_len = dfs(nr, nc, dir_idx, step + 1, turned, max_len)

            if not turned:
                new_dir_idx = get_clockwise(dir_idx)
                max_len = dfs(nr, nc, new_dir_idx, step + 1, True, max_len)

            return max_len

        max_trail = 0

        for i in range(rows):
            for j in range(cols):
                if layout[i][j] == 1:
                    max_trail = max(max_trail, 1)
                    for dir_idx in range(4):
                        trail_len = dfs(i, j, dir_idx, 0, False, 1)
                        max_trail = max(max_trail, trail_len)

        return max_trail

