			}
		}
	}

	var getLen func(int, int, int) int
	getLen = func(r, c, d int) int {
		if memo[r, c][d] != -1 {
			return memo[r, c][d]
		}
		nr, nc := r+dirs[d][0], c+dirs[d][1]
		res := 1
		if nr >= 0 && nr < n && nc >= 0 && nc < m {
			if layout[r][c] == 0 && layout[nr][nc] == 2 {
				res = 1 + getLen(nr, nc, d)
			} else if layout[r][c] == 2 && layout[nr][nc] == 0 {
				res = 1 + getLen(nr, nc, d)
			}
		}
		memo[r][c][d] = res
		return res
	}

