class Solution:
    def computeLongestZRoute(self, layout: list[list[int]]) -> int:
        R = len(layout)
        if R == 0: return 0
        C = len(layout[0])

        dirs = [(-1, -1), (-1, 1), (1, 1), (1, -1)]

        memo = {}

        def get_len(r, c, dr, dc, expected):
            state = (r, c, dr, dc, expected)
            if state in memo:
                return memo[state]

            nr, nc = r + dr, c + dc
            res = 0
            if 0 <= nr < R and 0 <= nc < C and layout[nr][nc] == expected:
                res = 1 + get_len(nr, nc, dr, dc, 2 if expected == 0 else 0)

            memo[state] = res
            return res

        max_len = 0
        for r in range(R):
            for c in range(C):
                if layout[r][c] == 1:
                    max_len = max(max_len, 1)
                    for i in range(4):
                        dr, dc = dirs[i]

                        l1 = get_len(r, c, dr, dc, 2)
                        max_len = max(max_len, 1 + l1)

                        for step in range(1, l1 + 1):
                            tr, tc = r + step * dr, c + step * dc

                            ni = (i + 1) % 4
                            ndr, ndc = dirs[ni]

                            current_val = layout[tr][tc]
                            next_expected = 2 if current_val == 0 else 0

                            l2 = get_len(tr, tc, ndr, ndc, next_expected)
                            max_len = max(max_len, 1 + step + l2)

        return max_len

