class Solution:
    def searchAccurateDuo(self, signal: str) -> str:
        counts = {}
        for char in signal:
            counts[char] = counts.get(char, 0) + 1

        for i in range(len(signal) - 1):
            c1 = signal[i]
            c2 = signal[i+1]
            if c1 != c2:
                if counts[c1] == int(c1) and counts[c2] == int(c2):
                    return c1 + c2
        return ""

