func solve(canvases int, expense [][]int) int {
    n := canvases
    numStyles := 3

    INF := int(1e18)

    pairs := n / 2

    dp := make([][][]int, pairs)
    for i := range dp {
        dp[i] = make([][]int, numStyles)
        for j := range dp[i] {
            dp[i][j] = make([]int, numStyles)
            for k := range dp[i][j] {
                dp[i][j][k] = INF
            }
        }
    }

    leftIdx := 0
    rightIdx := n - 1

    for styleLeft := 0; styleLeft < numStyles; styleLeft++ {
        for styleRight := 0; styleRight < numStyles; styleRight++ {
            if styleLeft != styleRight {
                dp[0][styleLeft][styleRight] = expense[leftIdx][styleLeft] + expense[rightIdx][styleRight]
            }
        }
    }

    for pairIdx := 1; pairIdx < pairs; pairIdx++ {
        leftIdx = pairIdx
        rightIdx = n - 1 - pairIdx

        for prevLeft := 0; prevLeft < numStyles; prevLeft++ {
            for prevRight := 0; prevRight < numStyles; prevRight++ {
                if dp[pairIdx-1][prevLeft][prevRight] >= INF {
                    continue
                }

                for currLeft := 0; currLeft < numStyles; currLeft++ {
                    if currLeft == prevLeft {
                        continue
                    }

                    for currRight := 0; currRight < numStyles; currRight++ {
                        if currRight == prevRight || currRight == currLeft {
                            continue
                        }

                        cost := dp[pairIdx-1][prevLeft][prevRight] + expense[leftIdx][currLeft] + expense[rightIdx][currRight]
                        dp[pairIdx][currLeft][currRight] = min(dp[pairIdx][currLeft][currRight], cost)
                    }
                }
            }
        }
    }

    result := INF
    for styleLeft := 0; styleLeft < numStyles; styleLeft++ {
        for styleRight := 0; styleRight < numStyles; styleRight++ {
            result = min(result, dp[pairs-1][styleLeft][styleRight])
        }
    }

    return result
}

