public class Solution {
    public int computeLeastExpense(int canvases, int[][] expense) {
        int n = canvases;
        int INF = Integer.MAX_VALUE / 2;

        int[][][] dp = new int[n/2 + 1][4][4];
        for (int i = 0; i <= n/2; i++) {
            for (int j = 0; j < 4; j++) {
                Arrays.fill(dp[i][j], INF);
            }
        }

        dp[0][0][0] = 0;

        for (int pair = 0; pair < n/2; pair++) {
            int leftIdx = pair;
            int rightIdx = n - 1 - pair;

            for (int prevLeft = 0; prevLeft <= 3; prevLeft++) {
                for (int prevRight = 0; prevRight <= 3; prevRight++) {
                    if (dp[pair][prevLeft][prevRight] >= INF) continue;

                    for (int currLeft = 1; currLeft <= 3; currLeft++) {
                        if (currLeft == prevLeft) continue;

                        for (int currRight = 1; currRight <= 3; currRight++) {
                            if (currRight == prevRight) continue;
                            if (currLeft == currRight) continue;

                            int cost = dp[pair][prevLeft][prevRight] + 
                                      expense[leftIdx][currLeft - 1] + 
                                      expense[rightIdx][currRight - 1];

                            dp[pair + 1][currLeft][currRight] = Math.min(
                                dp[pair + 1][currLeft][currRight], cost
                            );
                        }
                    }
                }
            }
        }

        int result = INF;
        for (int i = 1; i <= 3; i++) {
            for (int j = 1; j <= 3; j++) {
                result = Math.min(result, dp[n/2][i][j]);
            }
        }

        return result;
    }

