class Solution:
    def computeLeastExpense(self, canvases: int, expense: List[List[int]]) -> int:
        n = canvases
        half = n

        INF = float('inf')

        dp = {}

        def solve(pos, last_style):
            if pos == half:
                return 0

            state = (pos, last_style)
            if state in dp:
                return dp[state]

            mirror_pos = n - 1 - pos

            min_cost = INF

            for style1 in range(3):
                if last_style != -1 and style1 == last_style:
                    continue

                for style2 in range(3):
                    if style1 == style2:
                        continue

                    if pos + 1 < half:
                        next_last = style2
                    else:
                        next_last = style2

                    cost = expense[pos][style1] + expense[mirror_pos][style2]
                    future_cost = solve(pos + 1, next_last)

                    if future_cost != INF:
                        min_cost = min(min_cost, cost + future_cost)

            dp[state] = min_cost
            return min_cost

        result = solve(0, -1)
        return result if result != INF else 0

