        long[][] dp = new long[3][3];
        for (int i = 0; i < 3; i++) {
            for (int j = 0; j < 3; j++) {
                if (i == j) {
                    dp[i][j] = Long.MAX_VALUE / 2;
                } else {
                    dp[i][j] = (long) expense[0][i] + expense[n - 1][j];
                }
            }
        }

        for (int k = 1; k < m; k++) {
            long[][] next_dp = new long[3][3];
