class Solution:
    def computeLeastExpense(self, canvases: int, expense: list[list[int]]) -> int:
        n = canvases
        m = n

        dp = {}

        for s1 in range(3):
            for s2 in range(3):
                if s1 == s2:
                    continue
                cost = expense[m-1][s1] + expense[m][s2]
                dp[(s1, s2)] = cost

        for i in range(m - 2, -1, -1):
            new_dp = {}
            left_idx = i
            right_idx = n - 1 - i

            for (prev_s_left, prev_s_right), current_total_cost in dp.items():
                for s_left in range(3):
                    if s_left == prev_s_left:
                        continue
                    for s_right in range(3):
                        if s_right == prev_s_right or s_left == s_right:
                            continue

                        state = (s_left, s_right)
                        cost = current_total_cost + expense[left_idx][s_left] + expense[right_idx][s_right]

                        if state not in new_dp or cost < new_dp[state]:
                            new_dp[state] = cost
            dp = new_dp

        return min(dp.values())

