long long compute_binomial(int n, int k) {
    if (k > n || k < 0) return 0;
    if (k == 0 || k == n) return 1;

    vector<long long> C(k + 1, 0);
    C[0] = 1;

    for (int i = 1; i <= n; i++) {
        for (int j = min(i, k); j > 0; j--) {
            C[j] = (C[j] + C[j - 1]) % MOD;
        }
    }
    return C[k];
}

