public class Main {
    static final long MOD = 1000000007;

    static long modPow(long base, long exp, long mod) {
        long result = 1;
        base %= mod;
        while (exp > 0) {
            if ((exp & 1) == 1) {
                result = (result * base) % mod;
            }
            base = (base * base) % mod;
            exp >>= 1;
        }
        return result;
    }

    static long modInv(long a, long mod) {
        return modPow(a, mod - 2, mod);
    }

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String[] parts = br.readLine().split(" ");
        int M = Integer.parseInt(parts[0]);
        int N = Integer.parseInt(parts[1]);
        int L = Integer.parseInt(parts[2]);

        long result = computeExhibitDistance(M, N, L);
        System.out.println(result);
    }

    static long computeExhibitDistance(int M, int N, int L) {
        int totalCells = M * N;

        long[] fact = new long[totalCells + 1];
        fact[0] = 1;
        for (int i = 1; i <= totalCells; i++) {
            fact[i] = (fact[i - 1] * i) % MOD;
        }

        long[] invFact = new long[totalCells + 1];
        invFact[totalCells] = modInv(fact[totalCells], MOD);
        for (int i = totalCells - 1; i >= 0; i--) {
            invFact[i] = (invFact[i + 1] * (i + 1)) % MOD;
        }

        long C_total = (fact[totalCells] * invFact[L]) % MOD;
        C_total = (C_total * invFact[totalCells - L]) % MOD;

        long C_remaining = (fact[totalCells - 2] * invFact[L - 2]) % MOD;
        C_remaining = (C_remaining * invFact[totalCells - L]) % MOD;

        long totalDistance = 0;

        for (int r1 = 0; r1 < M; r1++) {
            for (int c1 = 0; c1 < N; c1++) {
                for (int r2 = 0; r2 < M; r2++) {
                    for (int c2 = 0; c2 < N; c2++) {
                        if (r1 == r2 && c1 == c2) continue;

                        int dist = Math.abs(r1 - r2) + Math.abs(c1 - c2);
                        totalDistance = (totalDistance + ((long)dist * C_remaining) % MOD) % MOD;
                    }
                }
            }
        }

        totalDistance = (totalDistance * modInv(2, MOD)) % MOD;
        totalDistance = (totalDistance * modInv(C_total, MOD)) % MOD;
        totalDistance = (totalDistance * C_total) % MOD;

        return totalDistance;
    }
}

class Solution:
    def computeExhibitDistance(self, M: int, N: int, L: int) -> int:
        MOD = 10**9 + 7

        total_cells = M * N

