        return idle
    }

    maxIdle := 0

    for leftK = 0; leftK <= k; leftK++ {
        rightK = k - leftK
        idle := calculateIdle(shiftDuration, startSlots, endSlots, pos, leftK, rightK)
        if idle > maxIdle {
