func calculateIdle(shiftDuration int, startSlots []int, endSlots []int, pos int, leftK int, rightK int) int {
    n := len(startSlots)

    leftBound := 0
    if pos > 0 {
        leftStart := max(0, pos-leftK-1)
        leftBound = endSlots[leftStart]
        for i := leftStart + 1; i < pos; i++ {
            duration := endSlots[i] - startSlots[i]
            leftBound += duration
        }
    }

    rightBound := shiftDuration
    if pos < n {
        rightEnd := min(n-1, pos+rightK)
        rightBound = startSlots[rightEnd]
        for i := pos; i < rightEnd; i++ {
            duration := endSlots[i] - startSlots[i]
            rightBound -= duration
        }
    }

    if rightBound <= leftBound {
        return 0
    }

    return rightBound - leftBound
}

