		var gap int
		if i == 0 {
			gap = solvePrefix(k, durations, shiftDuration, true)
		} else if i == n {
			gap = solvePrefix(k, durations, shiftDuration, false)
		} else {
			gap = solveMiddle(i, k, durations, shiftDuration)
		}
		if gap > ans {
			ans = gap
		}
	}

	return ans
}

func solvePrefix(k int, durations []int, shiftDuration int, fromStart bool) int {
	n := len(durations)
	if fromStart {
		sum := 0
		for i := 0; i < n-k; i++ {
			sum += durations[i]
		}
		return shiftDuration - sum
	} else {
		sum := 0
		for i := k; i < n; i++ {
			sum += durations[i]
		}
		return shiftDuration - sum
	}
}

func solveMiddle(idx int, k int, durations []int, shiftDuration int) int {
	n := len(durations)
	leftCount := idx
	rightCount := n - idx

	best := 0
	for kLeft := 0; kLeft <= k; kLeft++ {
		kRight := k - kLeft
		if kLeft > leftCount {
			continue
		}
		if kRight > rightCount {
			kRight = rightCount
		}

		sumLeft := 0
		for i := 0; i < leftCount-kLeft; i++ {
			sumLeft += durations[i]
		}

		sumRight := 0
		for i := idx + kRight; i < n; i++ {
			sumRight += durations[i]
		}

		gap := shiftDuration - sumLeft - sumRight
		if gap > best {
			best = gap
		}
	}
	return best
}

