    public int maxIdleTime(int shiftDuration, int k, int[] startSlots, int[] endSlots) {
        int n = startSlots.length;
        if (n == 0) return shiftDuration;

        int[] durations = new int[n];
        for (int i = 0; i < n; i++) {
            durations[i] = endSlots[i] - startSlots[i];
        }

        int maxIdle = 0;

        for (int i = 0; i <= n; i++) {
            for (int j = i; j <= n; j++) {
                int neededMoves = 0;
                if (i > 0) neededMoves++;
                if (j < n) neededMoves++;

                int gapSize = j - i - 1;
                if (gapSize > 0) {
                    neededMoves += gapSize;
                } else if (gapSize == 0) {

                }

                int totalMoves = 0;
                if (i > 0 && j < n) {
                    totalMoves = (j - i) + 1;
                } else if (i == 0 && j == n) {
                    totalMoves = n;
                } else {
                    totalMoves = (j - i);
                }

                if (totalMoves <= k) {
                    int currentIdle = 0;
                    long sumDurationsBefore = 0;
                    for (int m = 0; m < i; m++) sumDurationsBefore += durations[m];
                    long sumDurationsAfter = 0;
                    for (int m = j; m < n; m++) sumDurationsAfter += durations[m];

                    long availableSpace = shiftDuration - sumDurationsBefore - sumDurationsAfter;
                    if (availableSpace >= 0) {
                        maxIdle = Math.max(maxIdle, (int)availableSpace);
                    }
                }
            }
        }

        int[][] dp = new int[n + 1][k + 1];
        for (int i = 0; i < n; i++) {
            int currentGap = (i == 0) ? startSlots[i] : startSlots[i] - endSlots[i - 1];
            maxIdle = Math.max(maxIdle, currentGap);
        }
        maxIdle = Math.max(maxIdle, shiftDuration - endSlots[n - 1]);

        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                int numToRemove = j - i - 1;
                if (numToRemove <= k) {
                    maxIdle = Math.max(maxIdle, startSlots[j] - endSlots[i]);
                }
            }
        }

        return maxIdle;
    }
}

