class Scheduler:
    def maxIdleTime(self, shiftDuration: int, k: int, startSlots: list[int], endSlots: list[int]) -> int:
        n = len(startSlots)
        if n == 0:
            return shiftDuration

        durations = [endSlots[i] - startSlots[i] for i in range(n)]

        def check(L):
            if L <= 0: return True

            for i in range(n + 1):
                if i == 0:
                    gap_start = 0
                else:
                    gap_start = endSlots[i-1]

                if i == n:
                    gap_end = shiftDuration
                else:
                    gap_end = startSlots[i]

                if gap_end - gap_start >= L:
                    return True

            for i in range(n):
                for j in range(i, n):
                    needed_k = 0
                    total_dur = 0
                    for m in range(i, j + 1):
                        total_dur += durations[m]

                    if i > 0:
                        left_bound = endSlots[i-1]
                    else:
                        left_bound = 0

                    if j < n - 1:
                        right_bound = startSlots[j+1]
                    else:
                        right_bound = shiftDuration

                    if right_bound - left_bound - total_dur >= L:
                        move_count = 0
                        for m in range(i, j + 1):
                            move_count += 1
                        if move_count <= k:
                            return True

            for i in range(n):
                for j in range(i, n):
                    total_dur = sum(durations[i:j+1])

                    if i > 0:
                        if shiftDuration - endSlots[i-1] - total_dur >= L:
                            if (n - i) <= k:
                                return True
                    else:
                        if shiftDuration - total_dur >= L:
                            if n <= k:
                                return True

                    if j < n - 1:
                        if startSlots[j+1] - total_dur >= L:
                            if (j + 1) <= k:
                                return True
                    else:
                        if shiftDuration - total_dur >= L:
                            if n <= k:
                                return True

            for length in range(1, n + 1):
                if length <= k:
                    for i in range(n - length + 1):
                        window_dur = sum(durations[i:i+length])
                        if i == 0:
                            if n - length <= k:
                                if shiftDuration - window_dur >= L:
                                    return True
                        if i + length == n:
                            if n - length <= k:
                                if shiftDuration - window_dur >= L:
                                    return True

            for length in range(n - k, n + 1):
                if length < 0: continue
                for i in range(n - length + 1):
                    window_dur = sum(durations[i:i+length])
                    if shiftDuration - window_dur >= L:
                        return True
            return False

        low = 0
        high = shiftDuration
        ans = 0
        while low <= high:
            mid = (low + high)
            if check(mid):
                ans = mid
                low = mid + 1
            else:
                high = mid - 1
        return ans

