public class AdjustmentCalculator {

    public long minAdjustments(int[][] events) {
        long total = 0;
        for (int[] event : events) {
            total += calculateAdjustments(event[0], event[1]);
        }
        return total;
    }

    private long calculateAdjustments(int start, int end) {
        PriorityQueue<Long> pq = new PriorityQueue<>(Collections.reverseOrder());

        for (long i = start; i <= end; i++) {
            pq.offer(i);
        }

        long adjustments = 0;

        while (!pq.isEmpty()) {
            long first = pq.poll();
            if (first == 0) {
                continue;
            }

            if (pq.isEmpty()) {
                while (first > 0) {
                    first = first / 4;
                    adjustments++;
                }
                break;
            }

            long second = pq.poll();

            adjustments++;

            long newFirst = first / 4;
            long newSecond = second / 4;

            if (newFirst > 0) {
                pq.offer(newFirst);
            }
            if (newSecond > 0) {
                pq.offer(newSecond);
            }
        }

        return adjustments;
    }

