vector<vector<int>> arrangeGrid(vector<vector<int>>& grid) {
    int n = grid.size();

    for (int diag = 0; diag < n; diag++) {
        vector<int> elements;
        int i = diag;
        int j = 0;
        while (i >= 0 && j < n) {
            elements.push_back(grid[i][j]);
            i--;
            j++;
        }

        sort(elements.begin(), elements.end(), greater<int>());

        i = diag;
        j = 0;
        int idx = 0;
        while (i >= 0 && j < n) {
            grid[i][j] = elements[idx++];
            i--;
            j++;
        }
    }

    for (int diag = 1; diag < n; diag++) {
        vector<int> elements;
        int i = n - 1;
        int j = diag;
        while (i >= 0 && j < n) {
            elements.push_back(grid[i][j]);
            i--;
            j++;
        }

        sort(elements.begin(), elements.end());

        i = n - 1;
        j = diag;
        int idx = 0;
        while (i >= 0 && j < n) {
            grid[i][j] = elements[idx++];
            i--;
            j++;
        }
    }

    return grid;
}

