        var diagonal []int
        row, col := startRow, 0
        for row < n && col < n {
            diagonal = append(diagonal, grid[row][col])
            row++
            col++
        }

        sort.Slice(diagonal, func(i, j int) bool {
            return diagonal[i] > diagonal[j]
        })

        row, col = startRow, 0
        idx := 0
        for row < n && col < n {
            grid[row][col] = diagonal[idx]
            row++
            col++
            idx++
        }
    }

    for startCol := 1; startCol < n; startCol++ {
        var diagonal []int
        row, col := 0, startCol
        for row < n && col < n {
            diagonal = append(diagonal, grid[row][col])
            row++
            col++
        }

        sort.Slice(diagonal, func(i, j int) bool {
            return diagonal[i] < diagonal[j]
        })

        row, col = 0, startCol
        idx := 0
        for row < n && col < n {
            grid[row][col] = diagonal[idx]
            row++
            col++
            idx++
        }
    }

    return grid
