class Solution {
public:
    vector<int> processRequests(vector<int>& containers, vector<int>& requests) {
        int n = containers.size();
        vector<int> result;

        for (int req : requests) {
            int target_code = containers[req];
            int min_dist = INT_MAX;
            bool found = false;

            for (int i = 0; i < n; i++) {
                if (i != req && containers[i] == target_code) {
                    found = true;
                    int forward_dist = (i - req + n) % n;
                    int backward_dist = (req - i + n) % n;
                    int dist = min(forward_dist, backward_dist);
                    min_dist = min(min_dist, dist);
                }
            }

            if (found) {
                result.push_back(min_dist);
            } else {
                result.push_back(-1);
            }
        }

        return result;
    }
};

