using namespace std;

class Solution {
public:
    vector<int> processRequests(vector<int>& containers, vector<int>& requests) {
        int n = containers.size();
        unordered_map<int, vector<int>> pos_map;
        for (int i = 0; i < n; ++i) {
            pos_map[containers[i]].push_back(i);
        }

        vector<int> results;
        for (int req_idx : requests) {
            int val = containers[req_idx];
            const vector<int>& indices = pos_map[val];
            if (indices.size() <= 1) {
                results.push_back(-1);
                continue;
            }

            auto it = lower_bound(indices.begin(), indices.end(), req_idx);
            int pos_in_vec = distance(indices.begin(), it);

            int min_dist = n;

            int prev_idx = (pos_in_vec == 0) ? indices.back() : indices[pos_in_vec - 1];
            int dist_prev = abs(req_idx - prev_idx);
            dist_prev = min(dist_prev, n - dist_prev);
            min_dist = min(min_dist, dist_prev);

            int next_idx = (pos_in_vec == indices.size() - 1) ? indices[0] : indices[pos_in_vec + 1];
            int dist_next = abs(req_idx - next_idx);
            dist_next = min(dist_next, n - dist_next);
            min_dist = min(min_dist, dist_next);

            results.push_back(min_dist);
        }
        return results;
    }
};

