func solve() {
	scanner := bufio.NewScanner(os.Stdin)
	scanner.Split(bufio.ScanWords)

	if !scanner.Scan() {
		return
	}
	n, _ := strconv.Atoi(scanner.Text())
	containers := make([]int, n)
	for i := 0; i < n; i++ {
		scanner.Scan()
		containers[i], _ = strconv.Atoi(scanner.Text())
	}

	scanner.Scan()
	m, _ := strconv.Atoi(scanner.Text())
	requests := make([]int, m)
	for i := 0; i < m; i++ {
		scanner.Scan()
		requests[i], _ = strconv.Atoi(scanner.Text())
	}

	posMap := make(map[int][]int)
	for i, val := range containers {
		posMap[val] = append(posMap[val], i)
	}

	results := make([]int, m)
	for i, reqIdx := range requests {
		val := containers[reqIdx]
		indices := posMap[val]
		if len(indices) < 2 {
			results[i] = -1
			continue
		}

		idxInList := sort.SearchInts(indices, reqIdx)

		var minDist int = n

		prevIdx := (idxInList - 1 + len(indices)) % len(indices)
		d1 := (reqIdx - indices[prevIdx] + n) % n
		if d1 < minDist {
			minDist = d1
		}

		nextIdx := (idxInList + 1) % len(indices)
		d2 := (indices[nextIdx] - reqIdx + n) % n
		if d2 < minDist {
			minDist = d2
		}

		results[i] = minDist
	}

	fmt.Print("[")
	for i, res := range results {
		fmt.Print(res)
		if i < len(results)-1 {
			fmt.Print(", ")
		}
	}
	fmt.Println("]")
}

