        System.out.println("]");
    }

    private static int[] solve(int[] containers, int[] requests) {
        int n = containers.length;
        Map<Integer, List<Integer>> positions = new HashMap<>();
        for (int i = 0; i < n; i++) {
            positions.computeIfAbsent(containers[i], k -> new ArrayList<>()).add(i);
        }

        int[] results = new int[requests.length];
        for (int i = 0; i < requests.length; i++) {
            int idx = requests[i];
            int val = containers[idx];
            List<Integer> posList = positions.get(val);

            if (posList.size() <= 1) {
                results[i] = -1;
                continue;
            }

            int listIdx = Collections.binarySearch(posList, idx);
            int prevIdx = (listIdx - 1 + posList.size()) % posList.size();
            int nextIdx = (listIdx + 1) % posList.size();

            int d1 = Math.abs(idx - posList.get(prevIdx));
            d1 = Math.min(d1, n - d1);

            int d2 = Math.abs(idx - posList.get(nextIdx));
            d2 = Math.min(d2, n - d2);

            results[i] = Math.min(d1, d2);
        }
        return results;
    }

    private static int[] parseArray(String s) {
        s = s.substring(s.indexOf('[') + 1, s.lastIndexOf(']')).trim();
        if (s.isEmpty()) return new int[0];
        String[] parts = s.split(",");
        int[] res = new int[parts.length];
        for (int i = 0; i < parts.length; i++) {
            res[i] = Integer.parseInt(parts[i].trim());
        }
        return res;
    }
}

