func maxDisplacement(commands string, k int) int {
    n := len(commands)
    maxDist := 0

    for i := 0; i <= n; i++ {
        dist := computeMaxDistanceAtStep(commands, k, i)
        if dist > maxDist {
            maxDist = dist
        }
    }

    return maxDist
}

func computeMaxDistanceAtStep(commands string, k int, step int) int {
    n := len(commands)

    x := 0
    y := 0

    for i := 0; i < step && i < n; i++ {
        switch commands[i] {
        case 'N':
            y++
        case 'S':
            y--
        case 'E':
            x++
        case 'W':
            x--
        }
    }

    remaining := step
    changes := k

    contributions := make([]Contribution, 0)

    for i := 0; i < step && i < n; i++ {
        c := commands[i]

        currentContrib := getContribution(c, x, y)

        bestContrib := currentContrib
        bestDir := c

        for _, dir := range []byte{'N', 'S', 'E', 'W'} {
            if dir != c {
                contrib := getContribution(dir, x, y)
                if contrib > bestContrib {
                    bestContrib = contrib
                    bestDir = dir
                }
            }
        }

        gain := bestContrib - currentContrib
        contributions = append(contributions, Contribution{gain: gain, original: c, best: bestDir})
    }

    sortContributions(contributions)

    actualX := 0
    actualY := 0
    changesUsed := 0

    changeMap := make(map[int]byte)

    for i := 0; i < len(contributions) && changesUsed < changes; i++ {
        if contributions[i].gain > 0 {
            changeMap[i] = contributions[i].best
            changesUsed++
        }
    }

    for i := 0; i < step && i < n; i++ {
        dir := commands[i]
        if newDir, ok := changeMap[i]; ok {
            dir = newDir
        }

        switch dir {
        case 'N':
            actualY++
        case 'S':
            actualY--
        case 'E':
            actualX++
        case 'W':
            actualX--
        }
    }

    remaining = changes - changesUsed

    if remaining > 0 {
        if actualX >= 0 {
            actualX += remaining
        } else {
            actualX -= remaining
        }
    }

    return abs(actualX) + abs(actualY)
}

type Contribution struct {
    gain     int
    original byte
    best     byte
}

func sortContributions(contributions []Contribution) {
    for i := 0; i < len(contributions); i++ {
        for j := i + 1; j < len(contributions); j++ {
            if contributions[j].gain > contributions[i].gain {
                contributions[i], contributions[j] = contributions[j], contributions[i]
            }
        }
    }
}

func getContribution(dir byte, targetX, targetY int) int {
    dx := 0
    dy := 0

    switch dir {
    case 'N':
        dy = 1
    case 'S':
        dy = -1
    case 'E':
        dx = 1
    case 'W':
        dx = -1
    }

    if targetX >= 0 && dx > 0 {
        return 1
    }
    if targetX < 0 && dx < 0 {
        return 1
    }
    if targetY >= 0 && dy > 0 {
        return 1
    }
    if targetY < 0 && dy < 0 {
        return 1
    }
    if targetX > 0 && dx < 0 {
        return -1
    }
    if targetX < 0 && dx > 0 {
        return -1
    }
    if targetY > 0 && dy < 0 {
        return -1
    }
    if targetY < 0 && dy > 0 {
        return -1
    }

    return 0
}

