    public int maxDisplacement(String commands, int k) {
        int n = commands.length();
        int maxDist = 0;

        for (int i = 0; i < n; i++) {
            int x = 0, y = 0;
            PriorityQueue<Integer> improvements = new PriorityQueue<>(Collections.reverseOrder());

            for (int j = i; j < n; j++) {
                char cmd = commands.charAt(j);
                if (cmd == 'N') y++;
                else if (cmd == 'S') y--;
                else if (cmd == 'E') x++;
                else if (cmd == 'W') x--;

                int currentDist = Math.abs(x) + Math.abs(y);

                int bestImprovement = 0;
                if (x >= 0 && y >= 0) {
                    if (cmd == 'S') bestImprovement = 2;
                    else if (cmd == 'W') bestImprovement = 2;
                } else if (x >= 0 && y < 0) {
                    if (cmd == 'N') bestImprovement = 2;
                    else if (cmd == 'W') bestImprovement = 2;
                } else if (x < 0 && y >= 0) {
                    if (cmd == 'S') bestImprovement = 2;
                    else if (cmd == 'E') bestImprovement = 2;
                } else {
                    if (cmd == 'N') bestImprovement = 2;
                    else if (cmd == 'E') bestImprovement = 2;
                }

                improvements.add(bestImprovement);

                int additionalDist = 0;
                int changesUsed = 0;
                for (int imp : improvements) {
                    if (changesUsed >= k) break;
                    additionalDist += imp;
                    changesUsed++;
                }

                maxDist = Math.max(maxDist, currentDist + additionalDist);
            }
        }

        return maxDist;
    }

