                if (target_x != 0) {
                    if (target_x > 0 && dx < 1) can_improve = true;
                    else if (target_x < 0 && dx > -1) can_improve = true;
                }
                if (!can_improve && target_y != 0) {
                    if (target_y > 0 && dy < 1) can_improve = true;
