                    }
                } else {
                    current_x += dx;
                    current_y += dy;
                }
                max_dist = max(max_dist, abs(current_x) + abs(current_y));
            }
        };

        solve(1, 1);
        solve(1, -1);
        solve(-1, 1);
        solve(-1, -1);

