class RouteOptimizer {
public:
    vector<long long> computeCargoProfit(vector<int>& consumptionRates, vector<int>& cargoValues, int k) {
        int n = consumptionRates.size();
        vector<int> indices(n);
        for (int i = 0; i < n; ++i) indices[i] = i;

        sort(indices.begin(), indices.end(), [&](int a, int b) {
            return consumptionRates[a] < consumptionRates[b];
        });

        vector<long long> result(n);
        priority_queue<int, vector<int>, greater<int>> pq;
        long long currentSum = 0;

        int j = 0;
        for (int i = 0; i < n; ) {
            int start = i;
            while (i < n && consumptionRates[indices[i]] == consumptionRates[indices[start]]) {
                result[indices[i]] = currentSum;
                i++;
            }

            for (int idx = start; idx < i; ++idx) {
                int val = cargoValues[indices[idx]];
                pq.push(val);
                currentSum += val;
                if (pq.size() > k) {
                    currentSum -= pq.top();
                    pq.pop();
                }
            }
        }

        return result;
    }
};

