	sort.Slice(fleet, func(i, j int) bool {
		return fleet[i].consumptionRate < fleet[j].consumptionRate
	})

	results := make([]int64, n)
	h := &MinHeap{}
	heap.Init(h)
	var currentSum int64 = 0

	i := 0
	for i < n {
		j := i
		for j < n && fleet[j].consumptionRate == fleet[i].consumptionRate {
			results[fleet[j].id] = currentSum
			j++
		}
		for m := i; m < j; m++ {
			heap.Push(h, fleet[m].cargoValue)
			currentSum += int64(fleet[m].cargoValue)
			if h.Len() > k {
				currentSum -= int64(heap.Pop(h).(int))
			}
		}
		i = j
	}

	fmt.Print("[")
	for i := 0; i < n; i++ {
		fmt.Print(results[i])
		if i < n-1 {
			fmt.Print(", ")
		}
	}
	fmt.Println("]")
}

