class RouteOptimizer {
    static class Spacecraft {
        int id;
        int rate;
        int val;
        Spacecraft(int id, int rate, int val) {
            this.id = id;
            this.rate = rate;
            this.val = val;
        }
    }

    public long[] computeCargoProfit(int[] consumptionRates, int[] cargoValues, int k) {
        int n = consumptionRates.length;
        Spacecraft[] ships = new Spacecraft[n];
        for (int i = 0; i < n; i++) {
            ships[i] = new Spacecraft(i, consumptionRates[i], cargoValues[i]);
        }

        Arrays.sort(ships, (a, b) -> Integer.compare(a.rate, b.rate));

        long[] result = new long[n];
        PriorityQueue<Integer> pq = new PriorityQueue<>();
        long currentSum = 0;

        int j = 0;
        for (int i = 0; i < n; i++) {
            while (j < i && ships[j].rate < ships[i].rate) {
                pq.offer(ships[j].val);
                currentSum += ships[j].val;
                if (pq.size() > k) {
                    currentSum -= pq.poll();
                }
                j++;
            }

            if (i > 0 && ships[i].rate == ships[i-1].rate) {
                result[ships[i].id] = result[ships[i-1].id];
            } else {
                result[ships[i].id] = currentSum;
            }
        }

        return result;
    }

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line1 = br.readLine();
        if (line1 == null) return;
        int[] consumptionRates = parseArray(line1);
        int[] cargoValues = parseArray(br.readLine());
        int k = Integer.parseInt(br.readLine().trim());

        RouteOptimizer solver = new RouteOptimizer();
        long[] res = solver.computeCargoProfit(consumptionRates, cargoValues, k);

        StringBuilder sb = new StringBuilder();
        sb.append("[");
        for (int i = 0; i < res.length; i++) {
            sb.append(res[i]);
            if (i < res.length - 1) sb.append(", ");
        }
        sb.append("]");
        System.out.println(sb.toString());
    }

    private static int[] parseArray(String s) {
        s = s.replace("[", "").replace("]", "").replace(",", " ");
        StringTokenizer st = new StringTokenizer(s);
        List<Integer> list = new ArrayList<>();
        while (st.hasMoreTokens()) {
            list.add(Integer.parseInt(st.nextToken().trim()));
        }
        int[] res = new int[list.size()];
        for (int i = 0; i < list.size(); i++) res[i] = list.get(i);
        return res;
    }
}

