class ContestDistributor {
public:
    vector<int> distributeSupplies(const vector<int>& contests, const vector<int>& supplies) {
        int max_val = 0;
        for (int c : contests) if (c > max_val) max_val = c;
        for (int s : supplies) if (s > max_val) max_val = s;

        vector<int> first_index(max_val + 1, -1);
        for (int j = 0; j < (int)supplies.size(); ++j) {
            int s = supplies[j];
            if (s <= max_val && first_index[s] == -1) {
                first_index[s] = j;
            }
        }

        vector<int> best_supply_index(max_val + 1, -1);
        for (int s = 1; s <= max_val; ++s) {
            if (first_index[s] == -1) continue;
            int idx = first_index[s];
            for (int multiple = s; multiple <= max_val; multiple += s) {
                if (best_supply_index[multiple] == -1 || idx < best_supply_index[multiple]) {
                    best_supply_index[multiple] = idx;
                }
            }
        }

        vector<int> result;
        result.reserve(contests.size());
        for (int c : contests) {
            result.push_back(best_supply_index[c]);
        }
        return result;
    }
};

