func solve() {
	sc := bufio.NewScanner(os.Stdin)
	sc.Split(bufio.ScanWords)

	if !sc.Scan() {
		return
	}
	n, _ := strconv.Atoi(sc.Text())
	contests := make([]int, n)
	for i := 0; i < n; i++ {
		sc.Scan()
		contests[i], _ = strconv.Atoi(sc.Text())
	}

	if !sc.Scan() {
		return
	}
	m, _ := strconv.Atoi(sc.Text())
	supplies := make([]int, m)
	for i := 0; i < m; i++ {
		sc.Scan()
		supplies[i], _ = strconv.Atoi(sc.Text())
	}

	maxVal := 0
	for _, v := range contests {
		if v > maxVal {
			maxVal = v
		}
	}

	bestSupplyIndex := make([]int, maxVal+1)
	for i := range bestSupplyIndex {
		bestSupplyIndex[i] = -1
	}

	for i, s := range supplies {
		if s <= maxVal && bestSupplyIndex[s] == -1 {
			bestSupplyIndex[s] = i
		}
	}

	allocation := make([]int, n)
	memo := make([]int, maxVal+1)
	for i := range memo {
		memo[i] = -2
	}

	for i, c := range contests {
		if memo[c] != -2 {
			allocation[i] = memo[c]
			continue
		}

		bestIdx := -1
		for j := 1; j*j <= c; j++ {
			if c%j == 0 {
				d1 := j
				d2 := c / j

				if d1 <= maxVal {
					idx1 := bestSupplyIndex[d1]
					if idx1 != -1 {
						if bestIdx == -1 || idx1 < bestIdx {
							bestIdx = idx1
						}
					}
				}

				if d2 <= maxVal {
					idx2 := bestSupplyIndex[d2]
					if idx2 != -1 {
						if bestIdx == -1 || idx2 < bestIdx {
							bestIdx = idx2
						}
					}
				}
			}
		}
		memo[c] = bestIdx
		allocation[i] = bestIdx
	}

	out := bufio.NewWriter(os.Stdout)
	fmt.Fprint(out, "[")
	for i, v := range allocation {
		fmt.Fprint(out, v)
		if i < len(allocation)-1 {
			fmt.Fprint(out, ", ")
		}
	}
	fmt.Fprintln(out, "]")
	out.Flush()
}

