        for (int c : contests) maxVal = Math.max(maxVal, c);
        for (int s : supplies) maxVal = Math.max(maxVal, s);

        int[] firstIndex = new int[maxVal + 1];
        Arrays.fill(firstIndex, -1);

        for (int j = 0; j < supplies.length; j++) {
            int val = supplies[j];
            if (val <= maxVal && firstIndex[val] == -1) {
                firstIndex[val] = j;
            }
        }

        int[] minIdxForVal = new int[maxVal + 1];
        Arrays.fill(minIdxForVal, -1);

        for (int s = 1; s <= maxVal; s++) {
            if (firstIndex[s] != -1) {
                for (int multiple = s; multiple <= maxVal; multiple += s) {
                    if (minIdxForVal[multiple] == -1 || firstIndex[s] < minIdxForVal[multiple]) {
                        minIdxForVal[multiple] = firstIndex[s];
                    }
                }
            }
        }

        int[] allocation = new int[contests.length];
        for (int i = 0; i < contests.length; i++) {
            allocation[i] = minIdxForVal[contests[i]];
        }

        return allocation;
    }
}

