using namespace std;

class Solution {
public:
    long long maxAssetValue(vector<int>& treasures, long long stepCount) {
        int n = treasures.size();
        long long left = 0, right = 1e15;
        long long answer = 0;

        while (left <= right) {
            long long mid = left + (right - left) / 2;

            if (canAchieve(treasures, stepCount, mid)) {
                answer = mid;
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }

        return answer;
    }

    bool canAchieve(vector<int>& treasures, long long stepCount, long long target) {
        int n = treasures.size();
        vector<long long> needed(n);

        for (int i = 0; i < n; i++) {
            needed[i] = (target + treasures[i] - 1) / treasures[i];
        }

        for (int rightmost = 0; rightmost < n; rightmost++) {
            long long moves = 0;
            bool valid = true;

            for (int i = 0; i <= rightmost; i++) {
                long long visits = needed[i];

                if (i == rightmost) {
                    moves += (rightmost + 1) + (visits - 1) * 2;
                } else {
                    moves += visits * 2;
                }

                if (moves > stepCount) {
                    valid = false;
                    break;
                }
            }

            if (valid && moves <= stepCount) {
                return true;
            }
        }

        return false;
    }
};

