func maxAssetValue(treasures []int, stepCount int) int {
    n := len(treasures)

    left := 0
    right := 0

    for i := 0; i < n; i++ {
        right += treasures[i] * stepCount
    }

    answer := 0

    for left <= right {
        mid := left + (right-left)/2

        if canAchieve(treasures, stepCount, mid) {
            answer = mid
            left = mid + 1
        } else {
            right = mid - 1
        }
    }

    return answer
}

func canAchieve(treasures []int, stepCount int, target int) bool {
    n := len(treasures)

    visits := make([]int, n)
    for i := 0; i < n; i++ {
        visits[i] = (target + treasures[i] - 1) / treasures[i]
    }

    minSteps := minStepsToVisit(visits, n)

    return minSteps <= stepCount
}

func minStepsToVisit(visits []int, n int) int {
    totalVisits := 0
    for i := 0; i < n; i++ {
        totalVisits += visits[i]
    }

    maxVisits := 0
    for i := 0; i < n; i++ {
        if visits[i] > maxVisits {
            maxVisits = visits[i]
        }
    }

    minLeft := totalVisits
    for i := 0; i < n; i++ {
        sumLeft := 0
        for j := 0; j <= i; j++ {
            sumLeft += visits[j]
        }
        if sumLeft < minLeft {
            minLeft = sumLeft
        }
    }

    minRight := totalVisits
    for i := 0; i < n; i++ {
        sumRight := 0
        for j := i; j < n; j++ {
            sumRight += visits[j]
        }
        if sumRight < minRight {
            minRight = sumRight
        }
    }

    steps1 := (n - 1) + totalVisits
    steps2 := 2*(n-1) + minLeft
    steps3 := minRight

    minSteps := steps1
    if steps2 < minSteps {
        minSteps = steps2
    }
    if steps3 < minSteps {
        minSteps = steps3
    }

    return minSteps
}

import java.util.*;

public class Solution {

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);

        String[] treasuresStr = sc.nextLine().trim().split("\\s+");
        int n = treasuresStr.length;
        int[] treasures = new int[n];
        for (int i = 0; i < n; i++) {
            treasures[i] = Integer.parseInt(treasuresStr[i]);
        }

        int stepCount = sc.nextInt();

        int result = maxAssetValue(treasures, stepCount);
        System.out.println(result);

        sc.close();
    }

    public static int maxAssetValue(int[] treasures, int stepCount) {
        int n = treasures.length;
        long left = 0;
        long right = (long)stepCount * 1000000L;
        long answer = 0;

        while (left <= right) {
            long mid = left + (right - left) / 2;
            if (canAchieve(treasures, stepCount, mid)) {
                answer = mid;
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }

        return (int)answer;
    }

    private static boolean canAchieve(int[] treasures, int stepCount, long target) {
        int n = treasures.length;
        long[] visits = new long[n];

        for (int i = 0; i < n; i++) {
            visits[i] = (target + treasures[i] - 1) / treasures[i];
        }

        long minSteps = minStepsToVisit(visits, n);
        return minSteps <= stepCount;
    }

    private static long minStepsToVisit(long[] visits, int n) {
        long minSteps = Long.MAX_VALUE;

        for (int rightmost = 0; rightmost < n; rightmost++) {
            long steps = calculateSteps(visits, n, rightmost);
            minSteps = Math.min(minSteps, steps);
        }

        return minSteps;
    }

    private static long calculateSteps(long[] visits, int n, int rightmost) {
        long steps = 0;

        steps += rightmost + 1;

        for (int i = 0; i <= rightmost; i++) {
            if (visits[i] > 0) {
                steps += visits[i] - 1;
            }
        }

        long maxBacktrack = 0;
        for (int i = 0; i < rightmost; i++) {
            if (visits[i] > 1) {
                long backtrackCost = (visits[i] - 1) * 2 * (rightmost - i);
                maxBacktrack = Math.max(maxBacktrack, backtrackCost);
            }
        }

        steps += maxBacktrack;

        for (int i = rightmost + 1; i < n; i++) {
            if (visits[i] > 0) {
                return Long.MAX_VALUE;
            }
        }

        return steps;
    }
}

