bool check(long long target, const vector<int>& treasures, long long stepCount) {
    int n = treasures.size();
    vector<long long> needed(n);
    for (int i = 0; i < n; ++i) {
        needed[i] = (target + treasures[i] - 1) / treasures[i];
    }

    long long current_steps = 0;
    long long extra = 0;

    for (int i = 0; i < n; ++i) {
        current_steps++;
        long long required = needed[i];

        if (required > 1) {
            long long add = required - 1;
            current_steps += 2 * add;
            extra += add;
        }

        if (i < n - 1) {
            long long take = min(extra, (long long)1);
            extra -= take;
        }

        if (current_steps > stepCount) return false;
    }

    return current_steps <= stepCount;
}

