func solve(treasures []int, stepCount int64) int64 {
	n := len(treasures)
	var low int64 = 0
	var high int64 = 2e15
	var ans int64 = 0

	for low <= high {
		mid := low + (high-low)/2
		if mid == 0 {
			ans = max(ans, 0)
			low = mid + 1
			continue
		}
		if check(mid, treasures, stepCount) {
			ans = mid
			low = mid + 1
		} else {
			high = mid - 1
		}
	}
	return ans
}

func check(limit int64, treasures []int, k int64) bool {
	n := len(treasures)
	needed := make([]int64, n)
	for i := 0; i < n; i++ {
		needed[i] = (limit + int64(treasures[i]) - 1) / int64(treasures[i])
	}

	var totalSteps int64 = 0
	var currentPos int = -1
	var carry int64 = 0

	for i := 0; i < n; i++ {
		dist := int64(i - currentPos)
		totalSteps += dist
		currentPos = i

		req := needed[i] - carry
		if req > 0 {
			if i == n-1 {
				totalSteps += req * 2 - 1
				carry = 0
			} else {
				totalSteps += req * 2
				carry = req
			}
		} else {
			carry = 0
		}

		if totalSteps > k {
			return false
		}
	}

	return totalSteps <= k
}

