func balanceFields(fields [][3]float64) float64 {
    events := []float64{}

    for _, field := range fields {
        a, b, s := field[0], field[1], field[2]
        events = append(events, b)
        events = append(events, b+s)
    }

    sort.Float64s(events)

    unique := []float64{}
    for i, v := range events {
        if i == 0 || v != events[i-1] {
            unique = append(unique, v)
        }
    }

    totalArea := 0.0
    for _, field := range fields {
        s := field[2]
        totalArea += s * s
    }

    targetArea := totalArea / 2.0

    low := unique[0]
    high := unique[len(unique)-1]

    for i := 0; i < 100; i++ {
        mid := (low + high) / 2.0
        areaBelow := computeAreaBelow(fields, mid)

        if areaBelow < targetArea {
            low = mid
        } else {
            high = mid
        }
    }

    return (low + high) / 2.0
}

func computeAreaBelow(fields [][3]float64, y float64) float64 {
    area := 0.0

    for _, field := range fields {
        a, b, s := field[0], field[1], field[2]
        bottom := b
        top := b + s

        if y <= bottom {
            continue
        } else if y >= top {
            area += s * s
        } else {
            height := y - bottom
            area += s * height
        }
    }

    return area
}

