class Solution:
    def balanceFields(self, fields: List[List[int]]) -> float:
        events = []

        for a, b, s in fields:
            y_bottom = b
            y_top = b + s
            events.append((y_bottom, 1, a, a + s))
            events.append((y_top, -1, a, a + s))

        events.sort()

        def compute_total_area():
            total = 0
            for a, b, s in fields:
                total += s * s
            return total

        def area_below(y):
            segments = []
            for a, b, s in fields:
                y_bottom = b
                y_top = b + s
                if y <= y_bottom:
                    continue
                elif y >= y_top:
                    segments.append((a, a + s, s))
                else:
                    height = y - y_bottom
                    segments.append((a, a + s, height))

            area = 0
            for x_left, x_right, height in segments:
                area += (x_right - x_left) * height
            return area

        total_area = compute_total_area()
        target = total_area / 2.0

        y_values = set()
        for a, b, s in fields:
            y_values.add(b)
            y_values.add(b + s)
        y_values = sorted(y_values)

        if not y_values:
            return 0.0

        low = y_values[0]
        high = y_values[-1]

        for _ in range(100):
            mid = (low + high) / 2.0
            area = area_below(mid)
            if area < target:
                low = mid
            else:
                high = mid

        return (low + high) / 2.0

