            Integer[] teamScores = new Integer[scores[i].length];
            for (int j = 0; j < scores[i].length; j++) {
                teamScores[j] = scores[i][j];
            }
            Arrays.sort(teamScores, Collections.reverseOrder());

            int limit = Math.min(teamLimits[i], teamScores.length);
            for (int j = 0; j < limit; j++) {
                allScores.add(teamScores[j]);
            }
        }

        Collections.sort(allScores, Collections.reverseOrder());

        int total = 0;
        int count = Math.min(k, allScores.size());
        for (int i = 0; i < count; i++) {
            total += allScores.get(i);
