    public static long maxTotalScore(int[][] scores, int[] teamLimits, int k) {
        PriorityQueue<Integer> allEligiblePlayers = new PriorityQueue<>(Collections.reverseOrder());

        for (int i = 0; i < scores.length; i++) {
            Arrays.sort(scores[i]);
            int count = 0;
            for (int j = scores[i].length - 1; j >= 0 && count < teamLimits[i]; j--) {
                allEligiblePlayers.add(scores[i][j]);
                count++;
            }
        }

        long totalScore = 0;
        for (int i = 0; i < k && !allEligiblePlayers.isEmpty(); i++) {
            totalScore += allEligiblePlayers.poll();
        }

        return totalScore;
    }

    private static int[][] parse2DArray(String s) {
        s = s.trim();
        s = s.substring(2, s.length() - 2);
        String[] rows = s.split("\\],\\[");
        int[][] res = new int[rows.length][];
        for (int i = 0; i < rows.length; i++) {
            String[] parts = rows[i].split(",");
            res[i] = new int[parts.length];
            for (int j = 0; j < parts.length; j++) {
                res[i][j] = Integer.parseInt(parts[j].trim());
            }
        }
        return res;
    }

    private static int[] parse1DArray(String s) {
        s = s.trim();
        s = s.substring(1, s.length() - 1);
        String[] parts = s.split(",");
        int[] res = new int[parts.length];
        for (int i = 0; i < parts.length; i++) {
            res[i] = Integer.parseInt(parts[i].trim());
        }
        return res;
    }
