long long solve(vector<int>& values, vector<int>& risk, int k) {
    int n = values.size();

    vector<long long> prefixValues(n + 1, 0);
    for (int i = 0; i < n; i++) {
        prefixValues[i + 1] = prefixValues[i] + values[i];
    }

    vector<long long> prefixRisk(n + 1, 0);
    for (int i = 0; i < n; i++) {
        prefixRisk[i + 1] = prefixRisk[i] + risk[i];
    }

    vector<long long> dp(n + 1, LLONG_MAX);
    dp[0] = 0;

    for (int i = 1; i <= n; i++) {
        for (int j = 0; j < i; j++) {
            if (dp[j] == LLONG_MAX) continue;

            int vaultNum = 0;
            for (int t = 0; t < j; t++) {
                int start = t;
                while (t < j && dp[t + 1] != LLONG_MAX) {
                    t++;
                }
            }

            int numVaultsBefore = 0;
            long long tempDp = 0;
            for (int t = 0; t < j; t++) {
                if (t == 0 || dp[t] != dp[t-1] + 0) {
                    for (int s = 0; s <= t; s++) {
                        if (s == 0) {
                            if (dp[t+1] - dp[s] > 0 || t == 0) {
                                numVaultsBefore++;
                                break;
                            }
                        }
                    }
                }
            }

            numVaultsBefore = 0;
            for (int t = 1; t <= j; t++) {
                bool isVaultEnd = false;
                for (int s = 0; s < t; s++) {
                    if (dp[t] != LLONG_MAX) {
                        isVaultEnd = true;
                        break;
                    }
                }
                if (isVaultEnd && dp[t] != LLONG_MAX) {
                    numVaultsBefore++;
                }
            }

            numVaultsBefore = 0;
            vector<int> vaultEnds;
            for (int t = 1; t <= j; t++) {
                if (dp[t] != LLONG_MAX) {
                    bool isNewVault = true;
                    if (t > 1 && dp[t-1] != LLONG_MAX) {
                        isNewVault = false;
                    }
                    if (isNewVault || t == j) {
                        vaultEnds.push_back(t);
                    }
                }
            }
            numVaultsBefore = vaultEnds.size();

            int currentVaultIndex = numVaultsBefore + 1;

            long long sumValues = prefixValues[i];
            long long sumRisk = prefixRisk[i] - prefixRisk[j];
            long long cost = (sumValues + (long long)k * currentVaultIndex) * sumRisk;

            dp[i] = min(dp[i], dp[j] + cost);
        }
    }

    return dp[n];
}

