    public static long optimalExtractionCost(int[] values, int[] risk, int k) {
        int n = values.length;

        long[] prefixValues = new long[n + 1];
        for (int i = 0; i < n; i++) {
            prefixValues[i + 1] = prefixValues[i] + values[i];
        }

        long[] prefixRisk = new long[n + 1];
        for (int i = 0; i < n; i++) {
            prefixRisk[i + 1] = prefixRisk[i] + risk[i];
        }

        long[] dp = new long[n + 1];
        Arrays.fill(dp, Long.MAX_VALUE);
        dp[0] = 0;

        for (int i = 1; i <= n; i++) {
            for (int j = 0; j < i; j++) {
                int vaultNumber = countVaults(dp, j) + 1;

                long sumValues = prefixValues[i];
                long sumRisk = prefixRisk[i] - prefixRisk[j];
                long cost = (sumValues + (long) k * vaultNumber) * sumRisk;

                dp[i] = Math.min(dp[i], dp[j] + cost);
            }
        }

        return dp[n];
    }

    private static int countVaults(long[] dp, int index) {
        int count = 0;
        for (int i = 1; i <= index; i++) {
            if (dp[i] != Long.MAX_VALUE && dp[i] != dp[i - 1]) {
                count++;
            }
        }
        if (index > 0 && dp[index] != Long.MAX_VALUE) {
            int temp = 0;
            for (int i = 0; i < index; i++) {
                if (dp[i] < dp[index]) {
                    int c = 0;
                    for (int j = 1; j <= i; j++) {
                        if (dp[j] != Long.MAX_VALUE && (j == 1 || dp[j] != dp[j-1])) {
                            c++;
                        }
                    }
                }
            }
        }

        int vaults = 0;
        int prev = 0;
        for (int i = 1; i <= index; i++) {
            if (dp[i] != Long.MAX_VALUE) {
                vaults++;
                prev = i;
                while (i + 1 <= index && dp[i + 1] == Long.MAX_VALUE) {
                    i++;
                }
            }
        }
        return vaults;
    }
