class VaultPartitioner {
public:
    long long optimalExtractionCost(vector<int>& values, vector<int>& risk, int k) {
        int n = values.size();
        vector<long long> pref_val(n + 1, 0);
        vector<long long> pref_risk(n + 1, 0);
        for (int i = 0; i < n; ++i) {
            pref_val[i + 1] = pref_val[i] + values[i];
            pref_risk[i + 1] = pref_risk[i] + risk[i];
        }

        vector<vector<long long>> dp(n + 1, vector<long long>(n + 1, -1));
        dp[0][0] = 0;

        for (int i = 1; i <= n; ++i) {
            for (int r = 1; r <= n; ++r) {
                for (int l = 0; l < r; ++l) {
                    if (dp[i - 1][l] != -1) {
                        long long current_vault_cost = (pref_val[r] + (long long)k * i) * (pref_risk[r] - pref_risk[l]);
                        long long total_cost = dp[i - 1][l] + current_vault_cost;
                        if (dp[i][r] == -1 || total_cost < dp[i][r]) {
                            dp[i][r] = total_cost;
                        }
                    }
                }
            }
        }

        long long min_cost = -1;
        for (int i = 1; i <= n; ++i) {
            if (dp[i][n] != -1) {
                if (min_cost == -1 || dp[i][n] < min_cost) {
                    min_cost = dp[i][n];
                }
            }
        }
        return min_cost;
    }
};

