type VaultPartitioner struct{}

func (vp *VaultPartitioner) optimalExtractionCost(values []int, risk []int, k int) int {
	n := len(values)
	vSum := make([]int, n)
	rSum := make([]int, n+1)

	currentV := 0
	for i := 0; i < n; i++ {
		currentV += values[i]
		vSum[i] = currentV
		rSum[i+1] = rSum[i] + risk[i]
	}

	dp := make([][]int, n+1)
	for i := range dp {
		dp[i] = make([]int, n+1)
		for j := range dp[i] {
			dp[i][j] = math.MaxInt64 / 2
		}
	}

	dp[0][0] = 0

	for i := 1; i <= n; i++ {
		for j := 1; j <= i; j++ {
			for p := 0; p < i; p++ {
				cost := (vSum[i-1] + k*j) * (rSum[i] - rSum[p])
				if dp[j-1][p] + cost < dp[j][i] {
					dp[j][i] = dp[j-1][p] + cost
				}
			}
		}
	}

	minCost := math.MaxInt64 / 2
	for j := 1; j <= n; j++ {
		if dp[j][n] < minCost {
			minCost = dp[j][n]
		}
	}

	return minCost
}

