bool canSelectExclusiveSegments(string composition, int k) {
    int n = composition.length();

    if (k == 0) return true;

    unordered_map<char, int> firstOcc, lastOcc;
    for (int i = 0; i < n; i++) {
        char c = composition[i];
        if (firstOcc.find(c) == firstOcc.end()) {
            firstOcc[c] = i;
        }
        lastOcc[c] = i;
    }

    vector<pair<int, int>> intervals;
    for (int i = 0; i < n; i++) {
        int minFirst = i;
        int maxLast = i;
        bool allExclusive = true;

        for (int j = i; j < n; j++) {
            char c = composition[j];
            minFirst = min(minFirst, firstOcc[c]);
            maxLast = max(maxLast, lastOcc[c]);

            if (minFirst < i || maxLast > j) {
                allExclusive = false;
            } else {
                allExclusive = true;
            }

            if (allExclusive && i > 0 && j < n - 1) {
                intervals.push_back({i, j});
            }
        }
    }

    if (intervals.empty()) return false;

    sort(intervals.begin(), intervals.end());

    vector<int> dp(intervals.size(), 1);

    for (int i = 1; i < intervals.size(); i++) {
        for (int j = 0; j < i; j++) {
            if (intervals[j].second < intervals[i].first) {
                dp[i] = max(dp[i], dp[j] + 1);
            }
        }
    }

    int maxSegments = *max_element(dp.begin(), dp.end());
    return maxSegments >= k;
}

