func canSelectExclusiveSegments(composition string, k int) bool {
    if k == 0 {
        return true
    }

    n := len(composition)
    if n < 2 {
        return false
    }

    firstOccurrence := make(map[rune]int)
    lastOccurrence := make(map[rune]int)

    for i, ch := range composition {
        if _, exists := firstOccurrence[ch]; !exists {
            firstOccurrence[ch] = i
        }
        lastOccurrence[ch] = i
    }

    exclusiveChars := make([]rune, 0)
    for ch := range firstOccurrence {
        if firstOccurrence[ch] == lastOccurrence[ch] {
            exclusiveChars = append(exclusiveChars, ch)
        }
    }

    if len(exclusiveChars) == 0 {
        return false
    }

    positions := make([]int, len(exclusiveChars))
    for i, ch := range exclusiveChars {
        positions[i] = firstOccurrence[ch]
    }

    maxSegments := 0

    var backtrack func(int, int)
    backtrack = func(start int, count int) {
        if count > maxSegments {
            maxSegments = count
        }
        if maxSegments >= k {
            return
        }

        for left := start; left < n; left++ {
            for right := left; right < n; right++ {
                segment := composition[left:right+1]

                if left == 0 && right == n-1 {
                    continue
                }

                isExclusive := true
                segmentChars := make(map[rune]bool)
                for _, ch := range segment {
                    segmentChars[ch] = true
                }

                for ch := range segmentChars {
                    first := firstOccurrence[ch]
                    last := lastOccurrence[ch]
                    if first < left || last > right {
                        isExclusive = false
                        break
                    }
                }

                if isExclusive && len(segmentChars) > 0 {
                    backtrack(right+1, count+1)
                    if maxSegments >= k {
                        return
                    }
                }
            }
        }
    }

    backtrack(0, 0)

    return maxSegments >= k
}

