                break

        for i in range(len(merged) - 1):
            gap_start = merged[i][1] + 1
            gap_end = merged[i + 1][0] - 1
            if gap_start <= gap_end:
                gaps.append((gap_start, gap_end))

        if merged and merged[-1][1] < n - 1:
            gaps.append((merged[-1][1] + 1, n - 1))

        if len(gaps) >= k:
