                int nextL = currL, nextR = currR;
                for (int j = nextL; j <= nextR; j++) {
                    int c = composition.charAt(j) - 'a';
                    nextL = Math.min(nextL, first[c]);
                    nextR = Math.max(nextR, last[c]);
