class RelicProcessor {
public:
    int minFusionOperations(std::vector<int>& relicValues) {
        int n = relicValues.size();
        if (n <= 1) return 0;

        std::vector<long long> prefix_sum(n + 1, 0);
        for (int i = 0; i < n; ++i) {
            prefix_sum[i + 1] = prefix_sum[i] + relicValues[i];
        }

        std::vector<int> dp(n + 1, 0);
        std::vector<int> last_idx(n + 1, 0);
        std::deque<int> dq;
        dq.push_back(0);

        auto get_val = [&](int j) {
            return prefix_sum[j] + (prefix_sum[j] - prefix_sum[last_idx[j]]);
        };

        for (int i = 1; i <= n; ++i) {
            while (dq.size() >= 2 && prefix_sum[i] >= get_val(dq[1])) {
                dq.pop_front();
            }

            int best_j = dq.front();
            dp[i] = dp[best_j] + (i - best_j - 1);
            last_idx[i] = best_j;

            while (!dq.empty() && get_val(i) <= get_val(dq.back())) {
                dq.pop_back();
            }
            dq.push_back(i);
        }

        return dp[n];
    }
};

