	dp := make([]int, n+1)
	lastSum := make([]int64, n+1)
	prefixSum := make([]int64, n+1)

	for i := 0; i < n; i++ {
		prefixSum[i+1] = prefixSum[i] + int64(nums[i])
	}

	for i := 1; i <= n; i++ {
		for j := i - 1; j >= 0; j-- {
			currentSum := prefixSum[i] - prefixSum[j]
			if currentSum >= lastSum[j] {
				dp[i] = dp[j] + (i - j - 1)
				lastSum[i] = currentSum
				break
			}
		}
	}

	fmt.Println(dp[n])
}

