class RelicProcessor {
    public int minFusionOperations(int[] relicValues) {
        int n = relicValues.length;
        if (n <= 1) return 0;

        long[] prefixSums = new long[n + 1];
        for (int i = 0; i < n; i++) {
            prefixSums[i + 1] = prefixSums[i] + relicValues[i];
        }

        long[] lastElement = new long[n + 1];
        int[] count = new int[n + 1];
        int[] queue = new int[n + 1];
        int head = 0, tail = 0;
        queue[tail++] = 0;

        for (int i = 1; i <= n; i++) {
            int bestJ = 0;
            while (head + 1 < tail && prefixSums[queue[head + 1]] + lastElement[queue[head + 1]] <= prefixSums[i]) {
                head++;
            }
            bestJ = queue[head];

            lastElement[i] = prefixSums[i] - prefixSums[bestJ];
            count[i] = count[bestJ] + (i - bestJ - 1);

            while (tail > head && prefixSums[queue[tail - 1]] + lastElement[queue[tail - 1]] >= prefixSums[i] + lastElement[i]) {
                tail--;
            }
            queue[tail++] = i;
        }

        return count[n];
    }
}

