class RelicProcessor:
    def minFusionOperations(self, relicValues: list[int]) -> int:
        n = len(relicValues)
        if n == 0:
            return 0

        dp_sum = [0] * (n + 1)
        dp_count = [0] * (n + 1)

        for i in range(1, n + 1):
            for j in range(i - 1, -1, -1):
                current_sum = sum(relicValues[j:i])
                if current_sum >= dp_sum[j]:
                    dp_sum[i] = current_sum
                    dp_count[i] = dp_count[j] + 1
                    break

        return n - dp_count[n]

