func computeMinEnergy(devices []int) int {
    n := len(devices)
    memo := make(map[string]int)

    var dp func([]int) int
    dp = func(arr []int) int {
        if len(arr) == 0 {
            return 0
        }

        if len(arr) <= 2 {
            maxVal := arr[0]
            for _, v := range arr {
                if v > maxVal {
                    maxVal = v
                }
            }
            return maxVal
        }

        key := ""
        for i, v := range arr {
            if i > 0 {
                key += ","
            }
            key += fmt.Sprintf("%d", v)
        }

        if val, ok := memo[key]; ok {
            return val
        }

        minCost := math.MaxInt32

        limit := 3
        if len(arr) < 3 {
            limit = len(arr)
        }

        for i := 0; i < limit; i++ {
            for j := i + 1; j < limit; j++ {
                cost := arr[i]
                if arr[j] > cost {
                    cost = arr[j]
                }

                newArr := make([]int, 0, len(arr)-2)
                for k := 0; k < len(arr); k++ {
                    if k != i && k != j {
                        newArr = append(newArr, arr[k])
                    }
                }

                totalCost := cost + dp(newArr)
                if totalCost < minCost {
                    minCost = totalCost
                }
            }
        }

        memo[key] = minCost
        return minCost
    }

    return dp(devices)
}

