public class Solution {

    public int computeMinEnergy(int[] devices) {
        int n = devices.length;
        if (n <= 2) {
            int max = 0;
            for (int d : devices) {
                max = Math.max(max, d);
            }
            return max;
        }

        int[][] memo = new int[n + 1][n + 1];
        for (int[] row : memo) {
            Arrays.fill(row, -1);
        }
        return solve(devices, 0, n, memo);
    }

    private int solve(int[] devices, int start, int end, int[][] memo) {
        int len = end - start;

        if (len == 0) return 0;
        if (len <= 2) {
            int max = 0;
            for (int i = start; i < end; i++) {
                max = Math.max(max, devices[i]);
            }
            return max;
        }

        if (memo[start][end] != -1) {
            return memo[start][end];
        }

        int minCost = Integer.MAX_VALUE;

        int limit = Math.min(3, len);
        for (int i = 0; i < limit; i++) {
            for (int j = i + 1; j < limit; j++) {
                int cost = Math.max(devices[start + i], devices[start + j]);

                int[] remaining = new int[len - 2];
                int idx = 0;
                for (int k = 0; k < len; k++) {
                    if (k != i && k != j) {
                        remaining[idx++] = devices[start + k];
                    }
                }

                int remainingCost = computeMinEnergyHelper(remaining);
                minCost = Math.min(minCost, cost + remainingCost);
            }
        }

        memo[start][end] = minCost;
        return minCost;
    }

    private int computeMinEnergyHelper(int[] devices) {
        int n = devices.length;
        if (n == 0) return 0;
        if (n <= 2) {
            int max = 0;
            for (int d : devices) {
                max = Math.max(max, d);
            }
            return max;
        }

        return solveHelper(devices);
    }

    private int solveHelper(int[] devices) {
        int n = devices.length;
        if (n == 0) return 0;
        if (n <= 2) {
            int max = 0;
            for (int d : devices) {
                max = Math.max(max, d);
            }
            return max;
        }

        int minCost = Integer.MAX_VALUE;

        int limit = Math.min(3, n);
        for (int i = 0; i < limit; i++) {
            for (int j = i + 1; j < limit; j++) {
                int cost = Math.max(devices[i], devices[j]);

                int[] remaining = new int[n - 2];
                int idx = 0;
                for (int k = 0; k < n; k++) {
                    if (k != i && k != j) {
                        remaining[idx++] = devices[k];
                    }
                }

                int remainingCost = solveHelper(remaining);
                minCost = Math.min(minCost, cost + remainingCost);
            }
        }

        return minCost;
    }

