using namespace std;

class Solution {
public:
    int computeMinEnergy(vector<int>& devices) {
        int n = devices.size();
        if (n == 0) return 0;
        if (n <= 2) {
            int mx = 0;
            for (int x : devices) mx = max(mx, x);
            return mx;
        }

        map<pair<int, int>, int> memo;
        return solve(0, 1, 2, devices, memo);
    }

private:
    int solve(int i, int j, int k, const vector<int>& devices, map<pair<int, int>, int>& memo) {
        int n = devices.size();
        int next_idx = max({i, j, k}) + 1;

        if (next_idx >= n) {
            return max(devices[i], devices[j]);
        }

        vector<int> current = {i, j, k};
        sort(current.begin(), current.end());
        pair<int, int> state = {current[0], current[1]};
        if (memo.count(state)) return memo[state];

        int res1 = max(devices[i], devices[j]) + solve(k, next_idx, next_idx + 1 >= n ? -1 : next_idx + 1, devices, memo);
        int res2 = max(devices[i], devices[k]) + solve(j, next_idx, next_idx + 1 >= n ? -1 : next_idx + 1, devices, memo);
        int res3 = max(devices[j], devices[k]) + solve(i, next_idx, next_idx + 1 >= n ? -1 : next_idx + 1, devices, memo);

        return memo[state] = min({res1, res2, res3});
    }

    int solve(int i, int next_ptr, int next_ptr2, const vector<int>& devices, map<pair<int, int>, int>& memo) {
        int n = devices.size();
        if (next_ptr >= n) return devices[i];
        if (next_ptr2 == -1 || next_ptr2 >= n) return max(devices[i], devices[next_ptr]);

        pair<int, int> state = {min(i, next_ptr), max(i, next_ptr)};
        if (memo.count(state)) return memo[state];

        int j = next_ptr;
        int k = next_ptr2;
        int nxt = k + 1;

        int res1 = max(devices[i], devices[j]) + (nxt < n ? solve(k, nxt, nxt + 1 < n ? nxt + 1 : -1, devices, memo) : devices[k]);
        int res2 = max(devices[i], devices[k]) + (nxt < n ? solve(j, nxt, nxt + 1 < n ? nxt + 1 : -1, devices, memo) : devices[j]);
        int res3 = max(devices[j], devices[k]) + (nxt < n ? solve(i, nxt, nxt + 1 < n ? nxt + 1 : -1, devices, memo) : devices[i]);

        return memo[state] = min({res1, res2, res3});
    }
};

