func max(a, b int) int {
	if a > b {
		return a
	}
	return b
}

func min(a, b int) int {
	if a < b {
		return a
	}
	return b
}

func solve() {
	var n int
	var devices []int
	for {
		var val int
		_, err := fmt.Scan(&val)
		if err == io.EOF {
			break
		}
		devices = append(devices, val)
	}
	n = len(devices)

	if n == 0 {
		fmt.Println(0)
		return
	}

	memo := make(map[[2]int]int)

	var dp func(idx int, carry int) int
	dp = func(idx int, carry int) int {
		if idx == n {
			return carry
		}
		state := [2]int{idx, carry}
		if val, ok := memo[state]; ok {
			return val
		}

		remaining := n - idx
		if remaining == 1 {
			return max(carry, devices[idx])
		}
		if remaining == 2 {
			res := max(carry, max(devices[idx], devices[idx+1]))
			memo[state] = res
			return res
		}

		v1, v2, v3 := carry, devices[idx], devices[idx+1]

		res1 := max(v1, v2) + dp(idx+2, v3)
		res2 := max(v1, v3) + dp(idx+2, v2)
		res3 := max(v2, v3) + dp(idx+2, v1)

		ans := min(res1, min(res2, res3))
		memo[state] = ans
		return ans
	}

	fmt.Println(dp(1, devices[0]))
}

