import java.util.*;

public class Solution {
    private int[][] memo;
    private int[] devices;
    private int n;

    public int computeMinEnergy(int[] devices) {
        this.devices = devices;
        this.n = devices.length;
        this.memo = new int[n + 1][n + 1];
        for (int[] row : memo) {
            Arrays.fill(row, -1);
        }
        return solve(0, -1);
    }

    private int solve(int index, int carryIdx) {
        int currentCount = (n - index) + (carryIdx == -1 ? 0 : 1);

        if (currentCount <= 2) {
            if (currentCount == 0) return 0;
            if (currentCount == 1) {
                return carryIdx == -1 ? devices[index] : devices[carryIdx];
            }
            if (currentCount == 2) {
                if (carryIdx == -1) return Math.max(devices[index], devices[index + 1]);
                return Math.max(devices[carryIdx], devices[index]);
            }
        }

        if (carryIdx != -1 && memo[index][carryIdx] != -1) {
            return memo[index][carryIdx];
        }
        if (carryIdx == -1 && memo[index][n] != -1) {
            return memo[index][n];
        }

        int res = Integer.MAX_VALUE;

        if (carryIdx == -1) {
            int c1 = Math.max(devices[index], devices[index + 1]) + solve(index + 2, index + 2 >= n ? -1 : index + 2);
            int c2 = Math.max(devices[index], devices[index + 2]) + solve(index + 3, index + 1);
            int c3 = Math.max(devices[index + 1], devices[index + 2]) + solve(index + 3, index);
            res = Math.min(c1, Math.min(c2, c3));
        } else {
            int c1 = Math.max(devices[carryIdx], devices[index]) + solve(index + 1, index + 1 >= n ? -1 : index + 1);
            int c2 = Math.max(devices[carryIdx], devices[index + 1]) + solve(index + 2, index);
            int c3 = Math.max(devices[index], devices[index + 1]) + solve(index + 2, carryIdx);
            res = Math.min(c1, Math.min(c2, c3));
        }

        if (carryIdx != -1) memo[index][carryIdx] = res;
        else memo[index][n] = res;

        return res;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        String line = sc.nextLine().replaceAll("[\\[\\]]", "");
        if (line.trim().isEmpty()) {
            return;
        }
        String[] parts = line.split(",");
        int[] devices = new int[parts.length];
        for (int i = 0; i < parts.length; i++) {
            devices[i] = Integer.parseInt(parts[i].trim());
        }
        System.out.println(new Solution().computeMinEnergy(devices));
    }
