func assembleEngine(components []int, torque int, safetyLimit int) int {
    n := len(components)

    type State struct {
        balance int
        product int
    }

    states := make(map[int]map[int]bool)
    states[0] = make(map[int]bool)
    states[0][1] = true

    maxProduct := -1

    for i := 0; i < n; i++ {
        newStates := make(map[int]map[int]bool)

        for balance, products := range states {
            if newStates[balance] == nil {
                newStates[balance] = make(map[int]bool)
            }
            for product := range products {
                newStates[balance][product] = true
            }
        }

        for balance, products := range states {
            for product := range products {
                evenIndexInSubseq := (countBits(product) - 1) % 2 == 0

                var newBalance int
                if evenIndexInSubseq {
                    newBalance = balance + components[i]
                } else {
                    newBalance = balance - components[i]
                }

                newProduct := product * max(1, components[i])
                if components[i] == 0 {
                    newProduct = 0
                }

                if newProduct <= safetyLimit {
                    if newStates[newBalance] == nil {
                        newStates[newBalance] = make(map[int]bool)
                    }
                    newStates[newBalance][newProduct] = true

                    if newBalance == torque {
                        maxProduct = max(maxProduct, newProduct)
                    }
                }
            }
        }

        states = newStates
    }

    return maxProduct
}

func countBits(n int) int {
    count := 0
    for n > 0 {
        count++
        n /= 10
    }
    return count
}

func assembleEngineCorrect(components []int, torque int, safetyLimit int) int {
    n := len(components)

    dp := make(map[string]int)

    var dfs func(idx int, balance int, length int) int
    dfs = func(idx int, balance int, length int) int {
        if idx == n {
            if length > 0 && balance == torque {
                return 1
            }
            return -1
        }

        key := fmt.Sprintf("%d,%d,%d", idx, balance, length)
        if val, exists := dp[key]; exists {
            return val
        }

        result := dfs(idx+1, balance, length)

        posInSubseq := length
        var newBalance int
        if posInSubseq%2 == 0 {
            newBalance = balance + components[idx]
        } else {
            newBalance = balance - components[idx]
        }

        takeResult := dfs(idx+1, newBalance, length+1)

        if takeResult != -1 {
            newProduct := takeResult * max(1, components[idx])
            if components[idx] == 0 {
                newProduct = 0
            }
            if newProduct <= safetyLimit {
                if result == -1 {
                    result = newProduct
                } else {
                    result = max(result, newProduct)
                }
            }
        }

        dp[key] = result
        return result
    }

    return dfs(0, 0, 0)
}

