        dp.put(0, 1L);

        for (int i = 0; i < n; i++) {
            int num = components[i];
            Map<Integer, Long> newDp = new HashMap<>();

            for (Map.Entry<Integer, Long> entry : dp.entrySet()) {
                int balance = entry.getKey();
                long product = entry.getValue();

                if (!newDp.containsKey(balance) || newDp.get(balance) < product) {
                    newDp.put(balance, product);
                }

                int newBalanceEven = balance + num;
                long newProductEven = product * num;
                if (newProductEven <= safetyLimit) {
                    if (!newDp.containsKey(newBalanceEven) || newDp.get(newBalanceEven) < newProductEven) {
                        newDp.put(newBalanceEven, newProductEven);
                    }
                }

                int newBalanceOdd = balance - num;
                long newProductOdd = product * num;
                if (newProductOdd <= safetyLimit) {
                    if (!newDp.containsKey(newBalanceOdd) || newDp.get(newBalanceOdd) < newProductOdd) {
                        newDp.put(newBalanceOdd, newProductOdd);
