class EngineAssembler {
public:
    int assembleEngine(vector<int>& components, int torque, int safetyLimit) {
        int n = components.size();
        int max_sum = 0;
        for (int x : components) if (x > 0) max_sum += x;
        int min_sum = -max_sum;

        if (torque > max_sum || torque < min_sum) return -1;

        int offset = max_sum;
        int range = 2 * max_sum + 1;

        vector<vector<int>> dp_even(range, vector<int>(safetyLimit + 1, -1));
        vector<vector<int>> dp_odd(range, vector<int>(safetyLimit + 1, -1));

        for (int i = 0; i < n; ++i) {
            int val = components[i];
            vector<vector<int>> next_even = dp_even;
            vector<vector<int>> next_odd = dp_odd;

            int start_prod = (val <= safetyLimit) ? val : -1;
            if (start_prod != -1) {
                next_even[val + offset][start_prod] = 1;
            }

            for (int b = 0; b < range; ++b) {
                for (int p = 0; p <= safetyLimit; ++p) {
                    if (dp_even[b][p] != -1) {
                        int nb = b - val;
                        long long np = (long long)p * val;
                        if (nb >= 0 && nb < range && np <= safetyLimit) {
                            next_odd[nb][(int)np] = 1;
                        }
                    }
                    if (dp_odd[b][p] != -1) {
                        int nb = b + val;
                        long long np = (long long)p * val;
                        if (nb >= 0 && nb < range && np <= safetyLimit) {
                            next_even[nb][(int)np] = 1;
                        }
                    }
                }
            }
            dp_even = move(next_even);
            dp_odd = move(next_odd);
        }

        int max_prod = -1;
        int target_idx = torque + offset;
        if (target_idx >= 0 && target_idx < range) {
            for (int p = 0; p <= safetyLimit; ++p) {
                if (dp_even[target_idx][p] != -1 || dp_odd[target_idx][p] != -1) {
                    max_prod = max(max_prod, p);
                }
            }
        }

        return max_prod;
    }
};

