class EngineAssembler {
    public int assembleEngine(int[] components, int torque, int safetyLimit) {
        int n = components.length;
        int maxPossibleTorque = 0;
        int minPossibleTorque = 0;
        for (int x : components) {
            if (x > 0) maxPossibleTorque += x;
            else minPossibleTorque += x;
        }

        if (torque > n * 12 || torque < -n * 12) return -1;

        int offset = n * 12;
        boolean[][][] dp = new boolean[n + 1][2 * offset + 1][safetyLimit + 1];

        for (int i = 0; i < n; i++) {
            int val = components[i];

            for (int t = 0; t <= 2 * offset; t++) {
                for (int p = 0; p <= safetyLimit; p++) {
                    if (dp[i][t][p]) {
                        dp[i+1][t][p] = true;
                    }
                }
            }

            int tStart = val + offset;
            if (tStart >= 0 && tStart <= 2 * offset && val <= safetyLimit) {
                dp[i+1][tStart][val] = true;
            }

            for (int t = 0; t <= 2 * offset; t++) {
                for (int p = 1; p <= safetyLimit; p++) {
                    if (dp[i][t][p]) {
                        int nextTPlus = t + val;
                        long nextPPlus = (long) p * val;
                        if (nextTPlus >= 0 && nextTPlus <= 2 * offset && nextPPlus <= safetyLimit) {
                            dp[i+1][nextTPlus][(int)nextPPlus] = true;
                        }

                        int nextTMinus = t - val;
                        long nextPMinus = (long) p * val;
                        if (nextTMinus >= 0 && nextTMinus <= 2 * offset && nextPMinus <= safetyLimit) {
                            dp[i+1][nextTMinus][(int)nextPMinus] = true;
                        }
                    }
                }
            }
        }

        int targetT = torque + offset;
        if (targetT < 0 || targetT > 2 * offset) return -1;

        for (int p = safetyLimit; p >= 0; p--) {
            if (dp[n][targetT][p]) return p;
        }

        return -1;
    }
