        Integer[] gemsBoxed = new Integer[n];
        for (int i = 0; i < n; i++) {
            gemsBoxed[i] = gems[i];
        }
        Arrays.sort(gemsBoxed, Collections.reverseOrder());

        long totalPower = 0;
        int numRituals = n / 4;

        for (int day = 1; day <= numRituals; day++) {
            int startIdx = (day - 1) * 4;
            int[] group = new int[4];
            for (int i = 0; i < 4; i++) {
                group[i] = gemsBoxed[startIdx + i];
            }
            Arrays.sort(group);

            if (day % 2 == 1) {
                totalPower += group[3];
            } else {
                totalPower += group[2];
            }
        }

        return totalPower;
    }

