int n, k;

int toPerimeter(int x, int y) {
    if (x == 0 && y >= 0 && y <= edgeLength) return y;
    if (y == edgeLength && x >= 0 && x <= edgeLength) return edgeLength + x;
    if (x == edgeLength && y >= 0 && y <= edgeLength) return 2 * edgeLength + (edgeLength - y);
    if (y == 0 && x >= 0 && x <= edgeLength) return 3 * edgeLength + (edgeLength - x);
    return -1;
}

int perimeterDist(int p1, int p2) {
    int totalPerim = 4 * edgeLength;
    int d = abs(p1 - p2);
    return min(d, totalPerim - d);
}

int manhattanDist(pair<int, int> s1, pair<int, int> s2) {
    return abs(s1.first - s2.first) + abs(s1.second - s2.second);
}

bool canSelect(int minDist, vector<int>& perims) {
    int m = perims.size();
    vector<int> dp(1 << m, 0);
    dp[0] = 1;

    for (int mask = 0; mask < (1 << m); mask++) {
        if (!dp[mask]) continue;
        int cnt = __builtin_popcount(mask);
        if (cnt == k) return true;

        for (int i = 0; i < m; i++) {
            if (mask & (1 << i)) continue;

            bool valid = true;
            for (int j = 0; j < m; j++) {
                if (!(mask & (1 << j))) continue;
                int pd = perimeterDist(perims[i], perims[j]);
                int md = manhattanDist(sensors[i], sensors[j]);
                int actualDist = min(pd, md);
                if (actualDist < minDist) {
                    valid = false;
                    break;
                }
            }

            if (valid) {
                dp[mask | (1 << i)] = 1;
            }
        }
    }

    return false;
}

