    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            int pd = perimeterDist(perims[i], perims[j]);
            int md = manhattanDist(sensors[i], sensors[j]);
            allDists.insert(min(pd, md));
        }
    }

