func optimalSensorSpacing(edgeLength int, sensorList [][]int, selectionCount int) int {
    n := len(sensorList)

    distances := make([]int, n)
    for i := 0; i < n; i++ {
        distances[i] = getPerimeterDistance(sensorList[i][0], sensorList[i][1], edgeLength)
    }

    sort.Ints(distances)

    perimeter := 4 * edgeLength

    left, right := 0, perimeter/selectionCount
    answer := 0

    for left <= right {
        mid := (left + right) / 2
        if canSelect(distances, selectionCount, mid, perimeter) {
            answer = mid
            left = mid + 1
        } else {
            right = mid - 1
        }
    }

    return answer
}

func getPerimeterDistance(x, y, edgeLength int) int {
    if x == 0 && y >= 0 && y <= edgeLength {
        return y
    }
    if y == edgeLength && x >= 0 && x <= edgeLength {
        return edgeLength + x
    }
    if x == edgeLength && y >= 0 && y <= edgeLength {
        return 2*edgeLength + (edgeLength - y)
    }
    if y == 0 && x >= 0 && x <= edgeLength {
        return 3*edgeLength + (edgeLength - x)
    }
    return 0
}

func canSelect(distances []int, k int, minDist int, perimeter int) bool {
    n := len(distances)

    for start := 0; start < n; start++ {
        count := 1
        lastSelected := distances[start]

        for i := 1; i < n; i++ {
            idx := (start + i) % n

            var dist int
            if idx > start || (idx < start && start == 0) {
                if distances[idx] >= lastSelected {
                    dist = distances[idx] - lastSelected
                } else {
                    dist = perimeter - lastSelected + distances[idx]
                }
            } else {
                dist = perimeter - lastSelected + distances[idx]
            }

            if dist >= minDist {
                count++
                lastSelected = distances[idx]
                if count >= k {
                    firstDist := 0
                    if distances[start] >= distances[idx] {
                        firstDist = distances[start] - distances[idx]
                    } else {
                        firstDist = perimeter - distances[idx] + distances[start]
                    }
                    if firstDist >= minDist {
                        return true
                    }
                    break
                }
            }
        }
    }

    for start := 0; start < n; start++ {
        count := 1
        lastPos := distances[start]

        for i := start + 1; i < start + n; i++ {
            idx := i % n
            currentPos := distances[idx]
            if idx <= start {
                currentPos += perimeter
            }

            if currentPos - lastPos >= minDist {
                count++
                lastPos = currentPos
                if count == k {
                    return true
                }
            }
        }
    }

    return false
}

