public class Solution {

    public int optimalSensorSpacing(int edgeLength, int[][] sensorList, int selectionCount) {
        int n = sensorList.length;
        int[] positions = new int[n];

        for (int i = 0; i < n; i++) {
            positions[i] = coordToPerimeter(sensorList[i][0], sensorList[i][1], edgeLength);
        }

        Arrays.sort(positions);

        int left = 0;
        int right = 4 * edgeLength;
        int result = 0;

        while (left <= right) {
            int mid = left + (right - left) / 2;
            if (canSelect(positions, selectionCount, mid, edgeLength)) {
                result = mid;
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }

        return result;
    }

    private int coordToPerimeter(int x, int y, int edgeLength) {
        if (x == 0 && y >= 0 && y <= edgeLength) {
            return y;
        } else if (y == edgeLength && x >= 0 && x <= edgeLength) {
            return edgeLength + x;
        } else if (x == edgeLength && y >= 0 && y <= edgeLength) {
            return 2 * edgeLength + (edgeLength - y);
        } else {
            return 3 * edgeLength + (edgeLength - x);
        }
    }

    private boolean canSelect(int[] positions, int selectionCount, int minDist, int edgeLength) {
        int n = positions.length;
        int perimeter = 4 * edgeLength;

        for (int start = 0; start < n; start++) {
            int count = 1;
            int lastPos = positions[start];

            for (int i = 1; i < n; i++) {
                int idx = (start + i) % n;
                int currentPos = positions[idx];

                int dist;
                if (currentPos >= lastPos) {
                    dist = Math.min(currentPos - lastPos, lastPos + perimeter - currentPos);
                } else {
                    dist = Math.min(lastPos - currentPos, currentPos + perimeter - lastPos);
                }

                if (dist >= minDist) {
                    count++;
                    lastPos = currentPos;
                    if (count >= selectionCount) {
                        return true;
                    }
                }
            }
        }

        return false;
    }

