class Solution:
    def optimalSensorSpacing(self, edgeLength: int, sensorList: List[List[int]], selectionCount: int) -> int:
        def position_on_perimeter(x, y):
            if x == 0 and y >= 0 and y <= edgeLength:
                return y
            elif y == edgeLength and x > 0 and x <= edgeLength:
                return edgeLength + x
            elif x == edgeLength and y < edgeLength and y >= 0:
                return 2 * edgeLength + (edgeLength - y)
            elif y == 0 and x < edgeLength and x >= 0:
                return 3 * edgeLength + (edgeLength - x)
            return 0

        positions = []
        for x, y in sensorList:
            pos = position_on_perimeter(x, y)
            positions.append(pos)

        positions.sort()
        n = len(positions)
        perimeter = 4 * edgeLength

        def can_select(min_dist):
            for start_idx in range(n):
                count = 1
                last_pos = positions[start_idx]

                for i in range(1, n):
                    idx = (start_idx + i) % n
                    current_pos = positions[idx]

                    if idx > start_idx:
                        dist = current_pos - last_pos
                    else:
                        dist = (perimeter - last_pos) + current_pos

                    if dist >= min_dist:
                        count += 1
                        last_pos = current_pos
                        if count >= selectionCount:
                            return True

            return False

        left, right = 0, perimeter
        result = 0

        while left <= right:
            mid = (left + right)
            if can_select(mid):
                result = mid
                left = mid + 1
            else:
                right = mid - 1

        return result

