bool check(int k, int target, int selectionCount, const vector<Point>& sensors, vector<int>& selected) {
    if (selected.size() == selectionCount) {
        return true;
    }
    if (k == sensors.size()) {
        return false;
    }
    if (sensors.size() - k < selectionCount - selected.size()) {
        return false;
    }

    bool possible = true;
    for (int idx : selected) {
        if (manhattan(sensors[k], sensors[idx]) < target) {
            possible = false;
            break;
        }
    }

    if (possible) {
        selected.push_back(k);
        if (check(k + 1, target, selectionCount, sensors, selected)) return true;
        selected.pop_back();
    }

    if (check(k + 1, target, selectionCount, sensors, selected)) return true;

    return false;
}

