    public static int solve(int edgeLength, int[][] sensors, int selectionCount) {
        long perimeter = 4L * edgeLength;
        long[] pos = new long[sensors.length];
        for (int i = 0; i < sensors.length; i++) {
            int x = sensors[i][0];
            int y = sensors[i][1];
            if (y == 0) pos[i] = x;
            else if (x == edgeLength) pos[i] = edgeLength + y;
            else if (y == edgeLength) pos[i] = 2L * edgeLength + (edgeLength - x);
            else pos[i] = 3L * edgeLength + (edgeLength - y);
        }
        Arrays.sort(pos);
        int low = 1, high = 2 * edgeLength, ans = 0;
        while (low <= high) {
            int mid = low + (high - low) / 2;
            if (check(mid, pos, perimeter, selectionCount, sensors, edgeLength)) {
                ans = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        return ans;
    }

    private static boolean check(int d, long[] pos, long perimeter, int k, int[][] sensors, int edgeLength) {
        int n = pos.length;
        for (int i = 0; i < n; i++) {
            int count = 1;
            long lastPos = pos[i];
            for (int j = 1; j < n; j++) {
                long currentPos = pos[(i + j) % n];
                long distAlong;
                if (currentPos >= lastPos) distAlong = currentPos - lastPos;
                else distAlong = (perimeter - lastPos) + currentPos;

                if (distAlong >= d) {
                    if (manhattan(lastPos, currentPos, edgeLength) >= d) {
                        lastPos = currentPos;
                        count++;
                        if (count >= k) {
                            if (manhattan(lastPos, pos[i], edgeLength) >= d) return true;
                            else break;
                        }
                    }
                }
            }
        }
        return false;
    }

    private static int manhattan(long p1, long p2, int L) {
        int[] c1 = getCoord(p1, L);
        int[] c2 = getCoord(p2, L);
        return Math.abs(c1[0] - c2[0]) + Math.abs(c1[1] - c2[1]);
    }

    private static int[] getCoord(long p, int L) {
        if (p <= L) return new int[]{(int) p, 0};
        if (p <= 2L * L) return new int[]{L, (int) (p - L)};
        if (p <= 3L * L) return new int[]{(int) (3L * L - p), L};
        return new int[]{0, (int) (4L * L - p)};
    }
}

