long long factorial(int n) {
    if (n > 20) return 1e18;
    long long result = 1;
    for (int i = 2; i <= n; i++) {
        result *= i;
        if (result > 1e15) return 1e18;
    }
    return result;
}

vector<int> solve(int n, long long k) {
    vector<int> odds, evens;
    for (int i = 1; i <= n; i++) {
        if (i % 2 == 1) odds.push_back(i);
        else evens.push_back(i);
    }

    int numOdds = odds.size();
    int numEvens = evens.size();

    long long oddFact = factorial(numOdds);
    long long evenFact = factorial(numEvens);

    long long totalValid;
    if (abs(numOdds - numEvens) > 1) {
        return {};
    }

    if (numOdds == numEvens) {
        totalValid = oddFact * evenFact * 2;
        if (totalValid > 1e15) totalValid = 1e18;
    } else {
        totalValid = oddFact * evenFact;
        if (totalValid > 1e15) totalValid = 1e18;
    }

    if (k > totalValid) return {};

    vector<int> result;
    vector<int> availableOdds = odds;
    vector<int> availableEvens = evens;

    bool startWithOdd;
    long long permsStartingWithOdd;

    if (numOdds > numEvens) {
        startWithOdd = true;
    } else if (numEvens > numOdds) {
        startWithOdd = false;
    } else {
        permsStartingWithOdd = oddFact * evenFact;
        if (permsStartingWithOdd > 1e15) permsStartingWithOdd = 1e18;
        if (k <= permsStartingWithOdd) {
            startWithOdd = true;
        } else {
            startWithOdd = false;
            k -= permsStartingWithOdd;
        }
    }

    bool pickOdd = startWithOdd;

    for (int pos = 0; pos < n; pos++) {
        vector<int>& available = pickOdd ? availableOdds : availableEvens;

        int remainingOdds = availableOdds.size() - (pickOdd ? 1 : 0);
        int remainingEvens = availableEvens.size() - (pickOdd ? 0 : 1);

        for (int i = 0; i < available.size(); i++) {
            long long permsWithThis;
            if (pickOdd) {
                permsWithThis = factorial(remainingOdds) * factorial(remainingEvens);
            } else {
                permsWithThis = factorial(remainingOdds) * factorial(remainingEvens);
            }
            if (permsWithThis > 1e15) permsWithThis = 1e18;

            if (k <= permsWithThis) {
                result.push_back(available[i]);
                available.erase(available.begin() + i);
                break;
            } else {
                k -= permsWithThis;
            }
        }

        pickOdd = !pickOdd;
    }

    return result;
}

