public class Solution {

    public List<Integer> arrangeTunes(int n, int k) {
        int oddCount = (n + 1) / 2;
        int evenCount = n / 2;

        long totalStartingOdd = factorial(oddCount) * factorial(evenCount);
        long totalStartingEven = factorial(evenCount) * factorial(oddCount);

        if (oddCount > evenCount) {
            totalStartingEven = 0;
        } else if (evenCount > oddCount) {
            totalStartingOdd = 0;
        }

        long total = totalStartingOdd + totalStartingEven;

        if (k > total) {
            return new ArrayList<>();
        }

        List<Integer> odds = new ArrayList<>();
        List<Integer> evens = new ArrayList<>();

        for (int i = 1; i <= n; i++) {
            if (i % 2 == 1) {
                odds.add(i);
            } else {
                evens.add(i);
            }
        }

        boolean startWithOdd;
        long kAdjusted;

        if (k <= totalStartingOdd) {
            startWithOdd = true;
            kAdjusted = k;
        } else {
            startWithOdd = false;
            kAdjusted = k - totalStartingOdd;
        }

        List<Integer> first = startWithOdd ? odds : evens;
        List<Integer> second = startWithOdd ? evens : odds;

        List<Integer> firstPerm = getKthPermutation(first, kAdjusted);
        List<Integer> secondPerm = getKthPermutation(second, (kAdjusted - 1) / factorial(first.size()) + 1);

        kAdjusted = (kAdjusted - 1) % factorial(first.size()) + 1;
        firstPerm = getKthPermutation(first, kAdjusted);

        long firstPerms = factorial(first.size());
        long qIndex = (k - (startWithOdd ? 0 : totalStartingOdd) - 1) / firstPerms;
        long rIndex = (k - (startWithOdd ? 0 : totalStartingOdd) - 1) % firstPerms;

        firstPerm = getKthPermutation(first, rIndex + 1);
        secondPerm = getKthPermutation(second, qIndex + 1);

        List<Integer> result = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            if (i % 2 == 0) {
                result.add(firstPerm.get(i / 2));
            } else {
                result.add(secondPerm.get(i / 2));
            }
        }

        return result;
    }

    private long factorial(int n) {
        if (n > 20) return Long.MAX_VALUE;
        long result = 1;
        for (int i = 2; i <= n; i++) {
            result *= i;
        }
        return result;
    }

    private List<Integer> getKthPermutation(List<Integer> items, long k) {
        List<Integer> available = new ArrayList<>(items);
        List<Integer> result = new ArrayList<>();
        k--;

        for (int i = items.size(); i > 0; i--) {
            long fact = factorial(i - 1);
            int index = (int)(k / fact);
            result.add(available.get(index));
            available.remove(index);
            k %= fact;
        }

        return result;
    }

