    }

    int128 total_ways = 0;
    if (abs((int)odd.size() - (int)even.size()) <= 1) {
        if (odd.size() == even.size()) {
            total_ways = factorial(odd.size()) * factorial(even.size()) * 2;
        } else {
            total_ways = factorial(odd.size()) * factorial(even.size());
        }
    }

    if (k > total_ways) {
        cout << "[]" << endl;
        return 0;
    }

    vector<int> result;
    vector<bool> used(n + 1, false);
    int last_parity = -1; 

    for (int i = 0; i < n; ++i) {
        for (int val = 1; val <= n; ++val) {
            if (used[val]) continue;
            int current_parity = val % 2;
            if (last_parity != -1 && current_parity == last_parity) continue;

            int rem_odd = 0, rem_even = 0;
            for (int v = 1; v <= n; ++v) {
                if (!used[v] && v != val) {
                    if (v % 2 != 0) rem_odd++;
                    else rem_even++;
                }
            }

            int128 ways = 0;
            if (i == n - 1) {
                ways = 1;
            } else {
                int next_parity = 1 - current_parity;
                int pos_left = n - 1 - i;
                int req_next = (pos_left + 1) / 2;
                int req_other = pos_left / 2;

                if (next_parity == 1) {
                    if (rem_odd == req_next && rem_even == req_other) {
