import math

class Solution:
    def arrange_tunes(self, n, k):
        odds = [i for i in range(1, n + 1) if i % 2 != 0]
        evens = [i for i in range(1, n + 1) if i % 2 == 0]

        memo = {}

        def count_ways(o_count, e_count, last_was_odd):
            state = (o_count, e_count, last_was_odd)
            if state in memo:
                return memo[state]

            if o_count == 0 and e_count == 0:
                return 1

            res = 0
            if last_was_odd:
                if e_count > 0:
                    res = math.factorial(e_count) * math.factorial(o_count)
                else:
                    res = 0
            else:
                if o_count > 0:
                    res = math.factorial(o_count) * math.factorial(e_count)
                else:
                    res = 0

            memo[state] = res
            return res

        def get_total(o_rem, e_rem, last_was_odd):
            if o_rem == 0 and e_rem == 0:
                return 1
            if last_was_odd is None:
                return (count_ways(o_rem, e_rem, False) if o_rem > 0 else 0) + \
                       (count_ways(o_rem, e_rem, True) if e_rem > 0 else 0)
            if last_was_odd:
                if e_rem == 0: return 0
                return math.factorial(o_rem) * math.factorial(e_rem)
            else:
                if o_rem == 0: return 0
                return math.factorial(o_rem) * math.factorial(e_rem)

        total_possible = get_total(len(odds), len(evens), None)
        if k > total_possible:
            return []

        result = []
        o_available = sorted(odds)
        e_available = sorted(evens)
        last_was_odd = None

        for i in range(n):
            found = False
            candidates = []
            if last_was_odd is None:
                candidates = sorted([(x, True) for x in o_available] + [(x, False) for x in e_available])
            elif last_was_odd:
                candidates = [(x, False) for x in e_available]
            else:
                candidates = [(x, True) for x in o_available]

            for val, is_odd in candidates:
                o_next = len(o_available) - (1 if is_odd else 0)
                e_next = len(e_available) - (1 if not is_odd else 0)
                ways = math.factorial(o_next) * math.factorial(e_next)

                if k <= ways:
                    result.append(val)
                    if is_odd:
