int longestCommonPrefix(const string& a, const string& b) {
    int len = 0;
    int minLen = min(a.length(), b.length());
    for (int i = 0; i < minLen; i++) {
        if (a[i] == b[i]) {
            len++;
        } else {
            break;
        }
    }
    return len;
}

int findMaxPrefixForGroup(vector<string>& remaining, int groupSize) {
    if (remaining.size() < groupSize) {
        return 0;
    }

    map<string, int> freq;
    for (const auto& s : remaining) {
        freq[s]++;
    }

    int maxPrefix = 0;

    for (auto& p : freq) {
        if (p.second >= groupSize) {
            maxPrefix = max(maxPrefix, (int)p.first.length());
        }
    }

    if (maxPrefix > 0) {
        return maxPrefix;
    }

    for (size_t i = 0; i < remaining.size(); i++) {
        for (size_t j = i + 1; j < remaining.size(); j++) {
            int lcp = longestCommonPrefix(remaining[i], remaining[j]);
            maxPrefix = max(maxPrefix, lcp);
        }
    }

    return maxPrefix;
}

vector<int> solve(vector<string>& codenames, int groupSize) {
    int n = codenames.size();
    vector<int> result(n);

    for (int i = 0; i < n; i++) {
        vector<string> remaining;
        for (int j = 0; j < n; j++) {
            if (j != i) {
                remaining.push_back(codenames[j]);
            }
        }
        result[i] = findMaxPrefixForGroup(remaining, groupSize);
    }

    return result;
}

