func longestCommonPrefix(s1, s2 string) int {
	minLen := len(s1)
	if len(s2) < minLen {
		minLen = len(s2)
	}
	for i := 0; i < minLen; i++ {
		if s1[i] != s2[i] {
			return i
		}
	}
	return minLen
}

func computeMaxPrefix(codenames []string, groupSize int) int {
	if len(codenames) < groupSize {
		return 0
	}

	countMap := make(map[string]int)
	for _, name := range codenames {
		countMap[name]++
	}

	maxPrefix := 0

	for name, count := range countMap {
		if count >= groupSize {
			maxPrefix = max(maxPrefix, len(name))
		}
	}

	uniqueNames := make([]string, 0, len(countMap))
	for name := range countMap {
		uniqueNames = append(uniqueNames, name)
	}

	if groupSize == 2 {
		for i := 0; i < len(uniqueNames); i++ {
			for j := i + 1; j < len(uniqueNames); j++ {
				prefix := longestCommonPrefix(uniqueNames[i], uniqueNames[j])
				maxPrefix = max(maxPrefix, prefix)
			}
		}
	} else {
		var dfs func(int, []string, int)
		dfs = func(start int, selected []string, need int) {
			if need == 0 {
				minPrefix := len(selected[0])
				for i := 1; i < len(selected); i++ {
					prefix := longestCommonPrefix(selected[0], selected[i])
					minPrefix = min(minPrefix, prefix)
				}
				maxPrefix = max(maxPrefix, minPrefix)
				return
			}

			for i := start; i < len(uniqueNames); i++ {
				dfs(i+1, append(selected, uniqueNames[i]), need-1)
			}
		}
		dfs(0, []string{}, groupSize)
	}

	return maxPrefix
}

func max(a, b int) int {
	if a > b {
		return a
	}
	return b
}

func min(a, b int) int {
	if a < b {
		return a
	}
	return b
}

func solve(codenames []string, groupSize int) []int {
	n := len(codenames)
	result := make([]int, n)

	for i := 0; i < n; i++ {
		remaining := make([]string, 0, n-1)
		for j := 0; j < n; j++ {
			if i != j {
				remaining = append(remaining, codenames[j])
			}
		}
		result[i] = computeMaxPrefix(remaining, groupSize)
	}

	return result
}

