        for (int i = 0; i < result.size(); i++) {
            if (i > 0) System.out.print(" ");
            System.out.print(result.get(i));
        }
        System.out.println();
    }

    public static List<Integer> determineCommonPrefix(String[] codenames, int groupSize) {
        List<Integer> result = new ArrayList<>();

        for (int i = 0; i < codenames.length; i++) {
            List<String> remaining = new ArrayList<>();
            for (int j = 0; j < codenames.length; j++) {
                if (i != j) {
                    remaining.add(codenames[j]);
                }
            }

            if (remaining.size() < groupSize) {
                result.add(0);
            } else {
                int maxLen = findMaxCommonPrefix(remaining, groupSize);
                result.add(maxLen);
            }
        }

        return result;
    }

    public static int findMaxCommonPrefix(List<String> codenames, int groupSize) {
        Map<String, List<Integer>> codenameMap = new HashMap<>();

        for (int i = 0; i < codenames.size(); i++) {
            String name = codenames.get(i);
            codenameMap.putIfAbsent(name, new ArrayList<>());
            codenameMap.get(name).add(i);
        }

        int maxLen = 0;

        for (Map.Entry<String, List<Integer>> entry : codenameMap.entrySet()) {
            if (entry.getValue().size() >= groupSize) {
                maxLen = Math.max(maxLen, entry.getKey().length());
            }
        }

        if (maxLen > 0) {
            return maxLen;
        }

        List<String> uniqueCodenames = new ArrayList<>(codenames);

        for (int prefixLen = getMaxPossiblePrefixLen(uniqueCodenames); prefixLen >= 1; prefixLen--) {
            Map<String, Integer> prefixCount = new HashMap<>();

            for (String name : uniqueCodenames) {
                if (name.length() >= prefixLen) {
                    String prefix = name.substring(0, prefixLen);
                    prefixCount.put(prefix, prefixCount.getOrDefault(prefix, 0) + 1);
                }
            }

            for (int count : prefixCount.values()) {
                if (count >= groupSize) {
                    return prefixLen;
                }
            }
        }

        return 0;
    }

    public static int getMaxPossiblePrefixLen(List<String> codenames) {
        int max = 0;
        for (String name : codenames) {
            max = Math.max(max, name.length());
        }
        return max;
    }
}

