struct TrieNode {
    map<char, int> children;
    vector<int> indices;
};

class ClandestineOperation {
public:
    vector<int> determineCommonPrefix(vector<string>& codenames, int groupSize) {
        int n = codenames.size();
        if (n < groupSize) return vector<int>(n, 0);

        vector<TrieNode> trie(1);
        for (int i = 0; i < n; ++i) {
            int curr = 0;
            for (char c : codenames[i]) {
                if (trie[curr].children.find(c) == trie[curr].children.end()) {
                    trie[curr].children[c] = trie.size();
                    trie.emplace_back();
                }
                curr = trie[curr].children[c];
                trie[curr].indices.push_back(i);
            }
        }

        vector<int> max_depth(n, 0);
        vector<pair<int, int>> stack;
        stack.push_back({0, 0});

        while (!stack.empty()) {
            pair<int, int> top = stack.back();
            stack.pop_back();
            int u = top.first;
            int depth = top.second;

            if (trie[u].indices.size() >= groupSize) {
                if (trie[u].indices.size() > groupSize) {
                    for (int idx : trie[u].indices) {
                        max_depth[idx] = max(max_depth[idx], depth);
                    }
                } else {
                    int excluded_idx = -1;
                    int count = 0;
                    for (int i = 0; i < n; ++i) {
                        bool found = false;
                        for(int idx : trie[u].indices) if(idx == i) found = true;
                        if(!found) {
                            max_depth[i] = max(max_depth[i], depth);
                        }
                    }
                }
            }

            for (auto const& [ch, v] : trie[u].children) {
                stack.push_back({v, depth + 1});
            }
        }

        vector<int> res(n, 0);
        for (int i = 0; i < n; ++i) {
            int current_max = 0;
            vector<int> depths(100001, 0);

            auto dfs = [&](auto self, int u, int depth, int skip) -> void {
                int count = 0;
                for(int idx : trie[u].indices) if(idx != skip) count++;

                if(count >= groupSize) {
                    current_max = max(current_max, depth);
                    for (auto const& [ch, v] : trie[u].children) {
                        self(self, v, depth + 1, skip);
                    }
                }
            };

            dfs(dfs, 0, 0, i);
            res[i] = current_max;
        }

        return res;
    }
};

