func countReplicas(recordedReadings []int, ranges [][2]int) int {
    n := len(recordedReadings)
    if n == 0 {
        return 0
    }

    diffs := make([]int, n-1)
    for i := 0; i < n-1; i++ {
        diffs[i] = recordedReadings[i+1] - recordedReadings[i]
    }

    minFirst := ranges[0][0]
    maxFirst := ranges[0][1]

    for i := 0; i < n-1; i++ {
        cumSum := 0
        for j := 0; j <= i; j++ {
            cumSum += diffs[j]
        }

        minVal := ranges[i+1][0] - cumSum
        maxVal := ranges[i+1][1] - cumSum

        if minVal > minFirst {
            minFirst = minVal
        }
        if maxVal < maxFirst {
            maxFirst = maxVal
        }
    }

    if minFirst > maxFirst {
        return 0
    }

    return maxFirst - minFirst + 1
}

import java.util.*;
