public class Solution {

    public int countReplicas(int[] recordedReadings, int[][] ranges) {
        int n = recordedReadings.length;

        int[] diffs = new int[n - 1];
        for (int i = 0; i < n - 1; i++) {
            diffs[i] = recordedReadings[i + 1] - recordedReadings[i];
        }

        long minFirst = ranges[0][0];
        long maxFirst = ranges[0][1];

        for (int i = 1; i < n; i++) {
            long sumDiff = 0;
            for (int j = 0; j < i; j++) {
                sumDiff += diffs[j];
            }

            long rangeMin = ranges[i][0];
            long rangeMax = ranges[i][1];

            long requiredMinFirst = rangeMin - sumDiff;
            long requiredMaxFirst = rangeMax - sumDiff;

            minFirst = Math.max(minFirst, requiredMinFirst);
            maxFirst = Math.min(maxFirst, requiredMaxFirst);

            if (minFirst > maxFirst) {
                return 0;
            }
        }

        return (int)(maxFirst - minFirst + 1);
    }

