        List<int[]> list = new ArrayList<>();
        int i = 0;
        while (i < s.length()) {
            if (s.charAt(i) == '[') {
                int j = i;
                while (s.charAt(j) != ']') j++;
                String sub = s.substring(i + 1, j);
                String[] parts = sub.split(",");
                list.add(new int[]{Integer.parseInt(parts[0].trim()), Integer.parseInt(parts[1].trim())});
                i = j + 1;
            } else {
                i++;
            }
        }
        return list.toArray(new int[0][0]);
    }
