public class Main {

    static int cyclicDistance(char a, char b) {
        int diff = Math.abs(a - b);
        return Math.min(diff, 26 - diff);
    }

    static int solve(String s, int k) {
        int n = s.length();
        int[][][] dp = new int[n][n][k + 1];

        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                Arrays.fill(dp[i][j], -1);
            }
        }

        return helper(s, 0, n - 1, k, dp);
    }

    static int helper(String s, int left, int right, int remainingK, int[][][] dp) {
        if (left > right) {
            return 0;
        }

        if (left == right) {
            return 1;
        }

        if (remainingK < 0) {
            return 0;
        }

        if (dp[left][right][remainingK] != -1) {
            return dp[left][right][remainingK];
        }

        int result = 0;

        int cost = cyclicDistance(s.charAt(left), s.charAt(right));
        if (cost <= remainingK) {
            result = 2 + helper(s, left + 1, right - 1, remainingK - cost, dp);
        }

        result = Math.max(result, helper(s, left + 1, right, remainingK, dp));
        result = Math.max(result, helper(s, left, right - 1, remainingK, dp));

        dp[left][right][remainingK] = result;
        return result;
    }

