            v1 = ord(c1) - ord('a')
            v2 = ord(c2) - ord('a')
            forward = (v2 - v1) % 26
            backward = (v1 - v2) % 26
            return min(forward, backward)

        memo = {}

        def dp(i, j, shifts):
            if i > j:
                return 0
            if i == j:
