                result = 2 + dp(i + 1, j - 1, shifts - cost)

            result = max(result, dp(i + 1, j, shifts))
            result = max(result, dp(i, j - 1, shifts))

            memo[(i, j, shifts)] = result
            return result

        return dp(0, n - 1, modifications)

