            for (int x : cards) {
                max_val = max(max_val, x);
            }
            return (long long)max_val;
        }

        long long max_sum = 0;
        long long current_sum = 0;
        int left = 0;
        unordered_map<int, int> counts;

        for (int right = 0; right < filtered.size(); ++right) {
            counts[filtered[right]]++;
            current_sum += filtered[right];
            while (counts[filtered[right]] > 1) {
                counts[filtered[left]]--;
                current_sum -= filtered[left];
                left++;
            }
            max_sum = max(max_sum, current_sum);
        }

        return max_sum;
    }
};

