func solve() {
	reader := bufio.NewReader(os.Stdin)
	var input []int
	for {
		line, err := reader.ReadString('\n')
		if err != nil && len(line) == 0 {
			break
		}
		nums := strings.Fields(line)
		for _, s := range nums {
			s = strings.Trim(s, "[],")
			if s == "" {
				continue
			}
			val, e := strconv.Atoi(s)
			if e == nil {
				input = append(input, val)
			}
		}
		if err == io.EOF {
			break
		}
	}

	if len(input) == 0 {
		return
	}

	positives := []int{}
	maxVal := input[0]
	hasPositive := false
	for _, x := range input {
		if x > 0 {
			positives = append(positives, x)
			hasPositive = true
		}
		if x > maxVal {
			maxVal = x
		}
	}

	if !hasPositive {
		fmt.Println(maxVal)
		return
	}

	ans := 0
	lastSeen := make(map[int]int)
	start := 0
	currentSum := 0
	for i, x := range positives {
		if prevIdx, ok := lastSeen[x]; ok && prevIdx >= start {
			for j := start; j <= prevIdx; j++ {
				currentSum -= positives[j]
			}
			start = prevIdx + 1
		}
		lastSeen[x] = i
		currentSum += x
		if currentSum > ans {
			ans = currentSum
		}
	}
	fmt.Println(ans)
}

