long long countValidSegments(int L, vector<pair<int,int>>& pairs) {
    long long total = (long long)L * (L + 1) / 2;
    set<pair<int,int>> pairSet;
    for (auto& p : pairs) {
        int a = min(p.first, p.second);
        int b = max(p.first, p.second);
