class GameDesign:
    def maxAllowedSegments(self, levelCount: int, troublesomePairs: List[List[int]]) -> int:
        L = levelCount
        total_segments = L * (L + 1)

        def count_valid_segments(pairs):
            if not pairs:
                return total_segments

            normalized_pairs = []
            for p, q in pairs:
                if p > q:
                    p, q = q, p
                normalized_pairs.append((p, q))

            invalid_count = 0
            n = len(normalized_pairs)

            for mask in range(1, 1 << n):
                min_left = L + 1
                max_right = 0

                for i in range(n):
                    if mask & (1 << i):
                        p, q = normalized_pairs[i]
                        min_left = min(min_left, p)
                        max_right = max(max_right, q)

                if min_left <= max_right:
                    count = min_left * (L - max_right + 1)
                    bits = bin(mask).count('1')
                    if bits % 2 == 1:
                        invalid_count += count
                    else:
                        invalid_count -= count

            return total_segments - invalid_count

        max_segments = 0

        for skip_idx in range(len(troublesomePairs)):
            remaining_pairs = [troublesomePairs[i] for i in range(len(troublesomePairs)) if i != skip_idx]
            valid_segments = count_valid_segments(remaining_pairs)
            max_segments = max(max_segments, valid_segments)

        return max_segments

