        vector<int> min_q2(L + 2, L + 1);
        vector<int> best_pair_idx(L + 2, -1);

        for (int i = 0; i < (int)troublesomePairs.size(); ++i) {
            int p = troublesomePairs[i].first;
            int q = troublesomePairs[i].second;
            if (p > q) swap(p, q);
            if (q < min_q[p]) {
                min_q2[p] = min_q[p];
                min_q[p] = q;
                best_pair_idx[p] = i;
            } else if (q < min_q2[p]) {
                min_q2[p] = q;
            }
        }

        vector<int> f1(L + 2, L + 1);
        vector<int> f2(L + 2, L + 1);
        vector<int> id(L + 2, -1);

        for (int i = L; i >= 1; --i) {
            f1[i] = f1[i + 1];
            f2[i] = f2[i + 1];
            id[i] = id[i + 1];

            if (min_q[i] < f1[i]) {
                f2[i] = f1[i];
                f1[i] = min_q[i];
                id[i] = best_pair_idx[i];
            } else if (min_q[i] < f2[i]) {
                f2[i] = min_q[i];
            }

            if (min_q2[i] < f2[i]) {
                f2[i] = min_q2[i];
            }
        }

        long long base_sum = 0;
        for (int i = 1; i <= L; ++i) {
            base_sum += (f1[i] - i);
        }

        vector<long long> gain((int)troublesomePairs.size(), 0);
        for (int i = 1; i <= L; ++i) {
            if (id[i] != -1) {
                gain[id[i]] += (f2[i] - f1[i]);
            }
        }

        long long max_gain = 0;
        for (long long g : gain) {
            if (g > max_gain) max_gain = g;
        }

        return base_sum + max_gain;
    }
