    def maxAllowedSegments(self, levelCount: int, troublesomePairs: list[list[int]]) -> int:
        L = levelCount
        adj = [[] for _ in range(L + 1)]
        for u, v in troublesomePairs:
            if u > v:
                u, v = v, u
            adj[v].append(u)

        m1 = [0] * (L + 1)
        m2 = [0] * (L + 1)

