            cur_m2 = m2[v-1]
            for u in adj[v]:
                if u > cur_m1:
                    cur_m2 = cur_m1
                    cur_m1 = u
                elif u > cur_m2:
                    cur_m2 = u
            m1[v] = cur_m1
            m2[v] = cur_m2

        base_total = 0
