class Solution {
public:
    int countUnallocatedDeliveries(vector<int>& deliveries, vector<int>& containers) {
        int n = deliveries.size();
        vector<bool> used(n, false);
        int unallocated = 0;

        for (int i = 0; i < n; i++) {
            bool allocated = false;
            for (int j = 0; j < n; j++) {
                if (!used[j] && containers[j] >= deliveries[i]) {
                    used[j] = true;
                    allocated = true;
                    break;
                }
            }
            if (!allocated) {
                unallocated++;
            }
        }

        return unallocated;
    }
};

