class Solution {
public:
    int countUnallocatedDeliveries(vector<int>& deliveries, vector<int>& containers) {
        int n = deliveries.size();
        int tree_size = 1;
        while (tree_size < n) tree_size *= 2;
        vector<int> tree(2 * tree_size, 0);

        for (int i = 0; i < n; ++i) {
            tree[tree_size + i] = containers[i];
        }
        for (int i = tree_size - 1; i > 0; --i) {
            tree[i] = max(tree[2 * i], tree[2 * i + 1]);
        }

        int unallocated = 0;
        for (int d : deliveries) {
            if (tree[1] < d) {
                unallocated++;
                continue;
            }

            int node = 1;
            while (node < tree_size) {
                if (tree[2 * node] >= d) {
                    node = 2 * node;
                } else {
                    node = 2 * node + 1;
                }
            }

            int idx = node - tree_size;
            tree[node] = -1;
            node /= 2;
            while (node > 0) {
                tree[node] = max(tree[2 * node], tree[2 * node + 1]);
                node /= 2;
            }
        }
        return unallocated;
    }
};

