type SegmentTree struct {
	size int
	tree []int
}

func newSegmentTree(data []int) *SegmentTree {
	n := len(data)
	size := 1
	for size < n {
		size *= 2
	}
	tree := make([]int, 2*size)
	for i := 0; i < n; i++ {
		tree[size+i] = data[i]
	}
	for i := size - 1; i > 0; i-- {
		tree[i] = max(tree[2*i], tree[2*i+1])
	}
	return &SegmentTree{size, tree}
}

func (st *SegmentTree) findLeftmost(val int) int {
	if st.tree[1] < val {
		return -1
	}
	node := 1
	for node < st.size {
		if st.tree[2*node] >= val {
			node = 2 * node
		} else {
			node = 2*node + 1
		}
	}
	return node - st.size
}

func (st *SegmentTree) update(idx int, val int) {
	idx += st.size
	st.tree[idx] = val
	for idx > 1 {
		idx /= 2
		st.tree[idx] = max(st.tree[2*idx], st.tree[2*idx+1])
	}
}

func max(a, b int) int {
	if a > b {
		return a
	}
	return b
}

