public class Main {
    static class SegmentTree {
        int n;
        int[] tree;

        SegmentTree(int[] arr) {
            this.n = arr.length;
            this.tree = new int[4 * n];
            build(arr, 1, 0, n - 1);
        }

        void build(int[] arr, int v, int tl, int tr) {
            if (tl == tr) {
                tree[v] = arr[tl];
            } else {
                int tm = (tl + tr) / 2;
                build(arr, 2 * v, tl, tm);
                build(arr, 2 * v + 1, tm + 1, tr);
                tree[v] = Math.max(tree[2 * v], tree[2 * v + 1]);
            }
        }

        void update(int v, int tl, int tr, int pos, int newVal) {
            if (tl == tr) {
                tree[v] = newVal;
            } else {
                int tm = (tl + tr) / 2;
                if (pos <= tm)
                    update(2 * v, tl, tm, pos, newVal);
                else
                    update(2 * v + 1, tm + 1, tr, pos, newVal);
                tree[v] = Math.max(tree[2 * v], tree[2 * v + 1]);
            }
        }

        int findFirst(int v, int tl, int tr, int val) {
            if (tree[v] < val) return -1;
            if (tl == tr) return tl;
            int tm = (tl + tr) / 2;
            if (tree[2 * v] >= val)
                return findFirst(2 * v, tl, tm, val);
            else
                return findFirst(2 * v + 1, tm + 1, tr, val);
        }
    }

    public static void main(String[] args) throws IOException {
        Scanner sc = new Scanner(System.in);
        if (!sc.hasNext()) return;

        String dLine = sc.nextLine().replace("[", "").replace("]", "").replace(" ", "");
        String cLine = sc.nextLine().replace("[", "").replace("]", "").replace(" ", "");

