        int[] deliveries = new int[n];
        int[] containers = new int[n];

        for (int i = 0; i < n; i++) {
            deliveries[i] = Integer.parseInt(dStr[i]);
            containers[i] = Integer.parseInt(cStr[i]);
        }

        SegmentTree st = new SegmentTree(containers);
        int unallocated = 0;

        for (int i = 0; i < n; i++) {
            int idx = st.findFirst(1, 0, n - 1, deliveries[i]);
            if (idx != -1) {
                st.update(1, 0, n - 1, idx, -1);
            } else {
                unallocated++;
            }
        }

        System.out.println(unallocated);
    }
