class Solution:
    def countUnallocatedDeliveries(self, deliveries: list[int], containers: list[int]) -> int:
        n = len(containers)
        tree = [0] * (4 * n)

        def build(node, start, end):
            if start == end:
                tree[node] = containers[start]
                return
            mid = (start + end)
            build(2 * node, start, mid)
            build(2 * node + 1, mid + 1, end)
            tree[node] = max(tree[2 * node], tree[2 * node + 1])

        def query_and_update(node, start, end, val):
            if tree[node] < val:
                return -1
            if start == end:
                tree[node] = -1
                return start
            mid = (start + end)
            res = -1
            if tree[2 * node] >= val:
                res = query_and_update(2 * node, start, mid, val)
            else:
                res = query_and_update(2 * node + 1, mid + 1, end, val)
            tree[node] = max(tree[2 * node], tree[2 * node + 1])
            return res

        build(1, 0, n - 1)
        unallocated = 0
        for d in deliveries:
            idx = query_and_update(1, 0, n - 1, d)
            if idx == -1:
                unallocated += 1
        return unallocated

