class Solution {
public:
    long long minimalAssemblyTime(vector<int>& efficiency, vector<int>& supply) {
        int n = efficiency.size();
        int m = supply.size();

        vector<vector<long long>> finish(n, vector<long long>(m, 0));

        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                long long work_time = (long long)efficiency[i] * supply[j];
                long long start_time = 0;

                if (i > 0) {
                    start_time = max(start_time, finish[i-1][j]);
