func minimalAssemblyTime(efficiency []int, supply []int) int {
    n := len(efficiency)
    m := len(supply)

    finish := make([][]int, n)
    for i := range finish {
        finish[i] = make([]int, m)
    }

    finish[0][0] = efficiency[0] * supply[0]

    for j := 1; j < m; j++ {
        finish[0][j] = finish[0][j-1] + efficiency[0] * supply[j]
    }

    for i := 1; i < n; i++ {
        finish[i][0] = finish[i-1][0] + efficiency[i] * supply[0]
    }

    for i := 1; i < n; i++ {
        for j := 1; j < m; j++ {
            prev := finish[i][j-1]
            if finish[i-1][j] > prev {
                prev = finish[i-1][j]
            }
            finish[i][j] = prev + efficiency[i] * supply[j]
        }
    }

    return finish[n-1][m-1]
}

