public class Solution {
    public long minimalAssemblyTime(int[] efficiency, int[] supply) {
        int n = efficiency.length;
        int m = supply.length;

        long[] prefixEff = new long[n + 1];
        for (int i = 0; i < n; i++) {
            prefixEff[i + 1] = prefixEff[i] + efficiency[i];
        }

        long[] maxFinishTime = new long[m];
        long currentStart = 0;

        for (int j = 0; j < m; j++) {
            long minStartForThisVehicle = currentStart;

            for (int i = 0; i < n; i++) {
                if (j > 0) {
                    long prevVehicleFinishAtMechanicI = maxFinishTime[j-1] - (prefixEff[n] - prefixEff[i+1]);
                    long currentVehicleFinishAtMechanicI = minStartForThisVehicle + prefixEff[i+1];
                    if (currentVehicleFinishAtMechanicI < prevVehicleFinishAtMechanicI) {
                        minStartForThisVehicle += (prevVehicleFinishAtMechanicI - currentVehicleFinishAtMechanicI);
                    }
                }
            }

            maxFinishTime[j] = minStartForThisVehicle + prefixEff[n];
            currentStart = minStartForThisVehicle + efficiency[0];
        }

        return maxFinishTime[m - 1];
    }

