bool canDrain(vector<int> cells, vector<vector<int>>& operations, int k) {
    int n = cells.size();
    vector<vector<int>> availableOps(n);

    for (int i = 0; i < k; i++) {
        int start = operations[i][0];
        int end = operations[i][1];
        int drain = operations[i][2];
        for (int j = start; j <= end; j++) {
            availableOps[j].push_back(drain);
        }
    }

    for (int i = 0; i < n; i++) {
        sort(availableOps[i].begin(), availableOps[i].end());
    }

    int maxOps = 0;
    for (int i = 0; i < n; i++) {
        maxOps = max(maxOps, (int)availableOps[i].size());
    }

    for (int mask = 0; mask < (1 << maxOps); mask++) {
        vector<int> tempCells = cells;
        bool valid = true;

        for (int i = 0; i < n; i++) {
            for (int j = 0; j < availableOps[i].size(); j++) {
                if (mask & (1 << j)) {
                    tempCells[i] -= availableOps[i][j];
                }
            }
            if (tempCells[i] != 0) {
                valid = false;
                break;
            }
        }

        if (valid) {
            return true;
        }
    }

    return false;
}

int minFullyDrained(vector<int>& cells, vector<vector<int>>& operations) {
    int m = operations.size();

    for (int k = 0; k <= m; k++) {
        if (canDrain(cells, operations, k)) {
            return k;
        }
    }

    return -1;
}

