func backtrack(target []int, operations [][]int, k int, opIdx int) bool {
    allZero := true
    for i := 0; i < len(target); i++ {
        if target[i] < 0 {
            return false
        }
        if target[i] > 0 {
            allZero = false
        }
    }

    if allZero {
        return true
    }

    if opIdx >= k {
        return false
    }

    start := operations[opIdx][0]
    end := operations[opIdx][1]
    drain := operations[opIdx][2]

    maxDrains := 0
    for i := start; i <= end; i++ {
        if target[i] > 0 {
            d := target[i] / drain
            if maxDrains == 0 || d > maxDrains {
                maxDrains = d
            }
        }
    }
    if maxDrains == 0 {
        maxDrains = 100
    } else {
        maxDrains += 10
    }

    numCells := end - start + 1
    limit := 1 << numCells

    for times := 0; times <= maxDrains; times++ {
        for mask := 0; mask < limit; mask++ {
            newTarget := make([]int, len(target))
            copy(newTarget, target)

            for bit := 0; bit < numCells; bit++ {
                if (mask & (1 << bit)) != 0 {
                    idx := start + bit
                    newTarget[idx] -= drain * times
                }
            }

            if backtrack(newTarget, operations, k, opIdx+1) {
                return true
            }
        }
    }

    return false
}

