public class Solution {

    public static int minFullyDrained(int[] cells, int[][] operations) {
        int n = cells.length;
        int m = operations.length;

        for (int k = 1; k <= m; k++) {
            if (canDrainAll(cells, operations, k)) {
                return k;
            }
        }
        return -1;
    }

    public static boolean canDrainAll(int[] cells, int[][] operations, int k) {
        int n = cells.length;
        int[] target = cells.clone();
        return backtrack(target, operations, k, 0);
    }

    public static boolean backtrack(int[] cells, int[][] operations, int k, int cellIdx) {
        if (cellIdx == cells.length) {
            for (int val : cells) {
                if (val != 0) return false;
            }
            return true;
        }

        if (cells[cellIdx] == 0) {
            return backtrack(cells, operations, k, cellIdx + 1);
        }

        List<Integer> validOps = new ArrayList<>();
        for (int i = 0; i < k; i++) {
            int start = operations[i][0];
            int end = operations[i][1];
            if (start <= cellIdx && cellIdx <= end) {
                validOps.add(i);
            }
        }

        if (validOps.isEmpty()) {
            return false;
        }

        int target = cells[cellIdx];
        return tryDrain(cells, operations, k, cellIdx, validOps, target);
    }

    public static boolean tryDrain(int[] cells, int[][] operations, int k, int cellIdx, List<Integer> validOps, int remaining) {
        if (remaining == 0) {
            return backtrack(cells, operations, k, cellIdx + 1);
        }
        if (remaining < 0) {
            return false;
        }

        for (int opIdx : validOps) {
            int drain = operations[opIdx][2];
            int maxUses = remaining / drain;

            for (int uses = maxUses; uses >= 1; uses--) {
                int[] newCells = cells.clone();
                newCells[cellIdx] -= drain * uses;

                if (tryDrain(newCells, operations, k, cellIdx, validOps, newCells[cellIdx])) {
                    return true;
                }
            }
        }

        return false;
    }

