func solve() {
	var cells []int
	var operations [][]int

	decoder := json.NewDecoder(os.Stdin)
	if err := decoder.Decode(&cells); err != nil {
		return
	}
	if err := decoder.Decode(&operations); err != nil {
		return
	}

	n := len(cells)
	initial := State{}
	for i := 0; i < n; i++ {
		initial[i] = cells[i]
	}

	if isZero(initial, n) {
		fmt.Println(0)
		return
	}

	reachable := make(map[State]bool)
	reachable[initial] = true

	for k, op := range operations {
		start, end, drain := op[0], op[1], op[2]
		nextReachable := make(map[State]bool)
		for state := range reachable {
			nextReachable[state] = true

			subsetCount := 1 << (end - start + 1)
			for i := 1; i < subsetCount; i++ {
				newState := state
				possible := true
				for j := 0; j <= (end - start); j++ {
					if (i >> j) & 1 == 1 {
						idx := start + j
						if newState[idx] < drain {
							possible = false
							break
						}
						newState[idx] -= drain
					}
				}
				if possible {
					if isZero(newState, n) {
						fmt.Println(k + 1)
						return
					}
					nextReachable[newState] = true
				}
			}
		}
		reachable = nextReachable
	}

	fmt.Println(-1)
}

func isZero(s State, n int) bool {
	for i := 0; i < n; i++ {
		if s[i] != 0 {
			return false
		}
	}
	return true
}

