    private static boolean canDrain(int[] cells, List<int[]> operations, int k) {
        int n = cells.length;
        int[][] ops = new int[k][3];
        for (int i = 0; i < k; i++) {
            ops[i] = operations.get(i);
        }

        return backtrack(cells.clone(), ops, 0);
    }

    private static boolean backtrack(int[] currentCells, int[][] ops, int idx) {
        boolean allZero = true;
        for (int val : currentCells) {
            if (val > 0) {
                allZero = false;
                break;
            }
        }
        if (allZero) return true;
        if (idx == ops.length) return false;

        int start = ops[idx][0];
        int end = ops[idx][1];
        int drain = ops[idx][2];

        int maskLimit = 1 << (end - start + 1);
        for (int m = maskLimit - 1; m >= 0; m--) {
            boolean possible = true;
            for (int i = 0; i <= (end - start); i++) {
                if (((m >> i) & 1) == 1) {
                    if (currentCells[start + i] < drain) {
                        possible = false;
                        break;
                    }
                }
            }

            if (possible) {
                for (int i = 0; i <= (end - start); i++) {
                    if (((m >> i) & 1) == 1) currentCells[start + i] -= drain;
                }
                if (backtrack(currentCells, ops, idx + 1)) return true;
                for (int i = 0; i <= (end - start); i++) {
                    if (((m >> i) & 1) == 1) currentCells[start + i] += drain;
                }
            }
        }
        return false;
    }
}

class BatteryDrainer {
    public int minFullyDrained(int[] cells, int[][] operations) {
        int low = 1, high = operations.length;
        int result = -1;
        while (low <= high) {
            int mid = low + (high - low) / 2;
            if (canDrain(cells, operations, mid)) {
                result = mid;
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }
        return result;
    }

