class BatteryDrainer:
    def minFullyDrained(self, cells: List[int], operations: List[List[int]]) -> int:
        n = len(cells)

        def check(k):
            ops = operations[:k]
            m = len(ops)
            from collections import deque

            memo = {}

            def solve(idx, current_cells):
                state = (idx, current_cells)
                if state in memo:
                    return memo[state]

                if all(c == 0 for c in current_cells):
                    return True
                if idx == m:
                    return False

                start, end, drain = ops[idx]

                if solve(idx + 1, current_cells):
                    memo[state] = True
                    return True

                possible_indices = []
                for i in range(start, end + 1):
                    if current_cells[i] >= drain:
                        possible_indices.append(i)

                if not possible_indices:
                    memo[state] = False
                    return False

                num_p = len(possible_indices)
                for i in range(1, 1 << num_p):
                    next_cells = list(current_cells)
                    for j in range(num_p):
                        if (i >> j) & 1:
                            next_cells[possible_indices[j]] -= drain
                    if solve(idx + 1, tuple(next_cells)):
                        memo[state] = True
                        return True

                memo[state] = False
                return False

            return solve(0, tuple(cells))

        low = 1
        high = len(operations)
        ans = -1

        while low <= high:
            mid = (low + high)
            if check(mid):
                ans = mid
                high = mid - 1
            else:
                low = mid + 1
        return ans

