        boolean[] used = new boolean[tiles.length];
        generateCodes(tiles, used, "", uniqueCodes);
        return uniqueCodes.size();
    }

    private void generateCodes(int[] tiles, boolean[] used, String current, Set<String> uniqueCodes) {
        if (current.length() == 3) {
            int code = Integer.parseInt(current);
            if (code >= 100 && code % 2 == 0) {
                uniqueCodes.add(current);
            }
            return;
        }

        for (int i = 0; i < tiles.length; i++) {
            if (used[i]) continue;

            if (current.length() == 0 && tiles[i] == 0) continue;

            used[i] = true;
            generateCodes(tiles, used, current + tiles[i], uniqueCodes);
            used[i] = false;
        }
    }
