using namespace std;

long long memo[12][100][1000];
int current_sum;

long long dp(const string& s, int pos, bool is_less, bool is_started, int sum, int prod_mod) {
    if (sum > current_sum) return 0;
    if (pos == s.size()) {
        return (is_started && sum == current_sum && prod_mod == 0) ? 1 : 0;
    }
    if (is_less && memo[pos][sum][prod_mod] != -1) return memo[pos][sum][prod_mod];

    long long res = 0;
    int limit = is_less ? 9 : s[pos] - '0';

    for (int d = 0; d <= limit; ++d) {
        bool next_less = is_less || (d < limit);
        bool next_started = is_started || (d > 0);
        if (!next_started) {
            res += dp(s, pos + 1, next_less, false, 0, 0);
        } else {
            res += dp(s, pos + 1, next_less, true, sum + d, (prod_mod * d) % current_sum);
        }
    }

    if (is_less) memo[pos][sum][prod_mod] = res;
    return res;
}

long long count_charming(long long n) {
    if (n <= 0) return 0;
    string s = to_string(n);
    long long total = 0;
    for (int s_val = 1; s_val <= 9 * s.size(); ++s_val) {
        current_sum = s_val;
        for (int i = 0; i < 12; ++i)
            for (int j = 0; j < 100; ++j)
                for (int k = 0; k < 1000; ++k)
                    memo[i][j][k] = -1;
        total += dp(s, 0, false, false, 0, 1 % current_sum);
    }
    return total;
}

