var memo [12][100][1000]int64

func solve(n int, s int, p int, targetSum int, isLess bool, isStarted bool, numStr string) int64 {
	if n == len(numStr) {
		if isStarted && s == targetSum && p%targetSum == 0 {
			return 1
		}
		return 0
	}
	if isLess && isStarted && memo[n][s][p] != -1 {
		return memo[n][s][p]
	}

	var count int64 = 0
	limit := 9
	if !isLess {
		limit = int(numStr[n] - '0')
	}

	for i := 0; i <= limit; i++ {
		nextIsLess := isLess || (i < limit)
		nextIsStarted := isStarted || (i > 0)

		nextS := s
		nextP := p
		if nextIsStarted {
			nextS += i
			nextP = (nextP * i) % targetSum
		}

		if nextS <= targetSum {
			count += solve(n+1, nextS, nextP, targetSum, nextIsLess, nextIsStarted, numStr)
		}
	}

	if isLess && isStarted {
		memo[n][s][p] = count
	}
	return count
}

func countCharming(n int) int64 {
	if n <= 0 {
		return 0
	}
	s := strconv.Itoa(n)
	var total int64 = 0
	maxSum := 9 * len(s)

	for targetSum := 1; targetSum <= maxSum; targetSum++ {
		for i := 0; i < 12; i++ {
			for j := 0; j < 100; j++ {
				for k := 0; k < 1000; k++ {
					memo[i][j][k] = -1
				}
			}
		}
		total += solve(0, 0, 1, targetSum, false, false, s)
	}
	return total
}

func main() {
	var start, end int
	_, err := fmt.Scan(&start, &end)
	if err != nil {
		return
	}
	fmt.Println(countCharming(end) - countCharming(start-1))
}

import java.util.Scanner;

public class Main {
    private static long[][][][] memo;
    private static int currentSum;

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        if (!sc.hasNextLong()) return;
        long start = sc.nextLong();
        long end = sc.nextLong();
        System.out.println(countCharming(end) - countCharming(start - 1));
    }

    private static long countCharming(long n) {
        if (n <= 0) return 0;
        String s = String.valueOf(n);
        long total = 0;
        for (int sVal = 1; sVal <= 9 * s.length(); sVal++) {
            currentSum = sVal;
            memo = new long[s.length() + 1][sVal + 1][sVal][2];
            for (int i = 0; i <= s.length(); i++)
                for (int j = 0; j <= sVal; j++)
                    for (int k = 0; k < sVal; k++)
                        for (int l = 0; l < 2; l++)
                            memo[i][j][k][l] = -1;
            total += dp(s, 0, 0, 1, true);
        }
        return total;
    }

    private static long dp(String s, int idx, int sumSoFar, int prodMod, boolean isLess) {
        if (sumSoFar > currentSum) return 0;
        if (idx == s.length()) {
            return (sumSoFar == currentSum && prodMod == 0) ? 1 : 0;
        }
        if (memo[idx][sumSoFar][prodMod][isLess ? 1 : 0] != -1) {
            return memo[idx][sumSoFar][prodMod][isLess ? 1 : 0];
        }

        long count = 0;
        int limit = isLess ? s.charAt(idx) - '0' : 9;

        for (int d = 0; d <= limit; d++) {
            count += dp(s, idx + 1, sumSoFar + d, (prodMod * d) % currentSum, isLess && (d == limit));
        }

        return memo[idx][sumSoFar][prodMod][isLess ? 1 : 0] = count;
    }
}

import sys

class Solution:
    def charmingTokens(self, start: int, end: int) -> int:
        def solve(n):
            if n == 0:
                return 0
            s_n = str(n)
            L = len(s_n)
            memo = {}

            def dp(idx, is_less, is_started, current_sum, current_prod_mod, target_sum):
                if current_sum > target_sum:
                    return 0
                if idx == L:
                    return 1 if (is_started and current_sum == target_sum and current_prod_mod == 0) else 0

                state = (idx, is_less, is_started, current_sum, current_prod_mod)
                if state in memo:
                    return memo[state]

                res = 0
                limit = int(s_n[idx]) if not is_less else 9

                for d in range(limit + 1):
                    next_is_less = is_less or (d < limit)
                    next_is_started = is_started or (d > 0)

                    if not next_is_started:
                        res += dp(idx + 1, next_is_less, False, 0, 0, target_sum)
                    else:
                        next_sum = current_sum + d
                        next_prod_mod = (current_prod_mod * d) % target_sum if is_started else d % target_sum
                        res += dp(idx + 1, next_is_less, True, next_sum, next_prod_mod, target_sum)

                memo[state] = res
                return res

            total = 0
            max_sum = 9 * L
            for s in range(1, max_sum + 1):
                memo = {}
                count = dp(0, False, False, 0, 0, s)
                total += count
            return total

        return solve(end) - solve(start - 1)

