using namespace std;

int countOnes(const string& s) {
    int count = 0;
    for (char c : s) {
        if (c == '1') count++;
    }
    return count;
}

int solve(string p) {
    int n = p.length();
    string q = "1" + p + "1";
    int m = q.length();

    int originalCount = countOnes(p);
    int maxCount = originalCount;

    vector<pair<int, int>> oneSegments;
    vector<pair<int, int>> zeroSegments;

    for (int i = 0; i < m; i++) {
        if (q[i] == '1') {
            int j = i;
            while (j < m && q[j] == '1') j++;
            oneSegments.push_back({i, j - 1});
            i = j - 1;
        }
    }

    for (int i = 0; i < m; i++) {
        if (q[i] == '0') {
            int j = i;
            while (j < m && q[j] == '0') j++;
            zeroSegments.push_back({i, j - 1});
            i = j - 1;
        }
    }

    for (auto seg1 : oneSegments) {
        if (seg1.first == 0 || seg1.second == m - 1) continue;

        for (auto seg0 : zeroSegments) {
            if (seg0.first == 0 || seg0.second == m - 1) continue;

            string temp = q;

            for (int i = seg1.first; i <= seg1.second; i++) {
                temp[i] = '0';
            }

            bool validZeroSeg = true;
            if (seg0.first > 0 && temp[seg0.first - 1] != '1') validZeroSeg = false;
            if (seg0.second < m - 1 && temp[seg0.second + 1] != '1') validZeroSeg = false;

            if (!validZeroSeg) continue;

            for (int i = seg0.first; i <= seg0.second; i++) {
                temp[i] = '1';
            }

            string result = temp.substr(1, n);
            int count = countOnes(result);
            maxCount = max(maxCount, count);
        }
    }

    return maxCount;
}

int main() {
    string p;
    cin >> p;
    cout << solve(p) << endl;
    return 0;
}

