func optimizeLitPanelsAfterSwap(p string) int {
    q := "1" + p + "1"

    currentCount := strings.Count(p, "1")
    maxCount := currentCount

    litSegments := []struct{ start, end int }{}
    darkSegments := []struct{ start, end int }{}

    i := 0
    n := len(q)

    for i < n {
        if q[i] == '1' {
            start := i
            for i < n && q[i] == '1' {
                i++
            }
            litSegments = append(litSegments, struct{ start, end int }{start, i})
        } else {
            start := i
            for i < n && q[i] == '0' {
                i++
            }
            darkSegments = append(darkSegments, struct{ start, end int }{start, i})
        }
    }

    enclosedLitSegments := []struct{ start, end int }{}
    for _, seg := range litSegments {
        if seg.start > 0 && seg.end < n {
            enclosedLitSegments = append(enclosedLitSegments, seg)
        }
    }

    enclosedDarkSegments := []struct{ start, end int }{}
    for _, seg := range darkSegments {
        leftLit := false
        rightLit := false

        if seg.start > 0 && q[seg.start-1] == '1' {
            leftLit = true
        }
        if seg.end < n && q[seg.end] == '1' {
            rightLit = true
        }

        if leftLit && rightLit {
            enclosedDarkSegments = append(enclosedDarkSegments, seg)
        }
    }

    for _, litSeg := range enclosedLitSegments {
        litInOriginal := 0
        if litSeg.start >= 1 && litSeg.end <= len(p)+1 {
            originalStart := litSeg.start - 1
            originalEnd := litSeg.end - 1
            if originalStart < 0 {
                originalStart = 0
            }
            if originalEnd > len(p) {
                originalEnd = len(p)
            }
            for j := originalStart; j < originalEnd; j++ {
                if p[j] == '1' {
                    litInOriginal++
                }
            }
        }

        for _, darkSeg := range enclosedDarkSegments {
            darkInOriginal := 0
            if darkSeg.start >= 1 && darkSeg.end <= len(p)+1 {
                originalStart := darkSeg.start - 1
                originalEnd := darkSeg.end - 1
                if originalStart < 0 {
                    originalStart = 0
                }
                if originalEnd > len(p) {
                    originalEnd = len(p)
                }
                for j := originalStart; j < originalEnd; j++ {
                    if p[j] == '0' {
                        darkInOriginal++
                    }
                }
            }

            newCount := currentCount - litInOriginal + darkInOriginal
            if newCount > maxCount {
                maxCount = newCount
            }
        }
    }

    return maxCount
}

