public class PanelOptimizer {
    public int optimizeLitPanelsAfterSwap(String p) {
        String q = "1" + p + "1";

        List<int[]> litSegments = new ArrayList<>();
        List<int[]> darkSegments = new ArrayList<>();

        int i = 0;
        while (i < q.length()) {
            if (q.charAt(i) == '1') {
                int start = i;
                while (i < q.length() && q.charAt(i) == '1') {
                    i++;
                }
                litSegments.add(new int[]{start, i - 1});
            } else {
                int start = i;
                while (i < q.length() && q.charAt(i) == '0') {
                    i++;
                }
                darkSegments.add(new int[]{start, i - 1});
            }
        }

        List<int[]> enclosedLit = new ArrayList<>();
        for (int[] seg : litSegments) {
            if (seg[0] > 0 && seg[1] < q.length() - 1) {
                enclosedLit.add(seg);
            }
        }

        List<int[]> enclosedDark = new ArrayList<>();
        for (int[] seg : darkSegments) {
            if (seg[0] > 0 && seg[1] < q.length() - 1) {
                enclosedDark.add(seg);
            }
        }

        int originalCount = 0;
        for (int j = 0; j < p.length(); j++) {
            if (p.charAt(j) == '1') originalCount++;
        }

        int maxCount = originalCount;

        for (int[] litSeg : enclosedLit) {
            for (int[] darkSeg : enclosedDark) {
                int litStart = litSeg[0];
                int litEnd = litSeg[1];
                int darkStart = darkSeg[0];
                int darkEnd = darkSeg[1];

                int litLoss = 0;
                for (int j = litStart; j <= litEnd; j++) {
                    if (j >= 1 && j <= p.length()) {
                        litLoss++;
                    }
                }

                int darkGain = 0;
                for (int j = darkStart; j <= darkEnd; j++) {
                    if (j >= 1 && j <= p.length()) {
                        darkGain++;
                    }
                }

                int newCount = originalCount - litLoss + darkGain;
                maxCount = Math.max(maxCount, newCount);
            }
        }

        return maxCount;
    }

