                dark_segments.append((start, i - 1))
            else:
                i += 1

        enclosed_lit = []
        for start, end in lit_segments:
            if start > 0 and end < n - 1:
                enclosed_lit.append((start, end))

        enclosed_dark = []
        for start, end in dark_segments:
            if start > 0 and end < n - 1:
                enclosed_dark.append((start, end))

        for lit_start, lit_end in enclosed_lit:
