        int i = 0;
        int m = q.length();
        std::vector<std::pair<char, int>> segments;
        while (i < m) {
            int j = i;
            while (j < m && q[j] == q[i]) j++;
            segments.push_back({q[i], j - i});
            i = j;
        }

        std::vector<int> one_blocks;
        std::vector<int> zero_blocks;

        for (int k = 1; k < (int)segments.size() - 1; ++k) {
            if (segments[k].first == '1') {
                if (segments[k-1].first == '0' && segments[k+1].first == '0') {
                    one_blocks.push_back(segments[k].second);
                }
            } else {
                if (segments[k-1].first == '1' && segments[k+1].first == '1') {
                    zero_blocks.push_back(segments[k].second);
                }
            }
        }

        if (one_blocks.empty() || zero_blocks.empty()) return current_ones;

        int min_one = one_blocks[0];
        for (int val : one_blocks) if (val < min_one) min_one = val;

        int max_zero = zero_blocks[0];
        for (int val : zero_blocks) if (val > max_zero) max_zero = val;

        return current_ones - min_one + max_zero;
    }
};

