class PanelOptimizer {
    public int optimizeLitPanelsAfterSwap(String p) {
        int n = p.length();
        int initialLitCount = 0;
        for (char c : p.toCharArray()) {
            if (c == '1') initialLitCount++;
        }

        String q = "1" + p + "1";
        List<Integer> litBlocks = new ArrayList<>();
        List<Integer> darkBlocks = new ArrayList<>();

        int i = 0;
        while (i < q.length()) {
            int start = i;
            char current = q.charAt(i);
            while (i < q.length() && q.charAt(i) == current) {
                i++;
            }
            int len = i - start;
            if (current == '1') {
                litBlocks.add(len);
            } else {
                darkBlocks.add(len);
            }
        }

        int maxLit = initialLitCount;

        List<Integer> swappableLit = new ArrayList<>();
        for (int k = 1; k < litBlocks.size() - 1; k++) {
            swappableLit.add(litBlocks.get(k));
        }

        List<Integer> swappableDark = new ArrayList<>();
        for (int k = 0; k < darkBlocks.size(); k++) {
            swappableDark.add(darkBlocks.get(k));
        }

        if (swappableLit.isEmpty() || swappableDark.isEmpty()) {
            return initialLitCount;
        }

        int minLitBlock = Collections.min(swappableLit);
        int maxDarkBlock = Collections.max(swappableDark);

        maxLit = Math.max(maxLit, initialLitCount - minLitBlock + maxDarkBlock);

        return maxLit;
    }
}

