class PanelOptimizer:
    def optimizeLitPanelsAfterSwap(self, p: str) -> int:
        n = len(p)
        q = '1' + p + '1'
        m = len(q)

        runs = []
        if m > 0:
            curr_char = q[0]
            curr_len = 1
            for i in range(1, m):
                if q[i] == curr_char:
                    curr_len += 1
                else:
                    runs.append((curr_char, curr_len))
                    curr_char = q[i]
                    curr_len = 1
            runs.append((curr_char, curr_len))

        initial_ones = p.count('1')
        max_ones = initial_ones

        ones_blocks = []
        zeros_blocks = []

        for i in range(len(runs)):
            char, length = runs[i]
            if char == '1':
                ones_blocks.append((i, length))
            else:
                zeros_blocks.append((i, length))

        valid_ones = []
        for i, length in ones_blocks:
            if i > 0 and i < len(runs) - 1:
                valid_ones.append((i, length))

        valid_zeros = []
        for i, length in zeros_blocks:
            if i > 0 and i < len(runs) - 1:
                valid_zeros.append((i, length))

        if not valid_ones or not valid_zeros:
            return initial_ones

        max_zeros_len = 0
        for i, length in valid_zeros:
            if length > max_zeros_len:
                max_zeros_len = length

        min_ones_len = float('inf')
        for i, length in valid_ones:
            if length < min_ones_len:
                min_ones_len = length

        max_ones = initial_ones + max_zeros_len - min_ones_len
        return max(initial_ones, max_ones)

