using namespace std;

class UnionFind {
public:
    vector<int> parent;
    vector<int> rank;

    UnionFind(int n) {
        parent.resize(n);
        rank.resize(n, 0);
        for (int i = 0; i < n; i++) {
            parent[i] = i;
        }
    }

    int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    void unite(int x, int y) {
        int px = find(x);
        int py = find(y);
        if (px == py) return;

        if (rank[px] < rank[py]) {
            parent[px] = py;
        } else if (rank[px] > rank[py]) {
            parent[py] = px;
        } else {
            parent[py] = px;
            rank[px]++;
        }
    }

    int countComponents() {
        set<int> roots;
        for (int i = 0; i < parent.size(); i++) {
            roots.insert(find(i));
        }
        return roots.size();
    }
};

int commonElements(vector<int>& arr1, vector<int>& arr2) {
    set<int> set1(arr1.begin(), arr1.end());
    set<int> set2(arr2.begin(), arr2.end());

    int count = 0;
    for (int elem : set1) {
        if (set2.count(elem)) {
            count++;
        }
    }
    return count;
}

int countClusters(vector<vector<int>>& blueprints, int threshold) {
    int n = blueprints.size();
    if (n == 0) return 0;

    UnionFind uf(n);

    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            if (commonElements(blueprints[i], blueprints[j]) >= threshold) {
                uf.unite(i, j);
            }
        }
