func find(parent []int, i int) int {
    if parent[i] != i {
        parent[i] = find(parent, parent[i])
    }
    return parent[i]
}

func union(parent, rank []int, x, y int) {
    xroot := find(parent, x)
    yroot := find(parent, y)

    if xroot == yroot {
        return
    }

    if rank[xroot] < rank[yroot] {
        parent[xroot] = yroot
    } else if rank[xroot] > rank[yroot] {
        parent[yroot] = xroot
    } else {
        parent[yroot] = xroot
        rank[xroot]++
    }
}

func countClusters(blueprints [][]int, threshold int) int {
    n := len(blueprints)
    if n == 0 {
        return 0
    }

    parent := make([]int, n)
    rank := make([]int, n)
    for i := 0; i < n; i++ {
        parent[i] = i
        rank[i] = 0
    }

    for i := 0; i < n; i++ {
        for j := i + 1; j < n; j++ {
            if commonElements(blueprints[i], blueprints[j]) >= threshold {
                union(parent, rank, i, j)
            }
        }
    }

    clusters := make(map[int]bool)
    for i := 0; i < n; i++ {
        clusters[find(parent, i)] = true
    }

    return len(clusters)
}

