import java.util.*;

public class Solution {

    public int countClusters(int[][] blueprints, int threshold) {
        int n = blueprints.length;
        UnionFind uf = new UnionFind(n);

        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                if (commonElements(blueprints[i], blueprints[j]) >= threshold) {
                    uf.union(i, j);
                }
            }
        }

        return uf.getCount();
    }

    private int commonElements(int[] arr1, int[] arr2) {
        Set<Integer> set1 = new HashSet<>();
        for (int num : arr1) {
            set1.add(num);
        }

        Set<Integer> common = new HashSet<>();
        for (int num : arr2) {
            if (set1.contains(num)) {
                common.add(num);
            }
        }

        return common.size();
    }

    class UnionFind {
        private int[] parent;
        private int[] rank;
        private int count;

        public UnionFind(int n) {
            parent = new int[n];
            rank = new int[n];
            count = n;
            for (int i = 0; i < n; i++) {
                parent[i] = i;
                rank[i] = 0;
            }
        }

        public int find(int x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }

        public void union(int x, int y) {
            int rootX = find(x);
            int rootY = find(y);

            if (rootX != rootY) {
                if (rank[rootX] > rank[rootY]) {
                    parent[rootY] = rootX;
                } else if (rank[rootX] < rank[rootY]) {
                    parent[rootX] = rootY;
                } else {
                    parent[rootY] = rootX;
                    rank[rootX]++;
                }
                count--;
            }
        }

        public int getCount() {
            return count;
        }
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);

        String line = sc.nextLine().trim();
        line = line.substring(1, line.length() - 1);

        List<int[]> blueprintsList = new ArrayList<>();
        int i = 0;
        while (i < line.length()) {
            if (line.charAt(i) == '[') {
                int j = i + 1;
                while (j < line.length() && line.charAt(j) != ']') {
                    j++;
                }
                String innerArray = line.substring(i + 1, j);
                String[] parts = innerArray.split(",");
                int[] arr = new int[parts.length];
                for (int k = 0; k < parts.length; k++) {
                    arr[k] = Integer.parseInt(parts[k].trim());
                }
                blueprintsList.add(arr);
                i = j + 1;
            } else {
                i++;
            }
        }

        int[][] blueprints = new int[blueprintsList.size()][];
        for (int k = 0; k < blueprintsList.size(); k++) {
            blueprints[k] = blueprintsList.get(k);
        }

        int threshold = sc.nextInt();

        Solution solution = new Solution();
        int result = solution.countClusters(blueprints, threshold);
        System.out.println(result);

        sc.close();
    }
}

