class DSU {
public:
    std::vector<int> parent;
    int components;
    DSU(int n) {
        parent.resize(n);
        for (int i = 0; i < n; ++i) parent[i] = i;
        components = n;
    }
    int find(int i) {
        if (parent[i] == i) return i;
        return parent[i] = find(parent[i]);
    }
    void unite(int i, int j) {
        int root_i = find(i);
        int root_j = find(j);
        if (root_i != root_j) {
            parent[root_i] = root_j;
            components--;
        }
    }
};

int common_elements(const std::vector<int>& a, const std::vector<int>& b) {
    std::set<int> s1(a.begin(), a.end());
    std::set<int> s2(b.begin(), b.end());
    int count = 0;
    for (int x : s1) {
        if (s2.count(x)) count++;
    }
    return count;
}

