import java.util.*;

public class Solution {
    public int countClusters(int[][] blueprints, int threshold) {
        int n = blueprints.length;
        if (n == 0) return 0;

        int[] parent = new int[n];
        for (int i = 0; i < n; i++) parent[i] = i;

        Set<Integer>[] uniqueBlueprints = new HashSet[n];
        for (int i = 0; i < n; i++) {
            uniqueBlueprints[i] = new HashSet<>();
            for (int val : blueprints[i]) {
                uniqueBlueprints[i].add(val);
            }
        }

        int clusters = n;
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                if (find(parent, i) != find(parent, j)) {
                    if (countCommon(uniqueBlueprints[i], uniqueBlueprints[j]) >= threshold) {
                        union(parent, i, j);
                        clusters--;
                    }
                }
            }
        }
        return clusters;
    }

    private int countCommon(Set<Integer> s1, Set<Integer> s2) {
        int count = 0;
        if (s1.size() < s2.size()) {
            for (int val : s1) {
                if (s2.contains(val)) count++;
            }
        } else {
            for (int val : s2) {
                if (s1.contains(val)) count++;
            }
        }
        return count;
    }

    private int find(int[] parent, int i) {
        if (parent[i] == i) return i;
        return parent[i] = find(parent, parent[i]);
    }

    private void union(int[] parent, int i, int j) {
        int rootI = find(parent, i);
        int rootJ = find(parent, j);
        if (rootI != rootJ) parent[rootI] = rootJ;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        if (!sc.hasNext()) return;
        String input = sc.useDelimiter("\\A").next();
        input = input.trim();

        int thresholdIndex = input.lastIndexOf(",");
        int threshold = Integer.parseInt(input.substring(thresholdIndex + 1).replace("threshold =", "").replaceAll("[^0-9]", "").trim());

        String arrayPart = input.substring(0, thresholdIndex);
        arrayPart = arrayPart.substring(arrayPart.indexOf("[[") + 1, arrayPart.lastIndexOf("]]") + 1);

        List<int[]> list = new ArrayList<>();
        String[] rows = arrayPart.split("(?<=\\]),\\s*(?=\\[)");
        for (String row : rows) {
            String cleanRow = row.replaceAll("[\\[\\]\\s]", "");
            if (cleanRow.isEmpty()) {
                list.add(new int[0]);
                continue;
            }
            String[] parts = cleanRow.split(",");
            int[] arr = new int[parts.length];
            for (int i = 0; i < parts.length; i++) {
                arr[i] = Integer.parseInt(parts[i]);
            }
            list.add(arr);
        }

        int[][] blueprints = list.toArray(new int[0][]);
        System.out.println(new Solution().countClusters(blueprints, threshold));
    }
}

