class Solution:
    def countClusters(self, blueprints: List[List[int]], threshold: int) -> int:
        n = len(blueprints)
        if n == 0:
            return 0

        sets = [set(b) for b in blueprints]
        parent = list(range(n))

        def find(i):
            if parent[i] == i:
                return i
            parent[i] = find(parent[i])
            return parent[i]

        def union(i, j):
            root_i = find(i)
            root_j = find(j)
            if root_i != root_j:
                parent[root_i] = root_j
                return True
            return False

        for i in range(n):
            for j in range(i + 1, n):
                common = len(sets[i].intersection(sets[j]))
                if common >= threshold:
                    union(i, j)

        clusters = 0
        for i in range(n):
            if parent[i] == i:
                clusters += 1
        return clusters

