class MuseumExhibit {
    public int maxDisplayCases(int d, int caseWeight, int maxLoad) {
        long totalCells = (long) d * d;
        long weightLimitCases = (long) maxLoad / caseWeight;
        return (int) Math.min(totalCells, weightLimitCases);
    }
}

