func countDragonCrest(n int64) int64 {
	if n < 10 {
		return 0
	}

	digits := []int{}
	temp := n
	for temp > 0 {
		digits = append([]int{int(temp % 10)}, digits...)
		temp /= 10
	}

	memo := make(map[string]int64)
	return dp(0, true, -1, false, digits, memo)
}

func dp(pos int, tight bool, firstDigit int, started bool, digits []int, memo map[string]int64) int64 {
	if pos == len(digits) {
		if started && len(digits) >= 2 {
			return 1
		}
		return 0
	}

	key := fmt.Sprintf("%d_%v_%d_%v", pos, tight, firstDigit, started)
	if val, ok := memo[key]; ok {
		return val
	}

	limit := 9
	if tight {
		limit = digits[pos]
	}

	var result int64 = 0

	for digit := 0; digit <= limit; digit++ {
		if !started {
			if digit == 0 {
				result += dp(pos+1, tight && (digit == limit), -1, false, digits, memo)
			} else {
				result += dp(pos+1, tight && (digit == limit), digit, true, digits, memo)
			}
		} else {
			if pos == 0 {
				result += dp(pos+1, tight && (digit == limit), digit, true, digits, memo)
			} else {
				if digit < firstDigit {
					result += dp(pos+1, tight && (digit == limit), firstDigit, true, digits, memo)
				}
			}
		}
	}

	memo[key] = result
	return result
}

