public class Main {

    static long[][][][] memo;
    static String numStr;

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String[] parts = br.readLine().split(" ");
        long L = Long.parseLong(parts[0]);
        long R = Long.parseLong(parts[1]);

        long result = countDragonCrest(R) - countDragonCrest(L - 1);
        System.out.println(result);
    }

    static long countDragonCrest(long n) {
        if (n < 10) return 0;

        numStr = String.valueOf(n);
        int len = numStr.length();
        memo = new long[len][10][2][2];
        for (int i = 0; i < len; i++) {
            for (int j = 0; j < 10; j++) {
                for (int k = 0; k < 2; k++) {
                    for (int m = 0; m < 2; m++) {
                        memo[i][j][k][m] = -1;
                    }
                }
            }
        }

        return solve(0, 0, true, false);
    }

    static long solve(int pos, int firstDigit, boolean tight, boolean started) {
        if (pos == numStr.length()) {
            return started ? 1 : 0;
        }

        if (!tight && started && memo[pos][firstDigit][0][1] != -1) {
            return memo[pos][firstDigit][0][1];
        }

        int limit = tight ? (numStr.charAt(pos) - '0') : 9;
        long count = 0;

        for (int digit = 0; digit <= limit; digit++) {
            if (!started) {
                if (digit == 0) {
                    count += solve(pos + 1, 0, tight && (digit == limit), false);
                } else {
                    count += solve(pos + 1, digit, tight && (digit == limit), true);
                }
            } else {
                if (digit < firstDigit) {
                    count += solve(pos + 1, firstDigit, tight && (digit == limit), true);
                }
            }
        }

        if (!tight && started) {
            memo[pos][firstDigit][0][1] = count;
        }

        return count;
    }
}

def count_dragon_crest(n):
    if n < 10:
        return 0

    s = str(n)
    length = len(s)

    memo = {}

    def dp(pos, first_digit, is_tight, started):
        if pos == length:
            return 1 if started else 0

        state = (pos, first_digit, is_tight, started)
        if state in memo:
            return memo[state]

        limit = int(s[pos]) if is_tight else 9
        result = 0

        for digit in range(0, limit + 1):
            if not started:
                if digit == 0:
                    result += dp(pos + 1, -1, is_tight and (digit == limit), False)
                else:
                    result += dp(pos + 1, digit, is_tight and (digit == limit), True)
            else:
                if digit < first_digit:
                    result += dp(pos + 1, first_digit, is_tight and (digit == limit), True)

        memo[state] = result
        return result

    return dp(0, -1, True, False)

