ll dp(const string& s, int pos, int first_digit, bool is_less, bool is_started, bool is_crest) {
    if (pos == s.size()) {
        return is_crest ? 1 : 0;
    }
    if (memo[pos][first_digit][is_less][is_started][is_crest] != -1) {
        return memo[pos][first_digit][is_less][is_started][is_crest];
    }

    ll res = 0;
    int limit = is_less ? 9 : (s[pos] - '0');

    for (int d = 0; d <= limit; ++d) {
        bool next_less = is_less || (d < limit);
        if (!is_started) {
            if (d == 0) {
                res += dp(s, pos + 1, 0, next_less, false, false);
            } else {
                res += dp(s, pos + 1, d, next_less, true, false);
            }
        } else {
            if (d < first_digit) {
                res += dp(s, pos + 1, first_digit, next_less, true, true);
            } else {
                res += 0; 
            }
        }
    }
    return memo[pos][first_digit][is_less][is_started][is_crest] = res;
}

