func countSameLength(s string) int64 {
	L := len(s)
	var count int64 = 0
	highDigit := int(s[0] - '0')
	for d := 1; d < highDigit; d++ {
		count += power(int64(d), L-1)
	}

	memo = [20][10][2][2]int64{}
	for i := range memo {
		for j := range memo[i] {
			for k := range memo[i][j] {
				for l := range memo[i][j][k] {
					memo[i][j][k][l] = -1
				}
			}
		}
	}
	count += dp(1, highDigit, true, s)
	return count
}

func dp(idx int, limit int, isLess bool, s string) int64 {
	if idx == len(s) {
		return 1
	}
	lessIdx := 0
	if isLess {
		lessIdx = 1
	}
	if memo[idx][limit][lessIdx][0] != -1 {
		return memo[idx][limit][lessIdx][0]
	}

	upper := limit - 1
	if !isLess {
		digitAtIdx := int(s[idx] - '0')
		if digitAtIdx < upper {
			upper = digitAtIdx
		}
	}

	var res int64 = 0
	for d := 0; d <= upper; d++ {
		res += dp(idx+1, limit, isLess || (d < int(s[idx]-'0')), s)
	}
	memo[idx][limit][lessIdx][0] = res
	return res
}

