        Scanner sc = new Scanner(System.in);
        if (!sc.hasNextLong()) return;
        long L = sc.nextLong();
        long R = sc.nextLong();
        System.out.println(countDragonCrest(R) - countDragonCrest(L - 1));
    }

    private static long countDragonCrest(long n) {
        if (n < 10) return 0;
        String s = Long.toString(n);
        return solve(s);
    }

    private static long solve(String s) {
        int len = s.length();
        long total = 0;

        for (int d = 2; d < len; d++) {
            for (int firstDigit = 1; firstDigit <= 9; firstDigit++) {
                total += Math.pow(firstDigit, d - 1);
            }
        }

        int first = s.charAt(0) - '0';
        for (int f = 1; f < first; f++) {
            total += Math.pow(f, len - 1);
        }

        boolean possible = true;
        for (int i = 1; i < len; i++) {
            int currentDigit = s.charAt(i) - '0';
            int countSmaller = 0;
            for (int d = 0; d < first; d++) {
                if (d < currentDigit) {
                    countSmaller++;
                }
            }
            total += (long) countSmaller * Math.pow(first, len - 1 - i);
            if (currentDigit >= first) {
                possible = false;
                break;
            }
        }
        if (possible) total++;

        return total;
    }
}

