        }

        sccGraph = new ArrayList[sccCount];
        for (int i = 0; i < sccCount; i++) {
            sccGraph[i] = new ArrayList<>();
        }

        Set<Long> edges = new HashSet<>();
        for (int i = 1; i <= N; i++) {
            int from = sccId[i];
            int to = sccId[B[i]];
            if (from != to) {
                long edge = ((long)from << 32) | to;
                if (!edges.contains(edge)) {
                    edges.add(edge);
                    sccGraph[from].add(to);
                }
            }
        }

        inDegree = new int[sccCount];
        for (int i = 0; i < sccCount; i++) {
            for (int j : sccGraph[i]) {
                inDegree[j]++;
            }
        }
    }

    static long computeAssignments() {
        dp = new long[sccCount][M + 1];
        for (int i = 0; i < sccCount; i++) {
            Arrays.fill(dp[i], -1);
        }

        long result = 0;
        for (int i = 0; i < sccCount; i++) {
            if (inDegree[i] == 0) {
                for (int v = 1; v <= M; v++) {
                    result = (result + solve(i, v)) % MOD;
                }
            }
        }

        return result;
    }

    static long solve(int scc, int value) {
        if (dp[scc][value] != -1) {
            return dp[scc][value];
        }

        long result = 1;

        for (int child : sccGraph[scc]) {
            long childWays = 0;
            for (int v = 1; v <= value; v++) {
                childWays = (childWays + solve(child, v)) % MOD;
            }
            result = (result * childWays) % MOD;
        }

        dp[scc][value] = result;
        return result;
    }
