                    visited[curr] = true;
                    onStack[curr] = true;
                    curr = B[curr];
                }
                if (onStack[curr]) {
                    int start = curr;
                    cycle.add(start);
                    int temp = B[start];
                    while (temp != start) {
                        cycle.add(temp);
                        temp = B[temp];
                    }
                }

                resetOnStack(onStack, i);

                if (!cycle.isEmpty()) {
                    long[] dp = new long[M + 1];
                    Arrays.fill(dp, 1);

                    for (int node : cycle) {
                        for (int child : adj[node]) {
                            if (!isInCycle(child, cycle)) {
                                long[] childDP = solveTree(child, M, adj, cycle);
                                for (int j = 1; j <= M; j++) {
                                    dp[j] = (dp[j] * childDP[j]) % MOD;
                                }
                            }
                        }
                    }

                    long ways = 0;
                    for (int j = 1; j <= M; j++) {
                        ways = (ways + dp[j]) % MOD;
                    }
                    totalWays = (totalWays * ways) % MOD;
                }
            }
        }

        System.out.println(totalWays);
    }

    private static void resetOnStack(boolean[] onStack, int start) {
        int curr = start;
        while (curr != 0 && onStack[curr]) {
            onStack[curr] = false;
            curr = 0; 
        }
    }

    private static boolean isInCycle(int node, List<Integer> cycle) {
        for (int c : cycle) if (c == node) return true;
        return false;
    }

    private static long[] solveTree(int u, int M, List<Integer>[] adj, List<Integer> cycle) {
        long[] dp = new long[M + 1];
        Arrays.fill(dp, 1);
        for (int v : adj[u]) {
            long[] childDP = solveTree(v, M, adj, cycle);
            for (int j = 1; j <= M; j++) {
                dp[j] = (dp[j] * childDP[j]) % MOD;
            }
        }
        long[] prefixSum = new long[M + 1];
        for (int j = 1; j <= M; j++) {
            prefixSum[j] = (prefixSum[j - 1] + dp[j]) % MOD;
        }
        return prefixSum;
    }
