func canReach(N int64, hazards [][2]int64, A, B int64) bool {
    visited := make(map[int64]bool)
    queue := []int64{1}
    visited[1] = true

    for len(queue) > 0 {
        pos := queue[0]
        queue = queue[1:]

        for d := A; d <= B; d++ {
            next := pos + d
            if next > N {
                continue
            }
            if next == N {
                return true
            }

            if isInHazard(next, hazards) {
                continue
            }

            if visited[next] {
                continue
            }

            canReachN := false
            for dd := A; dd <= B; dd++ {
                if next+dd == N {
                    canReachN = true
                    break
                }
            }
            if canReachN {
                return true
            }

            shouldTrack := false
            for _, h := range hazards {
                if next >= h[0]-B && next <= h[1]+B {
                    shouldTrack = true
                    break
                }
            }

            if !shouldTrack {
                hIdx := findNextHazard(next, hazards)
                if hIdx < len(hazards) {
                    gap := hazards[hIdx][0] - next
                    if gap > B {
                        normalized := ((next - 1) % (B - A + 1))
                        if visited[normalized+1000000000] {
                            continue
                        }
                        visited[normalized+1000000000] = true

                        jumpToPos := hazards[hIdx][0] - B
                        for offset := int64(0); offset < B-A+1; offset++ {
                            checkPos := jumpToPos + offset
                            if checkPos > next && checkPos < hazards[hIdx][0] {
                                if ((checkPos-1)%(B-A+1)) == normalized {
                                    queue = append(queue, checkPos)
                                    visited[checkPos] = true
                                    break
                                }
                            }
                        }
                        continue
                    }
                } else {
                    if N-next > B {
                        normalized := ((next - 1) % (B - A + 1))
                        if visited[normalized+1000000000] {
                            continue
                        }
                        visited[normalized+1000000000] = true

                        for offset := int64(0); offset < B-A+1; offset++ {
                            checkPos := N - B + offset
                            if checkPos > next && checkPos < N {
                                if ((checkPos-1)%(B-A+1)) == normalized {
                                    queue = append(queue, checkPos)
                                    visited[checkPos] = true
                                    break
                                }
                            }
                        }
                        continue
                    }
                }
            }

            visited[next] = true
            queue = append(queue, next)
        }
    }

    return false
}

func isInHazard(pos int64, hazards [][2]int64) bool {
    for _, h := range hazards {
        if pos >= h[0] && pos <= h[1] {
            return true
        }
    }
    return false
}

func findNextHazard(pos int64, hazards [][2]int64) int {
    for i, h := range hazards {
        if h[0] > pos {
            return i
        }
    }
    return len(hazards)
}

