            long pos = queue.poll();

            if (pos == N) {
                return true;
            }

            for (int d = A; d <= B; d++) {
                long next = pos + d;

                if (next > N) continue;
                if (visited.contains(next)) continue;
                if (isHazardous(next, hazards)) continue;

                visited.add(next);
