                    long nextCritical = getNextCritical(next, N, hazards);
                    if (nextCritical - next <= B) {
                        if (!visited.contains(nextCritical)) {
                            visited.add(nextCritical);
                            queue.add(nextCritical);
                        }
                    }
                }
            }
        }

        return false;
    }

    static boolean isHazardous(long pos, long[][] hazards) {
        for (long[] h : hazards) {
            if (pos >= h[0] && pos <= h[1]) {
                return true;
            }
        }
        return false;
    }

    static boolean shouldTrack(long pos, long N, long[][] hazards, int B) {
        if (pos == N) return true;

        for (long[] h : hazards) {
            if (Math.abs(pos - h[0]) <= B || Math.abs(pos - h[1]) <= B) {
                return true;
            }
        }

        if (N - pos <= B) return true;

        return false;
    }

    static long getNextCritical(long pos, long N, long[][] hazards) {
        long next = N;
        for (long[] h : hazards) {
            if (h[0] > pos) {
                next = Math.min(next, h[0] - 1);
                break;
            }
        }
        return next;
    }
