        if i + 1 < n_critical:
            next_critical = critical_positions[i + 1]
            gap = next_critical - curr_pos

            if gap > B:
                can_bridge = False
                for d in range(A, B + 1):
                    target = curr_pos + d
                    if target < next_critical and not is_hazardous(target):
                        can_bridge = True
                        break

                if can_bridge:
                    pos = curr_pos
                    while pos < next_critical:
                        moved = False
                        for d in range(A, B + 1):
                            new_pos = pos + d
                            if new_pos >= next_critical:
                                break
                            if not is_hazardous(new_pos):
                                pos = new_pos
                                moved = True
                                break
                        if not moved:
                            can_bridge = False
                            break

                    if can_bridge and next_critical - pos <= B and next_critical - pos >= A:
                        reachable[i + 1] = True

    if reachable[pos_to_idx[N]]:
        print("Yes")
    else:
        print("No")

