typedef long long ll;

struct Matrix {
    bool mat[20][20];
    int size;
    Matrix(int s) : size(s) {
        for (int i = 0; i < size; ++i)
            for (int j = 0; j < size; ++j)
                mat[i][j] = false;
    }
};

Matrix multiply(const Matrix& A, const Matrix& B) {
    Matrix C(A.size);
    for (int i = 0; i < A.size; ++i) {
        for (int k = 0; k < A.size; ++k) {
            if (A.mat[i][k]) {
                for (int j = 0; j < A.size; ++j) {
                    if (B.mat[k][j]) C.mat[i][j] = true;
                }
            }
        }
    }
    return C;
}

Matrix power(Matrix A, ll p) {
    Matrix res(A.size);
    for (int i = 0; i < A.size; ++i) res.mat[i][i] = true;
    while (p > 0) {
        if (p & 1) res = multiply(res, A);
        A = multiply(A, A);
        p >>= 1;
    }
    return res;
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    ll N;
    int M, A, B;
    if (!(cin >> N >> M >> A >> B)) return 0;

    vector<pair<ll, ll>> hazards(M);
    for (int i = 0; i < M; ++i) {
        cin >> hazards[i].first >> hazards[i].second;
    }

    Matrix T(B);
    for (int i = 0; i < B - 1; ++i) T.mat[i][i + 1] = true;
    for (int d = A; d <= B; ++d) T.mat[B - 1][B - d] = true;

    vector<bool> dp(B, false);
    dp[B - 1] = true;

    ll current_pos = 1;

    for (int i = 0; i <= M; ++i) {
        ll next_stop = (i < M) ? hazards[i].first : N;
        ll dist = next_stop - current_pos;

        if (dist > 0) {
            Matrix step = power(T, dist);
            vector<bool> next_dp(B, false);
            for (int j = 0; j < B; ++j) {
                for (int k = 0; k < B; ++k) {
                    if (dp[k] && step.mat[j][k]) next_dp[j] = true;
                }
            }
            dp = next_dp;
        }

        if (i < M) {
            ll h_len = hazards[i].second - hazards[i].first + 1;
            for (int j = 0; j < B; ++j) {
                if (B - 1 - j < h_len) dp[j] = false;
            }
            current_pos = hazards[i].second;

            ll jump_after = 1;
            Matrix step = power(T, jump_after);
            vector<bool> next_dp(B, false);
            for (int j = 0; j < B; ++j) {
                for (int k = 0; k < B; ++k) {
                    if (dp[k] && step.mat[j][k]) next_dp[j] = true;
                }
            }
            dp = next_dp;
            current_pos += jump_after;
        }
    }

    if (dp[B - 1]) cout << "Yes" << endl;
    else cout << "No" << endl;

    return 0;
}

