func multiply(m1, m2 Matrix, size int) Matrix {
	var res Matrix
	for i := 0; i < size; i++ {
		for k := 0; k < size; k++ {
			if m1[i][k] {
				for j := 0; j < size; j++ {
					if m2[k][j] {
						res[i][j] = true
					}
				}
			}
		}
	}
	return res
}

func power(m Matrix, p int64, size int) Matrix {
	var res Matrix
	for i := 0; i < size; i++ {
		res[i][i] = true
	}
	for p > 0 {
		if p%2 == 1 {
			res = multiply(res, m, size)
		}
		m = multiply(m, m, size)
		p /= 2
	}
	return res
}

