public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        if (!sc.hasNextLong()) return;
        long n = sc.nextLong();
        int m = sc.nextInt();
        int a = sc.nextInt();
        int b = sc.nextInt();

        long[][] intervals = new long[m][2];
        for (int i = 0; i < m; i++) {
            intervals[i][0] = sc.nextLong();
            intervals[i][1] = sc.nextLong();
        }

        long currentPos = 1;
        int stateMask = 1; 

        for (int i = 0; i < m; i++) {
            long targetStart = intervals[i][0];
            long gap = targetStart - currentPos;
            stateMask = power(stateMask, gap, a, b);
            currentPos = targetStart;

            long targetEnd = intervals[i][1];
            long duration = targetEnd - currentPos + 1;
            stateMask = clearBits(stateMask, duration);
            currentPos = targetEnd + 1;
        }

        long finalGap = n - currentPos;
        stateMask = power(stateMask, finalGap, a, b);

        if ((stateMask & 1) != 0) {
            System.out.println("Yes");
        } else {
            System.out.println("No");
        }
    }

    private static int transition(int mask, int a, int b) {
        int nextMask = 0;
        for (int i = a; i <= b; i++) {
            nextMask |= (mask << i);
        }
        return nextMask & ((1 << 21) - 1);
    }

    private static int step(int mask, int a, int b) {
        int nextMask = 0;
        for (int j = 0; j < 20; j++) {
            if (((mask >> (j + 1)) & 1) != 0) {
                nextMask |= (1 << j);
            }
        }
        for (int i = a; i <= b; i++) {
            if ((mask & 1) != 1) continue;
            if (i - 1 < 21) {
                nextMask |= (1 << (i - 1));
            }
        }
        return nextMask & ((1 << 21) - 1);
    }

    private static int power(int mask, long steps, int a, int b) {
        if (steps <= 0) return mask;
        int[] memo = new int[1 << 20];
        Arrays.fill(memo, -1);
        List<Integer> history = new ArrayList<>();

        int curr = mask;
        for (long i = 0; i < steps; i++) {
            if (memo[curr] != -1) {
                int startIdx = memo[curr];
                int cycleLen = history.size() - startIdx;
                long remaining = steps - i;
                return history.get(startIdx + (int)(remaining % cycleLen));
            }
            memo[curr] = history.size();
            history.add(curr);
            curr = step(curr, a, b);
        }
        return curr;
    }

    private static int clearBits(int mask, long duration) {
        for (int i = 0; i < duration && i < 21; i++) {
            mask &= ~(1 << i);
        }
        return mask;
    }
}

import sys

def solve():
    input_data = sys.stdin.read().split()
    if not input_data:
        return

    N = int(input_data[0])
    M = int(input_data[1])
    A = int(input_data[2])
    B = int(input_data[3])

    hazards = []
    idx = 4
    for _ in range(M):
        s = int(input_data[idx])
        e = int(input_data[idx+1])
        hazards.append((s, e))
        idx += 2

    points = {1, N}
    for s, e in hazards:
        for offset in range(-B, B + 1):
            if 1 <= s + offset <= N:
                points.add(s + offset)
            if 1 <= e + offset <= N:
                points.add(e + offset)

    sorted_points = sorted(list(points))
    point_to_idx = {p: i for i, p in enumerate(sorted_points)}
    num_points = len(sorted_points)

    reachable = [False] * num_points
    reachable[0] = True

    hazard_ptr = 0

    for i in range(num_points):
        if not reachable[i]:
            continue

        curr_pos = sorted_points[i]

        while hazard_ptr < M and hazards[hazard_ptr][1] < curr_pos:
            hazard_ptr += 1

        next_idx = i + 1
        while next_idx < num_points:
            next_pos = sorted_points[next_idx]
            dist = next_pos - curr_pos

            if dist > B:
                break

            if dist >= A:
                is_hazardous = False
                temp_ptr = hazard_ptr
                while temp_ptr < M and hazards[temp_ptr][0] <= next_pos:
                    if hazards[temp_ptr][0] <= next_pos <= hazards[temp_ptr][1]:
                        is_hazardous = True
                        break
                    temp_ptr += 1

                if not is_hazardous:
                    reachable[next_idx] = True

            next_idx += 1

    if reachable[point_to_idx[N]]:
        print("Yes")
    else:
        print("No")

