func maxTowers(weights []int) int {
    n := len(weights)
    if n < 2 {
        return 0
    }

    used := make([]bool, n)
    towers := 0

    for i := 0; i < n; i++ {
        if used[i] {
            continue
        }
        for j := i + 1; j < n; j++ {
            if used[j] {
                continue
            }
            if weights[i]*2 <= weights[j] {
                used[i] = true
                used[j] = true
                towers++
                break
            }
        }
    }

    return towers
}

