        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        PrintWriter pw = new PrintWriter(System.out);

        int N = Integer.parseInt(br.readLine());
        String[] parts = br.readLine().split(" ");
        long[] W = new long[N + 1];
        for (int i = 1; i <= N; i++) {
            W[i] = Long.parseLong(parts[i - 1]);
        }

        int Q = Integer.parseInt(br.readLine());
        for (int q = 0; q < Q; q++) {
            parts = br.readLine().split(" ");
            int L = Integer.parseInt(parts[0]);
            int R = Integer.parseInt(parts[1]);

            int result = solve(W, L, R);
            pw.println(result);
        }

        pw.flush();
        pw.close();
    }

    static int solve(long[] W, int L, int R) {
        int n = R - L + 1;
        long[] stones = new long[n];
        for (int i = 0; i < n; i++) {
            stones[i] = W[L + i];
        }

        boolean[] used = new boolean[n];
        int towers = 0;

        for (int bottom = n - 1; bottom >= 0; bottom--) {
            if (used[bottom]) continue;

            int bestTop = -1;
            for (int top = bottom - 1; top >= 0; top--) {
                if (used[top]) continue;
                if (stones[top] * 2 <= stones[bottom]) {
                    if (bestTop == -1 || stones[top] > stones[bestTop]) {
                        bestTop = top;
                    }
                }
            }

            if (bestTop != -1) {
                used[bottom] = true;
                used[bestTop] = true;
                towers++;
            }
        }

        return towers;
    }
}

