using namespace std;

long long sumOfSquares(long long k) {
    return k * (k + 1) * (2 * k + 1) / 6;
}

bool canAchieve(long long rounds, const vector<long long>& D, long long M) {
    long long N = D.size();
    long long totalCost = 0;

    vector<long long> sortedD = D;
    sort(sortedD.begin(), sortedD.end());

    for (int i = 0; i < N && rounds > 0; i++) {
        long long roundsHere = min(rounds, rounds / (N - i) + (rounds % (N - i) > 0 ? 1 : 0));

        if (i == N - 1) {
            roundsHere = rounds;
        }

        long long cost = sumOfSquares(roundsHere) * sortedD[i];

        if (cost > M - totalCost) {
            return false;
        }

        totalCost += cost;
        rounds -= roundsHere;
    }

    return rounds == 0;
}

bool canAchieveGreedy(long long rounds, const vector<long long>& D, long long M) {
    long long N = D.size();
    long long totalCost = 0;

    vector<long long> sortedD = D;
    sort(sortedD.begin(), sortedD.end());

    long long fullRounds = rounds / N;
    long long extraRounds = rounds % N;

    for (int i = 0; i < N; i++) {
        long long roundsHere = fullRounds + (i < extraRounds ? 1 : 0);
        long long cost = sumOfSquares(roundsHere) * sortedD[i];

        if (M - totalCost < cost) {
            return false;
        }

        totalCost += cost;
    }

    return true;
}

