func canAchieve(d []int, m int64, target int64) bool {
    cost := int64(0)
    rounds := int64(0)

    for i := 0; i < len(d) && rounds < target; i++ {
        remaining := target - rounds
        maxRounds := remaining

        for k := int64(1); k <= maxRounds; k++ {
            newCost := k * k * int64(d[i])
            if cost + newCost > m {
                break
            }
            cost += newCost
            rounds++
            if rounds >= target {
                break
            }
        }
    }

    return rounds >= target
}

func canAchieveOptimal(d []int, m int64, target int64) bool {
    n := len(d)
    rounds := make([]int64, n)
    totalRounds := int64(0)
    totalCost := int64(0)

    for totalRounds < target {
        bestIdx := -1
        bestCost := int64(1e18 + 1)

        for i := 0; i < n; i++ {
            nextRounds := rounds[i] + 1
            incrementalCost := (2*nextRounds - 1) * int64(d[i])
            if incrementalCost < bestCost {
                bestCost = incrementalCost
                bestIdx = i
            }
        }

        if totalCost + bestCost > m {
            return false
        }

        rounds[bestIdx]++
        totalCost += bestCost
        totalRounds++
    }

    return true
}

