}

import java.util.*;
import java.io.*;

public class Main {

    static class Challenge {
        long d;
        long rounds;

        Challenge(long d) {
            this.d = d;
            this.rounds = 0;
        }

        long marginalCost() {
            return (2 * rounds + 1) * d;
        }
    }

    static boolean canAchieve(long targetRounds, long[] D, long M) {
        int n = D.length;
        PriorityQueue<Challenge> pq = new PriorityQueue<>((a, b) -> {
            long diff = a.marginalCost() - b.marginalCost();
            if (diff < 0) return -1;
            if (diff > 0) return 1;
            return 0;
        });

        for (long d : D) {
            pq.offer(new Challenge(d));
        }

        long totalCost = 0;
        long roundsAssigned = 0;

        while (roundsAssigned < targetRounds) {
            Challenge c = pq.poll();
            long cost = c.marginalCost();

            if (totalCost > M - cost) {
                return false;
            }

            totalCost += cost;
            c.rounds++;
            roundsAssigned++;
            pq.offer(c);
        }

        return totalCost <= M;
    }

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String[] firstLine = br.readLine().split(" ");
        int N = Integer.parseInt(firstLine[0]);
        long M = Long.parseLong(firstLine[1]);

        String[] secondLine = br.readLine().split(" ");
        long[] D = new long[N];
        for (int i = 0; i < N; i++) {
            D[i] = Long.parseLong(secondLine[i]);
        }

        long left = 0;
        long right = 2000000000L;
        long answer = 0;

        while (left <= right) {
            long mid = left + (right - left) / 2;
            if (canAchieve(mid, D, M)) {
                answer = mid;
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }

        System.out.println(answer);
    }
}

