    while (low <= high) {
        long long mid = low + (high - low) / 2;
        int128 total_cost = 0;
        for (int i = 0; i < n; ++i) {
            if (mid < d[i]) continue;
            long long k = (mid / d[i] - 1) / 2 + 1;
            total_cost += (int128)d[i] * k * k;
            if (total_cost > m) break;
        }
        if (total_cost <= m) {
            threshold = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    long long total_rounds = 0;
    int128 current_cost = 0;
    vector<pair<long long, int>> next_costs;

    for (int i = 0; i < n; ++i) {
        long long k = 0;
        if (threshold >= d[i]) {
            k = (threshold / d[i] - 1) / 2 + 1;
        }
        current_cost += (int128)d[i] * k * k;
        total_rounds += k;
        next_costs.push_back({(long long)get_cost_diff(d[i], k), i});
