		tree[2*node].minVal += lz
		tree[2*node].maxVal += lz
		tree[2*node].lazy += lz
		tree[2*node+1].minVal += lz
		tree[2*node+1].maxVal += lz
		tree[2*node+1].lazy += lz
		tree[node].lazy = 0
	}
}

func update(tree []Node, node, start, end, l, r int) {
	if tree[node].minVal > r || tree[node].maxVal < l {
		return
	}
	if tree[node].minVal >= l && tree[node].maxVal <= r {
		tree[node].minVal++
		tree[node].maxVal++
		tree[node].lazy++
		return
	}
	push(tree, node)
	mid := (start + end) / 2
	update(tree, 2*node, start, mid, l, r)
	update(tree, 2*node+1, mid+1, end, l, r)
	tree[node].minVal = tree[2*node].minVal
	tree[node].maxVal = tree[2*node+1].maxVal
}

func query(tree []Node, node, start, end, idx int) int {
	if start == end {
		return tree[node].minVal
	}
	push(tree, node)
	mid := (start + end) / 2
	if idx <= mid {
		return query(tree, 2*node, start, mid, idx)
	} else {
		return query(tree, 2*node+1, mid+1, end, idx)
	}
}

