bool check_parity(const vector<bool>& used_edges) {
    vector<vector<int>> adj(N);
    for (int i = 0; i < total_edges; i++) {
        if (used_edges[i]) {
            int u = all_edges[i].first;
            int v = all_edges[i].second;
            adj[u].push_back(v);
            adj[v].push_back(u);
        }
    }

    vector<int> dist(N, -1);
    queue<int> q;
    q.push(0);
    dist[0] = 0;

    while (!q.empty()) {
        int u = q.front();
        q.pop();
        for (int v : adj[u]) {
            if (dist[v] == -1) {
                dist[v] = dist[u] + 1;
                q.push(v);
            }
        }
    }

    int even_count = 0, odd_count = 0;
    for (int i = 0; i < N; i++) {
        if (dist[i] % 2 == 0) even_count++;
        else odd_count++;
    }

    return even_count == N/2 && odd_count == N/2;
}

