func isConnected(N int, edges [][2]int) bool {
	adj := make([][]int, N+1)
	for i := 0; i <= N; i++ {
		adj[i] = make([]int, 0)
	}

	for _, edge := range edges {
		u, v := edge[0], edge[1]
		adj[u] = append(adj[u], v)
		adj[v] = append(adj[v], u)
	}

	visited := make([]bool, N+1)
	queue := []int{1}
	visited[1] = true
	count := 1

	for len(queue) > 0 {
		node := queue[0]
		queue = queue[1:]

		for _, neighbor := range adj[node] {
			if !visited[neighbor] {
				visited[neighbor] = true
				count++
				queue = append(queue, neighbor)
			}
		}
	}

	return count == N
}

func bfs(N int, edges [][2]int) []int {
	adj := make([][]int, N+1)
	for i := 0; i <= N; i++ {
		adj[i] = make([]int, 0)
	}

	for _, edge := range edges {
		u, v := edge[0], edge[1]
		adj[u] = append(adj[u], v)
		adj[v] = append(adj[v], u)
	}

	dist := make([]int, N+1)
	for i := 0; i <= N; i++ {
		dist[i] = -1
	}

	queue := []int{1}
	dist[1] = 0

	for len(queue) > 0 {
		node := queue[0]
		queue = queue[1:]

		for _, neighbor := range adj[node] {
			if dist[neighbor] == -1 {
				dist[neighbor] = dist[node] + 1
				queue = append(queue, neighbor)
			}
		}
	}

	return dist
}

