        MOD = P;

        int maxEdges = N * (N - 1) / 2;
        int minEdges = N - 1;

        long[] results = new long[maxEdges - minEdges + 1];

        int[][] allEdges = new int[maxEdges][2];
        int idx = 0;
        for (int i = 1; i <= N; i++) {
            for (int j = i + 1; j <= N; j++) {
                allEdges[idx][0] = i;
                allEdges[idx][1] = j;
                idx++;
            }
        }

        for (int m = minEdges; m <= maxEdges; m++) {
            results[m - minEdges] = countValidGraphs(m, allEdges);
        }

        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < results.length; i++) {
            if (i > 0) sb.append(" ");
            sb.append(results[i]);
        }
        System.out.println(sb.toString());
    }

    static long countValidGraphs(int m, int[][] allEdges) {
        int totalEdges = allEdges.length;
        long count = 0;

        count = enumerateGraphs(0, 0, m, allEdges, new boolean[totalEdges], totalEdges);

        return count % MOD;
    }

    static long enumerateGraphs(int start, int current, int target, int[][] allEdges, boolean[] selected, int total) {
        if (current == target) {
            if (isConnectedAndValid(allEdges, selected)) {
                return 1;
            }
            return 0;
        }

        if (start >= total) return 0;

        long count = 0;

        for (int i = start; i <= total - (target - current); i++) {
            selected[i] = true;
            count += enumerateGraphs(i + 1, current + 1, target, allEdges, selected, total);
            count %= MOD;
            selected[i] = false;
