                graph[u].add(v);
                graph[v].add(u);
            }
        }

        int[] dist = new int[N + 1];
        Arrays.fill(dist, -1);
        Queue<Integer> q = new LinkedList<>();
        q.add(1);
        dist[1] = 0;
        int visited = 1;

        while (!q.isEmpty()) {
            int u = q.poll();
            for (int v : graph[u]) {
                if (dist[v] == -1) {
                    dist[v] = dist[u] + 1;
                    q.add(v);
                    visited++;
                }
            }
        }

        if (visited != N) return false;

        int evenCount = 0;
        int oddCount = 0;
        for (int i = 1; i <= N; i++) {
            if (dist[i] % 2 == 0) {
                evenCount++;
            } else {
                oddCount++;
            }
        }

        return evenCount == oddCount;
