func main() {
	var n int
	fmt.Scan(&n)

	jars := make([]int64, n)
	for i := 0; i < n; i++ {
		fmt.Scan(&jars[i])
	}

	type State struct {
		jars []int64
	}

	stateToKey := func(jars []int64) string {
		sorted := make([]int64, len(jars))
		copy(sorted, jars)
		sort.Slice(sorted, func(i, j int) bool {
			return sorted[i] < sorted[j]
		})
		key := ""
		for _, v := range sorted {
			key += fmt.Sprintf("%d,", v)
		}
		return key
	}

	visited := make(map[string]bool)
	xorResults := make(map[int64]bool)

	queue := [][]int64{jars}
	visited[stateToKey(jars)] = true

	for len(queue) > 0 {
		current := queue[0]
		queue = queue[1:]

		xorVal := int64(0)
		for _, v := range current {
			xorVal ^= v
		}
		xorResults[xorVal] = true

		n := len(current)
		for i := 0; i < n; i++ {
			for j := 0; j < n; j++ {
				if i == j {
					continue
				}

				next := make([]int64, 0, n-1)
				for k := 0; k < n; k++ {
					if k == i {
						continue
					} else if k == j {
						next = append(next, current[i]+current[j])
					} else {
						next = append(next, current[k])
					}
				}

				key := stateToKey(next)
				if !visited[key] {
					visited[key] = true
					queue = append(queue, next)
				}
			}
		}
	}

	fmt.Println(len(xorResults))
}

