public class Main {
    static int N;
    static long[] M;
    static Set<Long> results;

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        N = Integer.parseInt(br.readLine());
        String[] parts = br.readLine().split(" ");
        M = new long[N];
        for (int i = 0; i < N; i++) {
            M[i] = Long.parseLong(parts[i]);
        }

        results = new HashSet<>();
        long[] initial = new long[N];
        System.arraycopy(M, 0, initial, 0, N);

        Set<String> visited = new HashSet<>();
        dfs(initial, visited);

        System.out.println(results.size());
    }

    static void dfs(long[] state, Set<String> visited) {
        String key = arrayToString(state);
        if (visited.contains(key)) {
            return;
        }
        visited.add(key);

        long xor = 0;
        for (int i = 0; i < N; i++) {
            xor ^= state[i];
        }
        results.add(xor);

        for (int i = 0; i < N; i++) {
            if (state[i] == 0) continue;
            for (int j = 0; j < N; j++) {
                if (i == j) continue;
                long[] newState = new long[N];
                System.arraycopy(state, 0, newState, 0, N);
                newState[j] += newState[i];
                newState[i] = 0;
                dfs(newState, visited);
            }
        }
    }

    static String arrayToString(long[] arr) {
        long[] sorted = arr.clone();
        Arrays.sort(sorted);
        StringBuilder sb = new StringBuilder();
        for (long x : sorted) {
            sb.append(x).append(",");
        }
        return sb.toString();
    }
}

