        for (int w = X; w >= W[i]; w--) {
            for (int f = minEnergy; f >= 0; f--) {
                for (int wa = minEnergy; wa >= 0; wa--) {
                    if (dp[w - W[i]][f][wa] == -1) continue;

                    int newF = f;
                    int newWa = wa;
                    int newE = dp[w - W[i]][f][wa];

                    if (R[i] == 1) {
                        newF = min(minEnergy, f + B[i]);
                    } else if (R[i] == 2) {
                        newWa = min(minEnergy, wa + B[i]);
                    } else {
                        newE = newE + B[i];
                    }

                    dp[w][newF][newWa] = max(dp[w][newF][newWa], newE);
                }
            }
        }
    }

    for (int w = 0; w <= X; w++) {
        if (dp[w][minEnergy][minEnergy] >= minEnergy) {
            return true;
        }
    }

    return false;
}

