func solve() {
	reader := bufio.NewReader(os.Stdin)
	var n, x int
	fmt.Fscan(reader, &n, &x)

	type relic struct {
		b, w int
	}

	var fire, water, earth []relic
	for i := 0; i < n; i++ {
		var r, b, w int
		fmt.Fscan(reader, &r, &b, &w)
		if r == 1 {
			fire = append(fire, relic{b, w})
		} else if r == 2 {
			water = append(water, relic{b, w})
		} else {
			earth = append(earth, relic{b, w})
		}
	}

	getMinWeight := func(relics []relic, target int) []int {
		dp := make([]int, x+1)
		for i := range dp {
			dp[i] = -1
		}
		dp[0] = 0
		for _, r := range relics {
			for j := x; j >= r.w; j-- {
				if dp[j-r.w] != -1 {
					val := dp[j-r.w] + r.b
					if val > dp[j] {
						dp[j] = val
					}
				}
			}
		}

		minWForTarget := make([]int, target+1)
		for i := range minWForTarget {
			minWForTarget[i] = x + 1
		}

		for w := 0; w <= x; w++ {
			if dp[w] != -1 {
				energy := dp[w]
				if energy > target {
					energy = target
				}
				if w < minWForTarget[energy] {
					minWForTarget[energy] = w
				}
			}
		}

		for i := target - 1; i >= 0; i-- {
			if minWForTarget[i+1] < minWForTarget[i] {
				minWForTarget[i] = minWForTarget[i+1]
			}
		}
		return minWForTarget
	}

	check := func(v int) bool {
		if v == 0 {
			return true
		}
		w1 := getMinWeight(fire, v)
		w2 := getMinWeight(water, v)
		w3 := getMinWeight(earth, v)

		if w1[v] > x || w2[v] > x || w3[v] > x {
			return false
		}
		return w1[v]+w2[v]+w3[v] <= x
	}

	low, high := 0, 1000000000
	ans := 0
	for low <= high {
		mid := (low + high) / 2
		if check(mid) {
			ans = mid
			low = mid + 1
		} else {
			high = mid - 1
		}
	}
	fmt.Println(ans)
}

