            this.r = r;
            this.b = b;
            this.w = w;
        }
    }

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int N = Integer.parseInt(st.nextToken());
        int X = Integer.parseInt(st.nextToken());

        List<Relic> fire = new ArrayList<>();
        List<Relic> water = new ArrayList<>();
        List<Relic> earth = new ArrayList<>();

        for (int i = 0; i < N; i++) {
            st = new StringTokenizer(br.readLine());
            int r = Integer.parseInt(st.nextToken());
            int b = Integer.parseInt(st.nextToken());
            int w = Integer.parseInt(st.nextToken());
            if (r == 1) fire.add(new Relic(r, b, w));
            else if (r == 2) water.add(new Relic(r, b, w));
            else earth.add(new Relic(r, b, w));
        }

        int low = 0, high = N * 200000, ans = 0;
        while (low <= high) {
            int mid = low + (high - low) / 2;
            if (check(mid, X, fire, water, earth)) {
                ans = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        System.out.println(ans);
    }

    private static boolean check(int target, int X, List<Relic> f, List<Relic> w, List<Relic> e) {
        if (target == 0) return true;
        long w1 = getMinWeight(f, target);
        long w2 = getMinWeight(w, target);
        long w3 = getMinWeight(e, target);
        if (w1 > X || w2 > X || w3 > X) return false;
        return (w1 + w2 + w3) <= (long) X;
    }

    private static long getMinWeight(List<Relic> relics, int target) {
        if (target <= 0) return 0;
        int maxB = 0;
        for (Relic r : relics) maxB += r.b;
        if (maxB < target) return 1000000000L;

        int[] dp = new int[target + 1];
        Arrays.fill(dp, 1000000000);
        dp[0] = 0;
        for (Relic r : relics) {
            for (int j = target; j >= 0; j--) {
                if (dp[j] == 1000000000) continue;
                int nextB = Math.min(target, j + r.b);
                dp[nextB] = Math.min(dp[nextB], dp[j] + r.w);
            }
        }
        return (long) dp[target];
    }
}

using namespace std;

int computeG(vector<int>& elements) {
    if (elements.empty()) return 0;

    multiset<int> logbook(elements.begin(), elements.end());
    int operations = 0;

    while (!logbook.empty()) {
        int minVal = *logbook.begin();
        int maxVal = minVal;

        bool changed = true;
        while (changed) {
            changed = false;
            for (int val = minVal; val <= maxVal; val++) {
                if (logbook.find(val) == logbook.end()) {
                    return -1;
                }
            }

            int newMax = maxVal;
            for (int val = minVal; val <= maxVal; val++) {
                auto it = logbook.find(val);
                while (it != logbook.end() && *it == val) {
                    newMax = max(newMax, *it);
                    ++it;
                }
            }

            set<int> uniqueInRange;
            for (auto it = logbook.begin(); it != logbook.end(); ++it) {
                if (*it >= minVal && *it <= maxVal) {
                    uniqueInRange.insert(*it);
                }
            }
            for (int x : uniqueInRange) {
                newMax = max(newMax, x);
            }

            if (newMax > maxVal) {
                maxVal = newMax;
                changed = true;
            }
        }

        for (int val = minVal; val <= maxVal; val++) {
            while (logbook.find(val) != logbook.end()) {
                logbook.erase(logbook.find(val));
            }
        }

        operations++;
    }

    return operations;
}

int main() {
    int n;
    cin >> n;
    vector<int> S(n);
    for (int i = 0; i < n; i++) {
