    for (int i = 0; i < n; i++) {
        for (int j = i; j < n; j++) {
            vector<int> segment(S.begin() + i, S.begin() + j + 1);
            int g = computeG(segment);
            total += g;
        }
    }

    cout << total << endl;

    return 0;
}

