func computeG(arr []int) int {
	if len(arr) == 0 {
		return 0
	}

	present := make(map[int]bool)
	for _, v := range arr {
		present[v] = true
	}

	memo := make(map[string]int)
	return solveWithMemo(arr, present, memo)
}

func solveWithMemo(arr []int, present map[int]bool, memo map[string]int) int {
	if len(arr) == 0 {
		return 0
	}

	key := makeKey(arr)
	if val, ok := memo[key]; ok {
		return val
	}

	minVal := arr[0]
	maxVal := arr[0]
	for _, v := range arr {
		if v < minVal {
			minVal = v
		}
		if v > maxVal {
			maxVal = v
		}
	}

	result := len(arr)

	for a := minVal; a <= maxVal; a++ {
		for b := a; b <= maxVal; b++ {
			if canRemove(a, b, present) {
				newArr := removeRange(arr, a, b)
				newPresent := make(map[int]bool)
				for _, v := range newArr {
					newPresent[v] = true
				}
				result = min(result, 1+solveWithMemo(newArr, newPresent, memo))
			}
		}
	}

	memo[key] = result
	return result
}

func canRemove(a, b int, present map[int]bool) bool {
	for i := a; i <= b; i++ {
		if !present[i] {
			return false
		}
	}
	return true
}

func removeRange(arr []int, a, b int) []int {
	result := make([]int, 0)
	for _, v := range arr {
		if v < a || v > b {
			result = append(result, v)
		}
	}
	return result
}

func makeKey(arr []int) string {
	key := ""
	for i, v := range arr {
		if i > 0 {
			key += ","
		}
		key += fmt.Sprintf("%d", v)
	}
	return key
}

func min(a, b int) int {
	if a < b {
		return a
	}
	return b
}

