public class Main {

    static int computeG(List<Integer> segment) {
        Set<Integer> distinctSet = new HashSet<>(segment);
        if (distinctSet.isEmpty()) return 0;

        List<Integer> distinct = new ArrayList<>(distinctSet);
        Collections.sort(distinct);

        int k = distinct.size();
        Map<Integer, Integer> valueToIndex = new HashMap<>();
        for (int i = 0; i < k; i++) {
            valueToIndex.put(distinct.get(i), i);
        }

        int[] dp = new int[1 << k];
        Arrays.fill(dp, Integer.MAX_VALUE);
        dp[0] = 0;

        for (int mask = 0; mask < (1 << k); mask++) {
            if (dp[mask] == Integer.MAX_VALUE) continue;

            int firstZero = -1;
            for (int i = 0; i < k; i++) {
                if ((mask & (1 << i)) == 0) {
                    firstZero = i;
                    break;
                }
            }
            if (firstZero == -1) continue;

            for (int last = firstZero; last < k; last++) {
                int a = distinct.get(firstZero);
                int b = distinct.get(last);

                boolean canRemove = true;
                int newMask = mask;
                for (int val = a; val <= b; val++) {
                    if (distinctSet.contains(val)) {
                        int idx = valueToIndex.get(val);
                        newMask |= (1 << idx);
                    } else {
                        canRemove = false;
                        break;
                    }
                }

                if (canRemove) {
                    dp[newMask] = Math.min(dp[newMask], dp[mask] + 1);
                }
            }
        }

        return dp[(1 << k) - 1];
    }

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int n = Integer.parseInt(br.readLine());
        String[] parts = br.readLine().split(" ");
        int[] S = new int[n];
        for (int i = 0; i < n; i++) {
            S[i] = Integer.parseInt(parts[i]);
        }

        long total = 0;

        for (int i = 0; i < n; i++) {
            List<Integer> segment = new ArrayList<>();
            for (int j = i; j < n; j++) {
                segment.add(S[j]);
                int g = computeG(segment);
                total += g;
            }
        }

        System.out.println(total);
    }
}

def compute_g(subseq):
    if not subseq:
        return 0

    elements = list(subseq)
    operations = 0

    while elements:
        present = set(elements)
        min_val = min(present)
        max_val = max(present)

        best_a = -1
        best_b = -1

        for a in range(min_val, max_val + 1):
            for b in range(a, max_val + 1):
                valid = True
                for x in range(a, b + 1):
                    if x not in present:
                        valid = False
                        break

                if valid:
                    if best_a == -1 or (b - a) < (best_b - best_a):
                        best_a = a
                        best_b = b

        if best_a == -1:
            return float('inf')

        new_elements = []
        for elem in elements:
            if not (best_a <= elem <= best_b):
                new_elements.append(elem)

        elements = new_elements
        operations += 1

    return operations

