using namespace std;

struct Node {
    int min_val;
    int count;
    int lazy;
};

int n;
vector<int> s;
vector<Node> tree;

void build(int node, int start, int end) {
    tree[node].min_val = 0;
    tree[node].count = end - start + 1;
    tree[node].lazy = 0;
    if (start == end) return;
    int mid = (start + end) / 2;
    build(2 * node, start, mid);
    build(2 * node + 1, mid + 1, end);
}

void push(int node) {
    if (tree[node].lazy != 0) {
        tree[2 * node].min_val += tree[node].lazy;
        tree[2 * node].lazy += tree[node].lazy;
        tree[2 * node + 1].min_val += tree[node].lazy;
        tree[2 * node + 1].lazy += tree[node].lazy;
        tree[node].lazy = 0;
    }
}

void update(int node, int start, int end, int l, int r, int val) {
    if (start > end || start > r || end < l) return;
    if (start >= l && end <= r) {
        tree[node].min_val += val;
        tree[node].lazy += val;
        return;
    }
    push(node);
    int mid = (start + end) / 2;
    update(2 * node, start, mid, l, r, val);
    update(2 * node + 1, mid + 1, end, l, r, val);
    tree[node].min_val = min(tree[2 * node].min_val, tree[2 * node + 1].min_val);
    tree[node].count = 0;
    if (tree[node].min_val == tree[2 * node].min_val) tree[node].count += tree[2 * node].count;
    if (tree[node].min_val == tree[2 * node + 1].min_val) tree[node].count += tree[2 * node + 1].count;
}

