func solve() {
	var n int
	reader := bufio.NewReader(os.Stdin)
	fmt.Fscan(reader, &n)
	s := make([]int, n)
	for i := 0; i < n; i++ {
		fmt.Fscan(reader, &s[i])
	}

	left := make([]int, n)
	lastPos := make([]int, n+2)
	for i := 0; i < n; i++ {
		v := s[i]
		l := lastPos[v-1]
		r := lastPos[v+1]
		if l > r {
			left[i] = l
		} else {
			left[i] = r
		}
		lastPos[v] = i + 1
	}

	total := int64(0)
	stack := []int{-1}
	dp := make([]int64, n)

	for i := 0; i < n; i++ {
		for len(stack) > 1 && left[stack[len(stack)-1]] <= left[i] {
			stack = stack[:len(stack)-1]
		}

		prev := stack[len(stack)-1]
		if prev == -1 {
			dp[i] = int64(i+1) * int64(i+1-left[i])
		} else {
			dp[i] = dp[prev] + int64(i-prev)*int64(i+1-left[i])
		}
		stack = append(stack, i)
		total += dp[i]
	}

	fmt.Println(total)
}

