import java.util.*;
import java.io.*;

public class Main {
    static class FastReader {
        private InputStream in;
        private byte[] buffer = new byte[1024 * 8];
        private int pointer = 0;
        private int bufferLength = 0;

        public FastReader(InputStream in) {
            this.in = in;
        }

        private boolean fillBuffer() {
            try {
                bufferLength = in.read(buffer);
                pointer = 0;
                return bufferLength > 0;
            } catch (IOException e) {
                return false;
            }
        }

        private byte readByte() {
            if (pointer >= bufferLength) {
                if (!fillBuffer()) return -1;
            }
            return buffer[pointer++];
        }

        public int nextInt() {
            int c = readByte();
            while (c >= 0 && c <= 32) c = readByte();
            if (c == -1) return -1;
            int res = 0;
            while (c > 32) {
                res = res * 10 + (c - '0');
                c = readByte();
            }
            return res;
        }
    }

    public static void main(String[] args) {
        FastReader fr = new FastReader(System.in);
        int n = fr.nextInt();
        if (n == -1) return;
        int[] s = new int[n];
        for (int i = 0; i < n; i++) {
            s[i] = fr.nextInt();
        }

        long totalSum = 0;
        int[] lastPos = new int[n + 2];
        int[] prevSame = new int[n];
        Arrays.fill(lastPos, -1);
        for (int i = 0; i < n; i++) {
            prevSame[i] = lastPos[s[i]];
            lastPos[s[i]] = i;
        }

        int[] left = new int[n];
        int[] right = new int[n];
        Arrays.fill(left, -1);
        Arrays.fill(right, n);

        int[] stack = new int[n];
        int top = -1;
        for (int i = 0; i < n; i++) {
            while (top >= 0 && s[stack[top]] < s[i]) {
                right[stack[top]] = i;
                top--;
            }
            if (top >= 0) left[i] = stack[top];
            stack[++top] = i;
        }

        for (int i = 0; i < n; i++) {
            int L = left[i];
            int R = right[i];
            int P = prevSame[i];

            int start = Math.max(L, P);
            long count = (long)(i - start) * (R - i);
            totalSum += count;
        }

        System.out.println(totalSum);
    }
}

