            T[i] = row.toCharArray();
        }

        for (int a = 0; a <= N - M; a++) {
            for (int b = 0; b <= N - M; b++) {
                if (check(S, T, a, b, M)) {
                    System.out.println((a + 1) + " " + (b + 1));
                    return;
                }
            }
        }
    }

    private static boolean check(char[][] S, char[][] T, int r, int c, int M) {
        for (int i = 0; i < M; i++) {
            for (int j = 0; j < M; j++) {
                if (S[r + i][c + j] != T[i][j]) {
                    return false;
                }
            }
        }
        return true;
    }
