using namespace std;

int main() {
    int N, C;
    cin >> N >> C;

    vector<pair<int, int>> initial(N + 1);
    for (int i = 1; i <= N; i++) {
        cin >> initial[i].first >> initial[i].second;
    }

    int Q;
    cin >> Q;

    vector<pair<int, int>> queries(Q);
    int maxT = 0;
    for (int i = 0; i < Q; i++) {
        cin >> queries[i].first >> queries[i].second;
        maxT = max(maxT, queries[i].first);
    }

    vector<int> removed_at(N + 1, -1);
    map<int, pair<int, int>> pos;

    for (int i = 1; i <= N; i++) {
        pos[i] = initial[i];
    }

    for (int t = 1; t <= maxT; t++) {
        map<pair<int, int>, int> grid;
        for (auto& p : pos) {
            grid[p.second] = p.first;
        }

        bool bottom_full = true;
        for (int col = 1; col <= C; col++) {
            if (grid.find({col, 1}) == grid.end()) {
                bottom_full = false;
                break;
            }
        }

        if (bottom_full) {
            vector<int> to_remove;
            for (auto& p : pos) {
                if (p.second.second == 1) {
                    to_remove.push_back(p.first);
                    removed_at[p.first] = t;
                }
            }
            for (int id : to_remove) {
                pos.erase(id);
            }

            grid.clear();
            for (auto& p : pos) {
                grid[p.second] = p.first;
            }
        }

        vector<pair<int, pair<int, int>>> crates_by_level;
        for (auto& p : pos) {
            crates_by_level.push_back({p.second.second, {p.first, p.second.first}});
        }
        sort(crates_by_level.begin(), crates_by_level.end());

        map<int, pair<int, int>> new_pos;
        set<pair<int, int>> occupied;

        for (auto& item : crates_by_level) {
            int y = item.first;
            int id = item.second.first;
            int x = item.second.second;

            if (y == 1 || occupied.count({x, y - 1}) || grid.count({x, y - 1})) {
                new_pos[id] = {x, y};
                occupied.insert({x, y});
            } else {
                new_pos[id] = {x, y - 1};
                occupied.insert({x, y - 1});
            }
        }

        pos = new_pos;
    }

    for (int i = 0; i < Q; i++) {
        int t = queries[i].first;
        int r = queries[i].second;

        if (removed_at[r] == -1 || removed_at[r] > t) {
            cout << "Yes\n";
        } else {
            cout << "No\n";
        }
    }

    return 0;
}

