import (
	"bufio"
	"fmt"
	"os"
	"sort"
)

type Crate struct {
	id int
	x  int
	y  int
}

func main() {
	reader := bufio.NewReader(os.Stdin)
	writer := bufio.NewWriter(os.Stdout)
	defer writer.Flush()

	var N, C int
	fmt.Fscanf(reader, "%d %d\n", &N, &C)

	crates := make([]Crate, N)
	for i := 0; i < N; i++ {
		fmt.Fscanf(reader, "%d %d\n", &crates[i].x, &crates[i].y)
		crates[i].id = i + 1
	}

	var Q int
	fmt.Fscanf(reader, "%d\n", &Q)

	queries := make([][2]int, Q)
	for i := 0; i < Q; i++ {
		fmt.Fscanf(reader, "%d %d\n", &queries[i][0], &queries[i][1])
	}

	for _, query := range queries {
		T := query[0]
		R := query[1]

		currentCrates := make([]Crate, len(crates))
		copy(currentCrates, crates)

		exists := true
		for t := 1; t <= T && exists; t++ {
			occupied := make(map[[2]int]bool)
			for _, c := range currentCrates {
				occupied[[2]int{c.x, c.y}] = true
			}

			bottomCount := 0
			for x := 1; x <= C; x++ {
				if occupied[[2]int{x, 1}] {
					bottomCount++
				}
			}

			if bottomCount == C {
				newCrates := []Crate{}
				for _, c := range currentCrates {
					if c.y != 1 {
						newCrates = append(newCrates, c)
					} else if c.id == R {
						exists = false
					}
				}
				currentCrates = newCrates
				if !exists {
					break
				}
			}

			if len(currentCrates) == 0 {
				exists = false
				break
			}

			sort.Slice(currentCrates, func(i, j int) bool {
				if currentCrates[i].y != currentCrates[j].y {
					return currentCrates[i].y < currentCrates[j].y
				}
				return currentCrates[i].id < currentCrates[j].id
			})

			occupied = make(map[[2]int]bool)
			for i := range currentCrates {
				c := &currentCrates[i]
				if c.y > 1 && !occupied[[2]int{c.x, c.y - 1}] {
					c.y--
				}
				occupied[[2]int{c.x, c.y}] = true
			}

			found := false
			for _, c := range currentCrates {
				if c.id == R {
					found = true
					break
				}
			}
			if !found {
				exists = false
			}
		}

		if exists {
			fmt.Fprintln(writer, "Yes")
		} else {
			fmt.Fprintln(writer, "No")
		}
	}
}

import java.util.*;
import java.io.*;

public class Main {
    static class Crate {
        int id;
        int x;
        int y;

        Crate(int id, int x, int y) {
            this.id = id;
            this.x = x;
            this.y = y;
        }
    }

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String[] line = br.readLine().split(" ");
        int N = Integer.parseInt(line[0]);
        int C = Integer.parseInt(line[1]);

        Map<Integer, Crate> crates = new HashMap<>();

        for (int i = 1; i <= N; i++) {
            line = br.readLine().split(" ");
            int p = Integer.parseInt(line[0]);
            int q = Integer.parseInt(line[1]);
            crates.put(i, new Crate(i, p, q));
        }

        int Q = Integer.parseInt(br.readLine());
        List<Query> queries = new ArrayList<>();

        for (int i = 0; i < Q; i++) {
            line = br.readLine().split(" ");
            int t = Integer.parseInt(line[0]);
            int r = Integer.parseInt(line[1]);
            queries.add(new Query(t, r));
        }

        Map<Integer, Map<Integer, Boolean>> cache = new HashMap<>();

        for (Query query : queries) {
            boolean exists = simulate(new HashMap<>(crates), C, query.t, query.r);
            System.out.println(exists ? "Yes" : "No");
        }
    }

    static class Query {
        int t;
        int r;
        Query(int t, int r) {
            this.t = t;
            this.r = r;
        }
    }

    static boolean simulate(Map<Integer, Crate> crates, int C, int T, int R) {
        for (int time = 1; time <= T; time++) {
            Set<Integer> groundColumns = new HashSet<>();
            List<Integer> toRemove = new ArrayList<>();

            for (Crate crate : crates.values()) {
                if (crate.y == 1) {
                    groundColumns.add(crate.x);
                    toRemove.add(crate.id);
                }
            }

            if (groundColumns.size() == C) {
                for (int id : toRemove) {
                    crates.remove(id);
                }
                if (!crates.containsKey(R)) {
                    return false;
                }
            }

            List<Crate> sortedCrates = new ArrayList<>(crates.values());
            sortedCrates.sort(Comparator.comparingInt(c -> c.y));

            Set<String> occupied = new HashSet<>();
            for (Crate c : crates.values()) {
                occupied.add(c.x + "," + c.y);
            }

            for (Crate crate : sortedCrates) {
                if (crate.y > 1) {
                    String below = crate.x + "," + (crate.y - 1);
                    if (!occupied.contains(below)) {
                        occupied.remove(crate.x + "," + crate.y);
                        crate.y--;
                        occupied.add(crate.x + "," + crate.y);
                    }
                }
            }

            if (time >= 2 * N && isStable(crates, C)) {
                break;
            }
        }

        return crates.containsKey(R);
    }

    static boolean isStable(Map<Integer, Crate> crates, int C) {
        Set<Integer> groundColumns = new HashSet<>();
        for (Crate crate : crates.values()) {
            if (crate.y == 1) {
                groundColumns.add(crate.x);
            }
        }

        if (groundColumns.size() == C) {
            return false;
        }

        Set<String> occupied = new HashSet<>();
        for (Crate c : crates.values()) {
            occupied.add(c.x + "," + c.y);
        }

        for (Crate crate : crates.values()) {
            if (crate.y > 1) {
                String below = crate.x + "," + (crate.y - 1);
                if (!occupied.contains(below)) {
                    return false;
                }
            }
        }

        return true;
    }
}

