    for (int i = 0; i < N; ++i) {
        int x = crates[i].x;
        long long y = crates[i].y;
        auto it = lower_bound(col_crates[x].begin(), col_crates[x].end(), y);
        rank_in_col[i] = (int)distance(col_crates[x].begin(), it);
        final_y[i] = rank_in_col[i] + 1;
    }

