import java.io.*;
import java.util.*;

public class Main {
    static class FastReader {
        private final InputStream in;
        private final byte[] buffer = new byte[1024 * 8];
        private int pointer = 0;
        private int kount = 0;

        public FastReader(InputStream in) {
            this.in = in;
        }

        private int read() {
            if (pointer >= kount) {
                pointer = 0;
                try {
                    kount = in.read(buffer);
                } catch (IOException e) {
                    return -1;
                }
                if (kount <= 0) return -1;
            }
            return buffer[pointer++];
        }

        public int nextInt() {
            int c = read();
            while (c >= 0 && c <= 32) c = read();
            if (c == -1) return -1;
            int neg = 1;
            if (c == '-') {
                neg = -1;
                c = read();
            }
            int res = 0;
            while (c >= '0' && c <= '9') {
                res = res * 10 + (c - '0');
                c = read();
            }
            return res * neg;
        }

        public long nextLong() {
            int c = read();
            while (c >= 0 && c <= 32) c = read();
            if (c == -1) return -1;
            int neg = 1;
            if (c == '-') {
                neg = -1;
                c = read();
            }
            long res = 0;
            while (c >= '0' && c <= '9') {
                res = res * 10 + (c - '0');
                c = read();
            }
            return res * neg;
        }
    }

