map<pair<int,int>, pair<int,int>> memo;

pair<int,int> solve(int left, int right) {
    if (left == right) {
        int val = D[left] - '0';
        if (val == 0) {
            return {0, 1};
        } else {
            return {1, 1};
        }
    }

    auto key = make_pair(left, right);
    if (memo.find(key) != memo.end()) {
        return memo[key];
    }

    int len = right - left + 1;
    int group_size = len / 3;

    auto r1 = solve(left, left + group_size - 1);
    auto r2 = solve(left + group_size, left + 2 * group_size - 1);
    auto r3 = solve(left + 2 * group_size, right);

    int v1 = r1.first;
    int v2 = r2.first;
    int v3 = r3.first;

    int sum = v1 + v2 + v3;
    int current_val = (sum >= 2) ? 1 : 0;

    int cost_to_flip = 1e9;

    if (current_val == 0) {
        int option1 = r1.second + r2.second;
        int option2 = r1.second + r3.second;
        int option3 = r2.second + r3.second;
        cost_to_flip = min({option1, option2, option3});
    } else {
        int count_ones = (v1 == 1 ? 1 : 0) + (v2 == 1 ? 1 : 0) + (v3 == 1 ? 1 : 0);

        if (count_ones == 3) {
            int option1 = r1.second;
            int option2 = r2.second;
            int option3 = r3.second;
            cost_to_flip = min({option1, option2, option3});
        } else if (count_ones == 2) {
            if (v1 == 1 && v2 == 1) {
                int option1 = r1.second;
                int option2 = r2.second;
                cost_to_flip = min(option1, option2);
            } else if (v1 == 1 && v3 == 1) {
                int option1 = r1.second;
                int option2 = r3.second;
                cost_to_flip = min(option1, option2);
            } else {
                int option1 = r2.second;
                int option2 = r3.second;
                cost_to_flip = min(option1, option2);
            }
        }
    }

    memo[key] = {current_val, cost_to_flip};
    return {current_val, cost_to_flip};
}

