func minCostToFlip(d string, n int) int {
    length := 1
    for i := 0; i < n; i++ {
        length *= 3
    }

    dp := make([][][2]int, n+1)
    for i := 0; i <= n; i++ {
        levelLen := 1
        for j := 0; j < n-i; j++ {
            levelLen *= 3
        }
        dp[i] = make([][2]int, levelLen)
    }

    for i := 0; i < length; i++ {
        if d[i] == '0' {
            dp[0][i][0] = 0
            dp[0][i][1] = 1
        } else {
            dp[0][i][0] = 1
            dp[0][i][1] = 0
        }
    }

    for level := 1; level <= n; level++ {
        prevLen := 1
        for j := 0; j < n-level+1; j++ {
            prevLen *= 3
        }
        currLen := prevLen / 3

        for i := 0; i < currLen; i++ {
            idx := i * 3

            dp[level][i][0] = math.MaxInt32
            dp[level][i][1] = math.MaxInt32

            for v0 := 0; v0 <= 1; v0++ {
                for v1 := 0; v1 <= 1; v1++ {
                    for v2 := 0; v2 <= 1; v2++ {
                        result := majority(v0, v1, v2)
                        cost := dp[level-1][idx][v0] + dp[level-1][idx+1][v1] + dp[level-1][idx+2][v2]

                        if dp[level][i][result] > cost {
                            dp[level][i][result] = cost
                        }
                    }
                }
            }
        }
    }

    original := dp[n][0][0]
    flipped := dp[n][0][1]

    if original <= flipped {
        return flipped
    } else {
        return original
    }
}

