    static Map<String, Integer> memo;

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        N = sc.nextInt();
        data = sc.next();
        sc.close();

        int currentFinal = computeFinal(data);
        int targetFinal = 1 - currentFinal;

        int result = minChanges(data, 0, N, targetFinal);
        System.out.println(result);
    }

    static int computeFinal(String s) {
        String current = s;
        int levels = N;
        while (levels > 0) {
            current = applyFusion(current);
            levels--;
        }
        return current.charAt(0) - '0';
    }

    static String applyFusion(String s) {
        StringBuilder result = new StringBuilder();
        for (int i = 0; i < s.length(); i += 3) {
            int a = s.charAt(i) - '0';
            int b = s.charAt(i + 1) - '0';
            int c = s.charAt(i + 2) - '0';
            int consensus = (a + b + c >= 2) ? 1 : 0;
            result.append(consensus);
        }
        return result.toString();
    }

    static int minChanges(String s, int level, int totalLevels, int target) {
        if (level == totalLevels) {
            return (s.charAt(0) - '0' == target) ? 0 : Integer.MAX_VALUE / 2;
        }

        int minCost = Integer.MAX_VALUE / 2;
        int len = s.length();

        for (int mask = 0; mask < (1 << len); mask++) {
            String modified = flip(s, mask);
            String next = applyFusion(modified);
            int cost = Integer.bitCount(mask) + minChanges(next, level + 1, totalLevels, target);
            minCost = Math.min(minCost, cost);
        }

        return minCost;
    }

    static String flip(String s, int mask) {
        char[] arr = s.toCharArray();
        for (int i = 0; i < arr.length; i++) {
            if ((mask & (1 << i)) != 0) {
                arr[i] = (arr[i] == '0') ? '1' : '0';
            }
        }
        return new String(arr);
    }
}

