	}
	for len(cur) > 1 {
		next := make([]int, len(cur)/3)
		for i := 0; i < len(next); i++ {
			sum := cur[3*i] + cur[3*i+1] + cur[3*i+2]
			if sum >= 2 {
				next[i] = 1
			} else {
