                costs[0][0] + costs[1][0] + costs[2][1],
                costs[0][0] + costs[1][1] + costs[2][0],
                costs[0][1] + costs[1][0] + costs[2][0]
            )
            return res
        else:
            res = min(
                costs[0][1] + costs[1][1] + costs[2][1],
                costs[0][1] + costs[1][1] + costs[2][0],
                costs[0][1] + costs[1][0] + costs[2][1],
                costs[0][0] + costs[1][1] + costs[2][1]
            )
            return res

