                    it->second = (it->second + count) % MOD;
                } else {
                    next_dp[next_state] = count;
                }
            }
        }
        dp = move(next_dp);
    }

    vector<long long> results(N + 1, 0);
    for (auto const& [state, count] : dp) {
        results[state[N]] = (results[state[N]] + count) % MOD;
    }

    for (int k = 0; k <= N; ++k) {
        cout << results[k] << (k == N ? "" : " ");
    }
    cout << endl;

    return 0;
}

