import java.util.*;

public class Main {
    private static final long MOD = 998244353;

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        if (!sc.hasNextInt()) return;
        int N = sc.nextInt();
        int L = sc.nextInt();
        String B = sc.next();

        int numStates = 1 << N;
        long[][] dp = new long[L + 1][numStates];
        dp[0][0] = 1;

        int[][] nextStateMap = new int[numStates][26];
        for (int mask = 0; mask < numStates; mask++) {
            for (int c = 0; c < 26; c++) {
                char charC = (char) ('a' + c);
                int nextMask = 0;
                int[] lcs = new int[N + 1];
                for (int i = 0; i < N; i++) {
                    if ((mask & (1 << i)) != 0) {
                        lcs[i + 1] = Integer.bitCount(mask & ((1 << (i + 1)) - 1));
                    } else {
                        lcs[i + 1] = lcs[i];
                    }
                }

                int[] currentLCS = new int[N + 1];
                for (int j = 1; j <= N; j++) {
                    if (B.charAt(j - 1) == charC) {
                        currentLCS[j] = lcs[j - 1] + 1;
                    } else {
                        currentLCS[j] = Math.max(currentLCS[j - 1], lcs[j]);
                    }
                }

                int resMask = 0;
                for (int j = 1; j <= N; j++) {
                    if (currentLCS[j] > currentLCS[j - 1]) {
                        resMask |= (1 << (j - 1));
                    }
                }
                nextStateMap[mask][c] = resMask;
            }
        }

        for (int i = 0; i < L; i++) {
            for (int mask = 0; mask < numStates; mask++) {
                if (dp[i][mask] == 0) continue;
                for (int c = 0; c < 26; c++) {
                    int nMask = nextStateMap[mask][c];
                    dp[i + 1][nMask] = (dp[i + 1][nMask] + dp[i][mask]) % MOD;
                }
            }
        }

        long[] ans = new long[N + 1];
        for (int mask = 0; mask < numStates; mask++) {
            int k = Integer.bitCount(mask);
            ans[k] = (ans[k] + dp[L][mask]) % MOD;
        }

        StringBuilder sb = new StringBuilder();
        for (int i = 0; i <= N; i++) {
            sb.append(ans[i]).append(i == N ? "" : " ");
        }
        System.out.println(sb.toString());
    }
}

