    for _ in range(l):
        new_dp = {}
        for state, count in dp.items():
            for i in range(26):
                m = masks[i]
                new_state = (state << 1) | 1
                new_state &= (state | m)

                new_dp[new_state] = (new_dp.get(new_state, 0) + count) % mod
        dp = new_dp

    ans = [0] * (n + 1)
    for state, count in dp.items():
        k = bin(state).count('1')
        ans[k] = (ans[k] + count) % mod

    print(*(ans))

