            for (int j = 0; j < M[i]; j++) {
                int s = fr.nextInt();
                map.put(s, map.getOrDefault(s, 0) + 1);
            }
            counts.add(map);
        }

        double maxProb = 0.0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                double currentProb = calculateProbability(counts.get(i), M[i], counts.get(j), M[j]);
                if (currentProb > maxProb) {
                    maxProb = currentProb;
                }
            }
        }
        System.out.printf("%.15f\n", maxProb);
    }

    private static double calculateProbability(Map<Integer, Integer> map1, int m1, Map<Integer, Integer> map2, int m2) {
        long numerator = 0;
        if (map1.size() < map2.size()) {
            for (Map.Entry<Integer, Integer> entry : map1.entrySet()) {
                Integer symbol = entry.getKey();
                if (map2.containsKey(symbol)) {
                    numerator += (long) entry.getValue() * map2.get(symbol);
                }
            }
        } else {
            for (Map.Entry<Integer, Integer> entry : map2.entrySet()) {
                Integer symbol = entry.getKey();
                if (map1.containsKey(symbol)) {
                    numerator += (long) entry.getValue() * map1.get(symbol);
                }
            }
        }
        return (double) numerator / ((double) m1 * m2);
    }

    static class FastReader {
        private InputStream in;
        private byte[] buffer = new byte[1024 * 8];
        private int pointer = 0;
        private int k = 0;

        public FastReader(InputStream in) {
            this.in = in;
        }

        private int readByte() {
            if (pointer >= k) {
                pointer = 0;
                try {
                    k = in.read(buffer);
                } catch (IOException e) {
                    return -1;
                }
                if (k <= 0) return -1;
            }
            return buffer[pointer++];
        }

        public int nextInt() {
            int c = readByte();
            while (c >= 0 && c <= 32) c = readByte();
            if (c == -1) return -1;
            int res = 0;
            while (c > 32) {
                res = res * 10 + (c - '0');
                c = readByte();
            }
            return res;
        }
    }
}

