type Node struct {
	val         int
	priority    uint32
	size        int
	left, right *Node
}

func getSize(n *Node) int {
	if n == nil {
		return 0
	}
	return n.size
}

func updateSize(n *Node) {
	if n != nil {
		n.size = 1 + getSize(n.left) + getSize(n.right)
	}
}

func split(n *Node, k int) (*Node, *Node) {
	if n == nil {
		return nil, nil
	}
	leftSize := getSize(n.left)
	if leftSize >= k {
		l, r := split(n.left, k)
		n.left = r
		updateSize(n)
		return l, n
	} else {
		l, r := split(n.right, k-leftSize-1)
		n.right = l
		updateSize(n)
		return n, r
	}
}

func merge(l, r *Node) *Node {
	if l == nil {
		return r
	}
	if r == nil {
		return l
	}
	if l.priority > r.priority {
		l.right = merge(l.right, r)
		updateSize(l)
		return l
	} else {
		r.left = merge(l, r.left)
		updateSize(r)
		return r
	}
}

