public class Main {
    static class Node {
        int value;
        int priority;
        int size;
        Node left, right;

        Node(int value) {
            this.value = value;
            this.priority = (int) (Math.random() * Integer.MAX_VALUE);
            this.size = 1;
        }

        void updateSize() {
            this.size = 1 + getSize(left) + getSize(right);
        }
    }

    static int getSize(Node node) {
        return node == null ? 0 : node.size;
    }

    static Node[] split(Node node, int k) {
        if (node == null) return new Node[]{null, null};
        int leftSize = getSize(node.left);
        if (leftSize >= k) {
            Node[] res = split(node.left, k);
            node.left = res[1];
            node.updateSize();
            res[1] = node;
            return res;
        } else {
            Node[] res = split(node.right, k - leftSize - 1);
            node.right = res[0];
            node.updateSize();
            res[0] = node;
            return res;
        }
    }

    static Node merge(Node l, Node r) {
        if (l == null) return r;
        if (r == null) return l;
        if (l.priority > r.priority) {
            l.right = merge(l.right, r);
            l.updateSize();
            return l;
        } else {
            r.left = merge(l, r.left);
            r.updateSize();
            return r;
        }
    }

    static StringBuilder sb = new StringBuilder();

    static void inorder(Node node) {
        if (node == null) return;
        inorder(node.left);
        sb.append(node.value).append(" ");
        inorder(node.right);
    }

