func fft(a []complex128, invert bool) {
	n := len(a)
	for i, j := 1, 0; i < n; i++ {
		bit := n >> 1
		for ; j&bit != 0; bit >>= 1 {
			j ^= bit
		}
		j ^= bit
		if i < j {
			a[i], a[j] = a[j], a[i]
		}
	}
	for lenVal := 2; lenVal <= n; lenVal <<= 1 {
		ang := 2 * math.Pi / float64(lenVal)
		if invert {
			ang = -ang
		}
		wlen := cmplx.Exp(complex(0, ang))
		for i := 0; i < n; i += lenVal {
			w := complex(1, 0)
			for j := 0; j < lenVal/2; j++ {
				u := a[i+j]
				v := a[i+j+lenVal/2] * w
				a[i+j] = u + v
				a[i+j+lenVal/2] = u - v
				w *= wlen
			}
		}
	}
	if invert {
		for i := range a {
			a[i] /= complex(float64(n), 0)
		}
	}
}

