            current_ones++;
        }
        if (s[i - window_size] == '1') {
            current_ones--;
        }
        max_ones_in_window = max(max_ones_in_window, current_ones);
    }

    int min_swaps = total_ones - max_ones_in_window;
    cout << min_swaps << endl;

    return 0;
