int longestIncreasingSubsequence(const vector<int>& arr) {
    if (arr.empty()) return 0;

    vector<int> lis;

    for (int num : arr) {
        auto it = lower_bound(lis.begin(), lis.end(), num);
        if (it == lis.end()) {
