func findLIS(arr []int) int {
	if len(arr) == 0 {
		return 0
	}

	tails := make([]int, 0)

	for _, num := range arr {
		pos := sort.Search(len(tails), func(i int) bool {
			return tails[i] >= num
		})

		if pos == len(tails) {
			tails = append(tails, num)
		} else {
			tails[pos] = num
		}
	}

	return len(tails)
