    static int findLIS(List<Integer> arr) {
        if (arr.isEmpty()) {
            return 0;
        }

        List<Integer> dp = new ArrayList<>();

        for (int num : arr) {
            int pos = binarySearch(dp, num);
            if (pos == dp.size()) {
                dp.add(num);
            } else {
                dp.set(pos, num);
            }
        }

        return dp.size();
    }

    static int binarySearch(List<Integer> dp, int target) {
        int left = 0;
        int right = dp.size();

        while (left < right) {
            int mid = left + (right - left) / 2;
            if (dp.get(mid) < target) {
                left = mid + 1;
            } else {
                right = mid;
            }
        }

        return left;
    }
}

