func solve() {
	reader := bufio.NewReader(os.Stdin)
	s, _ := reader.ReadString('\n')
	if len(s) > 0 && s[len(s)-1] == '\n' {
		s = s[:len(s)-1]
	}
	if len(s) > 0 && s[len(s)-1] == '\r' {
		s = s[:len(s)-1]
	}

	result := make([]byte, 0, len(s))
	i := 0
	for i < len(s) {
		if s[i] == 'W' {
			countW := 0
			start := i
			for i < len(s) && s[i] == 'W' {
				countW++
				i++
			}
			if i < len(s) && s[i] == 'A' {
				result = append(result, 'A')
				for k := 0; k < countW; k++ {
					result = append(result, 'C')
				}
				i++
			} else {
				for k := 0; k < countW; k++ {
					result = append(result, s[start+k])
				}
			}
		} else {
			result = append(result, s[i])
			i++
		}
	}

	writer := bufio.NewWriter(os.Stdout)
	writer.Write(result)
	writer.WriteByte('\n')
	writer.Flush()
}

