		']': '[',
		'>': '<',
	}

	isValid := true
	for _, char := range input {
		if char == '(' || char == '[' || char == '<' {
			stack = append(stack, char)
		} else {
			opening, exists := pairs[char]
			if !exists {
				isValid = false
				break
			}
			if len(stack) == 0 || stack[len(stack)-1] != opening {
				isValid = false
				break
			}
			stack = stack[:len(stack)-1]
		}
	}

	if isValid && len(stack) == 0 {
		fmt.Println("Yes")
	} else {
		fmt.Println("No")
	}
}

