using namespace std;

int main() {
    int N;
    cin >> N;
    vector<string> S(N);
    for (int i = 0; i < N; i++) {
        cin >> S[i];
    }

    vector<vector<int>> answer(N, vector<int>(N, -1));

    for (int start = 0; start < N; start++) {
        for (int end = 0; end < N; end++) {
            if (start == end) {
                answer[start][end] = 0;
                continue;
            }

            map<pair<int, string>, int> dist;
            queue<pair<int, string>> q;

            q.push({start, ""});
            dist[{start, ""}] = 0;

            int result = -1;

            while (!q.empty()) {
                auto [node, suffix] = q.front();
                q.pop();

                int d = dist[{node, suffix}];

                if (d > 2 * N) continue;

                for (int next = 0; next < N; next++) {
                    if (S[node][next] == '-') continue;

                    char c = S[node][next];
                    string new_suffix;

                    if (suffix.empty()) {
                        new_suffix = string(1, c);
                    } else if (suffix[0] == c) {
                        new_suffix = suffix.substr(1);
                    } else {
                        new_suffix = string(1, c) + suffix;
                    }

                    if (next == end && new_suffix.empty()) {
                        result = d + 1;
                        break;
                    }

                    if (new_suffix.length() <= N) {
                        auto key = make_pair(next, new_suffix);
                        if (dist.find(key) == dist.end()) {
                            dist[key] = d + 1;
                            q.push({next, new_suffix});
                        }
                    }
                }

                if (result != -1) break;
            }

            answer[start][end] = result;
        }
    }

    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            if (j > 0) cout << " ";
            cout << answer[i][j];
        }
        cout << "\n";
    }

    return 0;
}

