func isPalindrome(s string) bool {
	n := len(s)
	for i := 0; i < n/2; i++ {
		if s[i] != s[n-1-i] {
			return false
		}
	}
	return true
}

func main() {
	scanner := bufio.NewScanner(os.Stdin)
	scanner.Scan()
	var n int
	fmt.Sscanf(scanner.Text(), "%d", &n)

	grid := make([]string, n)
	for i := 0; i < n; i++ {
		scanner.Scan()
		grid[i] = scanner.Text()
	}

	answer := make([][]int, n)
	for i := 0; i < n; i++ {
		answer[i] = make([]int, n)
		for j := 0; j < n; j++ {
			answer[i][j] = -1
		}
	}

	for start := 0; start < n; start++ {
		type State struct {
			node int
			path string
		}

		queue := []State{{start, ""}}
		visited := make(map[State]bool)
		visited[State{start, ""}] = true
		dist := make(map[State]int)
		dist[State{start, ""}] = 0

		minDist := make([]int, n)
		for i := 0; i < n; i++ {
			minDist[i] = -1
		}
		minDist[start] = 0

		head := 0
		for head < len(queue) {
			curr := queue[head]
			head++
			currDist := dist[curr]

			if isPalindrome(curr.path) {
				if minDist[curr.node] == -1 || currDist < minDist[curr.node] {
					minDist[curr.node] = currDist
				}
			}

			if len(curr.path) > 50 {
				continue
			}

			for next := 0; next < n; next++ {
				if grid[curr.node][next] != '-' {
					newPath := curr.path + string(grid[curr.node][next])
					newState := State{next, newPath}

					if !visited[newState] {
						visited[newState] = true
						dist[newState] = currDist + 1
						queue = append(queue, newState)

						if isPalindrome(newPath) {
							if minDist[next] == -1 || currDist+1 < minDist[next] {
								minDist[next] = currDist + 1
							}
						}
					}
				}
			}
		}

		answer[start] = minDist
	}

	writer := bufio.NewWriter(os.Stdout)
	for i := 0; i < n; i++ {
		for j := 0; j < n; j++ {
			if j > 0 {
				writer.WriteString(" ")
			}
			fmt.Fprintf(writer, "%d", answer[i][j])
		}
		writer.WriteString("\n")
	}
	writer.Flush()
}

import java.util.*;
import java.io.*;

public class Main {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int N = Integer.parseInt(br.readLine());
        char[][] S = new char[N][N];

        for (int i = 0; i < N; i++) {
            String line = br.readLine();
            for (int j = 0; j < N; j++) {
                S[i][j] = line.charAt(j);
            }
        }

        int[][] answer = new int[N][N];

        for (int start = 0; start < N; start++) {
            for (int end = 0; end < N; end++) {
                answer[start][end] = findMinPalindrome(N, S, start, end);
            }
        }

        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                if (j > 0) sb.append(' ');
                sb.append(answer[i][j]);
            }
            sb.append('\n');
        }
        System.out.print(sb);
    }

    static int findMinPalindrome(int N, char[][] S, int start, int end) {
        Map<State, Integer> dist = new HashMap<>();
        Queue<State> queue = new LinkedList<>();

        State initial = new State(start, end, "", "");
        queue.add(initial);
        dist.put(initial, 0);

        int result = -1;

        while (!queue.isEmpty()) {
            State curr = queue.poll();
            int d = dist.get(curr);

            if (d > 2 * N) continue;

            if (curr.left == curr.right && curr.prefix.equals(reverse(curr.suffix))) {
                if (result == -1 || d < result) {
                    result = d;
                }
                continue;
            }

            if (curr.prefix.length() <= curr.suffix.length()) {
                for (int next = 0; next < N; next++) {
                    if (S[curr.left][next] != '-') {
                        char c = S[curr.left][next];
                        String newPrefix = curr.prefix + c;
                        String newSuffix = curr.suffix;

                        while (newPrefix.length() > 0 && newSuffix.length() > 0 &&
                               newPrefix.charAt(0) == newSuffix.charAt(newSuffix.length() - 1)) {
                            newPrefix = newPrefix.substring(1);
                            newSuffix = newSuffix.substring(0, newSuffix.length() - 1);
                        }

                        State newState = new State(next, curr.right, newPrefix, newSuffix);
                        if (!dist.containsKey(newState) || dist.get(newState) > d + 1) {
                            dist.put(newState, d + 1);
                            queue.add(newState);
                        }
                    }
                }
            } else {
                for (int prev = 0; prev < N; prev++) {
                    if (S[prev][curr.right] != '-') {
                        char c = S[prev][curr.right];
                        String newPrefix = curr.prefix;
                        String newSuffix = c + curr.suffix;

                        while (newPrefix.length() > 0 && newSuffix.length() > 0 &&
                               newPrefix.charAt(0) == newSuffix.charAt(newSuffix.length() - 1)) {
                            newPrefix = newPrefix.substring(1);
                            newSuffix = newSuffix.substring(0, newSuffix.length() - 1);
                        }

                        State newState = new State(curr.left, prev, newPrefix, newSuffix);
                        if (!dist.containsKey(newState) || dist.get(newState) > d + 1) {
                            dist.put(newState, d + 1);
                            queue.add(newState);
                        }
                    }
                }
            }
        }

        return result;
    }

    static String reverse(String s) {
        return new StringBuilder(s).reverse().toString();
    }

    static class State {
        int left, right;
        String prefix, suffix;

        State(int left, int right, String prefix, String suffix) {
            this.left = left;
            this.right = right;
            this.prefix = prefix;
            this.suffix = suffix;
        }

        public boolean equals(Object o) {
            if (!(o instanceof State)) return false;
            State s = (State) o;
            return left == s.left && right == s.right && 
                   prefix.equals(s.prefix) && suffix.equals(s.suffix);
        }

        public int hashCode() {
            return Objects.hash(left, right, prefix, suffix);
        }
    }
}

