        int sz = dfs(v, u, root);
        if (sz > 0) {
            childSizes.push_back(sz);
        }
    }

    int numChildren = childSizes.size();

    if (u == root) {
        if (numChildren == 0) return 0;
        if (numChildren == 1) {
            return 1 + childSizes[0];
        }
        if (numChildren == 3) {
            return 1 + childSizes[0] + childSizes[1] + childSizes[2];
        }
        if (numChildren >= 4) {
            sort(childSizes.rbegin(), childSizes.rend());
            return 1 + childSizes[0] + childSizes[1] + childSizes[2];
        }
        return 0;
    } else {
        if (numChildren == 0) {
            return 1;
        }
        if (numChildren == 3) {
            return 1 + childSizes[0] + childSizes[1] + childSizes[2];
        }
        if (numChildren >= 4) {
            sort(childSizes.rbegin(), childSizes.rend());
            return 1 + childSizes[0] + childSizes[1] + childSizes[2];
        }
        return 0;
