		adj[u] = append(adj[u], v)
		adj[v] = append(adj[v], u)
	}

	maxNodes := -1

	for root := 1; root <= n; root++ {
		result := solve(root, adj, n)
		if result > maxNodes {
			maxNodes = result
		}
	}

	fmt.Fprintln(writer, maxNodes)
}

func solve(root int, adj [][]int, n int) int {
	visited := make([]bool, n+1)
	maxSize, hasHub := dfs(root, -1, adj, visited)
	if hasHub {
		return maxSize
	}
	return -1
}

func dfs(node int, parent int, adj [][]int, visited []bool) (int, bool) {
	visited[node] = true

	children := []int{}
	for _, neighbor := range adj[node] {
		if neighbor != parent {
			children = append(children, neighbor)
		}
	}

	if len(children) == 0 {
		return 1, false
	}

	childResults := []struct {
		size   int
		hasHub bool
	}{}

	for _, child := range children {
		size, hasHub := dfs(child, node, adj, visited)
		childResults = append(childResults, struct {
			size   int
			hasHub bool
		}{size, hasHub})
	}

	maxResult := -1
	hasHubResult := false

	if len(children) == 1 {
		if childResults[0].hasHub {
			maxResult = 1 + childResults[0].size
			hasHubResult = true
		}
	} else if len(children) >= 4 {
		sizes := []int{}
		anyHasHub := false
		for _, cr := range childResults {
			sizes = append(sizes, cr.size)
			if cr.hasHub {
				anyHasHub = true
			}
		}

		for numChildren := 4; numChildren <= len(children); numChildren++ {
			if numChildren != 1 && numChildren != 4 {
				continue
			}

			topIndices := getTopK(sizes, numChildren)
			total := 1
			checkHub := anyHasHub
			for _, idx := range topIndices {
				total += childResults[idx].size
			}

			if numChildren == 4 {
				checkHub = true
			}

			if checkHub && total > maxResult {
				maxResult = total
				hasHubResult = true
			}
		}
	}

	for numChildren := 4; numChildren <= len(children); numChildren++ {
		sizes := []int{}
		for _, cr := range childResults {
			sizes = append(sizes, cr.size)
		}

		topIndices := getTopK(sizes, numChildren)
		total := 1
		for _, idx := range topIndices {
			total += childResults[idx].size
		}

		if total > maxResult {
			maxResult = total
			hasHubResult = true
		}
	}

	return maxResult, hasHubResult
}

func getTopK(arr []int, k int) []int {
	if k > len(arr) {
		k = len(arr)
	}

	indices := make([]int, len(arr))
	for i := range indices {
		indices[i] = i
	}

	for i := 0; i < k; i++ {
		maxIdx := i
		for j := i + 1; j < len(indices); j++ {
			if arr[indices[j]] > arr[indices[maxIdx]] {
				maxIdx = j
			}
		}
		indices[i], indices[maxIdx] = indices[maxIdx], indices[i]
	}

	return indices[:k]
}

import java.util.*;
import java.io.*;

public class Main {
    static List<Integer>[] graph;
    static int n;
    static int maxNodes;

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        n = Integer.parseInt(br.readLine());

        graph = new ArrayList[n + 1];
        for (int i = 0; i <= n; i++) {
            graph[i] = new ArrayList<>();
        }

        for (int i = 0; i < n - 1; i++) {
            String[] parts = br.readLine().split(" ");
            int u = Integer.parseInt(parts[0]);
            int v = Integer.parseInt(parts[1]);
            graph[u].add(v);
            graph[v].add(u);
        }

        maxNodes = -1;

        for (int hub = 1; hub <= n; hub++) {
            if (graph[hub].size() >= 4) {
                tryHub(hub);
            }
        }

        System.out.println(maxNodes);
    }

    static void tryHub(int hub) {
        List<Integer> neighbors = graph[hub];
        int k = neighbors.size();

        for (int mask = 0; mask < (1 << k); mask++) {
            if (Integer.bitCount(mask) != 4) continue;

            Set<Integer> selected = new HashSet<>();
            selected.add(hub);
            List<Integer> hubNeighbors = new ArrayList<>();

            for (int i = 0; i < k; i++) {
                if ((mask & (1 << i)) != 0) {
                    hubNeighbors.add(neighbors.get(i));
                    selected.add(neighbors.get(i));
                }
            }

            boolean valid = true;
            for (int neighbor : hubNeighbors) {
                if (!extendFrom(neighbor, hub, selected)) {
                    valid = false;
                    break;
                }
            }

            if (valid && checkValid(selected, hub)) {
                maxNodes = Math.max(maxNodes, selected.size());
            }
        }
    }

    static boolean extendFrom(int node, int parent, Set<Integer> selected) {
        List<Integer> candidates = new ArrayList<>();
        for (int neighbor : graph[node]) {
            if (neighbor == parent) continue;
            if (!selected.contains(neighbor)) {
                candidates.add(neighbor);
            }
        }

        int currentDegree = 1;
        for (int neighbor : graph[node]) {
            if (selected.contains(neighbor)) currentDegree++;
        }

        if (currentDegree == 1) {
            return true;
        }

        if (currentDegree + candidates.size() < 4) {
            return false;
        }

        if (currentDegree == 4) {
            return true;
        }

        int needed = 4 - currentDegree;
        if (needed > candidates.size()) return false;

        return tryExtensions(node, candidates, needed, 0, new ArrayList<>(), selected);
    }

    static boolean tryExtensions(int node, List<Integer> candidates, int needed, int start, List<Integer> chosen, Set<Integer> selected) {
        if (chosen.size() == needed) {
            Set<Integer> newSelected = new HashSet<>(selected);
            for (int c : chosen) {
                newSelected.add(c);
            }

            boolean valid = true;
            for (int c : chosen) {
                if (!extendFrom(c, node, newSelected)) {
                    valid = false;
                    break;
                }
            }

            if (valid) {
                selected.addAll(newSelected);
                return true;
            }
            return false;
        }

        for (int i = start; i < candidates.size(); i++) {
            chosen.add(candidates.get(i));
            if (tryExtensions(node, candidates, needed, i + 1, chosen, selected)) {
                return true;
            }
            chosen.remove(chosen.size() - 1);
        }
        return false;
    }

    static boolean checkValid(Set<Integer> nodes, int hub) {
        Map<Integer, Integer> degrees = new HashMap<>();
        for (int node : nodes) {
            degrees.put(node, 0);
        }

        for (int node : nodes) {
            for (int neighbor : graph[node]) {
                if (nodes.contains(neighbor)) {
                    degrees.put(node, degrees.get(node) + 1);
                }
            }
        }

        boolean hasHub = false;
        for (int node : nodes) {
            int deg = degrees.get(node);
            if (deg != 1 && deg != 4) return false;
            if (deg == 4) hasHub = true;
        }

        return hasHub;
    }
}

def main():
    import sys
    from collections import defaultdict, deque

    input = sys.stdin.read
    data = input().split()

    n = int(data[0])

    if n == 1:
        print(-1)
        return

    idx = 1
    adj = defaultdict(list)

    for _ in range(n - 1):
        u = int(data[idx])
        v = int(data[idx + 1])
        idx += 2
        adj[u].append(v)
        adj[v].append(u)

    max_size = -1

    def compute_subtree(node, parent, active_edges):
        children = []
        for neighbor in adj[node]:
            if neighbor != parent and (min(node, neighbor), max(node, neighbor)) in active_edges:
                children.append(neighbor)

        if len(children) == 0:
            return 1, True

        if len(children) != 1 and len(children) != 4:
            return 0, False

        total = 1
        for child in children:
            size, valid = compute_subtree(child, node, active_edges)
            if not valid:
                return 0, False
            total += size

        return total, True

    def get_all_edges(node, parent, active_edges):
        edges = set()
        for neighbor in adj[node]:
            if neighbor != parent and (min(node, neighbor), max(node, neighbor)) in active_edges:
                edges.add((min(node, neighbor), max(node, neighbor)))
                edges.update(get_all_edges(neighbor, node, active_edges))
        return edges

    all_edges = set()
    for u in adj:
        for v in adj[u]:
            if u < v:
                all_edges.add((u, v))

    def try_all_subsets(edges_list):
        nonlocal max_size

        for mask in range(1, 1 << len(edges_list)):
            active = set()
            for i in range(len(edges_list)):
                if mask & (1 << i):
                    active.add(edges_list[i])

            nodes_in_graph = set()
            for u, v in active:
                nodes_in_graph.add(u)
                nodes_in_graph.add(v)

