func getTopK(arr []int, k int) []int {
	res := make([]int, k)
	for i := range res {
		res[i] = -1
	}
	for _, v := range arr {
		for i := 0; i < k; i++ {
			if v > res[i] {
				for j := k - 1; j > i; j-- {
					res[j] = res[j-1]
				}
				res[i] = v
				break
			}
		}
	}
	return res
}

func getUpValue(u, p int, adj [][]int, dp []int) int {
	siblings := make([]int, 0)
	for _, v := range adj[p] {
		if v == u {
			continue
		}
		if dp[v] != -1 {
			siblings = append(siblings, dp[v])
		}
	}

	parentCount := len(adj[p])
	if parentCount < 4 {
		return 1
	}

	top3 := getTopK(siblings, 3)
	if top3[2] == -1 {
		return 1
	}
	return top3[0] + top3[1] + top3[2] + 1
}

