public class Main {
    static class State implements Comparable<State> {
        int row, col, deck, cost;

        State(int row, int col, int deck, int cost) {
            this.row = row;
            this.col = col;
            this.deck = deck;
            this.cost = cost;
        }

        @Override
        public int compareTo(State other) {
            return Integer.compare(this.cost, other.cost);
        }
    }

    static int R, C;
    static int[][] D;
    static int[] dr = {-1, 1, 0, 0};
    static int[] dc = {0, 0, -1, 1};

    static int solve(int startR, int startC, int startDeck, int endR, int endC, int endDeck) {
        PriorityQueue<State> pq = new PriorityQueue<>();
        Map<String, Integer> dist = new HashMap<>();

        pq.offer(new State(startR, startC, startDeck, 0));
        String startKey = startR + "," + startC + "," + startDeck;
        dist.put(startKey, 0);

        while (!pq.isEmpty()) {
            State curr = pq.poll();

            if (curr.row == endR && curr.col == endC && curr.deck == endDeck) {
                return curr.cost;
            }

            String currKey = curr.row + "," + curr.col + "," + curr.deck;
            if (dist.containsKey(currKey) && dist.get(currKey) < curr.cost) {
                continue;
            }

            int maxDeck = D[curr.row][curr.col];

            for (int newDeck = 1; newDeck <= maxDeck; newDeck++) {
                if (newDeck != curr.deck) {
                    int newCost = curr.cost + Math.abs(newDeck - curr.deck);
                    String newKey = curr.row + "," + curr.col + "," + newDeck;
                    if (!dist.containsKey(newKey) || dist.get(newKey) > newCost) {
                        dist.put(newKey, newCost);
                        pq.offer(new State(curr.row, curr.col, newDeck, newCost));
                    }
                }
            }

            for (int dir = 0; dir < 4; dir++) {
                int newR = curr.row + dr[dir];
                int newC = curr.col + dc[dir];

                if (newR >= 0 && newR < R && newC >= 0 && newC < C) {
                    if (D[newR][newC] >= curr.deck) {
                        String newKey = newR + "," + newC + "," + curr.deck;
                        if (!dist.containsKey(newKey) || dist.get(newKey) > curr.cost) {
                            dist.put(newKey, curr.cost);
                            pq.offer(new State(newR, newC, curr.deck, curr.cost));
                        }
                    }
                }
            }
        }

        return -1;
    }

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());

        R = Integer.parseInt(st.nextToken());
        C = Integer.parseInt(st.nextToken());

        D = new int[R][C];
        for (int i = 0; i < R; i++) {
            st = new StringTokenizer(br.readLine());
            for (int j = 0; j < C; j++) {
                D[i][j] = Integer.parseInt(st.nextToken());
            }
        }

        int Q = Integer.parseInt(br.readLine());
        StringBuilder sb = new StringBuilder();

        for (int q = 0; q < Q; q++) {
            st = new StringTokenizer(br.readLine());
            int A = Integer.parseInt(st.nextToken()) - 1;
            int B = Integer.parseInt(st.nextToken()) - 1;
            int Y = Integer.parseInt(st.nextToken());
            int C = Integer.parseInt(st.nextToken()) - 1;
            int D = Integer.parseInt(st.nextToken()) - 1;
            int Z = Integer.parseInt(st.nextToken());

            int result = solve(A, B, Y, C, D, Z);
            sb.append(result).append("\n");
        }

        System.out.print(sb);
    }
}

