func main() {
	reader := bufio.NewReader(os.Stdin)
	var n, m int
	var x int64
	fmt.Fscanf(reader, "%d %d %d\n", &n, &m, &x)

	adj := make([][]int, n+1)
	rev := make([][]int, n+1)

	for i := 0; i < m; i++ {
		var u, v int
		fmt.Fscanf(reader, "%d %d\n", &u, &v)
		adj[u] = append(adj[u], v)
		rev[v] = append(rev[v], u)
	}

	dist := make([]int64, 2*n+1)
	for i := range dist {
		dist[i] = -1
	}

	pq := &PriorityQueue{}
	heap.Init(pq)

	dist[1] = 0
	heap.Push(pq, &State{node: 1, dist: 0})

	for pq.Len() > 0 {
		curr := heap.Pop(pq).(*State)
		u := curr.node
		d := curr.dist

		if d > dist[u] && dist[u] != -1 {
			continue
		}

		if u <= n {
			for _, v := range adj[u] {
				if dist[v] == -1 || dist[v] > d+1 {
					dist[v] = d + 1
					heap.Push(pq, &State{node: v, dist: dist[v]})
				}
			}
			if dist[u+n] == -1 || dist[u+n] > d+x {
				dist[u+n] = d + x
				heap.Push(pq, &State{node: u + n, dist: dist[u+n]})
			}
		} else {
			realU := u - n
			for _, v := range rev[realU] {
				if dist[v+n] == -1 || dist[v+n] > d+1 {
					dist[v+n] = d + 1
					heap.Push(pq, &State{node: v + n, dist: dist[v+n]})
				}
			}
			if dist[realU] == -1 || dist[realU] > d+x {
				dist[realU] = d + x
				heap.Push(pq, &State{node: realU, dist: dist[realU]})
			}
		}
	}

	ans1 := dist[n]
	ans2 := dist[2*n]

	if ans1 == -1 {
		fmt.Println(ans2)
	} else if ans2 == -1 {
		fmt.Println(ans1)
	} else {
		if ans1 < ans2 {
			fmt.Println(ans1)
		} else {
			fmt.Println(ans2)
		}
	}
}

