	defer writer.Flush()

	var N, Y int
	fmt.Fscan(reader, &N, &Y)

	P := make([]int, N)
	S := make([]int, N)

	for i := 0; i < N; i++ {
		fmt.Fscan(reader, &P[i], &S[i])
	}

	minSum := P[0] + S[0]
	for i := 1; i < N; i++ {
		if P[i]+S[i] < minSum {
			minSum = P[i] + S[i]
		}
	}

	minCost := int64(1e18)

	for T := minSum; T >= 1; T-- {
		valid := true
		for i := 0; i < N; i++ {
			if T > P[i]+S[i] {
				valid = false
				break
			}
		}
		if !valid {
			break
		}

		cost := solve(N, Y, P, S, T)
		if cost >= 0 && cost < minCost {
			minCost = cost
		}
	}

	fmt.Fprintln(writer, minCost)
}

func solve(N, Y int, P, S []int, T int) int64 {
	minP := make([]int, N)
	maxP := make([]int, N)

	for i := 0; i < N; i++ {
		minP[i] = T - S[i]
		if minP[i] < 0 {
			minP[i] = 0
		}
		maxP[i] = P[i]
		if maxP[i] > T {
			maxP[i] = T
		}
		if minP[i] > maxP[i] {
			return -1
		}
	}

	dp := make(map[int]int64)
	for p := minP[0]; p <= maxP[0]; p++ {
		cost := int64(P[0] - p + S[0] - (T - p))
		dp[p] = cost
	}

	for i := 1; i < N; i++ {
		newDp := make(map[int]int64)
		for p := minP[i]; p <= maxP[i]; p++ {
			minCost := int64(1e18)
			for prevP, prevCost := range dp {
				if abs(p-prevP) <= Y {
					if prevCost < minCost {
						minCost = prevCost
					}
				}
			}
			if minCost < int64(1e18) {
				cost := int64(P[i] - p + S[i] - (T - p))
				newDp[p] = minCost + cost
			}
		}
		if len(newDp) == 0 {
			return -1
		}
		dp = newDp
	}

	minCost := int64(1e18)
	for _, cost := range dp {
		if cost < minCost {
			minCost = cost
		}
	}

	if minCost == int64(1e18) {
		return -1
	}
	return minCost
}

