public class Main {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());

        int N = Integer.parseInt(st.nextToken());
        long Y = Long.parseLong(st.nextToken());

        long[] P = new long[N];
        long[] S = new long[N];
        long[] sum = new long[N];

        for (int i = 0; i < N; i++) {
            st = new StringTokenizer(br.readLine());
            P[i] = Long.parseLong(st.nextToken());
            S[i] = Long.parseLong(st.nextToken());
            sum[i] = P[i] + S[i];
        }

        long minSum = Long.MAX_VALUE;
        for (int i = 0; i < N; i++) {
            minSum = Math.min(minSum, sum[i]);
        }

        long answer = Long.MAX_VALUE;

        for (long T = 0; T <= minSum; T++) {
            boolean possible = true;
            for (int i = 0; i < N; i++) {
                if (sum[i] < T) {
                    possible = false;
                    break;
                }
            }
            if (!possible) continue;

            long cost = solve(N, Y, P, S, sum, T);
            if (cost >= 0) {
                answer = Math.min(answer, cost);
            }
        }

        System.out.println(answer);
    }

    static long solve(int N, long Y, long[] P, long[] S, long[] sum, long T) {
        TreeMap<Long, Long> dp = new TreeMap<>();

        long maxP0 = Math.min(P[0], T);
        for (long p = 0; p <= maxP0; p++) {
            dp.put(p, sum[0] - T);
        }

        for (int i = 1; i < N; i++) {
            TreeMap<Long, Long> newDp = new TreeMap<>();
            long maxPi = Math.min(P[i], T);

            for (long pi = 0; pi <= maxPi; pi++) {
                long minCost = Long.MAX_VALUE;

                Long lower = dp.floorKey(pi + Y);
                Long upper = dp.ceilingKey(pi - Y);

                if (lower != null && upper != null && upper <= lower) {
                    for (Map.Entry<Long, Long> entry : dp.subMap(upper, true, lower, true).entrySet()) {
                        minCost = Math.min(minCost, entry.getValue());
                    }
                }

                if (minCost < Long.MAX_VALUE) {
                    newDp.put(pi, minCost + sum[i] - T);
                }
            }

            dp = newDp;
        }

        long result = Long.MAX_VALUE;
        for (long cost : dp.values()) {
            result = Math.min(result, cost);
        }

        return result == Long.MAX_VALUE ? -1 : result;
    }
}

def main():
    N, Y = map(int, input().split())
    pairs = []
    for _ in range(N):
        p, s = map(int, input().split())
        pairs.append((p, s))

    min_sum = min(p + s for p, s in pairs)

    best_cost = float('inf')

    candidate_T = set()
    for p, s in pairs:
        candidate_T.add(p + s)
        for delta in range(min(Y * (N - 1) + 1, p + s + 1)):
            if p + s - delta >= 0:
                candidate_T.add(p + s - delta)

    for T in candidate_T:
        if T > min_sum:
            continue

        ranges = []
        valid = True
        for p, s in pairs:
            L = max(0, T - s)
            R = min(p, T)
            if L > R:
                valid = False
                break
            ranges.append((L, R))

        if not valid:
            continue

        dp = {}
        for val in range(ranges[0][0], ranges[0][1] + 1):
            dp[val] = 0

        for i in range(1, N):
            new_dp = {}
            L, R = ranges[i]

            for val in range(L, R + 1):
                min_cost = float('inf')
                for prev_val in dp:
                    if abs(val - prev_val) <= Y:
                        min_cost = min(min_cost, dp[prev_val])

                if min_cost < float('inf'):
                    new_dp[val] = min_cost

            dp = new_dp
            if not dp:
                valid = False
                break

        if not valid or not dp:
            continue

        base_cost = sum(p + s - T for p, s in pairs)
        min_extra = min(dp.values())
        total_cost = base_cost + min_extra
        best_cost = min(best_cost, total_cost)

    print(best_cost)

