public class Main {
    static class FastReader {
        BufferedReader br;
        StringTokenizer st;

        public FastReader() {
            br = new BufferedReader(new InputStreamReader(System.in));
        }

        String next() {
            while (st == null || !st.hasMoreElements()) {
                try {
                    st = new StringTokenizer(br.readLine());
                } catch (IOException e) {
                    e.printStackTrace();
                }
            }
            return st.nextToken();
        }

        int nextInt() {
            return Integer.parseInt(next());
        }

        long nextLong() {
            return Long.parseLong(next());
        }
    }

    public static void main(String[] args) {
        FastReader fr = new FastReader();
        int N = fr.nextInt();
        long Y = fr.nextLong();
        long[] P = new long[N];
        long[] S = new long[N];
        for (int i = 0; i < N; i++) {
            P[i] = fr.nextLong();
            S[i] = fr.nextLong();
        }

        long minT = 2;
        long maxT = 2000000000L;
        for (int i = 0; i < N; i++) {
            minT = Math.max(minT, 1 + 1); 
        }

        long L = 2, R = 2000000000L;
        long ans = Long.MAX_VALUE;

        while (L <= R) {
            long m1 = L + (R - L) / 3;
            long m2 = R - (R - L) / 3;
            long cost1 = calculateCost(N, Y, P, S, m1);
            long cost2 = calculateCost(N, Y, P, S, m2);
            ans = Math.min(ans, Math.min(cost1, cost2));
            if (cost1 < cost2) {
                R = m2 - 1;
            } else {
                L = m1 + 1;
            }
        }

        System.out.println(ans);
    }

    private static long calculateCost(int N, long Y, long[] P, long[] S, long T) {
        long totalCost = 0;
        long[] L = new long[N];
        long[] R = new long[N];

        for (int i = 0; i < N; i++) {
            L[i] = Math.max(1L, T - S[i]);
            R[i] = Math.min(T - 1, P[i]);
            if (L[i] > R[i]) {
                totalCost += (L[i] - R[i]);
                R[i] = L[i];
            }
            totalCost += (P[i] - R[i]);
        }

        long[] curL = new long[N];
        long[] curR = new long[N];
        curL[0] = L[0];
        curR[0] = R[0];

        for (int i = 1; i < N; i++) {
            curL[i] = Math.max(L[i], curL[i - 1] - Y);
            curR[i] = Math.min(R[i], curR[i - 1] + Y);
            if (curL[i] > curR[i]) return Long.MAX_VALUE / 2;
        }

        long[] finalP = new long[N];
        finalP[N - 1] = curR[N - 1];
        for (int i = N - 2; i >= 0; i--) {
            finalP[i] = Math.min(curR[i], finalP[i + 1] + Y);
        }

        long extraCost = 0;
        for (int i = 0; i < N; i++) {
            extraCost += (R[i] - finalP[i]);
        }

        return totalCost + extraCost;
    }
}

