    public static void main(String[] args) throws IOException {
        FastReader fr = new FastReader(System.in);
        int n = fr.nextInt();
        int m = fr.nextInt();
        Long[] r = new Long[n];
        for (int i = 0; i < n; i++) {
            r[i] = fr.nextLong();
        }
        Long[] t = new Long[m];
        for (int i = 0; i < m; i++) {
            t[i] = fr.nextLong();
        }

        Arrays.sort(r, Collections.reverseOrder());
        Arrays.sort(t, Collections.reverseOrder());

        long[] prefR = new long[n + 1];
        for (int i = 0; i < n; i++) {
            prefR[i + 1] = prefR[i] + r[i];
        }

        long[] prefT = new long[m + 1];
        for (int i = 0; i < m; i++) {
            prefT[i + 1] = prefT[i] + t[i];
        }

        long maxVal = 0;
        int maxTokensPossible = Math.min(n, m);

        int bestK = 0;
        for (int k = 1; k <= maxTokensPossible; k++) {
            if (t[k - 1] > 0) {
                bestK = k;
            } else {
                break;
            }
        }

        int bestJ = 0;
        for (int j = 1; j <= n; j++) {
            if (r[j - 1] > 0) {
                bestJ = j;
            } else {
                break;
            }
        }

        for (int k = 0; k <= maxTokensPossible; k++) {
            int numRelicsNeeded = Math.max(k, bestJ);
            long currentSum = prefT[k] + prefR[numRelicsNeeded];
            if (currentSum > maxVal) {
                maxVal = currentSum;
            }
        }

        System.out.println(maxVal);
    }

    static class FastReader {
        private InputStream in;
        private byte[] buffer = new byte[1024 * 8];
        private int pointer = 0;
        private int bufferLength = 0;

        public FastReader(InputStream in) {
            this.in = in;
        }

        private boolean hasNextByte() {
            if (pointer < bufferLength) return true;
            pointer = 0;
            try {
                bufferLength = in.read(buffer);
            } catch (IOException e) {
                return false;
            }
            return bufferLength > 0;
        }

        private int readByte() {
            return hasNextByte() ? buffer[pointer++] : -1;
        }

        public int nextInt() {
            return (int) nextLong();
        }

        public long nextLong() {
            int b = readByte();
            while (b != -1 && b <= 32) b = readByte();
            boolean negative = false;
            if (b == '-') {
                negative = true;
                b = readByte();
            }
            long res = 0;
            while (b >= '0' && b <= '9') {
                res = res * 10 + (b - '0');
                b = readByte();
            }
            return negative ? -res : res;
        }
    }
}

