using namespace std;

int main() {
    int P, Q;
    cin >> P >> Q;

    vector<vector<pair<int, int>>> adj(P + 1);

    for (int i = 0; i < Q; i++) {
        int u, v, w;
        cin >> u >> v >> w;
        adj[u].push_back({v, w});
        adj[v].push_back({u, w});
    }

    vector<long long> result(P + 1, -1);

    for (int start = 1; start <= P; start++) {
        if (result[start] != -1) continue;

        vector<int> component;
        queue<int> q;
        q.push(start);
        result[start] = 0;
        component.push_back(start);

        bool valid = true;

        while (!q.empty() && valid) {
            int u = q.front();
            q.pop();

            for (auto [v, w] : adj[u]) {
                long long expected = result[u] ^ w;

                if (result[v] == -1) {
                    result[v] = expected;
                    component.push_back(v);
                    q.push(v);
                } else if (result[v] != expected) {
                    valid = false;
                    break;
                }
            }
        }

        if (!valid) {
            cout << -1 << endl;
            return 0;
        }

        for (int bit = 0; bit < 30; bit++) {
            int count0 = 0, count1 = 0;

            for (int node : component) {
                if ((result[node] >> bit) & 1) {
                    count1++;
                } else {
                    count0++;
                }
            }

            if (count1 > count0) {
                for (int node : component) {
                    result[node] ^= (1LL << bit);
                }
            }
        }
    }

    for (int i = 1; i <= P; i++) {
        if (i > 1) cout << " ";
        cout << result[i];
    }
    cout << endl;

    return 0;
}

