import (
	"fmt"
	"os"
	"bufio"
)

type Edge struct {
	to, xorVal int
}

func main() {
	reader := bufio.NewReader(os.Stdin)
	writer := bufio.NewWriter(os.Stdout)
	defer writer.Flush()

	var P, Q int
	fmt.Fscan(reader, &P, &Q)

	graph := make([][]Edge, P+1)

	for i := 0; i < Q; i++ {
		var u, v, w int
		fmt.Fscan(reader, &u, &v, &w)
		graph[u] = append(graph[u], Edge{v, w})
		graph[v] = append(graph[v], Edge{u, w})
	}

	result := make([]int, P+1)
	visited := make([]bool, P+1)

	for start := 1; start <= P; start++ {
		if visited[start] {
			continue
		}

		component := []int{}
		values := make(map[int]int)

		queue := []int{start}
		visited[start] = true
		values[start] = 0
		component = append(component, start)
		valid := true

		for len(queue) > 0 {
			u := queue[0]
			queue = queue[1:]

			for _, edge := range graph[u] {
				v := edge.to
				w := edge.xorVal
				expected := values[u] ^ w

				if visited[v] {
					if values[v] != expected {
						valid = false
						break
					}
				} else {
					visited[v] = true
					values[v] = expected
					component = append(component, v)
					queue = append(queue, v)
				}
			}
			if !valid {
				break
			}
		}

		if !valid {
			fmt.Fprintln(writer, -1)
			return
		}

		bestConfig := make(map[int]int)
		for node, val := range values {
			bestConfig[node] = val
		}
		bestSum := 0
		for _, val := range values {
			bestSum += val
		}

		for bit := 0; bit < 30; bit++ {
			mask := 1 << bit
			newSum := 0
			for _, node := range component {
				newVal := values[node] ^ mask
				newSum += newVal
			}
			if newSum < bestSum {
				bestSum = newSum
				for _, node := range component {
					bestConfig[node] = values[node] ^ mask
				}
			}
		}

		for node, val := range bestConfig {
			result[node] = val
		}
	}

	for i := 1; i <= P; i++ {
		if i > 1 {
			fmt.Fprint(writer, " ")
		}
		fmt.Fprint(writer, result[i])
	}
	fmt.Fprintln(writer)
}

import java.util.*;
import java.io.*;

public class Main {
    static class Edge {
        int to;
        long weight;
        Edge(int to, long weight) {
            this.to = to;
            this.weight = weight;
        }
    }

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());

        int P = Integer.parseInt(st.nextToken());
        int Q = Integer.parseInt(st.nextToken());

        List<List<Edge>> graph = new ArrayList<>();
        for (int i = 0; i <= P; i++) {
            graph.add(new ArrayList<>());
        }

        for (int i = 0; i < Q; i++) {
            st = new StringTokenizer(br.readLine());
            int u = Integer.parseInt(st.nextToken());
            int v = Integer.parseInt(st.nextToken());
            long w = Long.parseLong(st.nextToken());

            graph.get(u).add(new Edge(v, w));
            graph.get(v).add(new Edge(u, w));
        }

        long[] result = new long[P + 1];
        boolean[] visited = new boolean[P + 1];

        for (int i = 1; i <= P; i++) {
            if (!visited[i]) {
                List<Integer> component = new ArrayList<>();
                Map<Integer, Long> values = new HashMap<>();

                if (!dfs(i, 0L, graph, visited, values, component)) {
                    System.out.println(-1);
                    return;
                }

                long minSum = Long.MAX_VALUE;
                long[] bestConfig = new long[P + 1];

                for (int root : component) {
                    long offset = values.get(root);
                    long sum = 0;
                    long[] config = new long[P + 1];

                    for (int node : component) {
                        config[node] = values.get(node) ^ offset;
                        sum += config[node];
                    }

                    if (sum < minSum) {
                        minSum = sum;
                        bestConfig = config;
                    }
                }

                for (int node : component) {
                    result[node] = bestConfig[node];
                }
            }
        }

        StringBuilder sb = new StringBuilder();
        for (int i = 1; i <= P; i++) {
            if (i > 1) sb.append(" ");
            sb.append(result[i]);
        }
        System.out.println(sb.toString());
    }

    static boolean dfs(int node, long value, List<List<Edge>> graph, 
                      boolean[] visited, Map<Integer, Long> values, List<Integer> component) {
        if (visited[node]) {
            return values.get(node) == value;
        }

        visited[node] = true;
        values.put(node, value);
        component.add(node);

        for (Edge edge : graph.get(node)) {
            long nextValue = value ^ edge.weight;
            if (!dfs(edge.to, nextValue, graph, visited, values, component)) {
                return false;
            }
        }

        return true;
    }
}

from collections import defaultdict, deque

def main():
    P, Q = map(int, input().split())

    graph = defaultdict(list)

    for _ in range(Q):
        u, v, w = map(int, input().split())
        graph[u].append((v, w))
        if u != v:
            graph[v].append((u, w))

    assignment = [None] * (P + 1)

    for start in range(1, P + 1):
        if assignment[start] is not None:
            continue

        assignment[start] = 0
        queue = deque([start])
        valid = True

        while queue and valid:
            node = queue.popleft()

            for neighbor, xor_val in graph[node]:
                expected = assignment[node] ^ xor_val

                if assignment[neighbor] is None:
                    assignment[neighbor] = expected
                    queue.append(neighbor)
                elif assignment[neighbor] != expected:
                    valid = False
                    break

        if not valid:
            print(-1)
            return

    result = assignment[1:]
    print(' '.join(map(str, result)))

