int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int P, Q;
    if (!(cin >> P >> Q)) return 0;

    vector<vector<Edge>> adj(P + 1);
    for (int i = 0; i < Q; ++i) {
        int u, v, w;
        cin >> u >> v >> w;
        adj[u].push_back({v, w});
        adj[v].push_back({u, w});
    }

    vector<long long> val(P + 1, -1);
    vector<long long> result(P + 1, 0);

    for (int i = 1; i <= P; ++i) {
        if (val[i] != -1) continue;

        vector<int> component;
        vector<int> q;
        q.push_back(i);
        val[i] = 0;
        component.push_back(i);

        int head = 0;
        while(head < (int)q.size()){
            int u = q[head++];
            for (auto& edge : adj[u]) {
                if (val[edge.to] == -1) {
                    val[edge.to] = val[u] ^ edge.weight;
                    component.push_back(edge.to);
                    q.push_back(edge.to);
                } else {
                    if ((val[edge.to] ^ val[u]) != edge.weight) {
                        cout << -1 << endl;
                        return 0;
                    }
                }
            }
        }

        for (int bit = 0; bit < 31; ++bit) {
            int count1 = 0;
            for (int node : component) {
                if ((val[node] >> bit) & 1) {
                    count1++;
                }
            }
            int count0 = (int)component.size() - count1;
            int bit_val = (count1 > count0) ? 1 : 0;
            for (int node : component) {
                if (bit_val) {
                    result[node] |= ((long long)((val[node] >> bit) & 1 ^ 1) << bit);
                } else {
                    result[node] |= ((long long)((val[node] >> bit) & 1) << bit);
                }
            }
        }
    }

    for (int i = 1; i <= P; ++i) {
        cout << result[i] << (i == P ? "" : " ");
    }
    cout << endl;

    return 0;
