}

func main() {
	reader := bufio.NewReader(os.Stdin)
	writer := bufio.NewWriter(os.Stdout)
	defer writer.Flush()

	var P, Q int
	fmt.Fscan(reader, &P, &Q)

	adj := make([][]Edge, P+1)
	for i := 0; i < Q; i++ {
		var u, v, w int
		fmt.Fscan(reader, &u, &v, &w)
		adj[u] = append(adj[u], Edge{v, w})
		adj[v] = append(adj[v], Edge{u, w})
	}

	res := make([]int, P+1)
	visited := make([]bool, P+1)
	compXor := make([]int, P+1)

	for i := 1; i <= P; i++ {
		if visited[i] {
			continue
		}

		component := []int{i}
		visited[i] = true
		compXor[i] = 0
		q := []int{i}

		for len(q) > 0 {
			u := q[0]
			q = q[1:]
			for _, edge := range adj[u] {
				if !visited[edge.to] {
					visited[edge.to] = true
					compXor[edge.to] = compXor[u] ^ edge.xor
					component = append(component, edge.to)
					q = append(q, edge.to)
				} else {
					if compXor[edge.to] != (compXor[u] ^ edge.xor) {
						fmt.Fprintln(writer, "-1")
						return
					}
				}
			}
		}

		bestX := 0
		for bit := 0; bit <= 30; bit++ {
			count0 := 0
			count1 := 0
			for _, node := range component {
				if (compXor[node]>>bit)&1 == 1 {
					count1++
				} else {
					count0++
				}
			}
			if count1 > count0 {
				bestX |= (1 << bit)
			}
		}

		for _, node := range component {
			res[node] = compXor[node] ^ bestX
		}
	}

	for i := 1; i <= P; i++ {
		fmt.Fprint(writer, res[i])
		if i < P {
			fmt.Fprint(writer, " ")
		}
	}
	fmt.Fprintln(writer)
