                        }
                    }

                    int bestBit = (count1 > count0) ? 1 : 0;
                    for (int node : component) {
                        if (bestBit == 1) {
                            result[node] |= (long) (((xorSum[node] >> bit) & 1) ^ 1) << bit;
                        } else {
