using namespace std;

class FenwickTree {
    vector<int> tree;
    int n;
public:
    FenwickTree(int size) : n(size), tree(size + 1, 0) {}

    void update(int idx, int delta) {
        idx++;
        while (idx <= n) {
            tree[idx] += delta;
            idx += idx & (-idx);
        }
    }

    int query(int idx) {
        idx++;
        int sum = 0;
        while (idx > 0) {
            sum += tree[idx];
            idx -= idx & (-idx);
        }
        return sum;
    }

    int rangeQuery(int left, int right) {
        if (left > right) return 0;
        if (left == 0) return query(right);
        return query(right) - query(left - 1);
    }
};

long long countInversions(const vector<int>& arr, int maxVal) {
    int n = arr.size();
    FenwickTree ft(maxVal);
    long long inversions = 0;

    for (int i = 0; i < n; i++) {
        if (arr[i] < maxVal - 1) {
            inversions += ft.rangeQuery(arr[i] + 1, maxVal - 1);
        }
        ft.update(arr[i], 1);
    }

    return inversions;
}

