func mergeAndCount(arr []int, temp []int, left, mid, right int) int {
	i := left
	j := mid + 1
	k := left
	invCount := 0

	for i <= mid && j <= right {
		if arr[i] <= arr[j] {
			temp[k] = arr[i]
			i++
		} else {
			temp[k] = arr[j]
			invCount += (mid - i + 1)
			j++
		}
		k++
	}

	for i <= mid {
		temp[k] = arr[i]
		i++
		k++
	}

	for j <= right {
		temp[k] = arr[j]
		j++
		k++
	}

	for i := left; i <= right; i++ {
		arr[i] = temp[i]
	}

	return invCount
}

func mergeSortAndCount(arr []int, temp []int, left, right int) int {
	invCount := 0
	if left < right {
		mid := (left + right) / 2
		invCount += mergeSortAndCount(arr, temp, left, mid)
		invCount += mergeSortAndCount(arr, temp, mid+1, right)
		invCount += mergeAndCount(arr, temp, left, mid, right)
	}
	return invCount
}

func countInversions(arr []int) int {
	n := len(arr)
	temp := make([]int, n)
	arrCopy := make([]int, n)
	copy(arrCopy, arr)
	return mergeSortAndCount(arrCopy, temp, 0, n-1)
}

