        a[i] = count[i];
        b[i] = f[i];
    }

    auto fwht = [&](vector<long long>& v) {
        int n = v.size();
        for (int len = 1; len < n; len <<= 1) {
            for (int i = 0; i < n; i += 2 * len) {
                for (int j = 0; j < len; j++) {
                    long long x = v[i + j];
                    long long y = v[i + len + j];
                    v[i + j] = x + y;
                    v[i + len + j] = x - y;
                }
            }
        }
    };

    fwht(a);
    fwht(b);
    vector<long long> c(1 << M);
    for (int i = 0; i < (1 << M); ++i) {
        c[i] = a[i] * b[i];
    }
    fwht(c);

    long long min_sum = (long long)L * M;
    for (int i = 0; i < (1 << M); ++i) {
        long long val = c[i] >> M;
        if (val < min_sum) min_sum = val;
    }

    cout << min_sum << endl;

    return 0;
}

