func main() {
	reader := bufio.NewReader(os.Stdin)
	var L, M int
	fmt.Fscan(reader, &L, &M)

	rowMasks := make([]int, L)
	for i := 0; i < L; i++ {
		var s string
		fmt.Fscan(reader, &s)
		mask := 0
		for j := 0; j < M; j++ {
			if s[j] == '1' {
				mask |= (1 << j)
			}
		}
		rowMasks[i] = mask
	}

	freq := make([]int, 1<<M)
	for _, m := range rowMasks {
		freq[m]++
	}

	popcount := make([]int, 1<<M)
	for i := 1; i < (1 << M); i++ {
		popcount[i] = popcount[i>>1] + (i & 1)
	}

	minSum := L * M

	for colOps := 0; colOps < (1 << M); colOps++ {
		currentSum := 0
		for rowVal, count := range freq {
			if count == 0 {
				continue
			}
			transformed := rowVal ^ colOps
			ones := popcount[transformed]
			zeros := M - ones
			if ones < zeros {
				currentSum += ones * count
			} else {
				currentSum += zeros * count
			}
		}
		if currentSum < minSum {
			minSum = currentSum
		}
	}

	fmt.Println(minSum)
}

