public class Main {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        if (!st.hasMoreTokens()) return;
        int L = Integer.parseInt(st.nextToken());
        int M = Integer.parseInt(st.nextToken());

        int[] counts = new int[1 << M];
        for (int i = 0; i < L; i++) {
            String line = br.readLine();
            int mask = 0;
            for (int j = 0; j < M; j++) {
                if (line.charAt(j) == '1') {
                    mask |= (1 << j);
                }
            }
            counts[mask]++;
        }

        long[] f = new long[1 << M];
        for (int i = 0; i < (1 << M); i++) {
            f[i] = counts[i];
        }

        int[] bitCount = new int[1 << M];
        for (int i = 0; i < (1 << M); i++) {
            bitCount[i] = Integer.bitCount(i);
        }

        long[] g = new long[1 << M];
        for (int i = 0; i < (1 << M); i++) {
            g[i] = Math.min(bitCount[i], M - bitCount[i]);
        }

        fwht(f, false);
        fwht(g, false);

        long[] h = new long[1 << M];
        for (int i = 0; i < (1 << M); i++) {
            h[i] = f[i] * g[i];
        }

        fwht(h, true);

        long minSum = Long.MAX_VALUE;
        for (int i = 0; i < (1 << M); i++) {
            minSum = Math.min(minSum, h[i]);
        }

        System.out.println(minSum);
    }

    private static void fwht(long[] a, boolean inverse) {
        int n = a.length;
        for (int len = 1; len < n; len <<= 1) {
            for (int i = 0; i < n; i += 2 * len) {
                for (int j = 0; j < len; j++) {
                    long u = a[i + j];
                    long v = a[i + len + j];
                    a[i + j] = u + v;
                    a[i + len + j] = u - v;
                }
            }
        }
        if (inverse) {
            for (int i = 0; i < n; i++) {
                a[i] /= n;
            }
        }
    }
}

