    vector<long long> divisors;
    long long limit = (long long)cbrt(P) + 1000;

    for (long long d = 1; d * d * d <= P && d <= limit; d++) {
        if (P % d == 0) {
            divisors.push_back(d);
            if (d * d != P) {
                divisors.push_back(P / d);
            }
        }
    }

    for (long long d : divisors) {
        long long q = P / d;
        long long discriminant = 12 * q - 3 * d * d;

