int dfs(int u, int parent) {
    if (used[u]) return 0;

    vector<int> childDepths;
    for (int v : adj[u]) {
        if (v != parent && !used[v]) {
            int depth = dfs(v, u);
            if (depth > 0) {
                childDepths.push_back(depth);
            }
        }
    }

    sort(childDepths.rbegin(), childDepths.rend());

    for (int depth : childDepths) {
        if (used[u]) break;

        if (depth == K - 1) {
            pathsFound++;
            used[u] = true;
            return 0;
        }
    }

    if (!used[u] && !childDepths.empty()) {
        return childDepths[0] + 1;
    }

    if (!used[u]) {
        return 1;
    }

    return 0;
}

bool tryPartition(int root) {
    used.assign(N * K + 1, false);
    pathsFound = 0;

    int remaining = dfs(root, -1);

    if (remaining == K) {
        pathsFound++;
    }

    return pathsFound == N;
}

