            int a = Integer.parseInt(edge[0]);
            int b = Integer.parseInt(edge[1]);
            adj[a].add(b);
            adj[b].add(a);
        }

        if (K == 1) {
            System.out.println("Yes");
            return;
        }

        visited = new boolean[totalNodes + 1];
        pathsFormed = 0;

        for (int start = 1; start <= totalNodes; start++) {
            if (!visited[start]) {
                dfs(start, -1);
                break;
            }
        }

        if (pathsFormed == N) {
            System.out.println("Yes");
        } else {
            System.out.println("No");
        }
    }

    static int dfs(int u, int parent) {
        List<Integer> childLengths = new ArrayList<>();

        for (int v : adj[u]) {
            if (v != parent && !visited[v]) {
                int len = dfs(v, u);
                if (len > 0) {
                    childLengths.add(len);
                }
            }
        }

        Collections.sort(childLengths, Collections.reverseOrder());

        int myLength = 0;

        for (int len : childLengths) {
            if (myLength == 0) {
                myLength = len;
            } else {
                int totalLen = myLength + 1 + len;
                if (totalLen == K) {
                    pathsFormed++;
                    myLength = 0;
                } else if (totalLen > K) {
                    myLength = 0;
                    break;
                }
            }
        }

        if (myLength > 0 && myLength < K) {
            visited[u] = true;
            return myLength + 1;
        } else {
            visited[u] = true;
            if (myLength == K - 1) {
                pathsFormed++;
                return 0;
            }
            return 0;
        }
    }
}

