int dijkstra(vector<bool>& tolled) {
    vector<int> dist(N + 1, 1e9);
    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;
    dist[1] = 0;
    pq.push({0, 1});

    while (!pq.empty()) {
        auto [d, u] = pq.top();
        pq.pop();

        if (d > dist[u]) continue;

        for (int edgeIdx : adj[u]) {
            int v = edges[edgeIdx].second;
            int cost = tolled[edgeIdx] ? 1 : 0;
            if (dist[u] + cost < dist[v]) {
                dist[v] = dist[u] + cost;
                pq.push({dist[v], v});
            }
        }
    }

    return dist[N];
}

bool canAchieve(int target) {
    vector<int> indices(M);
    for (int i = 0; i < M; i++) indices[i] = i;

    int totalCombos = 1 << M;
    for (int mask = 0; mask < totalCombos; mask++) {
        if (__builtin_popcount(mask) != K) continue;

        vector<bool> tolled(M, false);
        for (int i = 0; i < M; i++) {
            if (mask & (1 << i)) {
                tolled[i] = true;
            }
        }

        int minCost = dijkstra(tolled);
        if (minCost >= target) return true;
    }

    return false;
}

