type Edge struct {
	to   int
	cost int
}

type PQItem struct {
	node int
	dist int
	idx  int
}

type PriorityQueue []*PQItem

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].dist < pq[j].dist
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
	pq[i].idx = i
	pq[j].idx = j
}

func (pq *PriorityQueue) Push(x interface{}) {
	n := len(*pq)
	item := x.(*PQItem)
	item.idx = n
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	old[n-1] = nil
	item.idx = -1
	*pq = old[0 : n-1]
	return item
}

func dijkstra(n int, graph [][]Edge, start int, end int) int {
	dist := make([]int, n+1)
	for i := range dist {
		dist[i] = 1e9
	}
	dist[start] = 0

	pq := make(PriorityQueue, 0)
	heap.Init(&pq)
	heap.Push(&pq, &PQItem{node: start, dist: 0})

	for pq.Len() > 0 {
		item := heap.Pop(&pq).(*PQItem)
		u := item.node
		d := item.dist

		if d > dist[u] {
			continue
		}

		for _, edge := range graph[u] {
			v := edge.to
			newDist := dist[u] + edge.cost
			if newDist < dist[v] {
				dist[v] = newDist
				heap.Push(&pq, &PQItem{node: v, dist: newDist})
			}
		}
	}

	return dist[end]
}

func combinations(m int, k int) [][]int {
	result := [][]int{}
	var backtrack func(start int, combo []int)
	backtrack = func(start int, combo []int) {
		if len(combo) == k {
			temp := make([]int, k)
			copy(temp, combo)
			result = append(result, temp)
			return
		}
		for i := start; i < m; i++ {
			backtrack(i+1, append(combo, i))
		}
	}
	backtrack(0, []int{})
	return result
}

