public class Main {
    static int N, M, K;
    static int[] A, B;

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        N = sc.nextInt();
        M = sc.nextInt();
        K = sc.nextInt();

        A = new int[M];
        B = new int[M];

        for (int i = 0; i < M; i++) {
            A[i] = sc.nextInt();
            B[i] = sc.nextInt();
        }

        int maxCost = 0;

        if (M <= 20) {
            for (int mask = 0; mask < (1 << M); mask++) {
                if (Integer.bitCount(mask) == K) {
                    int cost = getShortestPath(mask);
                    maxCost = Math.max(maxCost, cost);
                }
            }
        } else {
            maxCost = solveLarge();
        }

        System.out.println(maxCost);
    }

    static int solveLarge() {
        int maxCost = 0;
        int[] indices = new int[K];
        maxCost = generateCombinations(0, 0, indices);
        return maxCost;
    }

    static int generateCombinations(int start, int depth, int[] indices) {
        if (depth == K) {
            int mask = 0;
            for (int i = 0; i < K; i++) {
                mask |= (1 << indices[i]);
            }
            return getShortestPath(mask);
        }

        int maxCost = 0;
        for (int i = start; i < M; i++) {
            indices[depth] = i;
            maxCost = Math.max(maxCost, generateCombinations(i + 1, depth + 1, indices));
        }
        return maxCost;
    }

    static int getShortestPath(int mask) {
        int[] dist = new int[N + 1];
        Arrays.fill(dist, Integer.MAX_VALUE);
        dist[1] = 0;

        PriorityQueue<int[]> pq = new PriorityQueue<>((a, b) -> a[1] - b[1]);
        pq.offer(new int[]{1, 0});

        while (!pq.isEmpty()) {
            int[] curr = pq.poll();
            int node = curr[0];
            int cost = curr[1];

            if (cost > dist[node]) continue;

            for (int i = 0; i < M; i++) {
                if (A[i] == node) {
                    int toll = ((mask & (1 << i)) != 0) ? 1 : 0;
                    int newCost = cost + toll;

                    if (newCost < dist[B[i]]) {
                        dist[B[i]] = newCost;
                        pq.offer(new int[]{B[i], newCost});
                    }
                }
            }
        }

        return dist[N] == Integer.MAX_VALUE ? 0 : dist[N];
    }
}

using namespace std;

const int INF = 1e9;

struct Edge {
    int to, cap, cost, rev;
};

vector<Edge> adj[105];
int dist[105];
int prevv[105], preve[105];

void add_edge(int from, int to, int cap, int cost) {
    adj[from].push_back({to, cap, cost, (int)adj[to].size()});
    adj[to].push_back({from, 0, -cost, (int)adj[from].size() - 1});
}

int min_cost_flow(int s, int t, int f) {
    int res = 0;
    while (f > 0) {
        fill(dist, dist + 105, INF);
        dist[s] = 0;
        bool update = true;
        while (update) {
            update = false;
            for (int v = 0; v < 105; v++) {
                if (dist[v] == INF) continue;
                for (int i = 0; i < adj[v].size(); i++) {
                    Edge &e = adj[v][i];
                    if (e.cap > 0 && dist[e.to] > dist[v] + e.cost) {
                        dist[e.to] = dist[v] + e.cost;
                        prevv[e.to] = v;
                        preve[e.to] = i;
                        update = true;
                    }
                }
            }
        }
        if (dist[t] == INF) return -1;
        int d = f;
        for (int v = t; v != s; v = prevv[v]) {
            d = min(d, adj[prevv[v]][preve[v]].cap);
        }
        f -= d;
        res += d * dist[t];
        for (int v = t; v != s; v = prevv[v]) {
            Edge &e = adj[prevv[v]][preve[v]];
            e.cap -= d;
            adj[v][e.rev].cap += d;
        }
    }
    return res;
}

bool check(int x, int n, int m, int k, const vector<pair<int, int>>& edges) {
    if (x == 0) return true;
    for (int i = 0; i < 105; i++) adj[i].clear();
    int s = 0, t = n + 1;
    add_edge(s, 1, x, 0);
    add_edge(n, t, x, 0);
    for (auto& e : edges) {
        add_edge(e.first, e.second, 1, 0);
        add_edge(e.first, e.second, m, 1);
    }
    int res = min_cost_flow(s, t, x);
    return (res != -1 && res <= k);
}

