                }

                long newPos = ((long)r << 32) | (c & 0xFFFFFFFFL);
                newSignals.put(newPos, newSignals.getOrDefault(newPos, 0) + count);
            }

            long origin = 0L;
            if (!newSignals.containsKey(origin)) {
                newSignals.put(origin, 1);
            }

            signals = newSignals;

            long targetPos = ((long)R << 32) | (C & 0xFFFFFFFFL);
            if (signals.containsKey(targetPos)) {
