	fmt.Scan(&N, &R, &C)

	var T string
	fmt.Scan(&T)

	dr := make([]int, N+1)
	dc := make([]int, N+1)

	for i := 0; i < N; i++ {
		dr[i+1] = dr[i]
		dc[i+1] = dc[i]
		switch T[i] {
		case 'N':
			dr[i+1]--
		case 'S':
			dr[i+1]++
		case 'W':
			dc[i+1]--
		case 'E':
			dc[i+1]++
		}
	}

	exists := make([]bool, N+1)
	active := make([]bool, N+1)
	active[0] = true

	ans := make([]byte, N)

	for t := 1; t <= N; t++ {
		targetR := R + dr[t]
		targetC := C + dc[t]

		found := false
		if targetR >= -N && targetR <= N && targetC >= -N && targetC <= N {
			for i := 0; i < t; i++ {
				if active[i] && dr[i] == targetR && dc[i] == targetC {
					found = true
					break
				}
			}
		}

		if found {
			ans[t-1] = '1'
		} else {
			ans[t-1] = '0'
		}

		atOrigin := false
		for i := 0; i < t; i++ {
			if active[i] && dr[i] == dr[t] && dc[i] == dc[t] {
				atOrigin = true
				break
			}
		}
		if !atOrigin {
			active[t] = true
		}
	}

	solveOptimized(N, R, C, T)
}

func solveOptimized(N int, R, C int, T string) {
	dr := make([]int, N+1)
	dc := make([]int, N+1)
	for i := 0; i < N; i++ {
		dr[i+1] = dr[i]
		dc[i+1] = dc[i]
		switch T[i] {
		case 'N': dr[i+1]--
		case 'S': dr[i+1]++
		case 'W': dc[i+1]--
		case 'E': dc[i+1]++
		}
	}

	type Point struct {
		r, c int
	}
	seen := make(map[Point]bool)
	active := make([]bool, N+1)

	seen[Point{0, 0}] = true
	active[0] = true

	ans := make([]byte, N)
	out := bufio.NewWriter(os.Stdout)

	for t := 1; t <= N; t++ {
		tr := R + dr[t]
		tc := C + dc[t]

		if seen[Point{tr, tc}] {
			ans[t-1] = '1'
		} else {
			ans[t-1] = '0'
		}

		if !seen[Point{dr[t], dc[t]}] {
			active[t] = true
			seen[Point{dr[t], dc[t]}] = true
		}
	}

	fmt.Fprintln(out, string(ans))
	out.Flush()
}

