bool isPalindrome(const string& s) {
    int n = s.length();
    for (int i = 0; i < n / 2; i++) {
        if (s[i] != s[n - 1 - i]) {
            return false;
        }
    }
    return true;
}

string findMinimalPalindrome(const string& prefix) {
    int n = prefix.length();

    for (int i = 0; i < n; i++) {
        string candidate = prefix;
        for (int j = n - 1 - i; j >= 0; j--) {
            candidate += prefix[j];
        }
        if (isPalindrome(candidate)) {
            return candidate;
        }
    }

    string result = prefix;
    for (int i = n - 1; i >= 0; i--) {
        result += prefix[i];
    }
    return result;
}

