	fmt.Scan(&prefix)

	n := len(prefix)

	for i := 0; i < n; i++ {
		candidate := prefix + reverse(prefix[:i])
		if isPalindrome(candidate) {
			fmt.Println(candidate)
			return
		}
	}

	fmt.Println(prefix + reverse(prefix))
}

import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        String prefix = sc.nextLine();
        sc.close();

        String result = findMinimalPalindrome(prefix);
        System.out.println(result);
    }

    static String findMinimalPalindrome(String s) {
        int n = s.length();

        for (int i = 0; i < n; i++) {
            if (isPalindrome(s, i)) {
                StringBuilder sb = new StringBuilder(s);
                for (int j = i - 1; j >= 0; j--) {
                    sb.append(s.charAt(j));
                }
                return sb.toString();
            }
        }

        return s;
    }

    static boolean isPalindrome(String s, int start) {
        int left = start;
        int right = s.length() - 1;

        while (left < right) {
            if (s.charAt(left) != s.charAt(right)) {
                return false;
            }
            left++;
            right--;
        }

        return true;
