		for j > 0 && t[i] != t[j] {
			j = pi[j-1]
		}
		if t[i] == t[j] {
			j++
		}
		pi[i] = j
	}

	overlap := pi[n-1]
	suffix := s[overlap:]
	resSuffix := make([]byte, len(suffix))
	for i := 0; i < len(suffix); i++ {
		resSuffix[i] = suffix[len(suffix)-1-i]
	}

