import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        if (!sc.hasNext()) return;
        String s = sc.next();
        int n = s.length();

        long base = 31;
        long mod = 1_000_000_007;

        long[] pow = new long[n + 1];
        long[] prefixHash = new long[n + 1];
        long[] suffixHash = new long[n + 1];

        pow[0] = 1;
        for (int i = 0; i < n; i++) {
            pow[i + 1] = (pow[i] * base) % mod;
            prefixHash[i + 1] = (prefixHash[i] * base + (s.charAt(i) - 'A' + 1)) % mod;
        }

        for (int i = n - 1; i >= 0; i--) {
            suffixHash[i] = (suffixHash[i + 1] * base + (s.charAt(i) - 'A' + 1)) % mod;
        }

        int maxPalindromeSuffixLen = 0;
        for (int len = 1; len <= n; len++) {
            int start = n - len;
            long h1 = (prefixHash[n] - prefixHash[start] * pow[len] % mod + mod) % mod;
            long h2 = suffixHash[start];
            if (h1 == h2) {
                maxPalindromeSuffixLen = len;
            }
        }

        StringBuilder sb = new StringBuilder(s);
        for (int i = n - maxPalindromeSuffixLen - 1; i >= 0; i--) {
            sb.append(s.charAt(i));
        }
        System.out.println(sb.toString());
    }
}

