using namespace std;

struct DSU {
    vector<int> parent;
    vector<int> size;
    vector<int> dist;
    DSU(int n) {
        parent.resize(n + 1);
        iota(parent.begin(), parent.end(), 0);
        size.assign(n + 1, 1);
        dist.assign(n + 1, 0);
    }
    pair<int, int> find(int i) {
        if (parent[i] == i)
            return {i, 0};
        pair<int, int> root = find(parent[i]);
        parent[i] = root.first;
        dist[i] = (dist[i] + root.second) % 2;
        return {parent[i], dist[i]};
    }
    void unite(int i, int j) {
        pair<int, int> root_i = find(i);
        pair<int, int> root_j = find(j);
        if (root_i.first != root_j.first) {
            if (size[root_i.first] < size[root_j.first]) swap(root_i, root_j);
            parent[root_j.first] = root_i.first;
            dist[root_j.first] = (root_i.second + 1 + root_j.second) % 2;
            size[root_i.first] += size[root_j.first];
        }
    }
};

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int N, M;
    if (!(cin >> N >> M)) return 0;

    DSU dsu(N);
    for (int i = 0; i < M; ++i) {
        int u, v;
        cin >> u >> v;
        dsu.unite(u, v);
    }

    vector<long long> black(N + 1, 0), white(N + 1, 0);
    for (int i = 1; i <= N; ++i) {
        pair<int, int> root = dsu.find(i);
        if (root.second == 0) black[root.first]++;
        else white[root.first]++;
    }

    long long total_edges = 0;
    for (int i = 1; i <= N; ++i) {
        if (dsu.parent[i] == i) {
            total_edges += black[i] * white[i];
        }
    }

    long long total_possible = 0;
    long long sum_n = 0;
    for (int i = 1; i <= N; ++i) {
        if (dsu.parent[i] == i) {
            long long sz = black[i] + white[i];
            total_possible += sz * sum_n;
            sum_n += sz;
        }
    }
    total_edges += total_possible;

    long long moves = total_edges - M;
    if (moves % 2 == 1) {
        cout << "Evelyn" << endl;
    } else {
        cout << "Marcus" << endl;
    }

    return 0;
