            }

            int[][] positions = new int[N + 1][2];
            int[] count = new int[N + 1];

            for (int i = 0; i < 2 * N; i++) {
                int species = B[i];
                positions[species][count[species]++] = i;
            }

            int result = 0;

            for (int x = 1; x <= N; x++) {
                for (int y = x + 1; y <= N; y++) {
                    int x1 = positions[x][0];
                    int x2 = positions[x][1];
                    int y1 = positions[y][0];
                    int y2 = positions[y][1];

                    if (Math.abs(x1 - x2) == 1) continue;
                    if (Math.abs(y1 - y2) == 1) continue;

                    if (canPairUp(x1, x2, y1, y2)) {
                        result++;
                    }
                }
            }

            sb.append(result).append("\n");
        }

        System.out.print(sb);
    }

    static boolean canPairUp(int x1, int x2, int y1, int y2) {
        int[] pos = {x1, x2, y1, y2};
        Arrays.sort(pos);

        if (pos[1] - pos[0] == 1 && pos[3] - pos[2] == 1) {
            return true;
        }

        if (pos[1] - pos[0] == 1) {
            return canSwapToAdjacent(x1, x2, y1, y2, pos[0], pos[1]);
        }
        if (pos[2] - pos[1] == 1) {
            return canSwapToAdjacent(x1, x2, y1, y2, pos[1], pos[2]);
        }
        if (pos[3] - pos[2] == 1) {
            return canSwapToAdjacent(x1, x2, y1, y2, pos[2], pos[3]);
        }

        return checkAllConfigurations(x1, x2, y1, y2);
    }

    static boolean canSwapToAdjacent(int x1, int x2, int y1, int y2, int adj1, int adj2) {
        boolean xHasAdj = (x1 == adj1 || x1 == adj2 || x2 == adj1 || x2 == adj2);
        boolean yHasAdj = (y1 == adj1 || y1 == adj2 || y2 == adj1 || y2 == adj2);
        return xHasAdj && yHasAdj;
    }

    static boolean checkAllConfigurations(int x1, int x2, int y1, int y2) {
        int[][] configs = {
            {x1, x2, y1, y2},
            {x1, y1, x2, y2},
            {x1, y2, x2, y1},
            {y1, x2, y2, x1},
            {y1, y2, x1, x2},
            {y2, x2, y1, x1}
        };

        for (int[] config : configs) {
            if (simulate(x1, x2, y1, y2, config)) {
                return true;
            }
        }

        return false;
    }

    static boolean simulate(int x1, int x2, int y1, int y2, int[] target) {
        int[] current = {x1, x2, y1, y2};

        for (int iter = 0; iter < 10; iter++) {
            boolean changed = false;
            for (int i = 0; i < 4; i++) {
                for (int j = i + 1; j < 4; j++) {
                    boolean iIsX = (current[i] == x1 || current[i] == x2);
                    boolean jIsY = (current[j] == y1 || current[j] == y2);
                    boolean iIsY = (current[i] == y1 || current[i] == y2);
                    boolean jIsX = (current[j] == x1 || current[j] == x2);

                    if ((iIsX && jIsY) || (iIsY && jIsX)) {
                        int temp = current[i];
                        current[i] = current[j];
                        current[j] = temp;

                        if (isAdjacent(current, x1, x2) && isAdjacent(current, y1, y2)) {
                            return true;
                        }

                        temp = current[i];
                        current[i] = current[j];
                        current[j] = temp;
                    }
                }
            }
        }

        return false;
    }

    static boolean isAdjacent(int[] arr, int p1, int p2) {
        int idx1 = -1, idx2 = -1;
        for (int i = 0; i < arr.length; i++) {
            if (arr[i] == p1) idx1 = i;
            if (arr[i] == p2) idx2 = i;
        }
        return Math.abs(idx1 - idx2) == 1;
    }
}

