using namespace std;

struct FenwickTree {
    int n;
    vector<int> tree;
    FenwickTree(int n) : n(n), tree(n + 1, 0) {}
    void add(int i, int val) {
        for (; i <= n; i += i & -i) tree[i] += val;
    }
    int query(int i) {
        int res = 0;
        for (; i > 0; i -= i & -i) res += tree[i];
        return res;
    }
    int query(int l, int r) {
        if (l > r) return 0;
        return query(r) - query(l - 1);
    }
};

void solve() {
    int N;
    if (!(cin >> N)) return;
    vector<int> B(2 * N);
    vector<vector<int>> pos(N + 1);
    for (int i = 0; i < 2 * N; ++i) {
        cin >> B[i];
        pos[B[i]].push_back(i + 1);
    }

    vector<int> valid_species;
    for (int i = 1; i <= N; ++i) {
        if (pos[i][1] - pos[i][0] > 1) {
            valid_species.push_back(i);
        }
    }

    if (valid_species.empty()) {
        cout << 0 << "\n";
        return;
    }

    struct Interval {
        int l, r, id;
    };
    vector<Interval> intervals;
    for (int id : valid_species) {
        intervals.push_back({pos[id][0], pos[id][1], id});
    }

    sort(intervals.begin(), intervals.end(), [](const Interval& a, const Interval& b) {
        return a.l < b.l;
    });

    long long total_valid_pairs = (long long)intervals.size() * (intervals.size() - 1) / 2;
    long long intersecting = 0;

    FenwickTree ft(2 * N);
    vector<int> r_coords;
    for (auto& interval : intervals) r_coords.push_back(interval.r);

    sort(r_coords.begin(), r_coords.end());
    r_coords.erase(unique(r_coords.begin(), r_coords.end()), r_coords.end());

    auto get_pos = [&](int val) {
        return lower_bound(r_coords.begin(), r_coords.end(), val) - r_coords.begin() + 1;
    };

    for (int i = (int)intervals.size() - 1; i >= 0; --i) {
        int r_idx = get_pos(intervals[i].r);
        intersecting += ft.query(1, r_idx - 1);
        ft.add(r_idx, 1);
    }

    cout << total_valid_pairs - intersecting << "\n";
}

