	var T int
	fmt.Fscan(reader, &T)

	for t := 0; t < T; t++ {
		var N int
		fmt.Fscan(reader, &N)

		B := make([]int, 2*N)
		pos := make([][]int, N+1)
		for i := 1; i <= N; i++ {
			pos[i] = make([]int, 0, 2)
		}

		for i := 0; i < 2*N; i++ {
			fmt.Fscan(reader, &B[i])
			pos[B[i]] = append(pos[B[i]], i)
		}

		valid := make([]int, 0)
		for i := 1; i <= N; i++ {
			if pos[i][1]-pos[i][0] > 1 {
				valid = append(valid, i)
			}
		}

		if len(valid) < 2 {
			fmt.Fprintln(writer, 0)
			continue
		}

		bit := make([]int, 2*N+1)
		update := func(idx int, val int) {
			for idx <= 2*N {
				bit[idx] += val
				idx += idx & -idx
			}
		}
		query := func(idx int) int {
			res := 0
			for idx > 0 {
				res += bit[idx]
				idx -= idx & -idx
			}
			return res
		}

		type Event struct {
			x, y1, y2, id, type_ int
		}
		events := make([]Event, 0)
		for _, i := range valid {
			l, r := pos[i][0]+1, pos[i][1]+1
			events = append(events, Event{l, l, r, i, 0})
		}

		ans := 0
		intersectCount := 0

		queries := make([]Event, 0)
		for _, i := range valid {
			l, r := pos[i][0]+1, pos[i][1]+1
			queries = append(queries, Event{l, l + 1, r - 1, i, 1})
			queries = append(queries, Event{r, l + 1, r - 1, i, -1})
		}

		combined := make([]Event, 0, len(events)+len(queries))
		combined = append(combined, events...)
		combined = append(combined, queries...)

		import "sort"
		sort.Slice(combined, func(i, j int) bool {
			if combined[i].x != combined[j].x {
				return combined[i].x < combined[j].x
			}
			return combined[i].type_ < combined[j].type_
		})

		for _, e := range combined {
			if e.type_ == 0 {
				update(e.y2, 1)
			} else {
				cnt := query(e.y2) - query(e.y1 - 1)
				intersectCount += e.type_ * cnt
			}
		}

		totalValid := len(valid)
		ans = (totalValid * (totalValid - 1) / 2) - intersectCount
		fmt.Fprintln(writer, ans)
	}
