            if (map[u] != -1 && map[u] != v) {
                System.out.println("-1");
                return;
            }
            map[u] = v;
        }

        List<Integer>[] adj = new ArrayList[26];
        for (int i = 0; i < 26; i++) adj[i] = new ArrayList<>();
        int[] inDegree = new int[26];
        boolean[] used = new boolean[26];

        for (int i = 0; i < 26; i++) {
            if (map[i] != -1 && map[i] != i) {
                adj[i].add(map[i]);
                inDegree[map[i]]++;
                used[i] = true;
                used[map[i]] = true;
            }
        }

        int totalOps = 0;
        boolean[] visited = new boolean[26];
        boolean[] onStack = new boolean[26];

        for (int i = 0; i < 26; i++) {
            if (used[i] && !visited[i]) {
                List<Integer> component = new ArrayList<>();
                if (hasCycle(i, adj, visited, onStack, component)) {
                    boolean pureCycle = true;
                    for (int node : component) {
                        if (inDegree[node] > 1) {
                            pureCycle = false;
                            break;
                        }
                    }
                    totalOps += component.size();
                    if (pureCycle) {
                        totalOps++;
                    }
                } else {
                    totalOps += countEdges(component, adj);
                }
            }
        }

        System.out.println(totalOps);
    }

    private static boolean hasCycle(int u, List<Integer>[] adj, boolean[] visited, boolean[] onStack, List<Integer> component) {
        visited[u] = true;
        onStack[u] = true;
        component.add(u);
        boolean cycleFound = false;
        for (int v : adj[u]) {
            if (onStack[v]) {
                cycleFound = true;
            } else if (!visited[v]) {
                if (hasCycle(v, adj, visited, onStack, component)) {
                    cycleFound = true;
                }
            }
        }
        onStack[u] = false;
        return cycleFound;
    }

    private static int countEdges(List<Integer> component, List<Integer>[] adj) {
        int edges = 0;
        for (int u : component) {
            edges += adj[u].size();
        }
        return edges;
    }
