        Set<Long> luminaries = new HashSet<>();

        for (int p = 1; p <= 60; p++) {
            long pow2 = 1L << p;
            if (pow2 > T) break;

            long maxR = (long) Math.sqrt((double) T / pow2);

            if (maxR > 2000000) {
                for (long r = 1; r <= maxR; r++) {
                    long val = pow2 * r * r;
                    if (val > T || val <= 0) break;
                    luminaries.add(val);
                }
            } else {
                for (long r = 1; r <= (int)maxR; r++) {
                    long val = pow2 * r * r;
                    if (val <= T) {
                        luminaries.add(val);
                    }
                }
            }
        }

        System.out.println(luminaries.size());
    }
}

