type State struct {
	row, col int
	bashes   int
	grid     [][]byte
}

type PQItem struct {
	state State
	index int
}

type PriorityQueue []*PQItem

func (pq PriorityQueue) Len() int { return len(pq) }
func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].state.bashes < pq[j].state.bashes
}
func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
	pq[i].index = i
	pq[j].index = j
}
func (pq *PriorityQueue) Push(x interface{}) {
	n := len(*pq)
	item := x.(*PQItem)
	item.index = n
	*pq = append(*pq, item)
}
func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	old[n-1] = nil
	item.index = -1
	*pq = old[0 : n-1]
	return item
}

func copyGrid(grid [][]byte) [][]byte {
	newGrid := make([][]byte, len(grid))
	for i := range grid {
		newGrid[i] = make([]byte, len(grid[i]))
		copy(newGrid[i], grid[i])
	}
	return newGrid
}

func gridKey(grid [][]byte) string {
	s := ""
	for i := range grid {
		s += string(grid[i])
	}
	return s
}

func main() {
	scanner := bufio.NewScanner(os.Stdin)
	scanner.Scan()
	var H, W int
	fmt.Sscanf(scanner.Text(), "%d %d", &H, &W)

	scanner.Scan()
	var A, B, C, D int
	fmt.Sscanf(scanner.Text(), "%d %d %d %d", &A, &B, &C, &D)
	A--
	B--
	C--
	D--

	grid := make([][]byte, H)
	for i := 0; i < H; i++ {
		scanner.Scan()
		grid[i] = []byte(scanner.Text())
	}

	pq := make(PriorityQueue, 0)
	heap.Init(&pq)

	startState := State{A, B, 0, copyGrid(grid)}
	heap.Push(&pq, &PQItem{state: startState})

	visited := make(map[string]map[int]map[int]bool)

	dirs := [][2]int{{-1, 0}, {1, 0}, {0, -1}, {0, 1}}

	for pq.Len() > 0 {
		item := heap.Pop(&pq).(*PQItem)
		state := item.state

		if state.row == C && state.col == D {
			fmt.Println(state.bashes)
			return
		}

		gk := gridKey(state.grid)
		if visited[gk] == nil {
			visited[gk] = make(map[int]map[int]bool)
		}
		if visited[gk][state.row] == nil {
			visited[gk][state.row] = make(map[int]bool)
		}
		if visited[gk][state.row][state.col] {
			continue
		}
		visited[gk][state.row][state.col] = true

		for _, d := range dirs {
			nr, nc := state.row+d[0], state.col+d[1]
			if nr >= 0 && nr < H && nc >= 0 && nc < W && state.grid[nr][nc] == '.' {
				newState := State{nr, nc, state.bashes, state.grid}
				heap.Push(&pq, &PQItem{state: newState})
			}
		}

		for _, d := range dirs {
			newGrid := copyGrid(state.grid)
			for step := 1; step <= 2; step++ {
				br, bc := state.row+d[0]*step, state.col+d[1]*step
				if br >= 0 && br < H && bc >= 0 && bc < W {
					newGrid[br][bc] = '.'
				}
			}
			newState := State{state.row, state.col, state.bashes + 1, newGrid}
			heap.Push(&pq, &PQItem{state: newState})
		}
	}

	fmt.Println(-1)
}

