public class Main {
    static int H, W, A, B, C, D;
    static char[][] initialGrid;

    static class State {
        int row, col, bashes;
        char[][] grid;

        State(int r, int c, int b, char[][] g) {
            row = r;
            col = c;
            bashes = b;
            grid = g;
        }
    }

    static char[][] copyGrid(char[][] grid) {
        char[][] newGrid = new char[H][W];
        for (int i = 0; i < H; i++) {
            for (int j = 0; j < W; j++) {
                newGrid[i][j] = grid[i][j];
            }
        }
        return newGrid;
    }

    static String gridToString(char[][] grid) {
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < H; i++) {
            sb.append(grid[i]);
        }
        return sb.toString();
    }

    static char[][] performBash(char[][] grid, int row, int col, int dir) {
        char[][] newGrid = copyGrid(grid);
        int[] dr = {-1, 1, 0, 0};
        int[] dc = {0, 0, -1, 1};

        for (int step = 1; step <= 2; step++) {
            int nr = row + dr[dir] * step;
            int nc = col + dc[dir] * step;
            if (nr >= 0 && nr < H && nc >= 0 && nc < W) {
                if (newGrid[nr][nc] == '#') {
                    newGrid[nr][nc] = '.';
                }
            }
        }
        return newGrid;
    }

    static int solve() {
        Queue<State> queue = new LinkedList<>();
        Map<String, Map<String, Integer>> visited = new HashMap<>();

        queue.add(new State(A - 1, B - 1, 0, initialGrid));
        String posKey = (A - 1) + "," + (B - 1);
        String gridKey = gridToString(initialGrid);
        visited.putIfAbsent(posKey, new HashMap<>());
        visited.get(posKey).put(gridKey, 0);

        int[] dr = {-1, 1, 0, 0};
        int[] dc = {0, 0, -1, 1};

        while (!queue.isEmpty()) {
            State curr = queue.poll();

            if (curr.row == C - 1 && curr.col == D - 1) {
                return curr.bashes;
            }

            for (int d = 0; d < 4; d++) {
                char[][] newGrid = performBash(curr.grid, curr.row, curr.col, d);
                String newGridKey = gridToString(newGrid);
                String currPosKey = curr.row + "," + curr.col;

                if (!visited.containsKey(currPosKey) || !visited.get(currPosKey).containsKey(newGridKey) || 
                    visited.get(currPosKey).get(newGridKey) > curr.bashes + 1) {
                    visited.putIfAbsent(currPosKey, new HashMap<>());
                    visited.get(currPosKey).put(newGridKey, curr.bashes + 1);
                    queue.add(new State(curr.row, curr.col, curr.bashes + 1, newGrid));
                }
            }

            for (int d = 0; d < 4; d++) {
                int nr = curr.row + dr[d];
                int nc = curr.col + dc[d];

                if (nr >= 0 && nr < H && nc >= 0 && nc < W && curr.grid[nr][nc] == '.') {
                    String newPosKey = nr + "," + nc;
                    String currGridKey = gridToString(curr.grid);

                    if (!visited.containsKey(newPosKey) || !visited.get(newPosKey).containsKey(currGridKey) || 
                        visited.get(newPosKey).get(currGridKey) > curr.bashes) {
                        visited.putIfAbsent(newPosKey, new HashMap<>());
                        visited.get(newPosKey).put(currGridKey, curr.bashes);
                        queue.add(new State(nr, nc, curr.bashes, curr.grid));
                    }
                }
            }
        }

        return -1;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        H = sc.nextInt();
        W = sc.nextInt();
        A = sc.nextInt();
        B = sc.nextInt();
        C = sc.nextInt();
        D = sc.nextInt();
        sc.nextLine();

        initialGrid = new char[H][W];
        for (int i = 0; i < H; i++) {
            String line = sc.nextLine();
            initialGrid[i] = line.toCharArray();
        }

        System.out.println(solve());
        sc.close();
    }
}

