    static long isqrt(long n) {
        if (n == 0) return 0;
        long x = (long) Math.sqrt(n);
        while (x * x > n) x--;
        while ((x + 1) * (x + 1) <= n) x++;
        return x;
    }

    static boolean isPerfectSquare(long n) {
        long sq = isqrt(n);
        return sq * sq == n;
    }

    static int countDistinctPrimes(long n) {
        int count = 0;

        for (long i = 2; i * i <= n; i++) {
            if (n % i == 0) {
                count++;
                while (n % i == 0) {
                    n /= i;
                }
            }
        }
        if (n > 1) count++;

        return count;
    }

