func max(a, b, c int64) int64 {
	res := a
	if b > res {
		res = b
	}
	if c > res {
		res = c
	}
	return res
}

func solve(n, k int, devices [][3]int64) int64 {
	if k == 0 {
		return 0
	}

	if n <= 20 {
		return solveBitmask(n, k, devices)
	}

	return solveGreedy(n, k, devices)
}

func solveBitmask(n, k int, devices [][3]int64) int64 {
	memo := make(map[int]map[int]int64)

	var dp func(mask int, pairs int) int64
	dp = func(mask int, pairs int) int64 {
		if pairs == k {
			return 0
		}

		if memo[mask] == nil {
			memo[mask] = make(map[int]int64)
		}
		if val, ok := memo[mask][pairs]; ok {
			return val
		}

		result := int64(-1)

		for i := 0; i < n; i++ {
			if (mask & (1 << i)) != 0 {
				continue
			}
			for j := i + 1; j < n; j++ {
				if (mask & (1 << j)) != 0 {
					continue
				}

				newMask := mask | (1 << i) | (1 << j)
				duoValue := max(
					devices[i][0]+devices[j][0],
					devices[i][1]+devices[j][1],
					devices[i][2]+devices[j][2],
				)

				subResult := dp(newMask, pairs+1)
				if subResult >= 0 {
					total := duoValue + subResult
					if result < 0 || total > result {
						result = total
					}
				}
			}
		}

		memo[mask][pairs] = result
		return result
	}

	return dp(0, 0)
}

func solveGreedy(n, k int, devices [][3]int64) int64 {
	type Pair struct {
		i, j  int
		value int64
	}

	var pairs []Pair
	for i := 0; i < n; i++ {
		for j := i + 1; j < n; j++ {
			value := max(
				devices[i][0]+devices[j][0],
				devices[i][1]+devices[j][1],
				devices[i][2]+devices[j][2],
			)
			pairs = append(pairs, Pair{i, j, value})
		}
	}

	for i := 0; i < len(pairs); i++ {
		for j := i + 1; j < len(pairs); j++ {
			if pairs[j].value > pairs[i].value {
				pairs[i], pairs[j] = pairs[j], pairs[i]
			}
		}
	}

	used := make([]bool, n)
	total := int64(0)
	count := 0

	for _, p := range pairs {
		if count == k {
			break
		}
		if !used[p.i] && !used[p.j] {
			used[p.i] = true
			used[p.j] = true
			total += p.value
			count++
		}
	}

	return total
}

