    static long pairValue(Device a, Device b) {
        return Math.max(Math.max((long)a.d + b.d, (long)a.p + b.p), (long)a.u + b.u);
    }

    static long solve(Device[] devices, int n, int k) {
        if (k == 1) {
            long maxVal = 0;
            for (int i = 0; i < n; i++) {
                for (int j = i + 1; j < n; j++) {
                    maxVal = Math.max(maxVal, pairValue(devices[i], devices[j]));
                }
            }
            return maxVal;
        }

        if (n <= 16) {
            return solveSmall(devices, n, k);
        }

        return solveGreedy(devices, n, k);
    }

    static long solveSmall(Device[] devices, int n, int k) {
        int[] perm = new int[n];
        for (int i = 0; i < n; i++) perm[i] = i;

        long maxTotal = 0;

        do {
            long total = 0;
            for (int i = 0; i < k; i++) {
                total += pairValue(devices[perm[2*i]], devices[perm[2*i+1]]);
            }
            maxTotal = Math.max(maxTotal, total);
        } while (nextPermutation(perm, 2*k));

        return maxTotal;
    }

    static boolean nextPermutation(int[] arr, int len) {
        int i = len - 2;
        while (i >= 0 && arr[i] >= arr[i + 1]) i--;
        if (i < 0) return false;

        int j = len - 1;
        while (arr[j] <= arr[i]) j--;

        int temp = arr[i];
        arr[i] = arr[j];
        arr[j] = temp;

        int left = i + 1, right = len - 1;
        while (left < right) {
            temp = arr[left];
            arr[left] = arr[right];
            arr[right] = temp;
            left++;
            right--;
        }
        return true;
    }

    static long solveGreedy(Device[] devices, int n, int k) {
        List<int[]> pairs = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                long val = pairValue(devices[i], devices[j]);
                pairs.add(new int[]{i, j, (int)(val >> 32), (int)val});
            }
        }

        pairs.sort((a, b) -> {
            long valA = ((long)a[2] << 32) | (a[3] & 0xFFFFFFFFL);
            long valB = ((long)b[2] << 32) | (b[3] & 0xFFFFFFFFL);
            return Long.compare(valB, valA);
        });

        boolean[] used = new boolean[n];
        long total = 0;
        int count = 0;

        for (int[] pair : pairs) {
            if (count == k) break;
            if (!used[pair[0]] && !used[pair[1]]) {
                used[pair[0]] = true;
                used[pair[1]] = true;
                long val = ((long)pair[2] << 32) | (pair[3] & 0xFFFFFFFFL);
                total += val;
                count++;
            }
        }

        return total;
    }

