def duo_value(dev1, dev2):
    return max(dev1[0] + dev2[0], dev1[1] + dev2[1], dev1[2] + dev2[2])

def solve(devices, k):
    n = len(devices)

    if k == 0:
        return 0

    memo = {}

    def dp(used_mask, pairs_left):
        if pairs_left == 0:
            return 0

        if (used_mask, pairs_left) in memo:
            return memo[(used_mask, pairs_left)]

        max_val = 0

        first = -1
        for i in range(n):
            if not (used_mask & (1 << i)):
                first = i
                break

        if first == -1:
            return 0

        for j in range(first + 1, n):
            if not (used_mask & (1 << j)):
                new_mask = used_mask | (1 << first) | (1 << j)
                val = duo_value(devices[first], devices[j]) + dp(new_mask, pairs_left - 1)
                max_val = max(max_val, val)

        memo[(used_mask, pairs_left)] = max_val
        return max_val

    return dp(0, k)

