func check(x int64, devices []Device, k int) bool {
	n := len(devices)
	var masks [3][]int
	for i := 0; i < n; i++ {
		masks[0] = append(masks[0], i)
		masks[1] = append(masks[1], i)
		masks[2] = append(masks[2], i)
	}

	sort.Slice(masks[0], func(i, j int) bool { return devices[masks[0][i]].d > devices[masks[0][j]].d })
	sort.Slice(masks[1], func(i, j int) bool { return devices[masks[1][i]].p > devices[masks[1][j]].p })
	sort.Slice(masks[2], func(i, j int) bool { return devices[masks[2][i]].u > devices[masks[2][j]].u })

	used := make([]bool, n)
	count := 0

	p0, p1, p2 := 0, 0, 0
	q0, q1, q2 := n-1, n-1, n-1

	for count < k {
		found := false
		for m := 0; m < 3; m++ {
			var ptrP *int
			var ptrQ *int
			var mArr []int

			if m == 0 { ptrP, ptrQ, mArr = &p0, &q0, masks[0] }
			if m == 1 { ptrP, ptrQ, mArr = &p1, &q1, masks[1] }
			if m == 2 { ptrP, ptrQ, mArr = &p2, &q2, masks[2] }

			for *ptrP < n && used[mArr[*ptrP]] { *ptrP++ }
			for *ptrQ >= 0 && used[mArr[*ptrQ]] { *ptrQ-- }

			if *ptrP < n && *ptrQ >= 0 && *ptrP != *ptrQ {
				u, v := mArr[*ptrP], mArr[*ptrQ]
				val := int64(0)
				if m == 0 { val = devices[u].d + devices[v].d }
				if m == 1 { val = devices[u].p + devices[v].p }
				if m == 2 { val = devices[u].u + devices[v].u }

				if val >= x {
					used[u] = true
					used[v] = true
					count++
					found = true
					break
				}
			}
		}
		if !found { break }
	}

	return count >= k
}

