struct State {
    set<pair<int,int>> intervals;
    int cost;
    vector<int> commands;
};

void mergeIntervals(set<pair<int,int>>& intervals) {
    if (intervals.empty()) return;
    vector<pair<int,int>> v(intervals.begin(), intervals.end());
    intervals.clear();
    sort(v.begin(), v.end());
    int start = v[0].first, end = v[0].second;
    for (int i = 1; i < v.size(); i++) {
        if (v[i].first <= end + 1) {
            end = max(end, v[i].second);
        } else {
            intervals.insert({start, end});
            start = v[i].first;
            end = v[i].second;
        }
    }
    intervals.insert({start, end});
}

void addInterval(set<pair<int,int>>& intervals, int l, int r) {
    if (l > r) return;
    intervals.insert({l, r});
    mergeIntervals(intervals);
}

bool isComplete(const set<pair<int,int>>& intervals, int N) {
    if (intervals.size() != 1) return false;
    auto it = intervals.begin();
    return it->first == 1 && it->second == N;
}

string serializeIntervals(const set<pair<int,int>>& intervals) {
    string s;
    for (auto& p : intervals) {
        s += to_string(p.first) + "," + to_string(p.second) + ";";
    }
    return s;
}

