    int N, M;
    cin >> N >> M;
    vector<pair<int,int>> updates(M);
    for (int i = 0; i < M; i++) {
        cin >> updates[i].first >> updates[i].second;
    }

    queue<State> q;
    map<string, int> visited;
    State initial;
    initial.cost = 0;
    q.push(initial);
    visited[serializeIntervals(initial.intervals)] = 0;

    while (!q.empty()) {
        State curr = q.front();
        q.pop();

        if (curr.commands.size() == M) {
            if (isComplete(curr.intervals, N)) {
                cout << curr.cost << endl;
                for (int i = 0; i < M; i++) {
                    if (i > 0) cout << " ";
                    cout << curr.commands[i];
                }
                cout << endl;
                return 0;
            }
            continue;
        }

        int idx = curr.commands.size();
        int A = updates[idx].first;
        int B = updates[idx].second;

        for (int cmd = 0; cmd <= 2; cmd++) {
            State next = curr;
            next.commands.push_back(cmd);

            if (cmd == 1) {
                next.cost++;
                addInterval(next.intervals, A, B);
            } else if (cmd == 2) {
                next.cost++;
                addInterval(next.intervals, 1, A - 1);
                addInterval(next.intervals, B + 1, N);
            }

            string key = serializeIntervals(next.intervals);
            if (visited.find(key) == visited.end() || visited[key] > next.cost) {
                visited[key] = next.cost;
                q.push(next);
            }
        }
    }

    cout << -1 << endl;
    return 0;
