type State struct {
	intervals []Interval
	step      int
	cost      int
	commands  []int
}

type Interval struct {
	left  int
	right int
}

func mergeIntervals(intervals []Interval) []Interval {
	if len(intervals) == 0 {
		return intervals
	}

	sorted := make([]Interval, len(intervals))
	copy(sorted, intervals)

	for i := 0; i < len(sorted); i++ {
		for j := i + 1; j < len(sorted); j++ {
			if sorted[i].left > sorted[j].left {
				sorted[i], sorted[j] = sorted[j], sorted[i]
			}
		}
	}

	result := []Interval{sorted[0]}
	for i := 1; i < len(sorted); i++ {
		last := &result[len(result)-1]
		if sorted[i].left <= last.right+1 {
			if sorted[i].right > last.right {
				last.right = sorted[i].right
			}
		} else {
			result = append(result, sorted[i])
		}
	}
	return result
}

func applyCommand(intervals []Interval, cmd int, a int, b int, n int) []Interval {
	if cmd == 0 {
		return intervals
	}

	newIntervals := make([]Interval, len(intervals))
	copy(newIntervals, intervals)

	if cmd == 1 {
		newIntervals = append(newIntervals, Interval{a, b})
	} else {
		if a > 1 {
			newIntervals = append(newIntervals, Interval{1, a - 1})
		}
		if b < n {
			newIntervals = append(newIntervals, Interval{b + 1, n})
		}
	}

	return mergeIntervals(newIntervals)
}

func isCovered(intervals []Interval, n int) bool {
	if len(intervals) == 0 {
		return n == 0
	}
	return len(intervals) == 1 && intervals[0].left == 1 && intervals[0].right == n
}

func main() {
	reader := bufio.NewReader(os.Stdin)
	writer := bufio.NewWriter(os.Stdout)
	defer writer.Flush()

	var n, m int
	fmt.Fscanf(reader, "%d %d\n", &n, &m)

	updates := make([][2]int, m)
	for i := 0; i < m; i++ {
		fmt.Fscanf(reader, "%d %d\n", &updates[i][0], &updates[i][1])
	}

	var solve func(step int, intervals []Interval) (bool, int, []int)
	memo := make(map[string]struct {
		found    bool
		cost     int
		commands []int
	})

	intervalsToString := func(intervals []Interval) string {
		s := ""
		for _, iv := range intervals {
			s += fmt.Sprintf("%d-%d,", iv.left, iv.right)
		}
		return s
	}

	solve = func(step int, intervals []Interval) (bool, int, []int) {
		if step == m {
			if isCovered(intervals, n) {
				return true, 0, []int{}
			}
			return false, 0, nil
		}

		key := fmt.Sprintf("%d:%s", step, intervalsToString(intervals))
		if cached, ok := memo[key]; ok {
			return cached.found, cached.cost, cached.commands
		}

		bestFound := false
		bestCost := 1000000000
		var bestCommands []int

		for cmd := 0; cmd <= 2; cmd++ {
			newIntervals := applyCommand(intervals, cmd, updates[step][0], updates[step][1], n)
			found, cost, commands := solve(step+1, newIntervals)

			if found {
				totalCost := cost
				if cmd > 0 {
					totalCost++
				}
				if !bestFound || totalCost < bestCost {
					bestFound = true
					bestCost = totalCost
					bestCommands = append([]int{cmd}, commands...)
				}
			}
		}

		memo[key] = struct {
			found    bool
			cost     int
			commands []int
		}{bestFound, bestCost, bestCommands}

		return bestFound, bestCost, bestCommands
	}

	found, cost, commands := solve(0, []Interval{})

	if !found {
		fmt.Fprintln(writer, -1)
	} else {
		fmt.Fprintln(writer, cost)
		for i, cmd := range commands {
			if i > 0 {
				fmt.Fprint(writer, " ")
			}
			fmt.Fprint(writer, cmd)
		}
		fmt.Fprintln(writer)
	}
}

