public class Main {
    static class Interval {
        int a, b;
        Interval(int a, int b) {
            this.a = a;
            this.b = b;
        }
    }

    static class State {
        List<int[]> intervals;
        int cost;
        int[] commands;

        State(List<int[]> intervals, int cost, int[] commands) {
            this.intervals = intervals;
            this.cost = cost;
            this.commands = commands;
        }
    }

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String[] first = br.readLine().split(" ");
        int N = Integer.parseInt(first[0]);
        int M = Integer.parseInt(first[1]);

        Interval[] updates = new Interval[M];
        for (int i = 0; i < M; i++) {
            String[] parts = br.readLine().split(" ");
            updates[i] = new Interval(Integer.parseInt(parts[0]), Integer.parseInt(parts[1]));
        }

        Queue<State> queue = new LinkedList<>();
        Map<String, Integer> visited = new HashMap<>();

        List<int[]> initial = new ArrayList<>();
        queue.add(new State(initial, 0, new int[M]));
        visited.put(serialize(initial), 0);

        State solution = null;

        while (!queue.isEmpty()) {
            State current = queue.poll();
            int step = 0;
            for (int i = 0; i < M; i++) {
                if (current.commands[i] != 0) step = i + 1;
            }
            if (step < M) step = Math.max(step, countNonZero(current.commands));

            if (step == M) {
                if (coversAll(current.intervals, N)) {
                    if (solution == null || current.cost < solution.cost) {
                        solution = current;
                    }
                }
                continue;
            }

            for (int cmd = 0; cmd <= 2; cmd++) {
                List<int[]> newIntervals = applyCommand(current.intervals, updates[step], cmd, N);
                int newCost = current.cost + (cmd == 0 ? 0 : 1);

                String key = serialize(newIntervals);
                if (!visited.containsKey(key) || visited.get(key) > newCost) {
                    visited.put(key, newCost);
                    int[] newCommands = current.commands.clone();
                    newCommands[step] = cmd;
                    queue.add(new State(newIntervals, newCost, newCommands));
                }
            }
        }

        if (solution == null) {
            System.out.println(-1);
        } else {
            System.out.println(solution.cost);
            for (int i = 0; i < M; i++) {
                if (i > 0) System.out.print(" ");
                System.out.print(solution.commands[i]);
            }
            System.out.println();
        }
    }

    static int countNonZero(int[] arr) {
        for (int i = arr.length - 1; i >= 0; i--) {
            if (arr[i] != 0) return i + 1;
        }
        return 0;
    }

    static List<int[]> applyCommand(List<int[]> intervals, Interval update, int cmd, int N) {
        List<int[]> result = new ArrayList<>(intervals);
        if (cmd == 1) {
            result.add(new int[]{update.a, update.b});
        } else if (cmd == 2) {
            if (update.a > 1) result.add(new int[]{1, update.a - 1});
            if (update.b < N) result.add(new int[]{update.b + 1, N});
        }
        return mergeIntervals(result);
    }

    static List<int[]> mergeIntervals(List<int[]> intervals) {
        if (intervals.isEmpty()) return intervals;
        List<int[]> sorted = new ArrayList<>(intervals);
        sorted.sort((a, b) -> a[0] - b[0]);
        List<int[]> merged = new ArrayList<>();
        int[] current = sorted.get(0);
        for (int i = 1; i < sorted.size(); i++) {
            if (sorted.get(i)[0] <= current[1] + 1) {
                current[1] = Math.max(current[1], sorted.get(i)[1]);
            } else {
                merged.add(current);
                current = sorted.get(i);
            }
        }
        merged.add(current);
        return merged;
    }

    static boolean coversAll(List<int[]> intervals, int N) {
        return intervals.size() == 1 && intervals.get(0)[0] == 1 && intervals.get(0)[1] == N;
    }

    static String serialize(List<int[]> intervals) {
        StringBuilder sb = new StringBuilder();
        for (int[] iv : intervals) {
            sb.append(iv[0]).append("-").append(iv[1]).append(";");
        }
        return sb.toString();
    }
}

