    vector<vector<Edge>> adj(N + 2);
    for (int i = 1; i <= M; ++i) {
        int a, b;
        cin >> a >> b;
        adj[a - 1].push_back({b, 1, i, 1});
        adj[b].push_back({a - 1, 1, i, 1});
        adj[0].push_back({a - 1, 1, i, 2});
        adj[a - 1].push_back({0, 1, i, 2});
        adj[b].push_back({N, 1, i, 2});
        adj[N].push_back({b, 1, i, 2});
    }

    vector<int> dist(N + 1, INF);
    vector<pair<int, int>> parent(N + 1, {-1, -1});
    vector<int> edge_type(N + 1, 0);
    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;

