    pq.push({0, 0});

    while (!pq.empty()) {
        int d = pq.top().first;
        int u = pq.top().second;
        pq.pop();

        if (d > dist[u]) continue;
        if (u == N) break;

        for (auto& edge : adj[u]) {
            if (dist[edge.to] > dist[u] + edge.cost) {
                dist[edge.to] = dist[u] + edge.cost;
                parent[edge.to] = {u, edge.id};
                edge_type[edge.to] = edge.type;
                pq.push({dist[edge.to], edge.to});
            }
        }
