	for i := 0; i < m; i++ {
		var a, b int
		fmt.Fscanf(reader, "%d %d\n", &a, &b)
		u, v := a-1, b
		adj[u] = append(adj[u], edge{v, i, 1})
		adj[v] = append(adj[v], edge{u, i, 1})
		adj[0] = append(adj[0], edge{u, i, 2})
		adj[u] = append(adj[u], edge{0, i, 2})
		adj[v] = append(adj[v], edge{n, i, 2})
		adj[n] = append(adj[n], edge{v, i, 2})
	}

	dist := make([]int, n+1)
	parent := make([]int, n+1)
	edgeUsed := make([]edge, n+1)
	for i := range dist {
		dist[i] = -1
		parent[i] = -1
	}

	queue := make([]int, 0, n+1)
	queue = append(queue, 0)
	dist[0] = 0

	head := 0
	for head < len(queue) {
		u := queue[head]
		head++
		if u == n {
			break
		}
		for _, e := range adj[u] {
			if dist[e.to] == -1 {
				dist[e.to] = dist[u] + 1
				parent[e.to] = u
				edgeUsed[e.to] = e
				queue = append(queue, e.to)
			}
		}
	}

	if dist[n] == -1 {
		fmt.Println("-1")
		return
	}

	commands := make([]int, m)
	curr := n
	for curr != 0 {
		e := edgeUsed[curr]
		commands[e.id] = e.cmd
		curr = parent[curr]
	}

	writer := bufio.NewWriter(os.Stdout)
	fmt.Fprintf(writer, "%d\n", dist[n])
	for i := 0; i < m; i++ {
		fmt.Fprintf(writer, "%d", commands[i])
		if i == m-1 {
			fmt.Fprintf(writer, "\n")
		} else {
			fmt.Fprintf(writer, " ")
		}
	}
	writer.Flush()
}

