	}
	inv[H+W] = power(fact[H+W], MOD-2)
	for i := H+W - 1; i >= 0; i-- {
		inv[i] = (inv[i+1] * int64(i+1)) % MOD
	}

	nCr := func(n, r int) int64 {
		if r < 0 || r > n {
			return 0
		}
		num := fact[n]
		den := (inv[r] * inv[n-r]) % MOD
		return (num * den) % MOD
	}

