vector<vector<ll>> matpow(vector<vector<ll>> A, ll p) {
    vector<vector<ll>> res(N, vector<ll>(N, 0));
    for(int i = 0; i < N; i++) res[i][i] = 1;
    while(p > 0) {
        if(p & 1) res = matmul(res, A);
        A = matmul(A, A);
        p >>= 1;
    }
    return res;
}

void solve(int idx, vector<vector<ll>>& D) {
