func matrixPower(M [][]int64, p int, mod int64) [][]int64 {
    n := len(M)
    result := make([][]int64, n)
    for i := 0; i < n; i++ {
        result[i] = make([]int64, n)
        result[i][i] = 1
    }

    base := make([][]int64, n)
    for i := 0; i < n; i++ {
        base[i] = make([]int64, n)
        copy(base[i], M[i])
    }

    for p > 0 {
        if p % 2 == 1 {
            result = matrixMultiply(result, base, mod)
        }
        base = matrixMultiply(base, base, mod)
        p /= 2
    }

    return result
}

func matrixMultiply(A, B [][]int64, mod int64) [][]int64 {
    n := len(A)
    C := make([][]int64, n)
    for i := 0; i < n; i++ {
        C[i] = make([]int64, n)
        for j := 0; j < n; j++ {
            var sum int64 = 0
            for k := 0; k < n; k++ {
                sum = (sum + (A[i][k] * B[k][j]) % mod) % mod
            }
            C[i][j] = sum
        }
    }
    return C
}

