func main() {
	reader := bufio.NewReader(os.Stdin)
	var L, K int
	fmt.Fscanf(reader, "%d %d\n", &L, &K)

	codeStr, _ := reader.ReadString('\n')
	updateStr, _ := reader.ReadString('\n')

	code := []byte(codeStr)
	update := []byte(updateStr)

	for i := 0; i < len(code); i++ {
		if code[i] < '1' || code[i] > '9' {
			code = code[:i]
			break
		}
	}
	for i := 0; i < len(update); i++ {
		if update[i] < '1' || update[i] > '9' {
			update = update[:i]
			break
		}
	}

	L = len(code)
	K = len(update)

	lastOccurrence := make([]int, 10)
	for i := 0; i < 10; i++ {
		lastOccurrence[i] = -1
	}
	for k := 0; k < K; k++ {
		digit := int(update[k] - '0')
		lastOccurrence[digit] = k
	}

	type pair struct {
		val byte
		idx int
	}

	bestUpdates := make([]pair, 0, 9)
	for d := 9; d >= 1; d-- {
		if lastOccurrence[d] != -1 {
			bestUpdates = append(bestUpdates, pair{byte(d + '0'), lastOccurrence[d]})
		}
	}

	sort.Slice(bestUpdates, func(i, j int) bool {
		return bestUpdates[i].idx < bestUpdates[j].idx
	})

	remainingK := K
	for i := 0; i < L && remainingK > 0; i++ {
		currentDigit := code[i]
		bestPossible := byte(0)
		bestIdx := -1

		for j := 0; j < len(bestUpdates); j++ {
			if bestUpdates[j].val > currentDigit {
				if bestUpdates[j].val > bestPossible {
					bestPossible = bestUpdates[j].val
					bestIdx = j
				}
			}
		}

		if bestIdx != -1 {
			code[i] = bestPossible
			remainingK--
		}
	}

	if remainingK > 0 {
		lastUpdateVal := update[K-1]
		code[L-1] = lastUpdateVal
	}

	os.Stdout.Write(code)
	os.Stdout.WriteString("\n")
}

