public class Main {
    public static void main(String[] args) throws IOException {
        FastReader fr = new FastReader(System.in);
        int L = fr.nextInt();
        int K = fr.nextInt();
        char[] code = fr.next().toCharArray();
        char[] update = fr.next().toCharArray();

        int[] lastSeen = new int[10];
        Arrays.fill(lastSeen, -1);
        for (int i = 0; i < K; i++) {
            lastSeen[update[i] - '0'] = i;
        }

        PriorityQueue<Integer> availablePositions = new PriorityQueue<>();
        for (int i = 0; i < L; i++) {
            availablePositions.add(i);
        }

        boolean[] positionModified = new boolean[L];
        int lastModifiedIdx = -1;

        for (int d = 9; d >= 1; d--) {
            int lastK = lastSeen[d];
            if (lastK == -1) continue;

            while (!availablePositions.isEmpty()) {
                int pos = availablePositions.peek();
                if (code[pos] - '0' < d) {
                    code[pos] = (char) (d + '0');
                    positionModified[pos] = true;
                    lastModifiedIdx = Math.max(lastModifiedIdx, lastK);
                    availablePositions.poll();
                } else {
                    break;
                }
            }
        }

        if (lastModifiedIdx < K - 1) {
            int targetPos = 0;
            for (int i = 0; i < L; i++) {
                if (positionModified[i]) {
                    targetPos = i;
                    break;
                }
            }
            code[targetPos] = update[K - 1];
        }

        PrintWriter out = new PrintWriter(System.out);
        out.println(new String(code));
        out.flush();
    }

    static class FastReader {
        BufferedReader br;
        StringTokenizer st;

        public FastReader(InputStream in) {
            br = new BufferedReader(new InputStreamReader(in));
        }

        String next() {
            while (st == null || !st.hasMoreElements()) {
                try {
                    st = new StringTokenizer(br.readLine());
                } catch (IOException e) {
                    e.printStackTrace();
                }
            }
            return st.nextToken();
        }

        int nextInt() {
            return Integer.parseInt(next());
        }
    }
}

