func gcd(a, b int64) int64 {
	for b != 0 {
		a, b = b, a%b
	}
	return a
}

func powMod(base, exp, mod int64) int64 {
	if mod == 1 {
		return 0
	}
	result := int64(1)
	base = base % mod
	for exp > 0 {
		if exp%2 == 1 {
			result = (result * base) % mod
		}
		exp = exp >> 1
		base = (base * base) % mod
	}
	return result
}

func findOrder(b, c int64, x int64) int64 {
	if c == 1 {
		return 1
	}
	if gcd(b, c) != 1 {
		return -1
	}

	val := int64(1)
	for n := int64(1); n <= x+10; n++ {
		val = (val * b) % c
		if val == 1 {
			return n
		}
	}
	return -1
}

func solve(x int64) (int64, int64) {
	if x == 1 {
		return 2, 1
	}

	b := int64(2)

	c := (int64(1) << x) - 1
	if c > 0 && c <= 1e18 {
		if findOrder(b, c, x) == x {
			return b, c
		}
	}

	for k := int64(1); k <= 1000; k++ {
		c := k*x + 1
		if c > 1e18 {
			break
		}
		if gcd(b, c) == 1 {
			if findOrder(b, c, x) == x {
				return b, c
			}
		}
	}

	b = x + 1
	c = x*x + x + 1
	if c <= 1e18 {
		return b, c
	}

	return 2, 3
}

