    static boolean checkPossible(int n, int[] b, List<Integer> zeros) {
        int m = zeros.size();

        for (int start = 0; start < m; start++) {
            if (tryAssignment(n, b, zeros, start)) {
                return true;
            }
        }

        return false;
    }

    static boolean tryAssignment(int n, int[] b, List<Integer> zeros, int start) {
        boolean[] covered = new boolean[n];
        for (int i = 0; i < n; i++) {
            if (b[i] == 1) covered[i] = true;
        }

        int m = zeros.size();
        for (int k = 0; k < m; k++) {
            int idx = (start + k) % m;
            int pos = zeros.get(idx);

            if (covered[pos]) continue;

            int next = (pos + 1) % n;
            if (!covered[next]) {
                covered[pos] = true;
                covered[next] = true;
            } else {
                int prev = (pos - 1 + n) % n;
                if (!covered[prev]) {
                    covered[prev] = true;
                    covered[pos] = true;
                } else {
                    return false;
                }
            }
        }

        for (int i = 0; i < n; i++) {
            if (!covered[i]) return false;
        }
        return true;
    }
