func check(s []int) bool {
	m := len(s)
	if m == 0 {
		return true
	}

	dp := make([]bool, m+1)

	for start := 0; start < 2; start++ {
		for i := 0; i <= m; i++ {
			dp[i] = false
		}

		if start == 0 {
			dp[0] = true
			for i := 0; i < m; i++ {
				if !dp[i] {
					continue
				}
				if s[i] >= 2 {
					dp[i+1] = true
				}
				if i+1 < m && s[i] == 1 && s[i+1] == 1 {
					dp[i+2] = true
				}
			}
			if dp[m] {
				return true
			}
		} else {
			if m < 2 || s[m-1] != 1 || s[0] != 1 {
				continue
			}
			dp[1] = true
			for i := 1; i < m-1; i++ {
				if !dp[i] {
					continue
				}
				if s[i] >= 2 {
					dp[i+1] = true
				}
				if i+1 < m-1 && s[i] == 1 && s[i+1] == 1 {
					dp[i+2] = true
				}
			}
			if dp[m-1] {
				return true
			}
		}
	}
	return false
