func getDivisors(n int) []int {
    divs := []int{}
    for i := 1; i*i <= n; i++ {
        if n%i == 0 {
            divs = append(divs, i)
            if i*i != n {
                divs = append(divs, n/i)
            }
        }
    }
    return divs
}

func getCoprimePairs(b int) [][2]int {
    pairs := [][2]int{}
    divs := getDivisors(b)
    for _, p := range divs {
        q := b / p
        if gcd(p, q) == 1 {
            pairs = append(pairs, [2]int{p, q})
        }
    }
    return pairs
}

func gcdSlice(arr []int) int {
    result := arr[0]
    for i := 1; i < len(arr); i++ {
        result = gcd(result, arr[i])
    }
    return result
}

