bool noOverlap(int s1, int e1, int s2, int e2) {
    return e1 < s2 || e2 < s1;
}

int main() {
    int N;
    cin >> N;

    vector<long long> C(N + 1);
    for (int i = 1; i <= N; i++) {
        cin >> C[i];
    }

    vector<int> S(N + 1), E(N + 1);
    for (int i = 1; i <= N; i++) {
        cin >> S[i] >> E[i];
    }

    vector<vector<int>> adj(N + 1);
    for (int i = 1; i <= N; i++) {
        for (int j = i + 1; j <= N; j++) {
            if (noOverlap(S[i], E[i], S[j], E[j])) {
                adj[i].push_back(j);
                adj[j].push_back(i);
            }
        }
    }

    int Q;
    cin >> Q;

    while (Q--) {
        int a, b;
        cin >> a >> b;

        vector<long long> dist(N + 1, LLONG_MAX);
        priority_queue<pair<long long, int>, vector<pair<long long, int>>, greater<pair<long long, int>>> pq;

        dist[a] = C[a];
        pq.push({C[a], a});

        while (!pq.empty()) {
            auto [d, u] = pq.top();
            pq.pop();

            if (d > dist[u]) continue;

            for (int v : adj[u]) {
                long long newDist = dist[u] + C[v];
                if (newDist < dist[v]) {
                    dist[v] = newDist;
                    pq.push({newDist, v});
                }
            }
        }

        if (dist[b] == LLONG_MAX) {
            cout << -1 << endl;
        } else {
            cout << dist[b] << endl;
        }
    }

    return 0;
}

