    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        PrintWriter pw = new PrintWriter(System.out);

        int N = Integer.parseInt(br.readLine());

        long[] C = new long[N + 1];
        String[] costLine = br.readLine().split(" ");
        for (int i = 1; i <= N; i++) {
            C[i] = Long.parseLong(costLine[i - 1]);
        }

        int[] S = new int[N + 1];
        int[] E = new int[N + 1];

        for (int i = 1; i <= N; i++) {
            String[] line = br.readLine().split(" ");
            S[i] = Integer.parseInt(line[0]);
            E[i] = Integer.parseInt(line[1]);
        }

        List<List<Integer>> adj = new ArrayList<>();
        for (int i = 0; i <= N; i++) {
            adj.add(new ArrayList<>());
        }

        for (int i = 1; i <= N; i++) {
            for (int j = i + 1; j <= N; j++) {
                if (E[i] < S[j] || E[j] < S[i]) {
                    adj.get(i).add(j);
                    adj.get(j).add(i);
                }
            }
        }

        int Q = Integer.parseInt(br.readLine());

        for (int q = 0; q < Q; q++) {
            String[] query = br.readLine().split(" ");
            int a = Integer.parseInt(query[0]);
            int b = Integer.parseInt(query[1]);

            long result = dijkstra(N, adj, C, a, b);
            pw.println(result);
        }

        pw.flush();
        pw.close();
        br.close();
    }

    static long dijkstra(int N, List<List<Integer>> adj, long[] C, int start, int end) {
        long[] dist = new long[N + 1];
        Arrays.fill(dist, Long.MAX_VALUE);
        dist[start] = C[start];

        PriorityQueue<State> pq = new PriorityQueue<>();
        pq.offer(new State(start, C[start]));

        while (!pq.isEmpty()) {
            State current = pq.poll();
            int u = current.node;
            long cost = current.cost;

            if (cost > dist[u]) continue;

            if (u == end) {
                return cost;
            }

            for (int v : adj.get(u)) {
                long newCost = cost + C[v];
                if (newCost < dist[v]) {
                    dist[v] = newCost;
                    pq.offer(new State(v, newCost));
                }
            }
        }

        return -1;
    }
}

