import java.util.*;
import java.io.*;

public class Main {
    static final long MOD = 998244353;

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line1 = br.readLine();
        if (line1 == null) return;
        int N = Integer.parseInt(line1.trim());
        String T = br.readLine();
        if (T == null) return;

        int K = 0;
        for (int i = 0; i < N; i++) {
            if (T.charAt(i) == '1') K++;
        }

        long[] fact = new long[N + 1];
        long[] invFact = new long[N + 1];
        fact[0] = 1;
        for (int i = 1; i <= N; i++) fact[i] = (fact[i - 1] * i) % MOD;
        invFact[N] = power(fact[N], MOD - 2);
        for (int i = N - 1; i >= 0; i--) invFact[i] = (invFact[i + 1] * (i + 1)) % MOD;

        long totalSequences = 0;
        for (int dN = 0; dN <= K; dN++) {
            long ways = nCr(K, dN, fact, invFact);
            long sumD = N + K - dN;
            long count = solveCircle(N, sumD, fact, invFact);
            totalSequences = (totalSequences + ways * count) % MOD;
        }

        long duplicateSequences = 0;
        if (N % 2 == 0) {
            boolean allOnes = true;
            for (int i = 0; i < N; i++) {
                if (T.charAt(i) == '0') {
                    allOnes = false;
                    break;
                }
            }
            if (allOnes) {
                duplicateSequences = nCr(N, N / 2, fact, invFact);
            }
        }

        long ans = (totalSequences - duplicateSequences + MOD) % MOD;
        System.out.println(ans);
    }

    static long solveCircle(int N, long sumD, long[] fact, long[] invFact) {
        long target = sumD - N;
        if (target < 0 || target > N) return 0;
        return nCr(N, (int) target, fact, invFact);
    }

    static long nCr(int n, int r, long[] fact, long[] invFact) {
        if (r < 0 || r > n) return 0;
        return fact[n] * invFact[r] % MOD * invFact[n - r] % MOD;
    }

    static long power(long base, long exp) {
        long res = 1;
        base %= MOD;
        while (exp > 0) {
            if (exp % 2 == 1) res = (res * base) % MOD;
            base = (base * base) % MOD;
            exp /= 2;
        }
        return res;
    }
}

