int solve(int n, string x, string y) {
    int countX = 0, countY = 0;
    for (char c : x) if (c == '1') countX++;
    for (char c : y) if (c == '1') countY++;

    if (countX != countY) return -1;

    vector<int> initial, target;
    for (int i = 0; i < n; i++) {
        if (x[i] == '1') initial.push_back(i);
        if (y[i] == '1') target.push_back(i);
    }

    if (initial == target) return 0;

    set<vector<int>> visited;
    queue<pair<vector<int>, int>> q;

    q.push({initial, 0});
    visited.insert(initial);

    while (!q.empty()) {
        auto [state, dist] = q.front();
        q.pop();

        for (int k = 0; k < n; k++) {
            vector<int> next = state;
            for (int& pos : next) {
                if (k < pos) pos--;
                else if (k > pos) pos++;
            }
            sort(next.begin(), next.end());

            vector<int> positions;
            for (int p : next) {
                if (positions.empty() || positions.back() != p) {
                    positions.push_back(p);
                }
            }

            if (positions == target) {
                return dist + 1;
            }

            if (visited.find(next) == visited.end()) {
                visited.insert(next);
                q.push({next, dist + 1});
            }
        }
    }

    return -1;
}

