func solve(N int, X string, Y string) int {
    countX := strings.Count(X, "1")
    countY := strings.Count(Y, "1")

    if countX != countY {
        return -1
    }

    initial := make([]int, N)
    for i := 0; i < N; i++ {
        if X[i] == '1' {
            initial[i] = 1
        }
    }

    target := make([]int, N)
    for i := 0; i < N; i++ {
        if Y[i] == '1' {
            target[i] = 1
        }
    }

    if stateToString(initial) == stateToString(target) {
        return 0
    }

    queue := [][]int{initial}
    visited := make(map[string]bool)
    visited[stateToString(initial)] = true
    steps := 0

    for len(queue) > 0 {
        steps++
        size := len(queue)

        for s := 0; s < size; s++ {
            current := queue[0]
            queue = queue[1:]

            for k := 0; k < N; k++ {
                next := applyOperation(current, k)

                nextStr := stateToString(next)
                if nextStr == stateToString(target) {
                    return steps
                }

                if !visited[nextStr] {
                    visited[nextStr] = true
                    queue = append(queue, next)
                }
            }
        }
    }

    return -1
}

func applyOperation(state []int, k int) []int {
    N := len(state)
    next := make([]int, N)

    for j := 0; j < N; j++ {
        if state[j] > 0 {
            var newPos int
            if k < j {
                newPos = j - 1
            } else if k > j {
                newPos = j + 1
            } else {
                newPos = j
            }
            next[newPos] += state[j]
        }
    }

    return next
}

func stateToString(state []int) string {
    var sb strings.Builder
    for i, v := range state {
        if i > 0 {
            sb.WriteString(",")
        }
        fmt.Fprintf(&sb, "%d", v)
    }
    return sb.String()
}

