        StringBuilder output = new StringBuilder();

        for (int t = 0; t < T; t++) {
            int N = Integer.parseInt(br.readLine());
            String X = br.readLine();
            String Y = br.readLine();

            int result = solve(N, X, Y);
            output.append(result).append("\n");
        }

        System.out.print(output);
    }

    static int solve(int N, String X, String Y) {
        int countX = 0, countY = 0;
        for (int i = 0; i < N; i++) {
            if (X.charAt(i) == '1') countX++;
            if (Y.charAt(i) == '1') countY++;
        }

        if (countX != countY) return -1;

        int[] initial = new int[N];
        for (int i = 0; i < N; i++) {
            if (X.charAt(i) == '1') initial[i] = 1;
        }

        if (matches(initial, Y)) return 0;

        Queue<State> queue = new LinkedList<>();
        Set<String> visited = new HashSet<>();

        String initStr = arrToString(initial);
        queue.offer(new State(initial, 0));
        visited.add(initStr);

        while (!queue.isEmpty()) {
            State curr = queue.poll();

            for (int k = 0; k < N; k++) {
                int[] next = move(curr.config, k);

                if (matches(next, Y)) {
                    return curr.steps + 1;
                }

                String nextStr = arrToString(next);
                if (!visited.contains(nextStr)) {
                    visited.add(nextStr);
                    queue.offer(new State(next, curr.steps + 1));
                }
            }
        }

        return -1;
    }

    static int[] move(int[] config, int k) {
        int N = config.length;
        int[] next = new int[N];

        for (int j = 0; j < N; j++) {
            if (config[j] > 0) {
                int newPos;
                if (k < j) {
                    newPos = j - 1;
                } else if (k > j) {
                    newPos = j + 1;
                } else {
                    newPos = j;
                }
                next[newPos] += config[j];
            }
        }

        return next;
    }

    static boolean matches(int[] config, String Y) {
        int N = config.length;
        for (int i = 0; i < N; i++) {
            boolean hasCandy = config[i] > 0;
            boolean shouldHave = Y.charAt(i) == '1';
            if (hasCandy != shouldHave) return false;
        }
        return true;
    }

    static String arrToString(int[] arr) {
        StringBuilder sb = new StringBuilder();
        for (int val : arr) {
            sb.append(val).append(",");
        }
        return sb.toString();
    }

    static class State {
        int[] config;
        int steps;

        State(int[] config, int steps) {
            this.config = config;
            this.steps = steps;
        }
    }
