from collections import deque

def apply_operation(state, k, n):
    new_state = [0] * n
    for j in range(n):
        if state[j] > 0:
            if k < j:
                new_state[j - 1] += state[j]
            elif k > j:
                new_state[j + 1] += state[j]
            else:
                new_state[j] += state[j]
    return tuple(new_state)

def has_candy(state, n):
    result = ['0'] * n
    for i in range(n):
        if state[i] > 0:
            result[i] = '1'
    return ''.join(result)

def solve(n, x, y):
    if x.count('1') != y.count('1'):
        return -1

    if x == y:
        return 0

    initial_state = tuple(1 if x[i] == '1' else 0 for i in range(n))

    queue = deque([(initial_state, 0)])
    visited = {initial_state}

    while queue:
        state, ops = queue.popleft()

        for k in range(n):
            new_state = apply_operation(state, k, n)

            if new_state not in visited:
                visited.add(new_state)

                config = has_candy(new_state, n)
                if config == y:
                    return ops + 1

                queue.append((new_state, ops + 1))

    return -1

