        String[] parts = br.readLine().split(" ");
        long[] p = new long[n];
        for (int i = 0; i < n; i++) {
            p[i] = Long.parseLong(parts[i]);
        }

        Map<State, Long> dp = new HashMap<>();
        dp.put(new State(0, 0), 0L);

        for (int i = 0; i < n; i++) {
            Map<State, Long> newDp = new HashMap<>();

            for (Map.Entry<State, Long> entry : dp.entrySet()) {
                State state = entry.getKey();
                long sum = entry.getValue();
                int len = state.len;
                long last = state.last;

                State addState = new State(len + 1, p[i]);
                long addSum = sum + p[i];
                newDp.put(addState, Math.max(newDp.getOrDefault(addState, Long.MIN_VALUE), addSum));

                if (len > 0) {
                    State removeState = new State(len - 1, len == 1 ? 0 : last);
                    long removeSum = sum - last;
                    newDp.put(removeState, Math.max(newDp.getOrDefault(removeState, Long.MIN_VALUE), removeSum));
                }
            }

            dp = newDp;
        }

        long maxSum = Long.MIN_VALUE;
        for (long sum : dp.values()) {
            maxSum = Math.max(maxSum, sum);
        }

        System.out.println(maxSum);
    }

    static class State {
        int len;
        long last;

        State(int len, long last) {
            this.len = len;
            this.last = last;
        }

        public boolean equals(Object o) {
            if (this == o) return true;
            if (!(o instanceof State)) return false;
            State state = (State) o;
            return len == state.len && last == state.last;
        }

        public int hashCode() {
            return Objects.hash(len, last);
        }
    }
}

