func NewFenwickTree(n int) *FenwickTree {
	return &FenwickTree{tree: make([]int, n+1)}
}

func (f *FenwickTree) Add(i int, val int) {
	for i < len(f.tree) {
		f.tree[i] += val
		i += i & -i
	}
}

func (f *FenwickTree) Query(i int) int {
	sum := 0
	for i > 0 {
		sum += f.tree[i]
		i -= i & -i
	}
	return sum
