            while (p) {
                if (p & 1) inv = (inv * base) % MOD;
                base = (base * base) % MOD;
                p >>= 1;
            }
            res = (res * inv) % MOD;
        }
        total = (total * res) % MOD;
    }

    bool symmetric = true;
    int sz = node->children.size();
