    static boolean canTransform(String L, String M) {
        if (L.equals(M)) {
            return true;
        }

        Set<String> visited = new HashSet<>();
        Queue<String> queue = new LinkedList<>();
        queue.add(L);
        visited.add(L);

        while (!queue.isEmpty()) {
            String current = queue.poll();

            List<String> nextStates = getNextStates(current);
            for (String next : nextStates) {
                if (next.equals(M)) {
                    return true;
                }
                if (!visited.contains(next)) {
                    visited.add(next);
                    queue.add(next);
                }
            }
        }

        return false;
    }

    static List<String> getNextStates(String s) {
        List<String> result = new ArrayList<>();
        char[] arr = s.toCharArray();
        int len = X + Y;

        for (int i = 0; i <= N - len; i++) {
            boolean canOpA = true;
            for (int j = i; j < i + X; j++) {
                if (arr[j] != '0') {
                    canOpA = false;
                    break;
                }
            }
            if (canOpA) {
                for (int j = i + X; j < i + X + Y; j++) {
                    if (arr[j] != '1') {
                        canOpA = false;
                        break;
                    }
                }
            }

            if (canOpA) {
                char[] newArr = arr.clone();
                for (int j = i; j < i + Y; j++) {
                    newArr[j] = '1';
                }
                for (int j = i + Y; j < i + Y + X; j++) {
                    newArr[j] = '0';
                }
                result.add(new String(newArr));
            }

            boolean canOpB = true;
            for (int j = i; j < i + Y; j++) {
                if (arr[j] != '1') {
                    canOpB = false;
                    break;
                }
            }
            if (canOpB) {
                for (int j = i + Y; j < i + Y + X; j++) {
                    if (arr[j] != '0') {
                        canOpB = false;
                        break;
                    }
                }
            }

            if (canOpB) {
                char[] newArr = arr.clone();
                for (int j = i; j < i + X; j++) {
                    newArr[j] = '0';
                }
                for (int j = i + X; j < i + X + Y; j++) {
                    newArr[j] = '1';
