vector<long long> get_canonical(int n, int x, int y, const string& s) {
    int g = 1;
    int a = x + y;
    int b = x;
    int current_pos = 0;
    vector<int> p;
    for (int i = 0; i < n; ++i) {
        if (s[i] == '1') {
            p.push_back(i);
        }
    }

    int k = p.size();
    if (k % y != 0) return {-1};
    int m = k / y;
    vector<long long> coords;
    for (int j = 0; j < m; ++j) {
        long long sum_p = 0;
        for (int i = 0; i < y; ++i) {
            sum_p += p[j * y + i];
        }
        long long val = sum_p - (long long)y * (y - 1) / 2;
        if (val % x != 0) return {-1};
        coords.push_back(val / x - (long long)j * (x + y));
    }
    return coords;
}

