            mPrefix[i + 1] = mPrefix[i] + mBlocks.get(i).len;
        }

        for (int i = 1; i < size; i++) {
            char type = lBlocks.get(i - 1).type;
            if (type == '0') {
                if (lPrefix[i] < mPrefix[i]) {
                    long diff = mPrefix[i] - lPrefix[i];
                    if (diff % y != 0) {
                        System.out.println("No");
                        return;
