                    if (diff % x != 0) {
                        System.out.println("No");
                        return;
                    }
                } else if (lPrefix[i] > mPrefix[i]) {
                    long diff = lPrefix[i] - mPrefix[i];
                    if (diff % y != 0) {
                        System.out.println("No");
                        return;
                    }
                }
            }
        }

        if (lPrefix[size] != mPrefix[size]) {
            System.out.println("No");
            return;
        }

        System.out.println("Yes");
    }

    static List<Block> parse(String s) {
        List<Block> res = new ArrayList<>();
        if (s.isEmpty()) return res;
        char curr = s.charAt(0);
        int count = 1;
        for (int i = 1; i < s.length(); i++) {
            if (s.charAt(i) == curr) {
                count++;
            } else {
                res.add(new Block(curr, count));
                curr = s.charAt(i);
                count = 1;
            }
        }
        res.add(new Block(curr, count));
        return res;
    }

