        if not s:
            return blocks

        current_char = s[0]
        count = 0
        for char in s:
            if char == current_char:
                count += 1
            else:
                blocks.append((current_char, count))
                current_char = char
                count = 1
        blocks.append((current_char, count))
        return blocks

    l_blocks = get_blocks(l_str)
    m_blocks = get_blocks(m_str)

    if l_blocks[0][0] != m_blocks[0][0] or l_blocks[-1][0] != m_blocks[-1][0]:
        print("No")
        return

    if len(l_blocks) != len(m_blocks):
        print("No")
        return

    for i in range(len(l_blocks)):
        char, l_count = l_blocks[i]
        _, m_count = m_blocks[i]

        if char == '0':
            if l_count < x and m_count >= x:
                print("No")
                return
            if l_count >= x and m_count < x:
