func canAchieve(X, Y []int, n, S int) bool {
	xFixed := []int{}
	xFree := 0
	yNeeds := []int{}

	for i := 0; i < n; i++ {
		if Y[i] != -1 {
			need := S - Y[i]
			if need < 0 {
				return false
			}
			yNeeds = append(yNeeds, need)
		}
	}

	for i := 0; i < n; i++ {
		if X[i] == -1 {
			xFree++
		} else {
			if X[i] > S {
				return false
			}
			xFixed = append(xFixed, X[i])
		}
	}

	if xFree < len(yNeeds) {
		return false
	}

	used := make([]bool, len(xFixed))
	for _, need := range yNeeds {
		found := false
		for j := 0; j < len(xFixed); j++ {
			if !used[j] && xFixed[j] == need {
				used[j] = true
				found = true
				break
			}
		}
		if !found {
			if xFree > 0 {
				xFree--
			} else {
				return false
			}
		}
	}

	remainingY := n - len(yNeeds)
	unusedX := 0
	for j := 0; j < len(xFixed); j++ {
		if !used[j] {
			unusedX++
		}
	}

	if unusedX > remainingY {
		return false
	}

	return true
}

