                if (X[i] != -1 && Y[j] != -1) {
                    possibleSums.add(X[i] + Y[j]);
                }
            }
        }

        if (possibleSums.isEmpty()) {
            possibleSums.add(minSum);
        }

        for (long sum : possibleSums) {
            if (sum < minSum) continue;
            if (canAchieve(X, Y, sum, n)) {
                System.out.println("Yes");
                return;
            }
        }

        System.out.println("No");
    }

    static boolean canAchieve(long[] X, long[] Y, long targetSum, int n) {
        List<Long> xValues = new ArrayList<>();
        List<Long> yNeeds = new ArrayList<>();

        int xWildcards = 0;
        int yWildcards = 0;

        for (int i = 0; i < n; i++) {
            if (X[i] == -1) {
                xWildcards++;
            } else {
                xValues.add(X[i]);
            }
        }

        for (int i = 0; i < n; i++) {
            if (Y[i] == -1) {
                yWildcards++;
            } else {
                long need = targetSum - Y[i];
                if (need < 0) return false;
                yNeeds.add(need);
            }
        }

        Collections.sort(xValues);
        Collections.sort(yNeeds);

        boolean[] usedX = new boolean[xValues.size()];

        for (long need : yNeeds) {
            boolean found = false;
            for (int j = 0; j < xValues.size(); j++) {
                if (!usedX[j] && xValues.get(j) == need) {
                    usedX[j] = true;
                    found = true;
                    break;
                }
            }
            if (!found) {
                if (xWildcards > 0) {
                    xWildcards--;
                } else {
                    return false;
                }
            }
        }

        int unmatchedX = 0;
        for (int j = 0; j < xValues.size(); j++) {
            if (!usedX[j]) unmatchedX++;
        }

        if (unmatchedX > yWildcards) return false;

        return true;
    }
