    sort(y_fixed.rbegin(), y_fixed.rend());

    long long S_min = 0;
    if (!x_fixed.empty() && !y_fixed.empty()) {
        int n_fixed_x = x_fixed.size();
        int n_fixed_y = y_fixed.size();
        int common = 0;
        for (int i = 0; i < n_fixed_x && i < n_fixed_y; ++i) {
