        }
    }
    for (long long x : x_fixed) S_min = max(S_min, x);
    for (long long y : y_fixed) S_min = max(S_min, y);

    auto check = [&](long long S) {
        vector<long long> x_req;
        for (long long y : y_fixed) {
            x_req.push_back(S - y);
        }
        sort(x_req.begin(), x_req.end());

