import sys

def solve():
    input_data = sys.stdin.read().split()
    if not input_data:
        return
    n = int(input_data[0])
    x_raw = list(map(int, input_data[1:n+1]))
    y_raw = list(map(int, input_data[n+1:2*n+1]))

    x_known = sorted([v for v in x_raw if v != -1])
    y_known = sorted([v for v in y_raw if v != -1], reverse=True)

    x_missing = n - len(x_known)
    y_missing = n - len(y_known)

    min_s = 0
    for i in range(min(len(x_known), len(y_known))):
        min_s = max(min_s, x_known[len(x_known) - 1 - i] + y_known[len(y_known) - 1 - i])
    if len(x_known) > 0:
        min_s = max(min_s, x_known[-1])
    if len(y_known) > 0:
        min_s = max(min_s, y_known[-1])

    possible_s = []
    if len(x_known) > 0 and len(y_known) > 0:
        for i in range(len(x_known)):
            for j in range(len(y_known)):
                s = x_known[i] + y_known[j]
                if s >= min_s:
                    possible_s.append(s)

    if not possible_s:
        possible_s.append(min_s)

    unique_s = sorted(list(set(possible_s)))

    for s in unique_s:
        temp_x = x_known[:]
        temp_y = y_known[:]

        i, j = 0, 0
        matches = 0
        while i < len(temp_x) and j < len(temp_y):
            if temp_x[i] + temp_y[j] <= s:
                matches += 1
                i += 1
                j += 1
            else:
                j += 1

        needed_x_for_y = len(temp_y) - matches
        needed_y_for_x = len(temp_x) - matches

        if needed_x_for_y <= x_missing and needed_y_for_x <= y_missing:
            remaining_slots = n - (matches + needed_x_for_y + needed_y_for_x)
            if remaining_slots >= 0:
                print("Yes")
                return

    print("No")

