using namespace std;

int n;
vector<int> robots;
unordered_map<int, int> memo;

int countSwaps(vector<int>& positions, int mask) {
    int swaps = 0;
    for (int i = 0; i < positions.size(); i++) {
        for (int j = i + 1; j < positions.size(); j++) {
            if (positions[i] > positions[j]) {
                swaps++;
            }
        }
        for (int bit = 0; bit < n; bit++) {
            if (!(mask & (1 << bit)) && bit < positions[i]) {
                swaps++;
            }
        }
    }
    return swaps;
}

int solve(int mask) {
    if (mask == 0) return 0;

    if (memo.find(mask) != memo.end()) {
        return memo[mask];
    }

    int result = INT_MAX;

    unordered_map<int, vector<int>> typePositions;
    for (int i = 0; i < n; i++) {
        if (mask & (1 << i)) {
            typePositions[robots[i]].push_back(i);
        }
    }

    for (auto& p : typePositions) {
        vector<int>& positions = p.second;

        for (int groupMask = 1; groupMask < (1 << positions.size()); groupMask++) {
            vector<int> selectedPos;
            int newMask = mask;

            for (int j = 0; j < positions.size(); j++) {
                if (groupMask & (1 << j)) {
                    selectedPos.push_back(positions[j]);
                    newMask ^= (1 << positions[j]);
                }
            }

            int swaps = countSwaps(selectedPos, mask);
            int cost = swaps + 1 + solve(newMask);
            result = min(result, cost);
        }
    }

    memo[mask] = result;
    return result;
}

int main() {
    int T;
    cin >> T;

    while (T--) {
        cin >> n;
        robots.clear();
        robots.resize(n);
        memo.clear();

        for (int i = 0; i < n; i++) {
