func minMoves(robots []int) int {
    type State struct {
        robots []int
        moves  int
    }

    queue := []State{{robots: robots, moves: 0}}
    visited := make(map[string]bool)
    visited[arrayToString(robots)] = true

    for len(queue) > 0 {
        current := queue[0]
        queue = queue[1:]

        if len(current.robots) == 0 {
            return current.moves
        }

        for j := 0; j < len(current.robots)-1; j++ {
            newRobots := make([]int, len(current.robots))
            copy(newRobots, current.robots)
            newRobots[j], newRobots[j+1] = newRobots[j+1], newRobots[j]

            key := arrayToString(newRobots)
            if !visited[key] {
                visited[key] = true
                queue = append(queue, State{robots: newRobots, moves: current.moves + 1})
            }
        }

        for j := 1; j <= len(current.robots); j++ {
            allSame := true
            for k := 1; k < j; k++ {
                if current.robots[k] != current.robots[0] {
                    allSame = false
                    break
                }
            }

            if allSame {
                newRobots := make([]int, len(current.robots)-j)
                copy(newRobots, current.robots[j:])

                key := arrayToString(newRobots)
                if !visited[key] {
                    visited[key] = true
                    queue = append(queue, State{robots: newRobots, moves: current.moves + 1})
                }
            }
        }
    }

    return -1
}

func arrayToString(arr []int) string {
    if len(arr) == 0 {
        return ""
    }
    var sb strings.Builder
    for i, v := range arr {
        if i > 0 {
            sb.WriteString(",")
        }
        sb.WriteString(strconv.Itoa(v))
    }
    return sb.String()
}

