        if (arr.length == 0) return 0;

        String key = Arrays.toString(arr);
        if (memo.containsKey(key)) return memo.get(key);

        int minMoves = Integer.MAX_VALUE;

        for (int type = 1; type <= arr.length; type++) {
            boolean found = false;
            for (int i = 0; i < arr.length; i++) {
                if (arr[i] == type) {
                    found = true;
                    break;
                }
            }
            if (!found) continue;

            int firstPos = -1;
            for (int i = 0; i < arr.length; i++) {
                if (arr[i] == type) {
                    firstPos = i;
                    break;
                }
            }

            int swaps = 0;
            int[] temp = arr.clone();

            for (int i = firstPos; i > 0; i--) {
                temp[i] = temp[i-1];
                temp[i-1] = type;
                swaps++;
            }

            int count = 0;
            for (int i = 0; i < temp.length; i++) {
                if (temp[i] == type) count++;
                else break;
            }

            int[] remaining = new int[temp.length - count];
            System.arraycopy(temp, count, remaining, 0, remaining.length);

            int moves = swaps + 1 + solve(remaining);
            minMoves = Math.min(minMoves, moves);
        }

        memo.put(key, minMoves);
        return minMoves;
    }

