public class Main {
    static class FastReader {
        private InputStream bf;
        private byte[] buffer = new byte[65536];
        private int ptr = 0;
        private int len = 0;

        public FastReader(InputStream bf) {
            this.bf = bf;
        }

        private byte read() {
            if (ptr == len) {
                ptr = 0;
                try {
                    len = bf.read(buffer);
                } catch (IOException e) {
                    return -1;
                }
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }

        public int nextInt() {
            int n = 0;
            byte b = read();
            while (b != -1 && b <= 32) b = read();
            if (b == -1) return -1;
            while (b > 32) {
                n = n * 10 + (b - '0');
                b = read();
            }
            return n;
        }
    }

    public static void main(String[] args) {
        FastReader fr = new FastReader(System.in);
        int T = fr.nextInt();
