        fact[0] = 1;
        for (int i = 1; i < N; i++) {
            fact[i] = (fact[i - 1] * i) % MOD;
        }

        for (int q = 0; q < Q; q++) {
            String[] query = br.readLine().split(" ");
            int s = Integer.parseInt(query[0]);
            int t = Integer.parseInt(query[1]);

            long ans = 0;

            for (int i = 2; i <= N; i++) {
                long contrib = computeContribution(N, s, t, i, fact);
                contrib = (contrib * (L[i] % MOD)) % MOD;
                ans = (ans + contrib) % MOD;
            }

            out.println(ans);
