    static long computeContribution(int N, int s, int t, int i, long[] fact) {
        if (i == s || i == t) {
            return fact[N - 1];
        }

        int min = Math.min(s, t);
        int max = Math.max(s, t);

        if (i == 1) {
            return fact[N - 1];
        }

        if (i < min) {
            long count = 0;
            count = (fact[N - 1] * 2) % MOD;
            count = (count * (min - i)) % MOD;
            count = (count * modInv(min - 1, MOD)) % MOD;
            return count;
        } else if (i > max) {
            long count = 0;
            count = (fact[N - 1] * 2) % MOD;
            count = (count * (i - max)) % MOD;
            count = (count * modInv(i - 1, MOD)) % MOD;
            return count;
        } else {
            long count = (fact[N - 1] * 2) % MOD;
            count = (count * modInv(i - 1, MOD)) % MOD;
            return count;
        }
    }

    static long modInv(long a, long mod) {
        return modPow(a, mod - 2, mod);
    }

    static long modPow(long base, long exp, long mod) {
        long result = 1;
        base %= mod;
        while (exp > 0) {
            if (exp % 2 == 1) {
                result = (result * base) % mod;
            }
            base = (base * base) % mod;
            exp /= 2;
        }
        return result;
    }
