    public static void main(String[] args) throws IOException {
        FastReader fr = new FastReader(System.in);
        int N = fr.nextInt();
        int Q = fr.nextInt();

        long[] L = new long[N + 1];
        for (int i = 2; i <= N; i++) {
            L[i] = fr.nextLong() % MOD;
        }

        long[] fact = new long[N + 1];
        fact[0] = 1;
        for (int i = 1; i <= N; i++) fact[i] = (fact[i - 1] * i) % MOD;

        long[] inv = new long[N + 1];
        inv[1] = 1;
        for (int i = 2; i <= N; i++) {
            inv[i] = (MOD - (MOD / i) * inv[MOD % i] % MOD) % MOD;
        }

        long[] S = new long[N + 1];
        for (int i = 2; i <= N; i++) {
            S[i] = (S[i - 1] + L[i] * inv[i - 1]) % MOD;
        }

        PrintWriter out = new PrintWriter(System.out);
        long totalPerms = fact[N - 1];

        for (int j = 0; j < Q; j++) {
            int s = fr.nextInt();
            int t = fr.nextInt();
            if (s > t) {
                int temp = s;
                s = t;
                t = temp;
            }

            long ans = (S[t] - S[s] + MOD) % MOD;
            ans = (ans * totalPerms) % MOD;
            out.println(ans);
        }
        out.flush();
    }

    static class FastReader {
        private InputStream in;
        private byte[] buffer = new byte[1024 * 8];
        private int pointer = 0;
        private int bufferLength = 0;

        public FastReader(InputStream in) {
            this.in = in;
        }

        private boolean hasNextByte() {
            if (pointer < bufferLength) return true;
            pointer = 0;
            try {
                bufferLength = in.read(buffer);
            } catch (IOException e) {
                return false;
            }
            return bufferLength > 0;
        }

        private int readByte() {
            return hasNextByte() ? buffer[pointer++] : -1;
        }

        public int nextInt() {
            int b = readByte();
            while (b != -1 && b <= 32) b = readByte();
            if (b == -1) return 0;
            int n = 0;
            boolean minus = false;
            if (b == '-') {
                minus = true;
                b = readByte();
            }
            while (b >= '0' && b <= '9') {
                n = n * 10 + (b - '0');
                b = readByte();
            }
            return minus ? -n : n;
        }

        public long nextLong() {
            int b = readByte();
            while (b != -1 && b <= 32) b = readByte();
            if (b == -1) return 0;
            long n = 0;
            boolean minus = false;
            if (b == '-') {
                minus = true;
                b = readByte();
            }
            while (b >= '0' && b <= '9') {
                n = n * 10 + (b - '0');
                b = readByte();
            }
            return minus ? -n : n;
        }
    }
}

