map<pair<int,int>, long long> memo;

long long solve(int l, int r) {
    if (r - l + 1 <= 1) return 0;

    pair<int,int> key = {l, r};
    if (memo.find(key) != memo.end()) return memo[key];

    long long result = 0;

    int len = r - l + 1;

    if (len == 2) {
        result = abs(c[l] - c[r]);
    } else {
        for (int k = l; k < r; k++) {
            int left_len = k - l + 1;
            int right_len = r - k;

            long long base = solve(l, k) + solve(k + 1, r);

            if (left_len % 2 == 1 && right_len % 2 == 1) {
                long long extra = 0;
                for (int i = l; i <= k; i++) {
                    for (int j = k + 1; j <= r; j++) {
                        extra = max(extra, abs(c[i] - c[j]));
                    }
                }
                result = max(result, base + extra);
            } else {
                result = max(result, base);
            }
        }
    }

    memo[key] = result;
    return result;
}

