func abs(x int) int {
	if x < 0 {
		return -x
	}
	return x
}

func max(a, b int) int {
	if a > b {
		return a
	}
	return b
}

func solve(cargo []int) int {
	n := len(cargo)
	if n == 0 {
		return 0
	}

	dp := make([][]int, n)
	for i := range dp {
		dp[i] = make([]int, n)
		for j := range dp[i] {
			dp[i][j] = -1
		}
	}

	var rec func(i, j int) int
	rec = func(i, j int) int {
		if i > j {
			return 0
		}
		if i == j {
			return 0
		}

		if dp[i][j] != -1 {
			return dp[i][j]
		}

		result := 0

		for k := i + 1; k <= j; k++ {
			benefit := abs(cargo[i] - cargo[k])

			left := 0
			if k > i+1 {
				left = rec(i+1, k-1)
			}
			right := 0
			if k < j {
				right = rec(k+1, j)
			}

			result = max(result, benefit+left+right)
		}

		dp[i][j] = result
		return result
	}

	return rec(0, n-1)
}

