func solve(R, C int, grid []string) int64 {
	type State struct {
		right []bool
		bottom []bool
	}

	xConfigs := [][]bool{
		{true, true, false, false},
		{false, true, true, false},
		{false, false, true, true},
		{true, false, false, true},
	}

	yConfigs := [][]bool{
		{true, false, true, false},
		{false, true, false, true},
	}

	var dp func(row, col int, topEdges []bool, leftEdge bool) int64
	memo := make(map[string]int64)

	dp = func(row, col int, topEdges []bool, leftEdge bool) int64 {
		if row == R {
			return 1
		}

		nextRow := row
		nextCol := col + 1
		if nextCol == C {
			nextCol = 0
			nextRow++
		}

		key := fmt.Sprintf("%d,%d,%v,%v", row, col, topEdges, leftEdge)
		if val, ok := memo[key]; ok {
			return val
		}

		cellType := grid[row][col]
		var configs [][]bool
		if cellType == 'X' {
			configs = xConfigs
		} else {
			configs = yConfigs
		}

		var total int64 = 0

		for _, config := range configs {
			top := config[0]
			right := config[1]
			bottom := config[2]
			left := config[3]

			if top != topEdges[col] {
				continue
			}
			if left != leftEdge {
				continue
			}

			if nextRow == R {
				if row == R-1 && col == C-1 {
					valid := true
					for c := 0; c < C; c++ {
						if c == col {
							if bottom {
								valid = false
								break
							}
						} else {
							if topEdges[c] {
								valid = false
								break
							}
						}
					}
					if !valid {
						continue
					}
					if right {
						continue
					}
				} else {
					continue
				}
			}

			newTopEdges := make([]bool, C)
			copy(newTopEdges, topEdges)
			if nextCol == 0 {
				newTopEdges[col] = bottom
			}

			newLeftEdge := right
			if nextCol == 0 {
				newLeftEdge = false
			}

			if row == R-1 && nextRow == R {
				valid := true
				for c := 0; c < C; c++ {
					if newTopEdges[c] {
						valid = false
						break
					}
				}
				if !valid {
					continue
				}
				if newLeftEdge {
					continue
				}
				total = (total + 1) % MOD
			} else {
				total = (total + dp(nextRow, nextCol, newTopEdges, newLeftEdge)) % MOD
			}
		}

		memo[key] = total
		return total
	}

	topEdges := make([]bool, C)
	return dp(0, 0, topEdges, false)
}

