    static void solve(int r, int c) {
        if (r == R) {
            if (isValid()) {
                result = (result + 1) % MOD;
            }
            return;
        }

        int nextR = c == C - 1 ? r + 1 : r;
        int nextC = c == C - 1 ? 0 : c + 1;

        if (board[r][c] == 'X') {
            for (int rot = 0; rot < 4; rot++) {
                config[r][c] = rot;
                solve(nextR, nextC);
            }
        } else {
            for (int rot = 0; rot < 2; rot++) {
                config[r][c] = rot;
                solve(nextR, nextC);
            }
        }
    }

