                int bottomI = (i + 1) % R;
                int[] bottomEdges = getEdges(bottomI, j);
                if (edges[2] != bottomEdges[0]) return false;
            }
        }
        return true;
    }

    static int[] getEdges(int r, int c) {
        int[] edges = new int[4];

        if (board[r][c] == 'X') {
            int rot = config[r][c];
            edges[0] = xConfigs[rot][0][0];
            edges[1] = xConfigs[rot][0][1];
