func countValidPairings(solar, lunar []int, n int) int {
    count := 0
    perm := make([]int, n)
    for i := 0; i < n; i++ {
        perm[i] = i
    }

    for {
        pairing := make([][2]int, n)
        for i := 0; i < n; i++ {
            pairing[i] = [2]int{solar[i], lunar[perm[i]]}
        }

        if isStronglyConnected(2*n, pairing) {
            count++
            count %= MOD
        }

        if !nextPermutation(perm) {
            break
        }
    }

    return count
}

func isStronglyConnected(numStations int, wormholes [][2]int) bool {
    adj := make([][]int, numStations+1)
    for i := 0; i <= numStations; i++ {
        adj[i] = []int{}
    }

    for i := 1; i < numStations; i++ {
        adj[i] = append(adj[i], i+1)
    }

    for _, wh := range wormholes {
        adj[wh[0]] = append(adj[wh[0]], wh[1])
    }

    for start := 1; start <= numStations; start++ {
        visited := make([]bool, numStations+1)
        dfs(start, adj, visited)
        for i := 1; i <= numStations; i++ {
            if !visited[i] {
                return false
            }
        }
    }

    return true
}

func dfs(node int, adj [][]int, visited []bool) {
    visited[node] = true
    for _, neighbor := range adj[node] {
        if !visited[neighbor] {
            dfs(neighbor, adj, visited)
        }
    }
}

func nextPermutation(arr []int) bool {
    n := len(arr)
    i := n - 2
    for i >= 0 && arr[i] >= arr[i+1] {
        i--
    }
    if i < 0 {
        return false
    }
    j := n - 1
    for arr[j] <= arr[i] {
        j--
    }
    arr[i], arr[j] = arr[j], arr[i]
    reverse(arr[i+1:])
    return true
}

func reverse(arr []int) {
    for i, j := 0, len(arr)-1; i < j; i, j = i+1, j-1 {
        arr[i], arr[j] = arr[j], arr[i]
    }
}

