            for (int lMask = 0; lMask < (1 << m); lMask++) {
                if (dp[sMask][lMask] == 0) continue;
                if (Integer.bitCount(sMask) != Integer.bitCount(lMask)) continue;

                int paired = Integer.bitCount(sMask);
                if (paired == m) continue;

                int nextS = -1;
                for (int i = 0; i < m; i++) {
                    if ((sMask & (1 << i)) == 0) {
                        nextS = i;
                        break;
                    }
                }

                for (int j = 0; j < m; j++) {
                    if ((lMask & (1 << j)) != 0) continue;

                    int newSMask = sMask | (1 << nextS);
                    int newLMask = lMask | (1 << j);

                    dp[newSMask][newLMask] = (dp[newSMask][newLMask] + dp[sMask][lMask]) % MOD;
                }
            }
        }

        long totalWays = dp[(1 << m) - 1][(1 << m) - 1];

        long validWays = 0;

        for (int sMask = 0; sMask < (1 << m); sMask++) {
