                        break;
                    }
                    ways = (ways * cnt) % MOD;
                }

                boolean stronglyConnected = true;
                for (int k = 0; k < n - 1; k++) {
                    boolean hasBackEdge = false;
                    for (int i = 0; i < m; i++) {
                        if (sPos.get(i) <= k && lPos.get(sToL[i]) > k) {
                            hasBackEdge = true;
                            break;
                        }
                    }
                    if (!hasBackEdge) {
                        stronglyConnected = false;
                        break;
                    }
                }

                if (stronglyConnected) {
                    validWays = (validWays + ways) % MOD;
                }
            }
