    static long countValid(int sIdx, int[] pairing, boolean[] usedL, List<Integer> sPos, List<Integer> lPos, int n) {
        int m = sPos.size();
        if (sIdx == m) {
            for (int k = 0; k < n - 1; k++) {
                boolean hasBackEdge = false;
                for (int i = 0; i < m; i++) {
                    if (sPos.get(i) <= k && lPos.get(pairing[i]) > k) {
                        hasBackEdge = true;
                        break;
                    }
                }
                if (!hasBackEdge) return 0;
            }
            return 1;
        }

        long count = 0;
        for (int j = 0; j < m; j++) {
            if (!usedL[j]) {
                pairing[sIdx] = j;
                usedL[j] = true;
                count = (count + countValid(sIdx + 1, pairing, usedL, sPos, lPos, n)) % MOD;
                usedL[j] = false;
            }
        }
        return count;
