    def count_matchings(s_pos, l_pos):
        if len(s_pos) == 0:
            return 1

        memo = {}

        def dp(s_idx, l_idx, min_unmatched):
            if s_idx == len(s_pos) and l_idx == len(l_pos):
                return 1 if min_unmatched == float('inf') else 0

            if s_idx == len(s_pos) or l_idx == len(l_pos):
                return 0

            key = (s_idx, l_idx, min_unmatched)
            if key in memo:
                return memo[key]

            result = 0

            for l_match_idx in range(l_idx, len(l_pos)):
                s_match_pos = s_pos[s_idx]
                l_match_pos = l_pos[l_match_idx]

                new_min = min_unmatched
                valid = True

                for i in range(s_idx + 1, len(s_pos)):
                    if s_pos[i] < l_match_pos:
                        new_min = min(new_min, s_pos[i])

                for i in range(l_idx, l_match_idx):
                    if l_pos[i] > s_match_pos:
                        if min_unmatched != float('inf') and l_pos[i] < min_unmatched:
                            valid = False
                            break

                if valid:
                    new_l_pos = l_pos[:l_idx] + l_pos[l_idx:l_match_idx] + l_pos[l_match_idx+1:]
                    result += dp(s_idx + 1, l_idx + (l_match_idx - l_idx), new_min)
                    result %= MOD

            memo[key] = result
            return result

        return dp(0, 0, float('inf'))

