func canSolve(N int, racers [][2]int, L, R int) bool {
	segments := make([]struct {
		lower, upper int
		fixed        bool
		value        int
	}, N)

	for i := 0; i < N; i++ {
		segments[i].lower = -1000000
		segments[i].upper = 1000000
		segments[i].fixed = false
	}

	for i := L; i <= R; i++ {
		a, b := racers[i][0], racers[i][1]
		if a > b {
			a, b = b, a
			if !checkRacer(segments, a-1, b-1, true) {
				return false
			}
		} else {
			if !checkRacer(segments, a-1, b-1, false) {
				return false
			}
		}
	}

	return true
}

func checkRacer(segments []struct {
	lower, upper int
	fixed        bool
	value        int
}, start, end int, reverse bool) bool {
	n := end - start + 1
	values := make([]int, n)
	fixed := make([]bool, n)
	lowerBounds := make([]int, n)
	upperBounds := make([]int, n)

	for i := 0; i < n; i++ {
		idx := start + i
		values[i] = segments[idx].value
		fixed[i] = segments[idx].fixed
		lowerBounds[i] = segments[idx].lower
		upperBounds[i] = segments[idx].upper
	}

	if reverse {
		for i := 0; i < n/2; i++ {
			values[i], values[n-1-i] = -values[n-1-i], -values[i]
			fixed[i], fixed[n-1-i] = fixed[n-1-i], fixed[i]
			lowerBounds[i], upperBounds[n-1-i] = -upperBounds[n-1-i], -lowerBounds[i]
			upperBounds[i], lowerBounds[n-1-i] = -lowerBounds[n-1-i], -upperBounds[i]
		}
		if n%2 == 1 {
			mid := n / 2
			values[mid] = -values[mid]
			lowerBounds[mid], upperBounds[mid] = -upperBounds[mid], -lowerBounds[mid]
		}
	}

	if !tryAssign(values, fixed, lowerBounds, upperBounds, n) {
		return false
	}

	for i := 0; i < n; i++ {
		idx := start + i
		if reverse {
			actualIdx := start + (n - 1 - i)
			actualValue := -values[n-1-i]
			actualLower := -upperBounds[n-1-i]
			actualUpper := -lowerBounds[n-1-i]

			if segments[actualIdx].fixed && segments[actualIdx].value != actualValue {
				return false
			}
			segments[actualIdx].fixed = true
			segments[actualIdx].value = actualValue
			if actualLower > segments[actualIdx].lower {
				segments[actualIdx].lower = actualLower
			}
			if actualUpper < segments[actualIdx].upper {
				segments[actualIdx].upper = actualUpper
			}
		} else {
			if segments[idx].fixed && segments[idx].value != values[i] {
				return false
			}
			segments[idx].fixed = fixed[i]
			segments[idx].value = values[i]
			if lowerBounds[i] > segments[idx].lower {
				segments[idx].lower = lowerBounds[i]
			}
			if upperBounds[i] < segments[idx].upper {
				segments[idx].upper = upperBounds[i]
			}
		}
	}

	return true
}

func tryAssign(values []int, fixed []bool, lower []int, upper []int, n int) bool {
	cumSum := 0
	numFixed := 0
	for i := 0; i < n; i++ {
		if fixed[i] {
			cumSum += values[i]
			numFixed++
		}
	}

	if numFixed == n {
		if cumSum != 0 {
			return false
		}
		cum := 0
		for i := 0; i < n-1; i++ {
			cum += values[i]
			if cum <= 0 {
				return false
			}
		}
		return true
	}

	target := -cumSum
	numUnfixed := n - numFixed

	avg := target / numUnfixed
	rem := target % numUnfixed

	cum := 0
	unfixedIdx := 0
	for i := 0; i < n-1; i++ {
		if fixed[i] {
			cum += values[i]
		} else {
			val := avg
			if unfixedIdx < rem {
				val++
			}
			unfixedIdx++
			cum += val
		}
		if cum <= 0 {
			return false
		}
	}

	return true
}

