		fmt.Fscan(reader, &racers[i].a, &racers[i].b)
	}

	bad := make([]int, m)
	for i := 0; i < m; i++ {
		bad[i] = m
	}

	left := make([]int, n+1)
	right := make([]int, n+1)
	for i := 0; i <= n; i++ {
		left[i] = -1
		right[i] = -1
	}

	lastConflict := -1

	for i := 0; i < m; i++ {
		a, b := racers[i].a, racers[i].b
		u, v := a, b
		if u > v {
			u, v = v, u
		}

		if left[u+1] != -1 {
			if lastConflict < left[u+1] {
				lastConflict = left[u+1]
			}
		}
		if right[v-1] != -1 {
			if lastConflict < right[v-1] {
				lastConflict = right[v-1]
			}
		}

		bad[i] = lastConflict

		if left[v] == -1 || left[v] < i {
			left[v] = i
		}
		if right[u] == -1 || right[u] < i {
			right[u] = i
		}
	}

	sparse := make([][]int, 20)
	sparse[0] = bad
	for j := 1; j < 20; j++ {
		sparse[j] = make([]int, m)
		for i := 0; i < m; i++ {
			prev := sparse[j-1][i]
			if prev == -1 {
				sparse[j][i] = -1
			} else {
				sparse[j][i] = sparse[j-1][i]
				if i >= (1<<(j-1)) {
					other := sparse[j-1][i]
					_ = other
				}
			}
		}
	}

	maxBad := make([]int, m)
	currMax := -1
	for i := 0; i < m; i++ {
		if bad[i] > currMax {
			currMax = bad[i]
		}
		maxBad[i] = currMax
	}

	for k := 0; k < q; k++ {
		var l, r int
		fmt.Fscan(reader, &l, &r)
		l--
		r--
		if maxBad[r] >= l {
			fmt.Fprintln(writer, "No")
		} else {
			fmt.Fprintln(writer, "Yes")
		}
	}
}

import java.io.*;
import java.util.*;

public class Main {
    static class FastReader {
        private final InputStream in;
        private final byte[] buffer = new byte[1024];
        private int ptr = 0;
        private int buflen = 0;

        public FastReader(InputStream in) {
            this.in = in;
        }

        private boolean hasNextByte() {
            if (ptr < buflen) return true;
            ptr = 0;
            try {
                buflen = in.read(buffer);
            } catch (IOException e) {
                e.printStackTrace();
            }
            return buflen > 0;
        }

        private int readByte() {
            return hasNextByte() ? buffer[ptr++] : -1;
        }

        private boolean isPrintableChar(int c) {
            return 33 <= c && c <= 126;
        }

        public boolean hasNext() {
            while (hasNextByte() && !isPrintableChar(buffer[ptr])) ptr++;
            return hasNextByte();
        }

        public int nextInt() {
            if (!hasNext()) throw new NoSuchElementException();
            int n = 0;
            boolean minus = false;
            int b = readByte();
            if (b == '-') {
                minus = true;
                b = readByte();
            }
            if (b < '0' || '9' < b) throw new NumberFormatException();
            while (true) {
                if ('0' <= b && b <= '9') {
                    n *= 10;
                    n += b - '0';
                } else if (b == -1 || !isPrintableChar(b)) {
                    return minus ? -n : n;
                } else {
                    throw new NumberFormatException();
                }
                b = readByte();
            }
        }
    }

    public static void main(String[] args) {
        FastReader sc = new FastReader(System.in);
        int n = sc.nextInt();
        int m = sc.nextInt();
        int q = sc.nextInt();

        int[] a = new int[m];
        int[] b = new int[m];
        for (int i = 0; i < m; i++) {
            a[i] = sc.nextInt();
            b[i] = sc.nextInt();
        }

        int[] bad = new int[m];
        Arrays.fill(bad, m);

        int[] lastPos = new int[n + 1];
        int[] lastNeg = new int[n + 1];
        Arrays.fill(lastPos, -1);
        Arrays.fill(lastNeg, -1);

        for (int i = 0; i < m; i++) {
            int u = a[i], v = b[i];
            if (u < v) {
                for (int j = u; j < v; j++) {
                    if (lastNeg[j] != -1) bad[lastNeg[j]] = Math.min(bad[lastNeg[j]], i);
                    lastPos[j] = i;
                }
            } else {
                for (int j = v; j < u; j++) {
                    if (lastPos[j] != -1) bad[lastPos[j]] = Math.min(bad[lastPos[j]], i);
                    lastNeg[j] = i;
                }
            }
        }

        int[] minBad = new int[m + 1];
        minBad[m] = m;
        for (int i = m - 1; i >= 0; i--) {
            minBad[i] = Math.min(bad[i], minBad[i + 1]);
        }

        PrintWriter out = new PrintWriter(System.out);
        for (int k = 0; k < q; k++) {
            int l = sc.nextInt() - 1;
            int r = sc.nextInt() - 1;
            if (minBad[l] > r) {
                out.println("Yes");
            } else {
                out.println("No");
            }
        }
        out.flush();
        out.close();
    }
}

import sys

def solve():
    input_data = sys.stdin.read().split()
    if not input_data:
        return

    ptr = 0
    N = int(input_data[ptr])
    M = int(input_data[ptr + 1])
    Q = int(input_data[ptr + 2])
    ptr += 3

    racers = []
    for i in range(M):
        a = int(input_data[ptr])
        b = int(input_data[ptr + 1])
        ptr += 2
        if a < b:
            racers.append((a, b, 0))
        else:
            racers.append((b, a, 1))

    queries = []
    for i in range(Q):
        l = int(input_data[ptr]) - 1
        r = int(input_data[ptr + 1]) - 1
        queries.append((l, r, i))
        ptr += 2

    log_m = (M).bit_length()
    sparse_left = [[-1] * M for _ in range(log_m)]
    sparse_right = [[N + 1] * M for _ in range(log_m)]

    for i in range(M):
        if racers[i][2] == 0:
            sparse_left[0][i] = racers[i][0]
            sparse_right[0][i] = racers[i][1]
        else:
            sparse_left[0][i] = racers[i][1]
            sparse_right[0][i] = racers[i][0]

    for k in range(1, log_m):
        for i in range(M - (1 << k) + 1):
            sparse_left[k][i] = max(sparse_left[k-1][i], sparse_left[k-1][i + (1 << (k-1))])
            sparse_right[k][i] = min(sparse_right[k-1][i], sparse_right[k-1][i + (1 << (k-1))])

    def query_max(l, r):
        k = (r - l + 1).bit_length() - 1
        return max(sparse_left[k][l], sparse_left[k][r - (1 << k) + 1])

    def query_min(l, r):
        k = (r - l + 1).bit_length() - 1
        return min(sparse_right[k][l], sparse_right[k][r - (1 << k) + 1])

    bad_threshold = [M] * M

    for i in range(M):
        low = i
        high = M - 1
        ans = M
        while low <= high:
            mid = (low + high)
            mx_l = query_max(i, mid)
            mn_r = query_min(i, mid)
            if mx_l >= mn_r:
                ans = mid
                high = mid - 1
            else:
                low = mid + 1
        bad_threshold[i] = ans

    min_bad = [M] * (M + 1)
    for i in range(M - 1, -1, -1):
        min_bad[i] = min(bad_threshold[i], min_bad[i+1])

    results = []
    for l, r, idx in queries:
        if min_bad[l] <= r:
            results.append("No")
        else:
            results.append("Yes")

    sys.stdout.write("\n".join(results) + "\n")

